// =============================================================================
// AERawIconsColor — same paste-and-go contract as AERawIcons, ONE difference:
// the recolour-to-currentColor step is skipped. Everything else (SVGRepo
// scaffold removal, viewBox normalisation into a 512 canvas, caching into
// AEFillIcons) is identical.
//
// WHEN TO USE WHICH:
//   AERawIcons      — a silhouette. Follows the theme accent. Default choice.
//   AERawIconsColor — the artwork IS the colour (a koi, a blossom). Flattening
//                     it to one fill turns overlapping petals into a blob.
//
// TRADEOFF, stated plainly: entries here ignore ThemeForge and `color`. They
// will look wrong on a theme whose palette fights them. Scope them to a theme
// override (as the sakura entries below are) rather than a global icon name.
//
// PRECEDENCE (see _aeIconRenderKind): theme override → CyberIcons (stroke) →
// AEFillIcons (hand-tuned fill) → AERawIcons → AERawIconsColor.
// =============================================================================
var AERawIconsColor = {
    sakuraBlossom: AE_SAKURA_ART.blossom,   // blossom branch
    sakuraFlower:  AE_SAKURA_ART.flower,    // single 5-petal flower
    koiFish:       AE_SAKURA_ART.koi,        // paired koi medallion
    ceLogo: LOGO_ART.ce,
    witchSpellbook: AE_WITCH_ART.spellbook  // [v2.36.0 WITCH-BOOK-ICON]
};

// Trim float noise from generated transform numbers.
