        //    <title>/<desc> so pasted icons don't inject native tooltips.
        var bg = svg.querySelector('#SVGRepo_bgCarrier');     if (bg) bg.remove();
        var tr = svg.querySelector('#SVGRepo_tracerCarrier'); if (tr) tr.remove();
        var carrier = svg.querySelector('#SVGRepo_iconCarrier');
