function _aeThemedIconSet() {
    var cls = document.documentElement.className || '';
    for (var key in AE_THEME_ICONS) {
        if (cls.indexOf(key) !== -1) return AE_THEME_ICONS[key];
    }
    return null;
}

// [v2.30.0 GHOST-SIGNATURE] Drive the toggle button's ghost glyph into its
// background-work state. Pure DOM class toggle; the .thinking CSS carries the
// per-theme animation (bulb gutter / foxfire ignite).
// [FEATURE v2.32.3 ENGINE-THINKING-SIGNAL, per user: "an indicator for any of our
// thinking and image generation pauses"] Was NOT yet wired to a real signal -- now
// driven from TWO independent sources: the engine's AE_ENGINE_THINKING relay (grep
// the case in the message switch) and this file's own callGenerateAPI wrapper
// (image gen is not always engine-initiated). Both call this with true at their
// start and false in a finally at their end. _aeThinkingRefs is a SHARED count so
// neither source can stomp the other's "on" with a premature "off" if a text
// generation and an image generation happen to overlap -- the glyph only goes
// dark once every caller that turned it on has turned it back off.
var _aeThinkingRefs = 0;
function _aeSetEngineThinking(on) {
    _aeThinkingRefs = Math.max(0, _aeThinkingRefs + (on ? 1 : -1));
    var t = document.getElementById('ae-toggle-btn');
    if (t) t.classList.toggle('thinking', _aeThinkingRefs > 0);
}

// [vNEXT] Unified icon resolution across both families. Precedence:
//   1. Active theme's override for this key (stroke path string, OR a
//      { fill: 'aeKey' } tag routing to the AEFillIcons family)
//   2. CyberIcons[icon]   -> stroke family (24x24, unthemed default)
//   3. AEFillIcons[icon]  -> fill family (512x512) — a same-named fallback,
//      so adding an AEFillIcons entry with an icon's existing name upgrades
//      it everywhere (any getCyberIconHTML/createCyberIcon/$.svg call site)
//      without touching AE_THEME_ICONS or the call site at all.
//   4. not found -> { kind: null }
// _aeIconExists() is the gate other code should use instead of checking
// CyberIcons[x] directly (that bypasses AEFillIcons and theme overrides).
function _aeIconRenderKind(icon) {
    var themed = _aeThemedIconSet();
    var themedVal = themed && themed[icon];
    if (themedVal && typeof themedVal === 'object' && themedVal.fill) return { kind: 'fill', key: themedVal.fill };
    if (themedVal) return { kind: 'stroke', path: themedVal };
    if (CyberIcons[icon]) return { kind: 'stroke', path: CyberIcons[icon] };
    if (AEFillIcons[icon] != null || AERawIcons[icon] != null) return { kind: 'fill', key: icon };
    if (typeof AERawIconsColor !== 'undefined' && AERawIconsColor[icon] != null) return { kind: 'fill', key: icon };
    return { kind: null };
}

function _aeIconExists(icon) {
    return _aeIconRenderKind(icon).kind !== null;
}

// Stroke-only path data for callers that specifically need CyberIcons'
// 24x24 path markup (e.g. to inline into a hand-built stroke <svg>). Returns
// '' for a fill-family icon — stroke path data can't represent one. Most
// code should call getCyberIconHTML/createCyberIcon instead, which handle
// both families automatically.
function _aeResolveIconPath(icon) {
    var r = _aeIconRenderKind(icon);
    return r.kind === 'stroke' ? r.path : '';
}

const getCyberIconHTML = (icon, arg2, arg3) => {
    let size = 16, color = 'currentColor', extraClass = '';
    if (typeof arg2 === 'number' || (typeof arg2 === 'string' && !isNaN(arg2))) {
        size = Number(arg2);
        if (typeof arg3 === 'string') {
            if (arg3.startsWith('#') || arg3.startsWith('var(') || arg3.startsWith('rgb')) color = arg3;
            else extraClass = arg3;
        }
    } else if (typeof arg2 === 'string') {
        color = arg2;
        if (typeof arg3 === 'string') extraClass = arg3;
    }
    const rk = _aeIconRenderKind(icon);
    if (rk.kind === 'fill') return aeFillIconHTML(rk.key, size, color, extraClass ? ('cyber-icon ' + extraClass) : 'cyber-icon');
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="${size}" height="${size}" fill="none" stroke="${color}" stroke-width="1.75" stroke-linecap="square" stroke-linejoin="miter" class="cyber-icon ${extraClass}">${rk.path || ''}</svg>`;
};

function createCyberIcon(icon, size = 16, color = 'currentColor', extraClass = '') {
    const rk = _aeIconRenderKind(icon);
    if (rk.kind === 'fill') return aeCreateFillIcon(rk.key, size, color, extraClass ? ('cyber-icon ' + extraClass) : 'cyber-icon');
    var svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('viewBox', '0 0 24 24');
    svg.setAttribute('width', String(size));
    svg.setAttribute('height', String(size));
    svg.setAttribute('fill', 'none');
    svg.setAttribute('stroke', color);
    svg.setAttribute('stroke-width', '1.75');
    svg.setAttribute('stroke-linecap', 'square');
    svg.setAttribute('stroke-linejoin', 'miter');
    if (extraClass) svg.setAttribute('class', 'cyber-icon ' + extraClass);
    else svg.setAttribute('class', 'cyber-icon');
    svg.innerHTML = rk.path || '';
    return svg;
}

(function injectPulseStylesSafe() {
    const attachStyles = () => {
        if(document.getElementById('cyber-pulse-css')) return;
        const style = document.createElement('style');
        style.id = 'cyber-pulse-css';
        style.textContent = `
            @keyframes cyber-pulse { 0%, 100% { filter: drop-shadow(0 0 2px var(--pulse-color)); stroke: var(--pulse-color); } 50% { filter: drop-shadow(0 0 8px var(--pulse-color)); stroke: var(--pulse-color-light); } }
            .cyber-pulse-green { --pulse-color: #00ff88; --pulse-color-light: #80ffc4; animation: cyber-pulse 3s infinite ease-in-out; }
            .cyber-pulse-cyan { --pulse-color: #00d4ff; --pulse-color-light: #80e9ff; animation: cyber-pulse 3s infinite ease-in-out; animation-delay: 0.5s; }
            .cyber-pulse-pink { --pulse-color: #ff00ff; --pulse-color-light: #ff80ff; animation: cyber-pulse 3s infinite ease-in-out; animation-delay: 1s; }
            .cyber-pulse-amber { --pulse-color: #ffb800; --pulse-color-light: #ffd666; animation: cyber-pulse 3s infinite ease-in-out; animation-delay: 1.5s; }
        `;
        (document.head || document.documentElement).appendChild(style);
    };
    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', attachStyles);
    else attachStyles();
})();
