// =============================================================================
// SECTION 4 — COMPONENT LIBRARY ($)
// All DOM builders. Use these instead of inline element construction.
// Every method returns a DOM element using theme tokens.
// =============================================================================

var $ = {
    // Advanced SVG Library for Cyberpunk/Custom themes
    // Refactored to use getCyberIconHTML for consistency
    svg: function(name, size, className) {
        // Use default color for generic SVG unless specified
        if (!_aeIconExists(name)) return null;
        return createCyberIcon(name, size || 16, 'currentColor', className || '');
    },

    // Labels and headings
    label: function(text) {
        var el = document.createElement('div');
        el.className = 'ae-label';
        el.textContent = text;
        return el;
    },

    // [v2.42.0 SCENE-SWITCH] Two-state slider toggle. onLabel/offLabel are the text shown
    // next to the track for each state; initialOn sets starting state; onChange(isOn) fires
    // after every flip. Returns the wrapper el with .setOn(bool) attached for callers that
    // need to sync it to state changes that didn't originate from a click (e.g. this file's
    // own repaint-from-broadcast pattern used elsewhere for chips/tabs).
    switch: function(onLabel, offLabel, initialOn, onChange) {
        var wrap = document.createElement('div');
        wrap.className = 'ae-switch' + (initialOn ? ' on' : '');
        wrap.setAttribute('role', 'switch');
        wrap.setAttribute('aria-checked', initialOn ? 'true' : 'false');
        var track = document.createElement('span'); track.className = 'ae-switch-track';
        var lbl = document.createElement('span'); lbl.className = 'ae-switch-lbl';
        lbl.textContent = initialOn ? onLabel : offLabel;
        wrap.appendChild(track); wrap.appendChild(lbl);
        var isOn = !!initialOn;
        function paint() {
            wrap.classList.toggle('on', isOn);
            wrap.setAttribute('aria-checked', isOn ? 'true' : 'false');
            lbl.textContent = isOn ? onLabel : offLabel;
        }
        wrap.addEventListener('click', function() {
            isOn = !isOn; paint();
            if (onChange) onChange(isOn);
        });
        wrap.setOn = function(v) { isOn = !!v; paint(); };
        return wrap;
    },

    // Generic button — variant: '' | 'primary' | 'action' | 'danger' | 'success' | 'ghost' | 'sm' | 'icon'
    btn: function(text, variants, onClick) {
        var b = document.createElement('button');
        b.className = 'ae-btn ' + (variants || '');
        
        // Cyberpunk Middleware: Type-safe interception to prevent crashes if 'text' is an object/node
        if (typeof text === 'string' && text.includes('⚡')) {
            b.innerHTML = text.replace(/⚡/g, getCyberIconHTML('bolt', 'currentColor', 'cyber-icon cyber-pulse-amber'));
        } else {
            b.innerHTML = text;
        }
        
        if (onClick) b.addEventListener('click', onClick);
        return b;
    },
    // SVG icon builder — 16x16 viewBox, stroke-based, inherits currentColor.
    // Usage: $.icon('trash') or $.icon('save', 12). Returns an <svg> element.
    icon: function(name, size) {
        var paths = {
            close:   '<line x1="3" y1="3" x2="13" y2="13"/><line x1="13" y1="3" x2="3" y2="13"/>',
            check:   '<polyline points="2,9 6.5,13 14,4"/>',
            edit:    '<path d="M10.5 2.5L13.5 5.5L5 14H2V11Z"/>',
            trash:   '<path d="M3 5H13M6 5V3H10V5M4.5 5L5.5 14H10.5L11.5 5"/>',
            gear:    '<circle cx="8" cy="8" r="2.5"/><path d="M8 1.5V4M8 12V14.5M1.5 8H4M12 8H14.5M3.4 3.4L5.4 5.4M10.6 10.6L12.6 12.6M3.4 12.6L5.4 10.6M10.6 5.4L12.6 3.4"/>',
            plus:    '<path d="M8 2V14M2 8H14"/>',
            search:  '<circle cx="7" cy="7" r="4.5"/><path d="M10.5 10.5L14 14"/>',
            back:    '<polyline points="11,2 4,8 11,14"/>',
            refresh: '<path d="M13 8a5.5 5.5 0 1 0-1.5 3.7"/><polyline points="13,3 13,8.5 7.5,8.5"/>',
            lock:    '<path d="M5 7V5a3 3 0 0 1 6 0V7"/><rect x="3" y="7" width="10" height="7" rx="1.5"/>',
            eye:     '<path d="M1 8C1 8 3.5 2.5 8 2.5C12.5 2.5 15 8 15 8C15 8 12.5 13.5 8 13.5C3.5 13.5 1 8 1 8Z"/><circle cx="8" cy="8" r="2"/>',
            star:    '<polygon points="8,2 9.8,6 14,6.5 11,9.2 11.8,13.5 8,11.3 4.2,13.5 5,9.2 2,6.5 6.2,6"/>',
            save:    '<path d="M3 14V2H11.5L13 3.5V14ZM5.5 2V6H10.5V2M6 9.5H10V14H6V9.5Z"/>',
            download:'<path d="M8 2.5V9.5M5 6.5L8 9.5L11 6.5"/><path d="M3 11.5V13H13V11.5"/>',
            image:   '<rect x="2" y="3" width="12" height="10" rx="1.5"/><polyline points="2,11 5,8 8.5,10.5 10.5,8.5 14,12"/>',
            home:    '<path d="M2.5 7.5L8 2.5L13.5 7.5"/><path d="M4 7V13.5H12V7"/><path d="M6.5 13.5V9.5H9.5V13.5"/>',
            clock:   '<circle cx="8" cy="8" r="5.5"/><polyline points="8,4.5 8,8 10.5,9.5"/>'
        };
        var d = paths[name] || '';
        var svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
        var sz = size || 14;
        svg.setAttribute('width', sz); svg.setAttribute('height', sz);
        svg.setAttribute('viewBox', '0 0 16 16');
        svg.setAttribute('fill', 'none'); svg.setAttribute('stroke', 'currentColor');
        svg.setAttribute('stroke-width', '1.5');
        svg.setAttribute('stroke-linecap', 'round'); svg.setAttribute('stroke-linejoin', 'round');
        svg.style.cssText = 'display:inline-block;vertical-align:middle;flex-shrink:0;';
        svg.innerHTML = d;
        return svg;
    },

    // Row of buttons
    btnRow: function(btns) {
        var row = document.createElement('div');
        row.className = 'ae-btn-row';
        btns.forEach(function(b) { row.appendChild(b); });
        return row;
    },

    // Chip / badge
    chip: function(text, colorVar, bgVar) {
        var el = document.createElement('span');
        el.className = 'ae-chip';
        el.textContent = text;
        el.style.color = 'var(' + (colorVar || '--ae-text-muted') + ')';
        el.style.background = 'var(' + (bgVar || '--ae-bg-hover') + ')';
        el.style.border = '1px solid var(' + (colorVar || '--ae-bg-border') + ')';
        return el;
    },

    // Collapsible section
    section: function(title, fillFn, opts) {
        opts = opts || {};
        // [v0.9.92 SEC-FIX] Refactor left startOpen + stateKey undefined -> render-time
        // ReferenceError aborted every profile before its Avatar Visuals / Image Slots
        // sections could render. Derive both from opts; restore persisted open-state so
        // a collapsed section stays collapsed across HUD re-renders (the click handler's
        // intent). Pass opts.key for a stable key when the title contains dynamic text.
        var stateKey = opts.key || title;
        var startOpen = (_sectionOpenState[stateKey] !== undefined) ? _sectionOpenState[stateKey] : !!opts.open;
        var wrap = document.createElement('div'); wrap.className = 'ae-section';
        var header = document.createElement('div'); header.className = 'ae-section-header';
        var headerText = document.createElement('span'); headerText.innerHTML = title;
        wrap.className = 'ae-section';

        var hdr = document.createElement('div');
        hdr.className = 'ae-section-hdr' + (startOpen ? ' open' : '');
        hdr.innerHTML = title + '<span class="ae-caret">▸</span>';

        var body = document.createElement('div');
        body.className = 'ae-section-body' + (startOpen ? ' open' : '');
        if (fillFn) fillFn(body);

        hdr.addEventListener('click', function() {
            var isOpen = body.classList.contains('open');
            hdr.classList.toggle('open', !isOpen);
            body.classList.toggle('open', !isOpen);
            _sectionOpenState[stateKey] = !isOpen; // persist across re-renders
        });

        wrap.appendChild(hdr);
        wrap.appendChild(body);
        return wrap;
    },

    // Avatar button
    avatar: function(name, bgUrl, bgColor, className, onClick) {
        var btn = document.createElement('button');
        btn.className = 'ae-avatar-btn' + (className ? ' ' + className : '');
        if (bgUrl) {
            btn.style.backgroundImage = 'url(' + JSON.stringify(bgUrl) + ')';
        } else {
            btn.style.background = bgColor || _nameToColor(name || '?');
        }
        if (!bgUrl) {
            var init = document.createElement('div');
            init.className = 'ae-avatar-initial';
            init.textContent = (name || '?').charAt(0).toUpperCase();
            btn.appendChild(init);
        }
        var lbl = document.createElement('div');
        lbl.className = 'ae-avatar-label';
        lbl.textContent = name || '';
        btn.appendChild(lbl);
        if (onClick) btn.addEventListener('click', onClick);
        return btn;
    },

    // Avatar grid container
    avatarGrid: function() {
        var g = document.createElement('div');
        g.className = 'ae-avatar-grid';
        return g;
    },

    // Resource row (pool or track)
    // editable=false → read-only bar + value display (unchanged).
    // editable=true  → inline − [value] + stepper.
    //   onAdjust(res, delta)  — called with ±1 on stepper clicks.
    //   onSet(res, value)     — called when user commits free-input.
    resource: function(res, editable, onAdjust, onSet) {
        var row = document.createElement('div');
        row.className = 'ae-res-row' + (editable ? ' editable' : '');

        var nameEl = document.createElement('span');
        nameEl.className = 'ae-res-name';
        nameEl.textContent = res.name || res.tag;
        row.appendChild(nameEl);

        if (res.type === 'pool') {
            // Progress bar — always rendered
            if (res.max !== undefined && res.max !== null) {
                var bWrap = document.createElement('div');
                bWrap.className = 'ae-res-bar-wrap';
                var bBar = document.createElement('div');
                bBar.className = 'ae-res-bar';
                var bPct = res.max > 0 ? Math.max(0, Math.min(100, (res.value / res.max) * 100)) : 0;
                bBar.style.width = bPct + '%';
                if (bPct < 25) bBar.classList.add('low');
                else if (bPct < 60) bBar.classList.add('mid');
                bWrap.appendChild(bBar);
                row.appendChild(bWrap);
            }
            if (editable) {
                // Inline stepper: − [value/max] +
                var pStepper = document.createElement('div');
                pStepper.className = 'ae-res-stepper';
                var pMinus = document.createElement('button');
                pMinus.type = 'button'; pMinus.className = 'ae-res-stepper-btn'; pMinus.textContent = '−';
                pMinus.addEventListener('click', function() { if (onAdjust) onAdjust(res, -1); });
                var pValBtn = document.createElement('button');
                pValBtn.type = 'button'; pValBtn.className = 'ae-res-val-btn';
                pValBtn.textContent = res.max !== undefined ? res.value + '/' + res.max : String(res.value);
                pValBtn.title = 'Click to set exact value';
                pValBtn.addEventListener('click', function() {
                    var pInp = document.createElement('input');
                    pInp.type = 'number'; pInp.className = 'ae-res-inline-input';
                    pInp.value = String(res.value); pInp.min = '0';
                    if (res.max !== undefined) pInp.max = String(res.max);
                    var pCommit = function() {
                        var v = parseInt(pInp.value, 10);
                        if (!isNaN(v) && onSet) onSet(res, v);
                        if (pInp.parentNode) pInp.parentNode.replaceChild(pValBtn, pInp);
                    };
                    pInp.addEventListener('blur', pCommit);
                    pInp.addEventListener('keydown', function(e) {
                        if (e.key === 'Enter') pInp.blur();
                        else if (e.key === 'Escape') { if (pInp.parentNode) pInp.parentNode.replaceChild(pValBtn, pInp); }
                    });
                    pStepper.replaceChild(pInp, pValBtn);
                    pInp.focus(); pInp.select();
                });
                var pPlus = document.createElement('button');
                pPlus.type = 'button'; pPlus.className = 'ae-res-stepper-btn'; pPlus.textContent = '+';
                pPlus.addEventListener('click', function() { if (onAdjust) onAdjust(res, 1); });
                pStepper.appendChild(pMinus); pStepper.appendChild(pValBtn); pStepper.appendChild(pPlus);
                row.appendChild(pStepper);
            } else {
                // Read-only value display
                var pValSpan = document.createElement('span');
                pValSpan.className = 'ae-res-val';
                pValSpan.textContent = res.max !== undefined ? res.value + '/' + res.max : String(res.value);
                row.appendChild(pValSpan);
            }
        } else if (res.type === 'track') {
            var trkStates = res.states || [];
            if (editable) {
                // Inline stepper: − [state-label] +
                var tStepper = document.createElement('div');
                tStepper.className = 'ae-res-stepper';
                var tMinus = document.createElement('button');
                tMinus.type = 'button'; tMinus.className = 'ae-res-stepper-btn'; tMinus.textContent = '−';
                tMinus.addEventListener('click', function() { if (onAdjust) onAdjust(res, -1); });
                var tLabel = document.createElement('span');
                tLabel.className = 'ae-track-badge';
                tLabel.textContent = trkStates[res.value] || String(res.value);
                tLabel.style.color = 'var(--ae-color-skill)';
                tLabel.style.borderColor = 'color-mix(in srgb, var(--ae-color-skill) 30%, transparent)';
                tLabel.style.background = 'var(--ae-surface-skill)';
                var tPlus = document.createElement('button');
                tPlus.type = 'button'; tPlus.className = 'ae-res-stepper-btn'; tPlus.textContent = '+';
                tPlus.addEventListener('click', function() { if (onAdjust) onAdjust(res, 1); });
                tStepper.appendChild(tMinus); tStepper.appendChild(tLabel); tStepper.appendChild(tPlus);
                row.appendChild(tStepper);
            } else {
                // Read-only track badge
                var tBadge = document.createElement('span');
                tBadge.className = 'ae-track-badge';
                tBadge.textContent = trkStates[res.value] || String(res.value);
                tBadge.style.color = 'var(--ae-color-skill)';
                tBadge.style.borderColor = 'color-mix(in srgb, var(--ae-color-skill) 30%, transparent)';
                tBadge.style.background = 'var(--ae-surface-skill)';
                row.appendChild(tBadge);
            }
        }
        return row;
    },

    // Faction row
    faction: function(fac, editable, onEdit) {
        var row = document.createElement('div');
        row.className = 'ae-fac-row';
        var name = document.createElement('span');
        name.className = 'ae-fac-name';
        name.textContent = (fac.isParty ? '⚔️ ' : '👤 ') + fac.name;
        row.appendChild(name);
        var badge = document.createElement('span');
        badge.className = 'ae-fac-badge';
        badge.textContent = fac.stateLabel || '—';
        if (editable && onEdit) { badge.style.cursor = 'pointer'; badge.addEventListener('click', function() { onEdit(fac); }); }
        row.appendChild(badge);
        return row;
    },

    // Skill row
    // skill(skill, editable?, onEdit?)
    // editable=true: clicking value opens inline editor via onEdit(skill, valEl, row)
    // fieldType 'number' → signed int; 'text'/'enum' → raw displayValue string
    skill: function(skill, editable, onEdit) {
        var row = document.createElement('div');
        row.className = 'ae-skill-row' + (editable ? ' editable' : '');
        var nameEl = document.createElement('span');
        nameEl.className = 'ae-skill-name';
        nameEl.textContent = skill.name;
        row.appendChild(nameEl);
        var valEl = document.createElement('span');
        valEl.className = 'ae-skill-mod';
        var ft = skill.fieldType || 'number';
        var dv = (skill.displayValue !== undefined && skill.displayValue !== null) ? String(skill.displayValue) : '';
        if (ft === 'number') {
            var numVal = dv !== '' ? parseInt(dv, 10) : (typeof skill.sheetMod === 'number' ? skill.sheetMod : 0);
            if (isNaN(numVal)) numVal = 0;
            valEl.textContent = numVal > 0 ? '+' + numVal : numVal < 0 ? String(numVal) : '0';
            valEl.classList.add(numVal > 0 ? 'pos' : numVal < 0 ? 'neg' : 'zero');
        } else {
            valEl.textContent = dv || '—';
            if (!dv) valEl.classList.add('zero');
        }
        if (editable && onEdit) {
            valEl.addEventListener('click', function() { onEdit(skill, valEl, row); });
        }
        row.appendChild(valEl);
        return row;
    },

    // Equipment row
    equip: function(item, isEquipped, onToggle) {
        var row = document.createElement('div');
        row.className = 'ae-equip-row';
        var icon = document.createElement('span');
        icon.textContent = isEquipped ? '🛡' : '🎒';
        icon.style.fontSize = '16px';
        row.appendChild(icon);
        var name = document.createElement('span');
        name.className = 'ae-equip-name';
        name.textContent = item.name;
        row.appendChild(name);
        var tog = document.createElement('button');
        tog.className = 'ae-equip-toggle ' + (isEquipped ? 'equipped' : 'unequipped');
        tog.textContent = isEquipped ? '✓ On' : 'Equip';
        tog.addEventListener('click', function() { onToggle && onToggle(item, !isEquipped); });
        row.appendChild(tog);
        return row;
    },

    // Narrative / quest card
    narrative: function(narr, onTrack, onInspect) {
        var card = document.createElement('div');
        card.className = 'ae-narr-card';
        if (onInspect) {
            card.style.cursor = 'pointer';
            card.addEventListener('click', function(e) {
                if (e.target.tagName === 'BUTTON') return;
                onInspect(narr);
            });
        }
        var name = document.createElement('div');
        name.className = 'ae-narr-name';
        name.textContent = (narr.icon ? narr.icon + ' ' : '') + narr.name;
        card.appendChild(name);
        if (narr.description) {
            var desc = document.createElement('div');
            desc.className = 'ae-narr-desc';
            desc.textContent = narr.description;
            card.appendChild(desc);
        }
        var stateEl = document.createElement('span');
        stateEl.className = 'ae-narr-state ' + (narr.storyState || 'locked');
        var stateLabel = narr.storyState === 'active' ? '[ ACTIVE ]' : narr.storyState === 'completed' ? '[ DONE ]' : '[ LOCKED ]';
        if (narr.isTracked) stateLabel = '[ TRACKED ]';
        stateEl.textContent = stateLabel;
        card.appendChild(stateEl);
        if (narr.storyState === 'active' && narr.questTarget && onTrack) {
            var trackBtn = $.btn('', 'ghost sm', function() { onTrack(narr); });
            trackBtn.innerHTML = $.svg('teleport', 12).outerHTML + ' Track Quest';
            trackBtn.style.marginTop = '6px';
            card.appendChild(trackBtn);
        }
        return card;
    },

    // Sub-tab system (for Hub)
    subTabs: function(tabsDef, initialIndex, onChange) {
        var wrap = document.createElement('div'); wrap.className = 'ae-sub-tabs-wrap';
        var header = document.createElement('div'); header.className = 'ae-sub-tabs';
        var body = document.createElement('div'); body.className = 'ae-sub-tabs-body';
        wrap.appendChild(header); wrap.appendChild(body);

        var panels = [];
        var btns = [];

        tabsDef.forEach(function(def, i) {
            var btn = document.createElement('button');
            btn.className = 'ae-sub-tab-btn' + (i === initialIndex ? ' active' : '');
            btn.innerHTML = def.label;

            var panel = document.createElement('div');
            panel.className = 'ae-sub-content' + (i === (initialIndex || 0) ? ' active' : '');  // [v0.9.92 TAB-FIX] defaultIdx->initialIndex
            if (def.fill) def.fill(panel);                                                       // [v0.9.92 TAB-FIX] tab->def
            panels.push(panel);
            wrap.appendChild(panel);

            btn.addEventListener('click', function() {
                header.querySelectorAll('.ae-sub-tab-btn').forEach(function(b) { b.classList.remove('active'); });  // [v0.9.92 TAB-FIX] tabBar->header
                panels.forEach(function(p) { p.classList.remove('active'); });
                btn.classList.add('active');
                panel.classList.add('active');
                if (typeof onChange === 'function') onChange(i);
            });
            header.appendChild(btn);                                                             // [v0.9.92 TAB-FIX] tabBar->header
        });
        return wrap;
    },

    // Unified picker bottom sheet
    picker: function(opts) {
        // opts: { title, items: [{id, label, icon?, meta?}], onSelect, searchable, selectedId }
        // HUD is hidden while the picker is open (avoids z-index conflicts).
        var _pkRoot = document.getElementById('ae-ui-root');
        var _pkWasVisible = _pkRoot && _pkRoot.style.display !== 'none';
        if (_pkWasVisible) _pkRoot.style.display = 'none';
        var _pkRestore = function() { if (_pkWasVisible && _pkRoot) _pkRoot.style.display = 'flex'; };
        var overlay = document.createElement('div');
        overlay.className = 'ae-picker-overlay';

        var sheet = document.createElement('div');
        sheet.className = 'ae-picker-sheet';

        var hdr = document.createElement('div');
        hdr.className = 'ae-picker-header';

        var title = document.createElement('span');
        title.className = 'ae-picker-title';
        title.textContent = opts.title || 'Choose';
        hdr.appendChild(title);

        var searchEl = null;
        if (opts.searchable !== false) {
            searchEl = document.createElement('input');
            searchEl.type = 'text';
            searchEl.className = 'ae-picker-search';
            searchEl.placeholder = 'Search…';
            hdr.appendChild(searchEl);
        }

        var closeBtn = $.btn('✕', 'icon ghost', function() { overlay.remove(); _pkRestore(); });
        hdr.appendChild(closeBtn);
        sheet.appendChild(hdr);

        var list = document.createElement('div');
        list.className = 'ae-picker-list';
        sheet.appendChild(list);

        function renderList(filter) {
            list.innerHTML = '';
            var items = opts.items || [];
            if (filter) {
                var fl = filter.toLowerCase();
                items = items.filter(function(it) { return (it.label||'').toLowerCase().includes(fl) || (it.meta||'').toLowerCase().includes(fl) || (it.group||'').toLowerCase().includes(fl); });
            }
            if (items.length === 0) {
                var empty = document.createElement('div'); empty.className = 'ae-picker-empty'; empty.textContent = filter ? 'No results for "' + filter + '"' : 'No items'; list.appendChild(empty); return;
            }
            var lastGroup = null;
            items.forEach(function(item) {
                // Group header
                if (opts.grouped && item.group && item.group !== lastGroup) {
                    lastGroup = item.group;
                    var gh = document.createElement('div'); gh.className = 'ae-picker-group'; gh.textContent = item.group; list.appendChild(gh);
                }
                var el = document.createElement('div');
                var cls = 'ae-picker-item';
                if (item.id === opts.selectedId) cls += ' selected';
                if (item.present) cls += ' pk-present';
                if (item.special) cls += ' pk-special';
                el.className = cls;
                // Icon
                if (item.icon) { 
                    var ic = document.createElement('span'); ic.className = 'ae-pk-icon'; 
                    if (item.icon.indexOf('<svg') !== -1) ic.innerHTML = item.icon; else ic.textContent = item.icon; 
                    el.appendChild(ic); 
                }
                // Label
                var lbl = document.createElement('span'); lbl.textContent = item.label || item.id; el.appendChild(lbl);
                // Meta
                if (item.meta) { var mt = document.createElement('span'); mt.className = 'ae-pk-meta'; mt.textContent = item.meta; el.appendChild(mt); }
                el.addEventListener('click', function() { overlay.remove(); _pkRestore(); if (opts.onSelect) opts.onSelect(item); });
                list.appendChild(el);
            });
        }
        renderList('');
        if (searchEl) searchEl.addEventListener('input', function() { renderList(searchEl.value); });

        overlay.appendChild(sheet);
        overlay.addEventListener('click', function(e) { if (e.target === overlay) { overlay.remove(); _pkRestore(); } });
        document.body.appendChild(overlay);
        if (searchEl) searchEl.focus();
        return overlay;
    },

    // Two-column grid
    twoCol: function(items) {
        var grid = document.createElement('div');
        grid.className = 'ae-two-col';
        items.forEach(function(item) { grid.appendChild(item); });
        return grid;
    },

    // Simple divider
    divider: function() {
        var d = document.createElement('hr');
        d.style.cssText = 'border:none;border-top:1px solid var(--ae-bg-border);margin:8px 0;';
        return d;
    }
};

// =============================================================================
// SECTION 5 — STATE
// =============================================================================

var engineScriptId  = null;
var activeStoryId   = '';
var _aeImgFields    = [];   // ImagePromptField[] from engine (or localStorage cache)
var _aeImgDefaults  = Object.assign({}, DEFAULT_IMG_DEFAULTS);
var lastSceneState  = null;
var _travelSeq      = 0;       // [DIAG] increments per travel dispatch to detect double-fire
var _renderPending  = false;   // [v0.9.25 FLICK1] RAF debounce: a frame render is already queued
var _renderNextState = null;   // [v0.9.25 FLICK1] latest state to commit when the frame fires
var cachedCharVisuals = [];
var _hudSilentMode  = false;
var _hubEditMode    = false;
var _playerFlavor   = '';           // [v0.9.13 X3] pending flavor text for next action
var _flavorInputEl  = null;          // [v0.9.13 X3] reference to the textarea DOM element

// [v0.9.13 X3] Sends pending player flavor to the engine before an action fires.
// Called by every action-dispatch function. Engine stores it in tempStorage and
// consumes it when writing the next > prompt (inject_narrative or outcomeNote).
function _sendFlavorIfAny() {
    var f = _playerFlavor.trim();
    if (f) { sendToEngine('AE_SET_PLAYER_FLAVOR', { text: f }); }
}
var _bridgeUnsubscribe = null; // bridge.on() cleanup — prevents double-registration on script reinject
var _sectionOpenState  = {};   // collapsible section open/close — persists across HUD re-renders
var _snapTextCollapsed = {};   // [v021] snapshot text collapse state
var _focusedEntityDetail = null; // [v021] focused entity detailed state from B contract
// Inline entity bubbles (items / narratives expand in place in the scene list).
var _entityDetailCache = {};     // entityId -> last detail payload (for instant repaint)
var _pendingEquipLookups = {};   // [FEATURE] entityId -> array of one-shot callbacks, drained by AE_ENTITY_DETAIL_RESPONSE below -- see _fetchEquippedItemDetail (Image Studio "append equipped items")
var _openBubbleRenderers = {};   // entityId -> fn(detail) repainting an open bubble body
var _entityBubbleOpen = {};      // entityId -> bool, persists expand state across re-renders

// Map state
var _mapPanX = 0, _mapPanY = 0;
var _mapPanSetup = false; // [v0.9.15] B6: guards window-level pan listeners against re-registration
var _mapGlideTimer = null;
var _mapSelectedId  = null;
var _mapPlayerLocId  = null;   // player’s actual location id
var _mapCurrentGraph = null;   // locationGraph from engine, or null
var _mapInVehicleId       = null;   // set when player's effective location IS a vehicle entity
var _mapOperateMode       = false;  // vehicle operate mode — map shows vehicle world-loc graph
var _mapOperateVehicleId  = null;   // vehicle entity ID when in operate mode
var _mapVehicleWorldLocId = null;   // vehicle's parentId — the world location it is at
var _mapPreOperateGraph   = null;   // saved player graph to restore after operating
var _mapVehicleBaselineGraph = null; // saved vehicle graph for adjacency checks
var _hubActiveSubTab = 0; // [v0.9.102] Persist Hub tab state

// [v0.9.9.12 JOURNAL] Player Journal state, driven by AE_JOURNAL_STATE from the engine.
var _journalState     = { bubbles: [] };  // last payload from engine (bubbles carry precomputed stampLabel)
var _jrnlEditingId    = null;             // bubble id currently in edit mode
var _jrnlEditDraft    = '';               // working text for the bubble being edited
var _jrnlBusy         = false;            // rewrite/compress in flight
var _jrnlShowArchived = false;            // archived list visibility
var _jrnlComposeDraft = '';               // draft for the new-entry box
var _jrnlStampNew     = false;            // stamp-on-add toggle

// [v2.1.5 CHARJOURNAL] Per-character journal state, driven by AE_CHAR_JOURNAL_STATE.
// Same shape as the player journal above MINUS stamp (confirmed dead — no engine
// handler; not carrying it forward into new code). Only one character journal
// popout is ever open at a time, so single vars (not a per-charId map) are enough —
// _cjrnlCharId tracks which character the currently-open popout belongs to.
var _cjrnlCharId      = null;             // charId the popout is currently showing
var _cjrnlCharName    = '';               // display name for the popout title
var _charJournalState = { bubbles: [] };  // last payload from engine for _cjrnlCharId
var _cjrnlEditingId   = null;
var _cjrnlEditDraft   = '';
var _cjrnlBusy        = false;
var _cjrnlShowArchived = false;
var _cjrnlComposeDraft = '';

// [CE-STRIP vNEXT] Holding popout state vars removed — Holding popout gone.

// Image preset management (all 5 slots synced from engine)
// [v2.13.0] _AE_PRESETS_LS_KEY/_aeAllPresets/_aeActivePresetIdx removed -- replaced
// by _aeImgFields/_aeImgDefaults + IMG_FIELDS_LS_KEY above.

// Image generation
var imgCache   = new Map();

// IndexedDB for images
var _imgDb = null;

// =============================================================================
// SECTION 6 — ENGINE MESSAGING
// =============================================================================

function sendToEngine(event, data) {
    if (!NAITMBridge || !engineScriptId) {
        console.warn('[AE Bridge] sendToEngine: no engine. Event:', event); return;
    }
    try { NAITMBridge.send(engineScriptId, Object.assign({ event: event }, data || {})); }
    catch(e) { console.error('[AE Bridge] sendToEngine failed:', e); }
}

function execActionInstance(entityId, instanceId, silent) {
    if (typeof PhantomManager !== 'undefined') PhantomManager.destroy(); // Auto-close phantom widget
    _sendFlavorIfAny(); // [v0.9.13 X3] send flavor before action fires
    // [WP-5] Run a new-system ActionInstance on the engine. Engine resolves the
    // target itself (prompts via aePickTarget when targetMode === 'player_pick').
    // Non-silent runs trigger story generation, so minimize the lower pane.
    if (!silent) { var rt = document.getElementById('ae-ui-root'); if (rt) rt.classList.add('minimized'); }
    sendToEngine('RUN_ACTION_INSTANCE', { entityId: entityId, instanceId: instanceId });
}

function execEntityAction(entityId, actionId, targetId, resolvedChoices) {
    if (typeof PhantomManager !== 'undefined') PhantomManager.destroy(); // Auto-close phantom widget
    _sendFlavorIfAny(); // [v0.9.13 X3]
    var _eaRoot = document.getElementById('ae-ui-root');
    if (_eaRoot) _eaRoot.classList.add('minimized');
    sendToEngine('EXECUTE_ENTITY_ACTION', { entityId: entityId, actionId: actionId, targetId: targetId || null, resolvedChoices: resolvedChoices || {} });
}
function requestSceneState()       { sendToEngine('REQUEST_SCENE_STATE', {}); }
function submitDirectorCut(prompt, uc, chars, enhance) {
    sendToEngine('DIRECTOR_CUT_SUBMIT', { prompt: prompt, uc: uc || '', chars: chars || [], enhance: !!enhance });
}
function requestNodeGraph(entityId) { sendToEngine('REQUEST_NODE_GRAPH', { entityId: entityId }); }

// [v0.9.9.12 JOURNAL] Journal transport. State mutations echo back as AE_JOURNAL_STATE;
// rewrite/compress return AE_JOURNAL_GEN_RESULT (text only — committed via 'update').
function requestJournal() { sendToEngine('AE_JOURNAL_REQ', {}); }
function journalAction(op, extra) { sendToEngine('AE_JOURNAL_ACTION', Object.assign({ op: op }, extra || {})); }
function journalGen(op, id, text) {
    _jrnlBusy = true; _jrnlEditingId = id;
    sendToEngine('AE_JOURNAL_GEN', { op: op, id: id, text: text || '' });
    if (document.getElementById('ae-jrnl-surface')) _renderJournalModal();
}

// [v2.1.5 CHARJOURNAL] Per-character journal transport — same three-message shape
// as the player journal above, every payload additionally carries charId.
function requestCharJournal(charId) { sendToEngine('AE_CHAR_JOURNAL_REQ', { charId: charId }); }
function charJournalAction(charId, op, extra) { sendToEngine('AE_CHAR_JOURNAL_ACTION', Object.assign({ charId: charId, op: op }, extra || {})); }
function charJournalGen(charId, op, id, text) {
    _cjrnlBusy = true; _cjrnlEditingId = id;
    sendToEngine('AE_CHAR_JOURNAL_GEN', { charId: charId, op: op, id: id, text: text || '' });
    if (document.getElementById('ae-cjrnl-surface')) _renderCharJournalModal();
}

// [v2.33.0 CHARCHAT-LAUNCHER] Ask the engine for the saved-thread roster (per-pair message
// counts) for the Chat launcher's contact list. Fetched ONCE per Chat-view open — the
// response (AE_CHARCHAT_THREADS_RESP) caches into _ccLauncherThreads; POV switching filters
// that cache in memory, never re-fetches, matching the engine picker's own discipline.
function requestCharChatThreads() { sendToEngine('AE_CHARCHAT_THREADS_REQ', {}); }

// [CE-STRIP vNEXT] requestHolding()/holdingAction() removed — Holding popout gone.

// =============================================================================
// SECTION 6b — BRIDGE-NATIVE HUD OVERLAYS  [v0.9.14 X1/X2]
// Replaces native NAI modals for three player-facing interactions:
//   _showHudPopup   — pop_up effect informational card (fire-and-forget)
//   _showHudPicker  — __ask__ option lists + target picker (roundtrip)
// Unlike $.picker(), these helpers do NOT hide #ae-ui-root so the scene
// stays visible behind the overlay backdrop.
// =============================================================================

function _showHudPopup(title, text) {
    var popOverlay = document.createElement('div');
    popOverlay.style.cssText = 'position:fixed;inset:0;z-index:var(--ae-z-popover);background:rgba(0,0,0,0.72);display:flex;align-items:center;justify-content:center;';
    var popCard = document.createElement('div');
    popCard.style.cssText = 'background:var(--ae-bg-panel);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius);padding:18px 20px;max-width:360px;width:90%;box-shadow:var(--ae-shadow);';
    var popTitle = document.createElement('div');
    popTitle.style.cssText = 'font-size:13px;font-weight:600;margin-bottom:10px;color:var(--ae-text-main);';
    popTitle.textContent = title || '';
    popCard.appendChild(popTitle);
    if (text) {
        var popText = document.createElement('div');
        popText.style.cssText = 'font-size:12px;line-height:1.6;color:var(--ae-text-muted);white-space:pre-wrap;margin-bottom:14px;';
        popText.textContent = text;
        popCard.appendChild(popText);
    }
    var popOk = $.btn('OK', 'primary', function() { popOverlay.remove(); });
    popOk.style.width = '100%';
    popCard.appendChild(popOk);
    popOverlay.appendChild(popCard);
    popOverlay.addEventListener('click', function(e) { if (e.target === popOverlay) popOverlay.remove(); });
    document.body.appendChild(popOverlay);
}

// [v0.9.18 ACT1b] Blocking free-text prompt for the ask_text effect.
// opts: { title, instructions, placeholder, onSend(text), onCancel() }
function _showHudTextPrompt(opts) {
    var ovl = document.createElement('div');
    ovl.style.cssText = 'position:fixed;inset:0;z-index:var(--ae-z-popover);background:rgba(0,0,0,0.72);display:flex;align-items:center;justify-content:center;';
    var card = document.createElement('div');
    card.style.cssText = 'background:var(--ae-bg-panel);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius);padding:18px 20px;max-width:400px;width:92%;box-shadow:var(--ae-shadow);';
    var ttl = document.createElement('div');
    ttl.style.cssText = 'font-size:14px;font-weight:600;margin-bottom:10px;color:var(--ae-accent);';
    ttl.textContent = opts.title || 'How do you do it?';
    card.appendChild(ttl);
    if (opts.instructions) {
        var ins = document.createElement('div');
        ins.style.cssText = 'font-size:12px;line-height:1.55;color:var(--ae-text-muted);white-space:pre-wrap;margin-bottom:12px;';
        ins.textContent = opts.instructions;
        card.appendChild(ins);
    }
    var ta = document.createElement('textarea');
    ta.rows = 3;
    ta.placeholder = opts.placeholder || 'Describe how you do it\u2026';
    ta.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-base);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-sm);color:var(--ae-text-main);font-size:13px;font-family:inherit;padding:8px 10px;resize:vertical;margin-bottom:12px;';
    card.appendChild(ta);
    var btnRow = document.createElement('div');
    btnRow.style.cssText = 'display:flex;gap:8px;';
    var _done = false;
    var sendBtn = $.btn('\u203a', 'primary', function() { // [v0.9.19 ACT2b] › chevron
        if (_done) return; _done = true;
        var v = ta.value;
        ovl.remove();
        if (opts.onSend) opts.onSend(v);
    });
    sendBtn.title = 'Send';
    sendBtn.style.cssText += ';flex:0 0 52px;font-size:22px;line-height:1;font-weight:700;';
    var skipBtn = $.btn('Skip', 'ghost', function() {
        if (_done) return; _done = true;
        ovl.remove();
        if (opts.onCancel) opts.onCancel();
    });
    skipBtn.style.flex = '1';
    btnRow.appendChild(skipBtn);
    btnRow.appendChild(sendBtn);
    card.appendChild(btnRow);
    ovl.appendChild(card);
    // Clicking the backdrop = skip (engine continues without flavor).
    ovl.addEventListener('click', function(e) { if (e.target === ovl) { if (_done) return; _done = true; ovl.remove(); if (opts.onCancel) opts.onCancel(); } });
    // Cmd/Ctrl+Enter to send.
    ta.addEventListener('keydown', function(e) { if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') { sendBtn.click(); } });
    document.body.appendChild(ovl);
    try { ta.focus(); } catch(_e) {}
}

// opts: { title, items:[{id,label,icon?}], searchable?, onSelect(item), onCancel() }
function _showHudPicker(opts) {
    var pkOverlay = document.createElement('div');
    pkOverlay.className = 'ae-picker-overlay'; // reuse existing CSS (position:fixed, z-index:var(--ae-z-popover))
    var pkSheet = document.createElement('div');
    pkSheet.className = 'ae-picker-sheet';
    var pkHdr = document.createElement('div');
    pkHdr.className = 'ae-picker-header';
    var pkTitle = document.createElement('span');
    pkTitle.className = 'ae-picker-title';
    pkTitle.textContent = opts.title || 'Choose';
    pkHdr.appendChild(pkTitle);
    var pkItems = opts.items || [];
    var pkSearch = null;
    if (opts.searchable !== false && pkItems.length > 5) {
        pkSearch = document.createElement('input');
        pkSearch.type = 'text';
        pkSearch.className = 'ae-picker-search';
        pkSearch.placeholder = 'Search…';
        pkHdr.appendChild(pkSearch);
    }
    var pkClose = $.btn('✕', 'icon ghost', function() { pkOverlay.remove(); if (opts.onCancel) opts.onCancel(); });
    pkHdr.appendChild(pkClose);
    pkSheet.appendChild(pkHdr);
    var pkList = document.createElement('div');
    pkList.className = 'ae-picker-list';
    pkSheet.appendChild(pkList);
    function pkRender(filter) {
        pkList.innerHTML = '';
        var shown = filter
            ? pkItems.filter(function(it) { return (it.label || '').toLowerCase().includes(filter.toLowerCase()); })
            : pkItems;
        if (!shown.length) {
            var emp = document.createElement('div');
            emp.className = 'ae-picker-empty';
            emp.textContent = filter ? 'No results' : 'No items';
            pkList.appendChild(emp);
            return;
        }
        shown.forEach(function(item) {
            var el = document.createElement('div');
            el.className = 'ae-picker-item';
            if (item.icon) { 
                var ic = document.createElement('span'); ic.className = 'ae-pk-icon'; 
                if (item.icon.indexOf('<svg') !== -1) ic.innerHTML = item.icon; else ic.textContent = item.icon; 
                el.appendChild(ic); 
            }
            var lbl = document.createElement('span'); lbl.textContent = item.label || item.id; el.appendChild(lbl);
            el.addEventListener('click', function() { pkOverlay.remove(); if (opts.onSelect) opts.onSelect(item); });
            pkList.appendChild(el);
        });
    }
    pkRender('');
    if (pkSearch) pkSearch.addEventListener('input', function() { pkRender(pkSearch.value); });
    pkOverlay.appendChild(pkSheet);
    pkOverlay.addEventListener('click', function(e) { if (e.target === pkOverlay) { pkOverlay.remove(); if (opts.onCancel) opts.onCancel(); } });
    document.body.appendChild(pkOverlay);
    if (pkSearch) { try { pkSearch.focus(); } catch(_e) {} }
    return pkOverlay;
}

function handleEngineMessage(payload, meta) {
    var event = payload && payload.event; if (!event) return;
    if (meta && meta.sid) engineScriptId = meta.sid;
    switch (event) {
        case 'AE_DIAG_REPLY': {
            // [v2.51.0 DIAG-CMD] Reply to window.CE_ENGINE.cmd() — always logged, not
            // channel-gated, since it's a direct response to something explicitly typed.
            console.log('[CE:diag] ' + payload.cmd + ' \u2192\n' + payload.out);
            break;
        }
        case 'AE_SLOT_OPTIONS': {
            // [v2.53.0 SLOT-PICK] Candidates for one field. The engine answers with the
            // BARE field id it was asked for; _slotOptPending maps that back to the key
            // this surface saves under. An unmapped reply is dropped rather than guessed
            // at -- writing to the wrong field is far worse than showing nothing.
            var soPend = _slotOptPending[payload.fieldKey];
            if (!soPend) break;
            delete _slotOptPending[payload.fieldKey];
            _clearSlotOptBusy(soPend.displayKey);
            if (payload.budget) _lastGenBudget = payload.budget;
            if (!payload.ok || !payload.options || !payload.options.length) {
                // [v2.55.0 GEN-BUDGET] A refused request and a failed one need different
                // advice, so they get different messages. 'budget' means wait or play on;
                // 'empty' means the model returned nothing and retrying is reasonable.
                var soReason = payload.reason || 'empty';
                if (soReason === 'budget') {
                    _showToast('Not enough generation budget \u2014 advance the story and retry.');
                    _showSlotOptFailure(soPend.displayKey, payload.budget);
                } else if (soReason === 'error') {
                    _showToast('Generation error on ' + soPend.label + '.');
                    if (payload.detail) console.warn('[CE:slotopts] ' + payload.detail);
                } else {
                    _showToast('Nothing came back for ' + soPend.label + ' \u2014 try again.');
                }
                break;
            }
            _renderSlotOptions(soPend.displayKey, soPend.label, payload.options);
            break;
        }
        case 'AE_POPUP_SHOW': {
            // [v0.9.14 X2] pop_up effect — show inline HUD card, no await on engine side.
            _showHudPopup(payload.title || 'Message', payload.text || '');
            break;
        }
        case 'AE_HUD_GEN_RESULT': {
            // [v1.2.0] Scene-fitting draft for the open Add-Entity popup. Fill and let
            // the user tweak before Create; re-enable the Generate button either way.
            if (_addEntityPopup && _addEntityPopup.kind === payload.kind) {
                if (_addEntityPopup.genBtn) { _addEntityPopup.genBtn.disabled = false; _addEntityPopup.genBtn.textContent = '\u2728 Generate from Scene'; }
                if (payload.ok) {
                    if (payload.name)  _addEntityPopup.nameEl.value = payload.name;
                    if (payload.brief) _addEntityPopup.descEl.value = payload.brief;
                    _showToast('Filled in \u2014 tweak and Create.');
                } else {
                    _showToast('Could not generate \u2014 type it in or try again.');
                }
            }
            break;
        }
        case 'AE_HUD_GEN_LOCATION_RESULT': {
            // [v1.4.0 LOCGEN] Scene-fitting location draft for the open Add-Location
            // popup. Fill and let the user tweak before Create; re-enable Generate
            // either way. >>> PAIRED with AE_HUD_GEN_RESULT directly above.
            if (_addLocationPopup) {
                if (_addLocationPopup.genBtn) { _addLocationPopup.genBtn.disabled = false; _addLocationPopup.genBtn.innerHTML = '\u2728 Generate from Story'; }
                if (payload.ok) {
                    if (payload.name)        _addLocationPopup.nameEl.value = payload.name;
                    if (payload.description) _addLocationPopup.descEl.value = payload.description;
                    if (payload.lore)        _addLocationPopup.loreEl.value = payload.lore;
                    _showToast('Filled in \u2014 tweak and Create.');
                } else {
                    _showToast('Could not generate \u2014 type it in or try again.');
                }
            }
            break;
        }
        case 'AE_ASK_TEXT_REQUEST': {
            // [v0.9.18 ACT1b] "How do you do it?" — blocking free-text prompt.
            // Sends AE_ASK_RESPONSE (shared resolve map) with the typed value, or null on cancel.
            _showHudTextPrompt({
                title: payload.title || 'How do you do it?',
                instructions: payload.instructions || '',
                placeholder: payload.placeholder || 'Describe how you do it\u2026',
                onSend: function(text) { sendToEngine('AE_ASK_RESPONSE', { promptId: payload.promptId, value: text }); },
                onCancel: function() { sendToEngine('AE_ASK_RESPONSE', { promptId: payload.promptId, value: null }); }
            });
            break;
        }
        case 'AE_ASK_REQUEST': {
            // [v0.9.14 X2] __ask__ sentinel — show HUD picker, send AE_ASK_RESPONSE on pick.
            var askOpts = (payload.options || []).map(function(o) { return { id: o.value, label: o.label }; });
            _showHudPicker({
                title: payload.label || 'Choose',
                items: askOpts,
                searchable: askOpts.length > 5,
                onSelect: function(item) { sendToEngine('AE_ASK_RESPONSE', { promptId: payload.promptId, value: item.id }); },
                onCancel: function() { sendToEngine('AE_ASK_RESPONSE', { promptId: payload.promptId, value: null }); }
            });
            break;
        }
        case 'AE_TARGET_PICKER_REQUEST': {
            // [v0.9.14 X1] requiresTarget action — show HUD picker, send AE_TARGET_SELECTED on pick.
            var tgtOpts = (payload.candidates || []).map(function(c) { return { id: c.id, label: c.name, icon: c.icon || '' }; });
            _showHudPicker({
                title: 'Choose Target',
                items: tgtOpts,
                searchable: tgtOpts.length > 5,
                onSelect: function(item) { sendToEngine('AE_TARGET_SELECTED', { promptId: payload.promptId, targetId: item.id }); },
                onCancel: function() { sendToEngine('AE_TARGET_SELECTED', { promptId: payload.promptId, targetId: null }); }
            });
            break;
        }
        case 'AE_MODAL_OPENED': {
            // Engine opened a native NAI modal (author/designer UI) — hide HUD.
            var _moRoot = document.getElementById('ae-ui-root');
            if (_moRoot) _moRoot.classList.add('ae-behind-modal');
            break;
        }
        case 'AE_MODAL_CLOSED': {
            // Engine's modal closed — restore HUD.
            var _mcRoot = document.getElementById('ae-ui-root');
            if (_mcRoot) _mcRoot.classList.remove('ae-behind-modal');
            break;
        }

        case 'HANDSHAKE_REQUEST':
            engineScriptId = meta.sid;
            console.log('[AE Bridge] Engine handshake received. Sending ACK. SID:', engineScriptId);
            sendToEngine('HANDSHAKE_ACK', {});
        showWaitingPlaceholder();  // show "connected, awaiting state" UI
        // Engine only handshakes when a story is open — reveal the toggle.
        (function() { var _t = document.getElementById('ae-toggle-btn'); if (_t) _t.style.display = 'flex'; })();
        break;
    case 'PING':
        sendToEngine('PONG', {}); break;
    case 'AE_IMG_FIELDS_SYNC':
        if (Array.isArray(payload.fields)) _aeImgFields = payload.fields;
        if (payload.defaults) _aeImgDefaults = Object.assign({}, DEFAULT_IMG_DEFAULTS, payload.defaults);
        try { localStorage.setItem(IMG_FIELDS_LS_KEY, JSON.stringify({ fields: _aeImgFields, defaults: _aeImgDefaults })); } catch(_) {}
        // [BUGFIX v2.1.7/v2.1.8] Sole repaint trigger for all three surfaces -- see
        // chip-click note (composer) and _renderSetupImageFields note (Setup tab).
        if (document.getElementById('ae-imgfields-surface')) _renderImageFieldsContent();
        (function() { var _isb = document.getElementById('ae-imgstudio-fieldsbar'); if (_isb && typeof _isb._aeRepaint === 'function') _isb._aeRepaint(); })();
        if (document.getElementById('ae-setup-imgfields-body')) _renderSetupImageFields();
        if (document.getElementById('ae-imggen-surface') && _imgGenModalTab === 'presets') _renderImageGenSurface();
        break;
    case 'SCENE_STATE_UPDATE':
        lastSceneState = payload;
        dbg('[CE:scene] SCENE_STATE_UPDATE playerLoc=' + (payload.locationName || payload.currentLocationId || '?') + ' focused=' + (_focusedEntityId || 'none'));
        if (payload.locationGraph) _mapCurrentGraph = payload.locationGraph;
        if (_focusedEntityId) {
            // [v0.9.25 FLICK1] When a character is focused, kick off the detail
            // fetch but don't call renderSceneHUD yet — AE_ENTITY_DETAIL_RESPONSE
            // will call _renderSceneTab once it has fresh data, avoiding the
            // stale-flash that occurred when renderSceneHUD ran with null/old detail.
            sendToEngine('AE_FETCH_ENTITY_DETAIL', { entityId: _focusedEntityId });
            // Still update map + banner + bottom pane (lightweight, no tab wipe).
            renderSceneHUD(payload);
        } else {
            renderSceneHUD(payload);
        }
        break;
    case 'AE_NODE_GRAPH_RESPONSE':
        (function() {
            var _ngRoot = document.getElementById('ae-ui-root');
            var _ngCtrl = _ngRoot && _ngRoot.querySelector('#ae-node-controls');
            if (_ngCtrl) _ngCtrl.style.display = 'none';
            if (_mapOperateMode) {
                if (payload.entityId === _mapVehicleWorldLocId) {
                    _mapVehicleBaselineGraph = payload.graph;
                }
            }
            _buildMapFromGraph(payload.entityId, payload.graph);
            // [v0.9.12] Auto-click the newly centered node so the control panel
            // immediately shows the correct travel/browse state without requiring
            // the user to re-click. Without this, the panel was hidden (display:none)
            // and only reappeared if the user explicitly clicked the center node,
            // at which point stale _mapCurrentGraph could cause 'Browse only' state.
            var _ngCanvas = _ngRoot && _ngRoot.querySelector('#ae-map-canvas');
            var _ngCurNode = _ngCanvas && _ngCanvas.querySelector('.ae-node.current');
            if (_ngCurNode) _ngCurNode.click();
        })();
        break;
    case 'AE_ENTITY_DETAIL_RESPONSE':
        if (payload && payload.id) {
            _entityDetailCache[payload.id] = payload;
            if (_openBubbleRenderers[payload.id]) {
                try { _openBubbleRenderers[payload.id](payload); } catch (e) {}
            }
            // [FEATURE] Drain any one-shot equipped-items lookups waiting on this id
            // (Image Studio's "append equipped items" checkbox) -- see _fetchEquippedItemDetail.
            if (_pendingEquipLookups[payload.id]) {
                var _eqCbs = _pendingEquipLookups[payload.id];
                delete _pendingEquipLookups[payload.id];
                _eqCbs.forEach(function(cb) { try { cb(payload); } catch (e) {} });
            }
        }
        if (_focusedEntityId === payload.id) {
            _focusedEntityDetail = payload;
            if (lastSceneState) _doRenderSceneHUD(lastSceneState);
            // [FEATURE] Route to whichever sheet is actually focused -- _focusedEntityKind
            // is set synchronously by _focusEntity/_focusLocation (see their own comments).
            if (_focusedEntityKind === 'location') _refreshPhantomLocationFocus();
            else _refreshPhantomInspectFocus(); // [PHANTOM-PRIMARY PASS 5]
        }
        break;
    case 'AE_CHAR_PROFILE_RESPONSE': {
        // [v0.9.93 PROFILE] Full editable record for the combined HUD profile.
        if (!payload || !payload.id) break;
        if (payload.error) { _showToast('Profile error: ' + payload.error); break; }
        _charProfileCache[payload.id] = payload;
        // [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] Removed branch (a) (regen-completion
        // patching for the old full profile sheet, #ae-profile-sheet-host) -- its only
        // trigger, _profileRegenKey, was set exclusively by the now-removed _profileField.
        // The flat dossier Profile tab has no regen mechanism of its own yet (per its own
        // comment) -- if that's wanted, it belongs there, reading this same cache.
        // (a) Open-fetch completion -> full render of the flat Profile tab.
        if (_profileFetchPending[payload.id]) {
            _profileFetchPending[payload.id] = false;
            if (_profileOpenCharId === payload.id) {
                var _flatHost = document.getElementById('ae-flat-profile-host');
                if (_flatHost) { _flatHost.innerHTML = ''; _buildFlatProfileTab(_flatHost, payload.id); }
            }
            break;
        }
        // (b) Save echo -> cache refreshed silently above; no DOM churn (avoids focus loss).
        break;
    }
    case 'CHARACTER_DATA_SYNC':
        cachedCharVisuals = payload.characters || [];
        // Async-load portrait thumbnails from IndexedDB for roster/banner display.
        cachedCharVisuals.forEach(function(vis) {
            if (vis.id) _loadCharAvatarImage(vis.id).then(function(url) {
                if (url) vis._avatarDataUrl = url;
                // [v2.34.0 CHARCHAT-LAUNCHER-FIX] avatar arrived async -> refresh launcher chips (initial -> photo)
                if (url && document.getElementById('ae-ccl-pov')) { _ccLauncherRenderPov(); _ccLauncherRenderContacts(); }
            });
        });
        // [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] _galleryRepaintCharsIfOpen() call removed
        // along with the function itself -- see CE-INDEX STUDIO-SHELL-TEARDOWN entry.
        _refreshPhantomInspectFocus(); // [BUGFIX] Visuals tab was stuck if this arrived after the sheet was already built
        // [v2.34.0 CHARCHAT-LAUNCHER-FIX, per user: "Text as has no selector"] The launcher's
        // POV strip + contact list are built from cachedCharVisuals; if the roster lands (or
        // updates) AFTER the launcher opened, repaint both so the POV chips actually appear.
        // Was the root cause of the empty "Text as" row -- the strip only ever had the pinned
        // "No POV" chip because the roster was still empty at open and nothing re-rendered it.
        if (document.getElementById('ae-ccl-pov')) _ccLauncherRenderPov();
        if (document.getElementById('ae-ccl-contacts')) _ccLauncherRenderContacts();
        break;
    case 'GENERATE_IMAGE':
        (function(p) {
            generateCommentImage(p).then(function(dataUrl) {
                if (!dataUrl) return;
                displayGeneratedImage(p.uuid, dataUrl, p);
                // [v0.9.8.0] If the Image Studio is open and awaiting this generation, show it inline.
                if (window._aeImgStudioCb) { try { window._aeImgStudioCb(p.uuid, dataUrl, p); } catch (_eis) {} }
                // [vNEXT] Action-driven image: drop it into a captioned phantom widget.
                // The image is already saved to the gallery by generateCommentImage -> dbSave.
                if (p.kind === 'action') { try { _spawnActionImagePhantom(dataUrl, p); } catch (_eap) { console.error('[AE Bridge] action image phantom failed:', _eap); } }
                // [v2.4.0 CHARCHAT-HUD] A chat photo. generateCommentImage has already
                // dbSave'd it and seeded imgCache under the FULL uuid; the document tag
                // carries only the 8-hex prefix, so _ccResolveImage matches by prefix.
                // Invalidating the index forces the next repaint to pick this up rather
                // than serve a pre-generation miss from the 2s throttle window.
                // [v2.13.0 CHARCHAT-SHELL-BASELINE] The chat photo's repaint hook is gone with
                // the panel that repainted. generateCommentImage has already dbSave'd the image
                // and seeded imgCache under the FULL uuid, so nothing is lost — the image is
                // in the gallery and the document tag (8-hex prefix of that uuid) still points
                // at it. What no longer exists is anything that DRAWS it in the chat. That is
                // the overhaul's first real job: a node widget from the engine as the anchor,
                // painted here (see Section 13c's note on the Auto-Illustrator mechanism).
                // [v2.15.0 CHARCHAT-IMGPAINT] A new chat photo just landed in the gallery.
                // The prefix index is throttled (2s), so without this the very next scan
                // would serve a stale index that does not contain this uuid and the anchor
                // would sit empty until the throttle aged out. Invalidate, then scan.
                if (p.kind === 'charchat') { _ccimgInvalidate(); _ccimgScan(); }
                if (p.kind === 'snapshot' && p.charId) {
                    _savePortrait(p.charId + '_em_Snapshot', dataUrl, 'gen', { fp: p.prompt || '', fu: (p.characters && p.characters[0] && p.characters[0].uc) || '', chars: p.characters || [], settings: p.settings || null }).catch(function() {});
                    _showToast('📸 Snapshot image saved');
                    if (_focusedEntityId === p.charId) { var _tpI = document.getElementById('ae-top-pane'); if (_tpI) _renderFocusBanner(_tpI, p.charId); }
                }
            }).catch(function(e) { console.error('[AE Bridge] GENERATE_IMAGE failed:', e); });
        })(payload);
        break;
    case 'SNAPSHOT_TEXT_RESULT': {
        if (payload.charId) {
            if (payload.text) { _snapTextCache[payload.charId] = payload.text; _showToast('✍️ Snapshot ready'); }
            else if (payload.error) { _showToast('⚠ ' + payload.error); }
            if (_focusedEntityId === payload.charId) { var _tpS = document.getElementById('ae-top-pane'); if (_tpS) _renderFocusBanner(_tpS, payload.charId); }
        }
        break;
    }
    // [PHANTOM-PRIMARY PASS 1] AE_CYOA_OPTIONS case removed — CYOA retired
    // entirely (was already dead, zero engine handler for the sends that fed it).
    case 'AE_GALLERY_LOCATIONS_RESPONSE': {
        if (window._aeGalleryLocationsCb) {
            window._aeGalleryLocationsCb(payload.locations || []);
            window._aeGalleryLocationsCb = null;
        }
        break;
    }
    case 'AE_WIZ_STATE': {
        _wizState = payload;
        if (document.getElementById('ae-wiz-transcript')) _wizRepaint();
        // [v2.1.0 WIZLIVE] The live-chat panel's persona picker feeds off the topic list.
        var lwb0 = document.getElementById('ae-wizlive-body');
        if (lwb0) _renderLiveWizTab(lwb0);
        break;
    }
    case 'AE_WIZLIVE_STATE': {
        // [v2.1.0 WIZLIVE] Live in-document chat state — repaint the panel if open.
        _liveWizState = payload;
        var lwb1 = document.getElementById('ae-wizlive-body');
        if (lwb1) _renderLiveWizTab(lwb1);
        break;
    }
    // [v2.13.0 CHARCHAT-SHELL-BASELINE] The panel is gone (see Section 13c), so this is no
    // longer a repaint pump — it is a state receipt with exactly two readers: the arm
    // listener's install/remove, and whatever the UI overhaul builds next. Everything the
    // engine still broadcasts (turns[], busyStage, lastThought, images, freshThoughts) keeps
    // arriving and is parked on _charChatState unread rather than dropped: the payload is the
    // engine contract, and narrowing it now would mean widening it again in two weeks.
    // [v2.33.0 CHARCHAT-LAUNCHER] Saved-thread roster for the Chat launcher's contact list.
    // Cache it and, if the launcher is currently open, repaint the contact list in place so
    // the message-count badges fill in without a flicker. One fetch per Chat-view open.
    case 'AE_CHARCHAT_THREADS_RESP': {
        _ccLauncherThreads = (payload && payload.threads) ? payload.threads : [];
        _ccLauncherThreadsLoaded = true;
        if (document.getElementById('ae-ccl-contacts')) _ccLauncherRenderContacts();
        break;
    }
    case 'AE_CHARCHAT_STATE': {
        _charChatState = payload;
        _ccSyncArmHook();
        // [v2.40.0 CHARCHAT-SENDSTATUS] busyStage ('thinking'/'image'/'') rides this
        // receipt; the send-button badge reads it (plus _ccEngineThinking) to say what is
        // happening and, on chat close, to take itself down.
        _ccStatusSync();
        // [v2.34.0 CHARCHAT-LAUNCHER-SETTINGS] freshThoughts / images / lastThought all ride
        // this receipt; if the launcher settings header is open, repaint its labels.
        if (document.getElementById('ae-ccl-settings')) _ccLauncherRenderSettings();
        // [v2.14.0 CHARCHAT-HEADER] Same receipt, same reasoning as the arm hook above:
        // AE_CHARCHAT_STATE is already this file's one signal for "a chat is active or
        // isn't," so the header dropdown and the background retheme ride it rather than
        // getting their own poll or lifecycle.
        _cchdrBgSync();   // [v2.34.0] popup menu removed; only the chat-active background retheme remains
        // [v2.15.0 CHARCHAT-IMGPAINT] Third rider on the same receipt, same reasoning as
        // the other two: this is already the one signal for "a chat is active or isn't."
        _ccimgSyncScanner();
        // [v2.42.0 CHARCHAT-MANAGER] Fourth rider: show/hide the floating chat manager
        // (Close under the HUD toggle + Summarize/Delete) off the same active/not signal.
        _ccManagerSync();
        break;
    }
    // [FEATURE v2.32.3 ENGINE-THINKING-SIGNAL, per user: "an indicator for any of our
    // thinking and image generation pauses... it is a current deficit that you can't see
    // when you're waiting on image generation"] Engine-side reference count (see engine
    // _aeThinkingPulse) already collapses overlapping generations to clean on/off edges,
    // so this is a plain pass-through -- no counting needed on this side. Same
    // _aeSetEngineThinking the toggle-button glyph already exposed (GHOST-SIGNATURE,
    // v2.30.0) and dormant since; this is the signal it was waiting on. Bridge-side image
    // generation calls the SAME function directly (grep _aeSetEngineThinking) since that
    // path is not always engine-initiated and this event alone would miss it.
    case 'AE_ENGINE_THINKING': {
        _aeSetEngineThinking(!!(payload && payload.on));
        // [v2.40.0 CHARCHAT-SENDSTATUS] Capture the same binary pulse for the send-button
        // status badge. busyStage never marks the MAIN reply (the engine only stamps
        // 'thinking'/'image' in its POST-reply sequence), so this edge is what lets the
        // badge say "replying\u2026" while the reply itself is generating.
        _ccEngineThinking = !!(payload && payload.on);
        _ccStatusSync();
        break;
    }
    // [v2.13.0] case 'AE_CHARCHAT_CONTACTS' DELETED with the panel's contacts screen — it
    // was that screen's only reader, and requestCharChatContacts (its only sender) went with
    // it. The engine's broadcastCharChatContacts / AE_CHARCHAT_CONTACTS_REQ are now
    // sender-less and reader-less respectively; they are deleted engine-side in the SAME pass
    // (engine v2.46.0), not left lying. Starting a chat is the native Chat toolbar button's
    // job until the overlay gives it a home.
    case 'AE_WIZ_REPLY': {
        _wizThinking = false;
        // Fresh state arrives right after; repaint handles the transcript. Just clear the spinner now.
        if (document.getElementById('ae-wiz-transcript')) {
            var twait = document.querySelector('.ae-wiz-thinking'); if (twait) twait.remove();
            if (payload && payload.ok === false) _showToast(payload.error || 'Wizard turn failed');
        }
        break;
    }
    case 'AE_WIZ_CONTEXT_SOURCES': {
        _wizSources = payload;
        _wizRenderSources();
        break;
    }
    case 'AE_WIZ_GEN_RESULT': {
        // [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] Fully orphaned -- its only remaining
        // sender (the Locations tab's "Generate here" batch-gen bar) was removed with
        // the rest of the Studio shell this pass. See CE-INDEX STUDIO-SHELL-TEARDOWN.
        break;
    }
    case 'AE_WIZ_ENTITIES': {
        // [DEAD, v2.45.0 ENTITY-CRUD-TEARDOWN] The only bridge sender of the request
        // this responds to (AE_WIZ_LIST_ENTITIES, from the now-removed _renderEntityTab)
        // is gone -- this case is a no-op unless the engine sends it unprompted. Left as
        // an empty case (not deleted outright) so an unexpected arrival doesn't fall
        // through to default-case console noise. Candidate for an engine-side sweep --
        // see CE-INDEX ENTITY-CRUD-TEARDOWN entry for the paired request-message list.
        break;
    }
    case 'AE_SYNC_LOREBOOK_RESULT': {
        // [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] Fully orphaned -- its only sender (the
        // Studio topbar's Sync-to-Lorebook button) was removed this pass. See CE-INDEX
        // STUDIO-SHELL-TEARDOWN entry.
        break;
    }
    case 'DIRECTOR_ENHANCE_RESULT':
        if (window._aeDirectorEnhanceCb) { window._aeDirectorEnhanceCb(payload); window._aeDirectorEnhanceCb = null; } break;
    case 'AUTO_SNAP_PROMPT_RESULT':
        // [v0.9.8.0] Architect-built prompt for the Image Studio composer.
        if (window._aeAutoSnapPromptCb) { window._aeAutoSnapPromptCb(payload); window._aeAutoSnapPromptCb = null; } break;
    case 'AE_SMART_MODAL':
        handleSmartModal(payload); break;
    case 'BOT_RESPONSE':
        /* Obsolete Chatbot Route */ break;
    case 'STORY_ID_SYNC':
        if (payload.storyId) activeStoryId = payload.storyId; break;
    case 'CHAT_SUMMARY_RESULT':
        /* Obsolete Chatbot Route */ break;
    case 'CLICK_GENERATE_NOW':
        setTimeout(function() {
            var btn = findNAIGenerateButton();
            if (btn) { btn.click(); dbg('[CE:gen] Generate clicked.'); }
            else dbg('[CE:gen] Generate button not found.');
        }, 50); break;
    // [FEATURE] AE_INSPECT_RESPONSE case removed — its only consumer (#ae-inspect-popup,
    // built by _showLocationInspect) was deleted in the same patch that replaced it with
    // _focusLocation's full sheet. The engine still sends AE_INSPECT_LOCATION/
    // AE_INSPECT_RESPONSE (nothing calls that dispatcher case bridge-side anymore either,
    // since AE_INSPECT_LOCATION was only ever sent from the deleted function) — flagged in
    // CE-INDEX for a future engine-side cleanup pass, not touched engine-side this patch.
    case 'AE_DELETE_PORTRAIT_CASCADE': {
        var charId = payload.charId;
        if (!charId) break;
        var slots = _getEmoSlots(charId);
        var keysToDelete = [charId + '_portrait'];
        slots.forEach(function(slotName) {
            keysToDelete.push(charId + '_em_' + slotName);
        });
        console.log('[AE Bridge] Deleting gallery assets for ' + charId, keysToDelete);
        keysToDelete.forEach(function(key) {
            _deletePortrait(key).catch(function(e) { console.error('[AE Bridge] Failed to delete portrait key ' + key, e); });
        });
        // [v2.47.0 EMOSTUDIO-24DEFAULT] Pre-existing leak, fixed while in this handler for
        // the 24-slot default: the IndexedDB images were swept but the localStorage slot
        // list and tag overrides for this character were never removed, so a deleted
        // character's config sat in localStorage forever.
        try { localStorage.removeItem('ae_emo_slots_' + charId); } catch (_) {}
        try { localStorage.removeItem('ae_emo_tags_' + charId); } catch (_) {}
        break;
    }
    // [v2.13.0] AE_ALL_PRESETS_SYNC removed -- folded into AE_IMG_FIELDS_SYNC above.
    case 'AE_JOURNAL_STATE': {
        // [v0.9.9.12 JOURNAL] Full journal projection from the engine (stampLabels precomputed).
        _journalState = (payload && Array.isArray(payload.bubbles)) ? payload : { bubbles: [] };
        if (document.getElementById('ae-jrnl-surface')) _renderJournalModal();
        break;
    }
    case 'AE_JOURNAL_GEN_RESULT': {
        // [v0.9.9.12 JOURNAL] Rewrite/compress returned — load into edit mode for review.
        _jrnlBusy = false;
        if (payload && payload.ok && payload.text) {
            _jrnlEditingId = payload.id;
            _jrnlEditDraft = payload.text;
            _showToast(payload.op === 'compress' ? '\u25BD Compressed — review & save' : '\u270D Rewritten — review & save');
        } else {
            _showToast('Generation failed or returned nothing');
        }
        if (document.getElementById('ae-jrnl-surface')) _renderJournalModal();
        break;
    }
    case 'AE_CHAR_JOURNAL_STATE': {
        // [v2.1.5 CHARJOURNAL] Full per-character journal projection. Guard against a
        // stale broadcast for a character other than the one currently open (e.g. a
        // late reply after the popout was closed and a different one opened).
        if (!payload || payload.charId !== _cjrnlCharId) break;
        _charJournalState = (Array.isArray(payload.bubbles)) ? payload : { bubbles: [] };
        if (document.getElementById('ae-cjrnl-surface')) _renderCharJournalModal();
        break;
    }
    case 'AE_CHAR_JOURNAL_GEN_RESULT': {
        if (!payload || payload.charId !== _cjrnlCharId) break;
        _cjrnlBusy = false;
        if (payload.ok && payload.text) {
            _cjrnlEditingId = payload.id;
            _cjrnlEditDraft = payload.text;
            _showToast(payload.op === 'compress' ? '\u25BD Compressed — review & save' : '\u270D Rewritten — review & save');
        } else {
            _showToast('Generation failed or returned nothing');
        }
        if (document.getElementById('ae-cjrnl-surface')) _renderCharJournalModal();
        break;
    }
    // [CE-STRIP vNEXT] AE_HOLDING_STATE case removed — Holding popout gone, engine never sends this anymore.
    default: console.log('[AE Bridge] Unhandled engine event:', event, payload);
    }
}

// =============================================================================
// SECTION 7 — IMAGE GENERATION
// =============================================================================

function loadCachedImgFields() {
    try { var s = localStorage.getItem(IMG_FIELDS_LS_KEY); if (s) { var p = JSON.parse(s); if (Array.isArray(p.fields)) _aeImgFields = p.fields; if (p.defaults) _aeImgDefaults = Object.assign({}, DEFAULT_IMG_DEFAULTS, p.defaults); } } catch(_) {}
}

// [v2.13.0 IMGFIELDS] Bridge-side mirror of the engine's compileActiveImageFields().
// Needed only for the bridge's OWN standalone generation paths that don't round-trip
// through the engine (avatar generation, location "Generate Scene") -- the Image
// Studio composer's own Generate/Enhance go through the engine (submitDirectorPhoto),
// which compiles server-side from its own authoritative imagePromptFields state.
function _compileActiveImgFields() {
    var qualityParts = [], negativeParts = [];
    (_aeImgFields || []).forEach(function(f) {
        if (!f.active) return;
        var w = (typeof f.weight === 'number' && f.weight > 0) ? Math.max(0.1, Math.min(10, f.weight)) : 1;
        var bp = (f.basePrompt || '').trim(), uc = (f.uc || '').trim();
        if (bp) qualityParts.push(w !== 1 ? (w + '::' + bp + '::') : bp);
        if (uc) negativeParts.push(w !== 1 ? (w + '::' + uc + '::') : uc);
    });
    return { quality: qualityParts.join(', '), negative: negativeParts.join(', ') };
}

function imgFieldAction(op, extra) { sendToEngine('AE_IMG_FIELD_ACTION', Object.assign({ op: op }, extra || {})); }

async function callGenerateAPI(body) {
    // [FEATURE v2.32.3 ENGINE-THINKING-SIGNAL] This is THE single choke point for every
    // image generation in this file (5 callers: chat photos, avatars, Image Studio, action
    // images, and one more -- grep "callGenerateAPI(" for the full list), so wrapping here
    // once covers all of them rather than duplicating try/finally at each call site.
    // finally guarantees the off-call fires even on a thrown auth/network/decode error.
    _aeSetEngineThinking(true);
    try {
        var auth = getAuthToken();
        if (!auth || auth === 'Bearer undefined') throw new Error('No NAI auth token. ' + _authDebug());
        var resp = await fetch('https://image.novelai.net/ai/generate-image-stream', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': auth },
            body: JSON.stringify(body)
        });
        if (!resp.ok) throw new Error('NAI API ' + resp.status);
        var reader = resp.body.getReader(), dec = new TextDecoder();
        var buf = '', chunks = [], lastJpeg = null;
        while (true) {
            var rd = await reader.read(); if (rd.done) break;
            buf += dec.decode(rd.value, { stream: true });
            var lines = buf.split('\n'); buf = lines.pop();
            for (var l of lines) {
                if (l.startsWith('data:')) chunks.push(l.slice(5).trim());
                else if (l.trim() === '' && chunks.length) { try { var ev = JSON.parse(chunks.join('')); if (ev.image) lastJpeg = ev.image; } catch(_) {} chunks = []; }
            }
        }
        if (!lastJpeg) throw new Error('No image returned.');
        return 'data:image/png;base64,' + lastJpeg;
    } finally {
        _aeSetEngineThinking(false);
    }
}

function buildRequestBody(fp, fu, chars, settings) {
    var charPos = []; var charNeg = [];
    (chars || []).forEach(function(c) {
        if (c.visuals && c.visuals.trim()) { charPos.push({ char_caption: c.visuals, centers: [{ x: 0.5, y: 0.5 }] }); charNeg.push({ char_caption: c.uc || '', centers: [{ x: 0.5, y: 0.5 }] }); } // [CHANGE] caption -> char_caption (v4.5 multichar key)
    });
    var seed = settings.seed && settings.seed !== 0 ? settings.seed : Math.floor(Math.random() * 4294967295);
    return {
        input: fp, model: 'nai-diffusion-4-5-full', action: 'generate',
        parameters: {
            width: settings.width, height: settings.height,
            scale: settings.scale, steps: settings.steps,
            sampler: 'k_euler_ancestral', noise_schedule: 'karras', n_samples: 1, seed: seed,
            params_version: 3, qualityToggle: false, uc: fu, characterPrompts: [],
            reference_image_multiple: [], reference_information_extracted_multiple: [], reference_strength_multiple: [],
            v4_prompt:          { caption: { base_caption: fp, char_captions: charPos }, use_coords: false, use_order: true },
            v4_negative_prompt: { caption: { base_caption: fu, char_captions: charNeg }, use_coords: false, use_order: true }
        }
    };
}

async function generateCommentImage(imagePayload) {
    var fp = [imagePayload.settings.quality, imagePayload.extraBaseVisuals, imagePayload.prompt].filter(Boolean).join(', ');
    var fu = [imagePayload.settings.negative, imagePayload.extraBaseUC].filter(Boolean).join(', ');
    var body = buildRequestBody(fp, fu, imagePayload.characters || [], imagePayload.settings);
    var dataUrl = await callGenerateAPI(body);
    dbSave(imagePayload.uuid, imagePayload.prompt, dataUrl, fp, fu, imagePayload.characters || [], imagePayload.settings, { header: imagePayload.header || '', body: imagePayload.body || '' }).catch(function() {});
    imgCache.set(imagePayload.uuid, { dataUrl: dataUrl, fp: fp, fu: fu, prompt: imagePayload.prompt, characters: imagePayload.characters || [], settings: imagePayload.settings });
    return dataUrl;
}

// [vNEXT] Build and float a phantom widget for an action-driven image, captioned
// with the effect's header/body. Falls back to the thumbnail strip (already drawn
// by displayGeneratedImage) if the phantom host isn't available.
function _spawnActionImagePhantom(dataUrl, payload) {
    if (typeof PhantomManager === 'undefined' || !PhantomManager.spawnContent) return;
    var header = (payload && payload.header) || '';
    var body   = (payload && payload.body) || '';

    var node = document.createElement('div');
    node.style.cssText = 'display:flex;flex-direction:column;width:100%;';

    var img = document.createElement('img');
    img.src = dataUrl;
    img.style.cssText = 'width:100%;height:auto;display:block;cursor:pointer;';
    img.title = (payload && payload.prompt) || '';
    img.addEventListener('click', function() { try { _showLightbox(dataUrl, (payload && payload.prompt) || ''); } catch (_e) {} });
    node.appendChild(img);

    if (body) {
        var cap = document.createElement('div');
        cap.style.cssText = 'padding:12px 16px;font-size:13px;line-height:1.5;color:var(--ae-text-main);white-space:pre-wrap;';
        cap.textContent = body;
        node.appendChild(cap);
    }

    PhantomManager.spawnContent(header || '\ud83d\udcf8 Image', node);
}

function displayGeneratedImage(uuid, dataUrl, payload) {
    if (payload.autoDownload) { _downloadAsPng(dataUrl, 'ae-' + uuid.slice(0, 8) + '.png'); }
    var root = document.getElementById('ae-ui-root');
    var pane = root && root.querySelector('#ae-top-pane');
    if (!pane) return;
    var strip = pane.querySelector('#ae-img-strip');
    if (!strip) {
        strip = document.createElement('div'); strip.id = 'ae-img-strip';
        strip.style.cssText = 'position:absolute;top:52px;right:8px;display:flex;flex-direction:column;gap:4px;z-index:3;max-height:calc(100% - 60px);overflow-y:auto;align-items:flex-end;'; // [CHANGE] top 8->52 to clear portrait edit button
        var clr = document.createElement('button'); clr.textContent = '\ud83d\uddd1'; clr.title = 'Clear thumbnails (images stay saved in the gallery)';
        clr.style.cssText = 'width:24px;height:24px;padding:0;border-radius:6px;border:1px solid rgba(255,255,255,0.15);background:rgba(0,0,0,0.45);color:#fff;cursor:pointer;font-size:12px;flex-shrink:0;';
        clr.addEventListener('click', function() { var w = strip.querySelectorAll('.ae-img-wrap'); for (var i = 0; i < w.length; i++) w[i].remove(); });
        strip.appendChild(clr); pane.appendChild(strip);
    }
    var wrap = document.createElement('div'); wrap.className = 'ae-img-wrap'; wrap.setAttribute('data-uuid', uuid);
    wrap.style.cssText = 'position:relative;width:60px;height:60px;flex-shrink:0;';
    var thumb = document.createElement('img');
    thumb.src = dataUrl; thumb.title = (payload.prompt || '').slice(0, 80); thumb.setAttribute('data-nai-uuid', uuid);
    thumb.style.cssText = 'width:60px;height:60px;object-fit:cover;border-radius:6px;border:1px solid rgba(255,255,255,0.15);cursor:pointer;box-shadow:var(--ae-shadow-sm);display:block;';
    thumb.addEventListener('click', function() { _showLightbox(dataUrl, payload.prompt || ''); });
    var edit = document.createElement('button'); edit.textContent = '\u270f\ufe0f'; edit.title = 'View / edit prompt';
    edit.style.cssText = 'position:absolute;top:2px;left:2px;width:18px;height:18px;padding:0;border:none;border-radius:4px;background:rgba(0,0,0,0.55);color:#fff;cursor:pointer;font-size:9px;line-height:18px;';
    edit.addEventListener('click', function(e) { e.stopPropagation(); openPromptEditor(uuid); });
    wrap.appendChild(thumb); wrap.appendChild(edit);
    var firstWrap = strip.querySelector('.ae-img-wrap');
    if (firstWrap) strip.insertBefore(wrap, firstWrap); else strip.appendChild(wrap);
    var wraps = strip.querySelectorAll('.ae-img-wrap');
    while (wraps.length > 8) { wraps[wraps.length - 1].remove(); wraps = strip.querySelectorAll('.ae-img-wrap'); }
}

var _manualPicOverlay = null;

// [v0.9.7] Inline quick-action composer state (persists across scene re-renders).
// [v0.9.83-fix] Reinstated — these were removed by accident alongside the dead
// showQuickActionCreator() block, which caused a ReferenceError on HUD render.
var _composerEditId = null, _composerEditName = null;
var _composerAttr = null, _composerStake = null, _composerTarget = null, _composerStakeAuto = true;
var _composerLuckSpend = 0;

// [v0.9.7] Small name-prompt overlay used by the inline composer's Save Preset.
function _promptPresetName(initial, onSave) {
    var ov = document.createElement('div');
    ov.style.cssText = 'position:fixed;inset:0;z-index:var(--ae-z-popover);background:var(--ae-overlay-bg,rgba(0,0,0,0.6));display:flex;align-items:center;justify-content:center;font-family:var(--ae-font-sans);';
    ov.addEventListener('click', function(e) { if (e.target === ov) ov.remove(); });
    var card = document.createElement('div');
    card.style.cssText = 'width:min(340px,90vw);background:var(--ae-bg-panel);border:1px solid var(--ae-bg-border);border-radius:12px;padding:16px;display:flex;flex-direction:column;gap:10px;box-shadow:var(--ae-shadow-lg,0 8px 32px rgba(0,0,0,0.5));';
    var t = document.createElement('div'); t.textContent = 'Name this preset'; t.style.cssText = 'font-size:13px;font-weight:bold;color:var(--ae-accent);';
    var inp = document.createElement('input'); inp.type = 'text'; inp.value = initial || ''; inp.placeholder = 'e.g. Pick the lock';
    inp.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-input,var(--ae-bg-base));color:var(--ae-text-main);border:1px solid var(--ae-bg-border);border-radius:6px;padding:7px 9px;font-size:12px;font-family:inherit;';
    function _commit() { var nm = inp.value.trim() || 'Quick Action'; ov.remove(); onSave(nm); }
    var row = document.createElement('div'); row.style.cssText = 'display:flex;gap:8px;';
    var cancel = $.btn('Cancel', 'ghost sm', function() { ov.remove(); }); cancel.style.flex = '1 1 0';
    var save = $.btn('Save', 'primary sm', _commit); save.style.flex = '1 1 0';
    row.appendChild(cancel); row.appendChild(save);
    card.appendChild(t); card.appendChild(inp); card.appendChild(row);
    ov.appendChild(card); document.body.appendChild(ov);
    setTimeout(function() { inp.focus(); }, 30);
    inp.addEventListener('keydown', function(e) { if (e.key === 'Enter') _commit(); });
}

function triggerAutoSnap() {
    // [img] ⚙️ "Auto-Snap Scene" -> engine reads recent story, enhances, generates.
    sendToEngine('AUTO_SNAP', {});
    _showToast('📸 Auto-Snap: building scene from recent story…');
}

// [v0.9.8.0] === IMAGE STUDIO (phantom widget) =================================
// Merged image composer hosted inside a Phantom Widget. Replaces the old
// fullscreen Manual Image overlay + standalone Auto-Snap. One camera button on the
// left tray opens this. The composer offers: a base prompt, negative/UC, two
// character-name fields (whole-word matched engine-side to pull their visuals), a
// paragraph-count field, and three actions:
//   Auto-Snap : engine scans the recent story and FILLS the prompt + character
//               names (does not generate); the user reviews/edits then Generates.
//   Enhance   : runs the existing architect pass over the typed prompt.
//   Generate  : renders with the active preset; the image FILLS the widget on
//               success (form hidden) with PNG download + Edit -- Edit brings the
//               same form back in place, pre-filled, rather than opening a
//               separate overlay. [v2.1.3 BUGFIX]
var _imgStudioParaKey = 'ae_img_studio_paragraphs';

function spawnImageStudio(prefill) {
    // [v2.19.0 SHELL-3 IMAGE-INFLOW] Thin wrapper over the real widget mode now --
    // see the 'Image' branch inside PhantomManager.spawn. Kept as its own function
    // (rather than calling spawn directly at both call sites) since it's the
    // documented entry point the edit/regenerate flow prefills through.
    if (typeof PhantomManager === 'undefined' || !PhantomManager.spawn) { _showToast('Open a story first.'); return; }
    PhantomManager.spawn('Image', prefill || null);
}

function _buildImageStudioBody(prefill) {
    var root = document.createElement('div');
    root.style.cssText = 'display:flex;flex-direction:column;gap:10px;padding:14px;';

    var formArea = document.createElement('div');
    formArea.style.cssText = 'display:flex;flex-direction:column;gap:10px;';
    root.appendChild(formArea);

    // [v2.13.0 IMGFIELDS] Field toggle bar -- sits ABOVE the base prompt so active
    // fields can be switched before any generation. Clicking a chip sends the
    // toggle to the engine and repaints from the synced result.
    var fieldsBar = document.createElement('div');
    fieldsBar.id = 'ae-imgstudio-fieldsbar'; // [BUGFIX v2.1.8] see _aeRepaint note below
    fieldsBar.style.cssText = 'display:flex;flex-wrap:wrap;gap:6px;';
    function _repaintFieldsBar() {
        fieldsBar.innerHTML = '';
        if (!_aeImgFields || !_aeImgFields.length) {
            var none = document.createElement('div'); none.textContent = 'No prompt fields yet -- add some from the Image Fields panel.';
            none.style.cssText = 'font-size:10px;opacity:0.5;font-style:italic;'; fieldsBar.appendChild(none);
            return;
        }
        _aeImgFields.forEach(function(f) {
            // [BUGFIX v2.1.7] No optimistic local mutation/repaint -- see note above.
            // AE_IMG_FIELDS_SYNC is the sole repaint trigger (fieldsBar._aeRepaint).
            var chip = $.btn(f.name || '(unnamed)', f.active ? 'primary sm' : 'ghost sm', function() {
                imgFieldAction('toggle', { id: f.id });
            });
            fieldsBar.appendChild(chip);
        });
    }
    // [BUGFIX v2.1.8] This is the half of the "sole repaint trigger" mechanism that
    // was never actually wired up -- AE_IMG_FIELDS_SYNC's handler has looked up
    // #ae-imgstudio-fieldsbar and called its ._aeRepaint since v2.1.7, but this
    // element never carried either the id or the property, so that lookup always
    // silently found nothing. Chips toggled fine server-side (_aeImgFields itself
    // updated correctly) but an already-open composer never repainted to show it --
    // the reported "buttons don't always seem to remain selected."
    fieldsBar._aeRepaint = _repaintFieldsBar;
    _repaintFieldsBar();
    formArea.appendChild(fieldsBar);

    // [v2.44.0 IMGGEN-MODAL] Quick access to the full presets editor + image gallery.
    var imgGenLink = $.btn('\u2699 Presets & Gallery', 'ghost sm', function() { openImageGenModal({ tab: 'presets' }); });
    imgGenLink.style.cssText += ';align-self:flex-start;margin-bottom:4px;';
    formArea.appendChild(imgGenLink);

    var hint = document.createElement('div');
    hint.textContent = 'Describe an image, or Auto-Snap to build a prompt from the recent story. Enhance refines a rough prompt; Generate renders it with the active fields + defaults.';
    hint.style.cssText = 'font-size:11px;opacity:0.6;line-height:1.4;';
    formArea.appendChild(hint);

    function field(label, ph, rows) {
        var wrap = document.createElement('div'); wrap.style.cssText = 'display:flex;flex-direction:column;gap:3px;';
        var lb = document.createElement('label'); lb.textContent = label; lb.style.cssText = 'font-size:11px;font-weight:bold;opacity:0.8;'; wrap.appendChild(lb);
        var el;
        if (rows) { el = document.createElement('textarea'); el.rows = rows; }
        else { el = document.createElement('input'); el.type = 'text'; }
        el.placeholder = ph || '';
        el.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-input,var(--ae-bg-base));color:var(--ae-text-main);border:1px solid var(--ae-bg-border);border-radius:6px;padding:6px 8px;font-size:12px;resize:vertical;font-family:inherit;';
        wrap.appendChild(el); formArea.appendChild(wrap); return el;
    }

    var promptTA = field('Base Prompt', 'e.g. two knights duel on a rain-soaked bridge at dusk', 3);
    // [FEATURE] "Pick location to append its visuals to base prompt." Reuses the
    // same AE_FETCH_GALLERY_LOCATIONS round trip _focusLocation's Lorebook/Gallery
    // tabs use (full-world location list with locationVisuals) rather than the
    // narrower current-map-neighborhood picker ($.pickerItems.locations, fed by
    // the active graph only) -- Image Studio generation isn't tied to the
    // player's current position, so any location in the world should be pickable.
    var locBtn = $.btn('\ud83d\udccd + Location Visuals', 'ghost sm', function() {
        locBtn.disabled = true;
        window._aeGalleryLocationsCb = function(locs) {
            locBtn.disabled = false;
            if (!locs || !locs.length) { _showToast('No locations found.'); return; }
            var items = locs.map(function(l) { return { id: l.id, label: l.name, meta: l.locationVisuals ? '' : 'no visuals set', _loc: l }; });
            $.picker({ title: 'Append Location Visuals', items: items, searchable: true, onSelect: function(item) {
                var l = item._loc;
                if (!l.locationVisuals) { _showToast(l.name + ' has no Scene Visuals set.'); return; }
                var sep = promptTA.value.trim() ? ', ' : '';
                promptTA.value = promptTA.value + sep + l.locationVisuals;
            } });
        };
        sendToEngine('AE_FETCH_GALLERY_LOCATIONS', {});
    });
    locBtn.style.cssText += ';align-self:flex-start;';
    formArea.appendChild(locBtn);
    var ucTA     = field('Negative / Unwanted (optional)', 'leave blank to use active fields default', 2);

    // -- Ratio + Scale (moved here from the old per-preset slot model) --
    var rsRow = document.createElement('div'); rsRow.style.cssText = 'display:flex;gap:8px;';
    // [v2.49.0 IMGGEN-RATIO-PICK, per user] Free-form Width/Height number inputs
    // replaced with the same three fixed ratio buttons the Presets panel and the
    // Emotion Studio already use (Portrait 832x1216 / Square 1024x1024 /
    // Landscape 1216x832). Three surfaces now offer the identical choice set
    // instead of two pickers plus one pair of raw inputs that could produce a
    // dimension NAI won't accept. Scale keeps its number input -- it's a genuine
    // continuous value, unlike the ratio.
    var ratWrap = document.createElement('div'); ratWrap.style.cssText = 'flex:2 1 0;display:flex;flex-direction:column;gap:3px;';
    var ratLb = document.createElement('label'); ratLb.textContent = 'Ratio'; ratLb.style.cssText = 'font-size:11px;font-weight:bold;opacity:0.8;'; ratWrap.appendChild(ratLb);
    var ratRow = document.createElement('div'); ratRow.style.cssText = 'display:flex;gap:4px;'; ratWrap.appendChild(ratRow);
    var IMG_RATIOS = [{ l: 'Portrait', w: 832, h: 1216 }, { l: 'Square', w: 1024, h: 1024 }, { l: 'Landscape', w: 1216, h: 832 }];
    IMG_RATIOS.forEach(function(sz) {
        var rb = document.createElement('button'); rb.type = 'button'; rb.textContent = sz.l;
        rb.title = sz.w + '\u00d7' + sz.h;
        var active = (_aeImgDefaults.width === sz.w && _aeImgDefaults.height === sz.h);
        rb.style.cssText = 'flex:1 1 0;box-sizing:border-box;background:' + (active ? 'var(--ae-accent-dim)' : 'var(--ae-bg-input,var(--ae-bg-base))') + ';color:' + (active ? 'var(--ae-accent)' : 'var(--ae-text-muted)') + ';border:1px solid ' + (active ? 'var(--ae-accent)' : 'var(--ae-bg-border)') + ';border-radius:6px;padding:6px 4px;font-size:10.5px;cursor:pointer;';
        rb.addEventListener('click', function() {
            _aeImgDefaults.width = sz.w; _aeImgDefaults.height = sz.h;
            ratRow.querySelectorAll('button').forEach(function(o) {
                var on = (o === rb);
                o.style.background = on ? 'var(--ae-accent-dim)' : 'var(--ae-bg-input,var(--ae-bg-base))';
                o.style.color = on ? 'var(--ae-accent)' : 'var(--ae-text-muted)';
                o.style.borderColor = on ? 'var(--ae-accent)' : 'var(--ae-bg-border)';
            });
            imgFieldAction('setDefaults', { width: _aeImgDefaults.width, height: _aeImgDefaults.height, scale: _aeImgDefaults.scale });
        });
        ratRow.appendChild(rb);
    });
    var sWrap = document.createElement('div'); sWrap.style.cssText = 'flex:1 1 0;display:flex;flex-direction:column;gap:3px;';
    var sLb = document.createElement('label'); sLb.textContent = 'Scale'; sLb.style.cssText = 'font-size:11px;font-weight:bold;opacity:0.8;'; sWrap.appendChild(sLb);
    var sIn = document.createElement('input'); sIn.type = 'number'; sIn.step = '0.5'; sIn.placeholder = '5 (default)'; sIn.value = String(_aeImgDefaults.scale || '');
    sIn.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-input,var(--ae-bg-base));color:var(--ae-text-main);border:1px solid var(--ae-bg-border);border-radius:6px;padding:6px 8px;font-size:12px;'; sWrap.appendChild(sIn);
    rsRow.appendChild(ratWrap); rsRow.appendChild(sWrap); formArea.appendChild(rsRow);
    // Writing back becomes the new "last used" default (also feeds Auto-Snap, which has no widget of its own).
    // Ratio buttons persist on click (above); only Scale needs a change listener now.
    sIn.addEventListener('change', function() {
        _aeImgDefaults.scale = parseFloat(sIn.value) || 5.0;
        imgFieldAction('setDefaults', { width: _aeImgDefaults.width, height: _aeImgDefaults.height, scale: _aeImgDefaults.scale });
    });

    // -- Character slots (click-to-add, cap 4, including a blank one-off) --
    // [v2.13.0 IMGFIELDS] Replaces the old two free-text name inputs. Picking a
    // character pre-fills name/visuals/uc from the bridge's own synced cache
    // (cachedCharVisuals -- no engine round-trip needed); editing those fields is
    // a ONE-OFF override for this generation only, never written back.
    var charsLb = document.createElement('label'); charsLb.textContent = 'Characters (up to 4, optional)'; charsLb.style.cssText = 'font-size:11px;font-weight:bold;opacity:0.8;'; formArea.appendChild(charsLb);
    var charsWrap = document.createElement('div'); charsWrap.style.cssText = 'display:flex;flex-direction:column;gap:6px;'; formArea.appendChild(charsWrap);
    var charSlots = [];   // { id, name, visuals, uc } -- current field values live in the DOM inputs, read at gather time. id is null for a blank one-off slot (no character to look up equipped items for).

    // [FEATURE] "Append characters equipped items to character prompt." Reuses
    // buildEntityDetailPayload's children (engine Section 12) -- already returns,
    // for a character id, every item parented under them with isEquipped set --
    // the exact same data the character sheet's Status tab already reads. No
    // engine change needed. _entityDetailCache/_pendingEquipLookups avoid a
    // redundant round trip if this character's detail was already fetched
    // (e.g. from focusing them in the Inspect sheet earlier in the session).
    function _fetchEquippedItemDetail(charId, cb) {
        var cached = _entityDetailCache[charId];
        if (cached) { cb(cached); return; }
        (_pendingEquipLookups[charId] = _pendingEquipLookups[charId] || []).push(cb);
        sendToEngine('AE_FETCH_ENTITY_DETAIL', { entityId: charId });
    }

    function _repaintCharSlots() {
        charsWrap.innerHTML = '';
        charSlots.forEach(function(slot, idx) {
            var card = document.createElement('div'); card.style.cssText = 'border:1px solid var(--ae-bg-border);border-radius:6px;padding:8px;display:flex;flex-direction:column;gap:4px;';
            var topRow = document.createElement('div'); topRow.style.cssText = 'display:flex;gap:6px;align-items:center;';
            var nIn = document.createElement('input'); nIn.type = 'text'; nIn.placeholder = 'Name (blank = unnamed one-off)'; nIn.value = slot.name || '';
            nIn.style.cssText = 'flex:1;background:var(--ae-bg-input,var(--ae-bg-base));color:var(--ae-text-main);border:1px solid var(--ae-bg-border);border-radius:4px;padding:4px 6px;font-size:11px;';
            nIn.addEventListener('input', function() { slot.name = nIn.value; });
            var rmBtn = $.btn('\u2715', 'ghost sm icon', function() { charSlots.splice(idx, 1); _repaintCharSlots(); });
            topRow.appendChild(nIn); topRow.appendChild(rmBtn); card.appendChild(topRow);
            var vIn = document.createElement('textarea'); vIn.placeholder = 'Visual tags'; vIn.rows = 2; vIn.value = slot.visuals || '';
            vIn.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-input,var(--ae-bg-base));color:var(--ae-text-main);border:1px solid var(--ae-bg-border);border-radius:4px;padding:4px 6px;font-size:11px;resize:vertical;';
            vIn.addEventListener('input', function() { slot.visuals = vIn.value; }); card.appendChild(vIn);
            // [FEATURE] Equipped-items append -- disabled for blank one-off slots
            // (no character id to look items up for) or characters with none equipped.
            var eqRow = document.createElement('label'); eqRow.style.cssText = 'display:flex;align-items:center;gap:5px;font-size:10.5px;color:var(--ae-text-muted);cursor:pointer;';
            var eqCb = document.createElement('input'); eqCb.type = 'checkbox'; eqCb.disabled = !slot.id; eqCb.checked = !!slot._equipOn;
            eqCb.addEventListener('change', function() {
                slot._equipOn = eqCb.checked;
                if (slot._equipAppended) {
                    vIn.value = vIn.value.split(slot._equipAppended).join('');
                    slot._equipAppended = ''; slot.visuals = vIn.value;
                }
                if (eqCb.checked && slot.id) {
                    _fetchEquippedItemDetail(slot.id, function(detail) {
                        var names = (detail.children || [])
                            .filter(function(c) { return c.type === 'item' && c.isEquipped; })
                            .map(function(it) { return (it.description && it.description.trim()) || it.name; }).filter(Boolean);  // [v2.37.0 EQUIP-DESC-NOT-NAME, per user: "item names instead of descriptions are being added to image generation prompts"] engine already sends description on every child (buildEntityDetailPayload) -- was reading .name instead. Falls back to name only when an item has no description written yet.
                        if (!names.length) { _showToast('No equipped items found.'); return; }
                        var sep = vIn.value.trim() ? ', ' : '';
                        slot._equipAppended = sep + names.join(', ');
                        vIn.value = vIn.value + slot._equipAppended;
                        slot.visuals = vIn.value;
                    });
                }
            });
            var eqTxt = document.createElement('span'); eqTxt.textContent = 'Append equipped items';
            eqRow.appendChild(eqCb); eqRow.appendChild(eqTxt); card.appendChild(eqRow);
            var uIn = document.createElement('input'); uIn.type = 'text'; uIn.placeholder = 'UC (optional)'; uIn.value = slot.uc || '';
            uIn.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-input,var(--ae-bg-base));color:var(--ae-text-main);border:1px solid var(--ae-bg-border);border-radius:4px;padding:4px 6px;font-size:11px;';
            uIn.addEventListener('input', function() { slot.uc = uIn.value; }); card.appendChild(uIn);
            charsWrap.appendChild(card);
        });
        if (charSlots.length < 4) {
            var addBtn = $.btn('+ Add Character', 'ghost sm', function() {
                var items = [{ id: '__blank__', label: 'Blank (one-off, unnamed)' }].concat(
                    (cachedCharVisuals || []).filter(function(v) { return v.name && v.name.trim(); })
                        .map(function(v) { return { id: v.id, label: v.name }; })
                );
                $.picker({ title: 'Add Character', items: items, searchable: true, onSelect: function(item) {
                    if (item.id === '__blank__') { charSlots.push({ id: null, name: '', visuals: '', uc: '' }); }
                    else {
                        var v = (cachedCharVisuals || []).find(function(x) { return x.id === item.id; }) || {};
                        charSlots.push({ id: v.id || null, name: v.name || '', visuals: v.visuals || '', uc: v.uc || '' });
                    }
                    _repaintCharSlots();
                } });
            });
            addBtn.style.width = '100%'; charsWrap.appendChild(addBtn);
        }
    }
    _repaintCharSlots();


    // Auto-Snap row: paragraph-count + scan button.
    var asRow = document.createElement('div'); asRow.style.cssText = 'display:flex;gap:8px;align-items:flex-end;';
    var paraWrap = document.createElement('div'); paraWrap.style.cssText = 'display:flex;flex-direction:column;gap:3px;flex:0 0 96px;';
    var paraLb = document.createElement('label'); paraLb.textContent = 'Scan \u00b6'; paraLb.title = 'How many recent paragraphs Auto-Snap reads'; paraLb.style.cssText = 'font-size:11px;font-weight:bold;opacity:0.8;'; paraWrap.appendChild(paraLb);
    var paraIn = document.createElement('input'); paraIn.type = 'number'; paraIn.min = '1'; paraIn.max = '20';
    var savedPara = 4; try { var sp = parseInt(localStorage.getItem(_imgStudioParaKey), 10); if (sp > 0) savedPara = sp; } catch (_sp) {}
    paraIn.value = String(savedPara);
    paraIn.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-input,var(--ae-bg-base));color:var(--ae-text-main);border:1px solid var(--ae-bg-border);border-radius:6px;padding:6px 8px;font-size:12px;font-family:inherit;';
    paraIn.addEventListener('change', function() { try { localStorage.setItem(_imgStudioParaKey, String(parseInt(paraIn.value, 10) || 4)); } catch (_ps) {} });
    paraWrap.appendChild(paraIn); asRow.appendChild(paraWrap);
    var snapBtn = $.btn('\ud83d\udcdc Auto-Snap', 'ghost', function() {
        snapBtn.disabled = true; snapBtn.innerHTML = '\ud83d\udcdc Scanning\u2026';
        window._aeAutoSnapPromptCb = function(payload) {
            snapBtn.disabled = false; snapBtn.innerHTML = '\ud83d\udcdc Auto-Snap';
            if (!payload || payload.error) { _showToast('\u26a0 ' + ((payload && payload.error) || 'Auto-snap failed')); return; }
            if (payload.prompt) promptTA.value = payload.prompt;
            var nm = (payload.charNames || []).slice(0, 4);
            charSlots = nm.map(function(n) {
                var v = (cachedCharVisuals || []).find(function(x) { return x.name === n; }) || {};
                return { id: v.id || null, name: n, visuals: v.visuals || '', uc: v.uc || '' };
            });
            _repaintCharSlots();
            _showToast('\ud83d\udcdc Prompt built \u2014 review, then Generate.');
        };
        sendToEngine('AUTO_SNAP_PROMPT', { paragraphs: parseInt(paraIn.value, 10) || 4 });
    });
    snapBtn.style.flex = '1 1 0'; asRow.appendChild(snapBtn);
    formArea.appendChild(asRow);

    function gatherChars() {
        return charSlots.filter(function(s) { return (s.name && s.name.trim()) || (s.visuals && s.visuals.trim()) || (s.uc && s.uc.trim()); })
            .map(function(s) { return { name: s.name || '', visuals: s.visuals || '', uc: s.uc || '' }; });
    }

    // Action row: Enhance + Generate.
    var btnRow = document.createElement('div'); btnRow.style.cssText = 'display:flex;gap:8px;margin-top:2px;';
    var enhanceBtn = $.btn('\u2728 Enhance', 'ghost', function() {
        var p = promptTA.value.trim(); if (!p) { _showToast('Enter a prompt first.'); return; }
        enhanceBtn.disabled = true; enhanceBtn.innerHTML = '\u2728 Enhancing\u2026';
        window._aeDirectorEnhanceCb = function(payload) {
            enhanceBtn.disabled = false; enhanceBtn.innerHTML = '\u2728 Enhance';
            if (!payload || payload.error) { _showToast('\u26a0 ' + ((payload && payload.error) || 'Enhance failed')); return; }
            if (payload.enhancedPrompt) promptTA.value = payload.enhancedPrompt;
            if (Array.isArray(payload.charVisuals)) {
                payload.charVisuals.forEach(function(cv, i) { if (charSlots[i] && cv && cv.visuals) charSlots[i].visuals = cv.visuals; });
                _repaintCharSlots();
            }
            _showToast('\u2728 Prompt enhanced \u2014 review, then Generate.');
        };
        submitDirectorCut(p, ucTA.value.trim(), gatherChars(), true);
    });
    enhanceBtn.style.flex = '1 1 0';
    var genBtn = $.btn('\ud83d\udcf8 Generate', 'primary', function() {
        var p = promptTA.value.trim(); if (!p) { _showToast('Enter a prompt first.'); return; }
        genBtn.disabled = true; genBtn.innerHTML = '\u23f3 Generating\u2026';
        window._aeImgStudioCb = function(uuid, dataUrl, p2) {
            window._aeImgStudioCb = null;
            genBtn.disabled = false; genBtn.innerHTML = '\ud83d\udcf8 Generate';
            _imgStudioShowResult(resultArea, uuid, dataUrl, formArea);
        };
        submitDirectorCut(p, ucTA.value.trim(), gatherChars(), false);
    });
    genBtn.style.flex = '1 1 0';
    btnRow.appendChild(enhanceBtn); btnRow.appendChild(genBtn); formArea.appendChild(btnRow);

    var resultArea = document.createElement('div'); resultArea.style.cssText = 'display:none;flex-direction:column;gap:8px;flex:1;';
    root.appendChild(resultArea);

    // Optional prefill (used by edit/regenerate flows).
    if (prefill) {
        if (prefill.prompt) promptTA.value = prefill.prompt;
        if (prefill.uc) ucTA.value = prefill.uc;
        if (prefill.chars && prefill.chars.length) {
            charSlots = prefill.chars.slice(0, 4).map(function(c) { return { name: c.name || '', visuals: c.visuals || '', uc: c.uc || '' }; });
            _repaintCharSlots();
        }
    }
    return root;
}

// [v0.9.8.0] Render a freshly generated image inside the Image Studio result
// area. [BUGFIX v2.1.3] Now FILLS the widget (formArea hidden) instead of the
// form staying visible with the image tacked on below it -- only Download and
// Edit show. Edit brings the SAME generation form back in place (its fields
// were never cleared, so the last prompt/UC/character names are right there
// to tweak) rather than opening the separate openPromptEditor overlay, per
