    var taFp = _aeMakeTA(panel, 'Base Prompt', fp, 5);
    var taFu = _aeMakeTA(panel, 'Base Unwanted Content', fu, 3);
    var chHdr = document.createElement('div'); chHdr.style.cssText = 'color:var(--ae-text-dim,rgba(255,255,255,0.5));font-size:12px;margin:12px 0 6px;'; chHdr.textContent = 'Characters (' + characters.length + ' attached)'; panel.appendChild(chHdr);
    var charFields = [];
