async function regenImage(uuid, fp, fu, characters, settings) {
    var body = buildRequestBody(fp, fu, characters, settings);
    var dataUrl = await callGenerateAPI(body);
    var prev = imgCache.get(uuid) || {};
    var entry = { dataUrl: dataUrl, fp: fp, fu: fu, prompt: prev.prompt || fp, characters: characters || [], settings: settings };
    imgCache.set(uuid, entry);
    dbSave(uuid, entry.prompt, dataUrl, fp, fu, characters, settings).catch(function() {});
    // [v020] If this is a portrait/slot key, keep the persistent portrait record in sync.
    if (/_em_|_portrait$/.test(uuid)) { _savePortrait(uuid, dataUrl, 'gen', { fp: fp, fu: fu, chars: characters || [], settings: settings }).catch(function() {}); }
    var oldImgs = document.querySelectorAll('[data-nai-uuid="' + uuid + '"]');
    for (var i = 0; i < oldImgs.length; i++) oldImgs[i].src = dataUrl;
    _showToast('\ud83d\udd04 Regenerated.');
}

function findNAIGenerateButton() {
    var btns = document.querySelectorAll('button');
    for (var i = 0; i < btns.length; i++) {
        var b = btns[i];
        var txt = (b.textContent || b.getAttribute('aria-label') || '').trim().toLowerCase();
        if (txt === 'generate' || txt.includes('generate') && b.offsetParent) return b;
    }
    return null;
}

// =============================================================================
// SECTION 8 — INDEXEDDB (image + roster persistence)
// =============================================================================

function openImgDB() {
    return new Promise(function(resolve, reject) {
        if (_imgDb) { resolve(_imgDb); return; }
        var req = indexedDB.open('nai_illustrator', 3);
        req.onupgradeneeded = function(e) { var db = e.target.result; if (!db.objectStoreNames.contains('images')) db.createObjectStore('images', { keyPath: 'uuid' }); };
        req.onsuccess = function(e) { _imgDb = e.target.result; resolve(_imgDb); };
        req.onerror = reject;
    });
}

async function dbSave(uuid, prompt, dataUrl, fp, fu, chars, settings, caption) {
    // [v0.9.8.0] storyId stamps each record so the story image gallery can scope by story.
    // [vNEXT] Optional caption { header, body } from action-driven images is stamped too.
    // [v2.49.0 WEBP-STORAGE] Same convert-before-transaction rule as _savePortrait.
    try { var storeUrl = await _toWebPForStore(dataUrl); var db = await openImgDB(); var tx = db.transaction('images', 'readwrite'); tx.objectStore('images').put({ uuid: uuid, prompt: prompt, dataUrl: storeUrl, fp: fp, fu: fu, chars: chars, settings: settings, storyId: activeStoryId || '', header: (caption && caption.header) || '', body: (caption && caption.body) || '', ts: Date.now() }); }
    catch(_) {}
}

// [v0.9.8.1] Read every record from the nai_illustrator images store.
function dbGetAll() {
    return openImgDB().then(function(db) {
        return new Promise(function(resolve) {
            var req = db.transaction('images', 'readonly').objectStore('images').getAll();
            req.onsuccess = function(e) { resolve(e.target.result || []); };
            req.onerror   = function() { resolve([]); };
        });
    }).catch(function() { return []; });
}

// [v0.9.8.1] Delete a single record from nai_illustrator by uuid.
function dbDelete(uuid) {
    return openImgDB().then(function(db) {
        return new Promise(function(resolve) {
            var tx = db.transaction('images', 'readwrite');
            tx.objectStore('images').delete(uuid);
            tx.oncomplete = resolve; tx.onerror = resolve;
        });
    }).catch(function() {});
}

// =============================================================================
// SECTION 8b — PORTRAIT IndexedDB  (nai_roster_db / portraits)
// Key pattern: charId + '_portrait'           — base portrait
//              charId + '_em_' + emotionName  — per-emotion portrait
// Uses same DB name as Auto-Illustrator SnapBot for cross-compatibility.
// =============================================================================

var _rosterDb2 = null;
function _openRosterDB() {
    return new Promise(function(resolve, reject) {
        if (_rosterDb2) { resolve(_rosterDb2); return; }
        var req = indexedDB.open('nai_roster_db', 1);
        req.onupgradeneeded = function(e) { var d = e.target.result; if (!d.objectStoreNames.contains('portraits')) d.createObjectStore('portraits', { keyPath: 'id' }); };
        req.onsuccess = function(e) { _rosterDb2 = e.target.result; resolve(_rosterDb2); };
        req.onerror   = function(e) { reject(e.target.error); };
    });
}
function _savePortrait(id, dataUrl, source, meta) {
    // [v2.49.0 WEBP-STORAGE] Convert BEFORE the transaction opens -- an IndexedDB
    // transaction auto-closes when the event loop yields, so awaiting the canvas
    // decode inside it would abort the write.
    return _toWebPForStore(dataUrl).then(function(storeUrl) {
    return _openRosterDB().then(function(d) {
        return new Promise(function(res, rej) {
            var tx = d.transaction('portraits', 'readwrite');
            // [v019] Record extended with source ('gen'|'upload') + optional generation
            // meta { fp, fu, chars, settings } so slots are prompt-editable / regenerable.
            tx.objectStore('portraits').put({ id: id, dataUrl: storeUrl, ts: Date.now(), source: source || 'gen', meta: meta || null });
            tx.oncomplete = res; tx.onerror = function(e) { rej(e.target.error); };
        });
    });
    });
}
// [v019] Full-record loader (dataUrl + source + meta) for the slot prompt editor.
function _loadPortraitRec(id) {
    return _openRosterDB().then(function(d) {
        return new Promise(function(res) {
            var req = d.transaction('portraits', 'readonly').objectStore('portraits').get(id);
            req.onsuccess = function(e) { res(e.target.result || null); };
            req.onerror   = function() { res(null); };
        });
    }).catch(function() { return null; });
}
function _loadPortrait(id) {
    return _openRosterDB().then(function(d) {
        return new Promise(function(res) {
            var req = d.transaction('portraits', 'readonly').objectStore('portraits').get(id);
            req.onsuccess = function(e) { res(e.target.result ? e.target.result.dataUrl : null); };
            req.onerror   = function() { res(null); };
        });
    }).catch(function() { return null; });
}
function _getAllPortraitRecords() {
    return _openRosterDB().then(function(d) {
        return new Promise(function(res) {
            var req = d.transaction('portraits', 'readonly').objectStore('portraits').getAll();
            req.onsuccess = function(e) { res(e.target.result || []); };
            req.onerror   = function() { res([]); };
        });
    }).catch(function() { return []; });
}
function _deletePortrait(id) {
    return _openRosterDB().then(function(d) {
        return new Promise(function(res) {
            var tx = d.transaction('portraits', 'readwrite');
            tx.objectStore('portraits').delete(id); tx.oncomplete = res; tx.onerror = res;
        });
    }).catch(function() {});
}

// [v0.9.28] Default scene background: fetch a remote image ONCE, cache it in the
// portrait store keyed by URL hash, then serve from cache. Returns a dataUrl, or
// null on failure (caller then falls back to the CSS gradient).
function _aeHashStr(s) {
    var h = 5381, i = 0;
    for (i = 0; i < s.length; i++) { h = ((h << 5) + h + s.charCodeAt(i)) >>> 0; }
    return h.toString(36);
}
function _loadOrFetchDefaultBg(url) {
    if (!url) return Promise.resolve(null);
    var key = '__ae_bg__' + _aeHashStr(url);
    return _loadPortrait(key).then(function(cached) {
        if (cached) return cached;
        return fetch(url, { cache: 'force-cache' })
            .then(function(r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.blob(); })
            .then(function(blob) {
                return new Promise(function(res, rej) {
                    var fr = new FileReader();
                    fr.onload = function() { res(fr.result); };
                    fr.onerror = function() { rej(fr.error); };
                    fr.readAsDataURL(blob);
                });
            })
            .then(function(dataUrl) {
                _savePortrait(key, dataUrl, 'default-bg', { url: url }).catch(function() {});
                return dataUrl;
            });
    }).catch(function(err) { console.warn('[AE Bridge] default bg load failed:', err); return null; });
}

// [v2.49.0 WEBP-STORAGE] Convert any image dataUrl to WebP for compact storage.
// Was defined but had ZERO callers -- every image was being stored as the raw PNG
// data URL NAI returns. Now wired into BOTH storage choke points (_savePortrait for
// the portraits DB, dbSave for the gallery DB) via _toWebPForStore below, so there
// is no path that writes an unconverted image.
// Quality 0.90 is the "minimal quality loss" ask -- WebP at 0.90 is visually
// indistinguishable from source on illustration content while typically running
// 25-40% of the PNG byte size.
function _toWebP(dataUrl, quality) {
    return new Promise(function(resolve, reject) {
        var img = new Image();
        img.onload = function() {
            var c = document.createElement('canvas'); c.width = img.naturalWidth; c.height = img.naturalHeight;
            c.getContext('2d').drawImage(img, 0, 0);
            resolve(c.toDataURL('image/webp', quality || 0.90));
        };
        img.onerror = reject; img.src = dataUrl;
    });
}

// [v2.49.0 WEBP-STORAGE] Storage-path wrapper around _toWebP. Three guards that
// matter, all learned from what would otherwise silently corrupt or bloat data:
//   1. Already-WebP input is returned untouched -- re-encoding lossy-on-lossy on
//      every resave (e.g. an Edit/regenerate round trip) would compound artifacts.
//   2. Non-data-URL input (the default-bg fetch path can hand us a blob URL) is
//      returned untouched rather than fed to a canvas that would taint-fail.
//   3. ANY failure resolves with the ORIGINAL dataUrl rather than rejecting. A
//      conversion problem must never cost the user their generated image -- worst
//      case we store the larger original, which is exactly today's behavior.
function _toWebPForStore(dataUrl) {
    try {
        if (typeof dataUrl !== 'string' || dataUrl.indexOf('data:image/') !== 0) return Promise.resolve(dataUrl);
        if (dataUrl.indexOf('data:image/webp') === 0) return Promise.resolve(dataUrl);
        return _toWebP(dataUrl, 0.90).then(function(out) {
            // toDataURL silently falls back to PNG if the browser can't encode WebP.
            // Detect that and keep the original rather than storing a re-encoded PNG.
            if (typeof out !== 'string' || out.indexOf('data:image/webp') !== 0) return dataUrl;
            return out;
        }).catch(function() { return dataUrl; });
    } catch (_) { return Promise.resolve(dataUrl); }
}

// [v2.49.0 WEBP-STORAGE] Download helper. Storage is WebP but downloads must be PNG
// per user ("only generations downloaded as png"), so every download site routes
// through here instead of assigning a stored dataUrl straight to a link named .png
// -- which, once storage became WebP, would have handed out WebP bytes in a
// PNG-named file. Falls back to downloading whatever we have if the decode fails.
function _downloadAsPng(dataUrl, filename) {
    function fire(href) {
        var a = document.createElement('a');
        a.href = href; a.download = filename;
        document.body.appendChild(a); a.click(); document.body.removeChild(a);
    }
    try {
        if (typeof dataUrl !== 'string' || dataUrl.indexOf('data:image/png') === 0) { fire(dataUrl); return; }
        var img = new Image();
        img.onload = function() {
            try {
                var c = document.createElement('canvas');
                c.width = img.naturalWidth; c.height = img.naturalHeight;
                c.getContext('2d').drawImage(img, 0, 0);
                fire(c.toDataURL('image/png'));
            } catch (_) { fire(dataUrl); }
        };
        img.onerror = function() { fire(dataUrl); };
        img.src = dataUrl;
    } catch (_) { fire(dataUrl); }
}

// Default tag text per emotion-slot name (mirrors Auto-Illustrator SnapBot v7.x
// conventions). Used by _getEmoTags() as the fallback when a character has no
// saved per-slot override. The old fixed 24-emotion list this was keyed against
// (_AE_EMOTIONS) was removed [CLEANUP]; slots are now free-form per _getEmoSlots().
var _AE_EMOTION_TAGS = {
    neutral:'neutral expression, calm, composed', happy:'happy, bright smile, cheerful',
    sad:'sad expression, downcast eyes, melancholy', angry:'angry expression, furrowed brows, glaring',
    surprised:'surprised, wide eyes, mouth slightly open', embarrassed:'embarrassed, blushing cheeks, flustered',
    shy:'shy, looking away bashfully', disgusted:'disgusted expression, grimacing',
    laughing:'laughing, big smile, eyes crinkled', tired:'tired, heavy half-lidded eyes, exhausted',
    excited:'excited, bright sparkling eyes, energetic', nervous:'nervous, anxious, tense expression',
    confused:'confused, head tilted, puzzled look', worried:'worried, frowning slightly, concerned',
    scared:'scared, wide fearful eyes, trembling', love:'loving expression, soft smile, warm adoring eyes',
    smug:'smug, self-satisfied smirk', bored:'bored, disinterested, deadpan',
    irritated:'irritated, annoyed, exasperated', determined:'determined, focused, resolute',
    playful:'playful, mischievous smile', hurt:'hurt, pained emotional expression',
    aroused:'flushed cheeks, heated gaze', thinking:'thinking, finger to chin, contemplative'
};

// [v2.47.0 EMOSTUDIO-24DEFAULT] The 24 canonical CharChat emotion words -- same set
// resolveEmotion()/EMOTION_MAP normalises model output onto engine-side, so a slot
// named exactly one of these is guaranteed reachable by the chat avatar's future
// per-emotion lookup (see _ccavPaintOne below). Derived from _AE_EMOTION_TAGS's own
// keys rather than a second hand-typed list, so the two can never drift apart.
var CANON_EMOTION_SLOTS = Object.keys(_AE_EMOTION_TAGS);

// Per-character emotion tag overrides in localStorage. Falls back to _AE_EMOTION_TAGS.
function _getEmoTags(charId) { try { return JSON.parse(localStorage.getItem('ae_emo_tags_' + charId)) || {}; } catch(_) { return {}; } }
function _setEmoTags(charId, tags) { try { localStorage.setItem('ae_emo_tags_' + charId, JSON.stringify(tags)); } catch(_) {} }
// [v019] Managed per-character image-slot list (replaces the fixed 24 emotions).
// [FEATURE v2.3.0 AVATAR-SLOT] 'Avatar' is now a permanent, pinned-first member of
// this same list (charId+'_em_Avatar' key) rather than a separate always-present
// mechanism -- see _loadCharAvatarImage below for the legacy charId+'_portrait'
// read fallback, and SECTION 21e / the flat focus Visuals+Gallery tab for the
// non-deletable rendering guard keyed off AVATAR_SLOT_NAME.
var AVATAR_SLOT_NAME = 'Avatar';
// [v2.47.0 EMOSTUDIO-24DEFAULT] A fresh character now seeds Avatar + Snapshot (both
// pinned, unchanged) PLUS all 24 canonical emotion slots -- per user, so CharChat's
// emotion tag has a matching portrait slot out of the box instead of the old
// two-slot-then-manually-add-24 workflow. An EXISTING saved list is merged, never
// replaced: any of the three pinned/canonical names missing from it get appended
// (covers characters who saved a list before this patch), and any custom slot names
// the user already added are left exactly where they were. This makes the migration
// idempotent -- running it twice is a no-op -- and non-destructive: no image, tag
// override, or slot name is ever dropped by this function.
function _getEmoSlots(charId) {
    var raw = null;
    try { raw = JSON.parse(localStorage.getItem('ae_emo_slots_' + charId)); } catch(_) {}
    if (raw && raw.length) {
        var changed = false;
        if (raw.indexOf(AVATAR_SLOT_NAME) === -1) { raw = [AVATAR_SLOT_NAME].concat(raw); changed = true; }
        CANON_EMOTION_SLOTS.forEach(function(nm) { if (raw.indexOf(nm) === -1) { raw.push(nm); changed = true; } });
        if (changed) _setEmoSlots(charId, raw);
        return raw;
    }
    var seeded = [AVATAR_SLOT_NAME, 'Snapshot'].concat(CANON_EMOTION_SLOTS);
    _setEmoSlots(charId, seeded);
    return seeded;
}
function _setEmoSlots(charId, list) { try { localStorage.setItem('ae_emo_slots_' + charId, JSON.stringify(list)); } catch(_) {} }
// [FEATURE v2.3.0 AVATAR-SLOT] Avatar image lookup: prefers the new slot key
// (charId+'_em_Avatar'); falls back to the pre-2.3.0 legacy key (charId+'_portrait')
// for characters that haven't regenerated/reuploaded since the merge. New saves
// always write to the slot key going forward -- the legacy key is read-only from
// here on, never written again, and simply ages out as characters get new avatars.
function _loadCharAvatarImage(charId) {
    return _loadPortrait(charId + '_em_' + AVATAR_SLOT_NAME).then(function(url) {
        if (url) return url;
        return _loadPortrait(charId + '_portrait');
    }).catch(function() { return null; });
}
// [v2.47.0 EMOSTUDIO-24DEFAULT] Emotion-aware sibling of _loadCharAvatarImage, used
// only by the CharChat avatar painter (_ccavPaintOne). Chain: the exact emotion slot
// first, then the pinned Avatar slot (a character with no matching emotion portrait
// still shows SOMETHING rather than nothing), then the pre-2.3.0 legacy key. A blank
// or missing emotion arg degrades to plain _loadCharAvatarImage behavior -- this stays
// a strict superset, never a second competing lookup path.
function _loadCharEmotionImage(charId, emotion) {
    if (!emotion) return _loadCharAvatarImage(charId);
    return _loadPortrait(charId + '_em_' + emotion).then(function(url) {
        if (url) return url;
        return _loadCharAvatarImage(charId);
    }).catch(function() { return _loadCharAvatarImage(charId); });
}

// Generate an avatar image using current preset + character visual fields.
// emotionTags: optional comma-separated tags for this emotion state.
async function _generateAvatarImage(charVisual, emotionTags) {
    // [BUGFIX v2.1.3] Was folding charVisual.visuals/avatarVisuals/uc straight into
    // the BASE fp/fu strings and calling buildRequestBody with an empty chars array --
    // so a solo avatar/snapshot never used NAI's v4.5 per-character caption fields at
    // all (v4_prompt.caption.char_captions / v4_negative_prompt.caption.char_captions,
    // the actual "character fields"). Everything describing THIS character (identity
    // visuals, avatar-specific staging, the emotion tag for this slot, and their UC)
    // now goes through the chars array instead; fp/fu carry ONLY the genuinely global
    // preset tags. buildRequestBody already does this correctly for multi-character
    // scene generation (see its charPos/charNeg construction) -- this brings the
    // single-character avatar path in line with that, rather than inventing a second
    // convention.
    var _avCompiled = _compileActiveImgFields();
    var fp = _avCompiled.quality.trim();
    var fu = _avCompiled.negative.trim();
    var charVisuals = [charVisual.visuals || '', charVisual.avatarVisuals || '', emotionTags || ''].filter(Boolean).join(', ');
    var charUc = charVisual.uc || '';
    var chars = charVisuals ? [{ visuals: charVisuals, uc: charUc }] : [];
    var seed = (charVisual.avatarSeed && charVisual.avatarSeed !== 0) ? charVisual.avatarSeed : Math.floor(Math.random() * 4294967295);
    var _avSettings = {
        width:  charVisual.avatarWidth  || 832,
        height: charVisual.avatarHeight || 1216,
        steps:  Math.min(_aeImgDefaults.steps || 28, 28),
        scale:  _aeImgDefaults.scale || 5.0,
        seed:   seed
    };
    // [v019] Return prompt + settings so generated slots carry editable meta.
    var _avUrl = await callGenerateAPI(buildRequestBody(fp, fu, chars, _avSettings));
    return { dataUrl: _avUrl, fp: fp, fu: fu, characters: chars, settings: _avSettings };
}

// Gallery-specific lightbox (self-contained, no dependency on bridge _showLightbox).
function _galleryLightbox(src, caption) {
    var lb = document.createElement('div'); lb.className = 'ae-lightbox'; lb.style.zIndex = '9999999';
    var img = document.createElement('img'); img.src = src; lb.appendChild(img);
    if (caption) { var cap = document.createElement('div'); cap.style.cssText = 'color:rgba(255,255,255,0.55);font-size:12px;font-family:var(--ae-font-sans);margin-top:6px;'; cap.textContent = caption; lb.appendChild(cap); }
    lb.addEventListener('click', function() { lb.remove(); }); document.body.appendChild(lb);
}

// =============================================================================
// SECTION 9 — CHAT OVERLAY
// (Core functions: openDirectChat, finishBotTyping, showSummaryBlock)
// Full chat styles/render omitted here — port from AE-Bridge.txt v7.x
// =============================================================================

function openDirectChat(char, forceImage) {
    if (!char || !char.id) return;
    // Open the existing chat overlay from the snapbot chat system.
    // This function delegates to the existing implementation from AE-Bridge.txt.
    // If migrating: copy openDirectChat, injectChatStyles, renderMessages, finishBotTyping
    // from auto-illustrator-sb-bridge-v790.txt into this section.
    console.log('[AE Bridge] openDirectChat:', char.name);
    // Minimal stub: engine hijack start
    sendToEngine('HIJACK_GENERATION_START', {
        charId: char.id, chatMode: 'chat', storyId: activeStoryId,
        chatHistory: loadChatHistory(char.id),
        enableThinkTags: !!(char.bot && char.bot.enableThinkTags),
        emotionStates: (char.emotions || []).map(function(e) { return e.name; })
    });
}

function finishBotTyping(char, sendBtn, statusDot, typingRow, content, fallback, thoughts, emotionState, imagePayload) {
    if (pendingBotTimeout) { clearTimeout(pendingBotTimeout); pendingBotTimeout = null; }
    botTyping = false;
    if (sendBtn) sendBtn.disabled = false;
    if (statusDot) statusDot.classList.remove('thinking');
    if (typingRow && typingRow.parentNode) typingRow.parentNode.removeChild(typingRow);
    var finalText = content || fallback || '[No response]';
    var history = loadChatHistory(char.id);
    history.push({ id: Date.now().toString(36), role: 'bot', content: finalText, thoughts: thoughts || null, emotionState: emotionState || 'neutral', imagePayload: imagePayload || null, timestamp: Date.now() });
    saveChatHistory(char.id, history);
    console.log('[AE Bridge] Bot reply received:', char.name, '—', emotionState);
}

function showSummaryBlock(container, summary) {
    var block = document.createElement('div');
    block.style.cssText = 'background:var(--ae-bg-raised);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-sm);padding:10px;font-size:11px;color:var(--ae-text-muted);';
    block.textContent = '📋 ' + summary;
    container.appendChild(block);
}

// =============================================================================
// SECTION 10 — HUD CORE RENDERER
// =============================================================================

// [v0.9.9.2] Render/refresh the clock chip in the scene banner from the SceneClockInfo
// shipped on SCENE_STATE. Create-or-update by id so it survives banner re-renders.
function _renderClockChip(root, clock) {
    if (!root) return;
    var existing = root.querySelector('#ae-clock-chip');
    if (!clock || !clock.enabled) { if (existing && existing.parentNode) existing.parentNode.removeChild(existing); return; }
    var content = root.querySelector('.ae-scene-content');
    if (!content) return;
    var chip = existing;
    if (!chip) {
        chip = document.createElement('div');
        chip.id = 'ae-clock-chip';
        chip.className = 'ae-clock-chip';
        content.appendChild(chip);
    }
    while (chip.firstChild) chip.removeChild(chip.firstChild);

    var stampEl = document.createElement('span');
    stampEl.className = 'ae-clock-stamp';
    stampEl.textContent = clock.stamp || '';
    chip.appendChild(stampEl);

    var btnRow = document.createElement('span');
    btnRow.className = 'ae-clock-btns';
    function _mkClockBtn(label, title, fn) {
        var b = document.createElement('button');
        b.className = 'ae-clock-btn'; b.type = 'button'; b.textContent = label;
        if (title) b.title = title;
        b.addEventListener('click', function(ev) { ev.stopPropagation(); fn(); });
        return b;
    }
    btnRow.appendChild(_mkClockBtn('+1h', 'Advance one hour', function() { sendToEngine('AE_TIME_ADVANCE', { hours: 1 }); }));
    btnRow.appendChild(_mkClockBtn('+1d', 'Advance one day', function() { sendToEngine('AE_TIME_ADVANCE', { hours: 24 }); }));
    btnRow.appendChild(_mkClockBtn('Set', 'Set day and hour', function() { _toggleClockSetEditor(chip, clock); }));
    btnRow.appendChild(_mkClockBtn('\ud83d\udcc5', 'Open Calendar', function() { sendToEngine('AE_OPEN_CALENDAR', {}); }));
    chip.appendChild(btnRow);
}

// [v0.9.9.2] Inline day/hour set editor. Day is the absolute day count (climbs forever);
// hour is 0-23. Sends AE_TIME_SET with absolute clock hours = day*24 + hour.
function _toggleClockSetEditor(chip, clock) {
    var existing = chip.querySelector('.ae-clock-set');
    if (existing) { if (existing.parentNode) existing.parentNode.removeChild(existing); return; }
    var box = document.createElement('span');
    box.className = 'ae-clock-set';

    var dLbl = document.createElement('span'); dLbl.className = 'ae-clock-lbl'; dLbl.textContent = 'Day';
    var dayIn = document.createElement('input');
    dayIn.type = 'number'; dayIn.className = 'ae-clock-num'; dayIn.min = '0';
    dayIn.value = String(clock.absoluteDay || 0);
    dayIn.title = 'Absolute day (0 = the first day)';

    var hLbl = document.createElement('span'); hLbl.className = 'ae-clock-lbl'; hLbl.textContent = 'Hr';
    var hourIn = document.createElement('input');
    hourIn.type = 'number'; hourIn.className = 'ae-clock-num'; hourIn.min = '0'; hourIn.max = '23';
    hourIn.value = String(clock.hourOfDay || 0);
    hourIn.title = 'Hour of day (0-23)';

    var go = document.createElement('button');
    go.className = 'ae-clock-btn'; go.type = 'button'; go.textContent = 'Go';
    go.addEventListener('click', function(ev) {
        ev.stopPropagation();
        var d = Math.max(0, Math.floor(Number(dayIn.value) || 0));
        var h = Math.max(0, Math.min(23, Math.floor(Number(hourIn.value) || 0)));
        sendToEngine('AE_TIME_SET', { hours: d * 24 + h });
    });

    box.appendChild(dLbl); box.appendChild(dayIn);
    box.appendChild(hLbl); box.appendChild(hourIn);
    box.appendChild(go);
    chip.appendChild(box);
}

function renderSceneHUD(state) {
    if (!state) return;
    // [v0.9.25 FLICK1] Debounce via requestAnimationFrame: coalesce rapid broadcasts
    // (multiple queueSceneStateBroadcast() calls from a single action chain) into one
    // DOM update per frame. Only the most-recent state is rendered.
    _renderNextState = state;
    if (_renderPending) return;
    _renderPending = true;
    requestAnimationFrame(function() {
        _renderPending = false;
        var s = _renderNextState;
        _renderNextState = null;
        if (!s) return;
        _doRenderSceneHUD(s);
    });
}

function _doRenderSceneHUD(state) {
    var root = document.getElementById('ae-ui-root');
    if (!root) return;

    // Clear ALL waiting placeholders (search entire document for Phantom instances)
    document.querySelectorAll('.ae-waiting-placeholder').forEach(function(el) { el.remove(); });

    // [v0.9.7.5 FOCUS-FIX] Always call _updateBanner — it handles focused/unfocused internally.
    _updateBanner(document, state);
    _renderClockChip(root, state.clock);   // [v0.9.9.2] clock chip in the scene banner

    var _activeBtn = root.querySelector('.ae-tab-btn.active');
    var _activeTarget = _activeBtn ? _activeBtn.getAttribute('data-target') : 'ae-tab-map';

    // Phantom Widget Visibility Override
    function shouldRender(tabId) {
        if (_activeTarget === tabId) return true;
        var t = document.getElementById(tabId);
        return t && t.closest('.ae-phantom-widget'); // Force render if stolen
    }

    // Pass 'document' to all renderers so relocated Phantom tabs are found!
    _renderMapTab(document, state);
    
    // [v0.9.7.5 FOCUS-FIX2] _renderSceneTab handles focused state internally.
    if (shouldRender('ae-tab-scene')) _renderSceneTab(document, state);
    if (shouldRender('ae-tab-hub')) _renderHubTab(document, state);

    _updateBottomPaneBackground(root, state);
}

function showWaitingPlaceholder() {
    var root = document.getElementById('ae-ui-root');
    if (!root) return;

    // Map tab: inject a status overlay INSIDE the viewport — never wipe the map DOM structure
    var mapViewport = root.querySelector('#ae-map-viewport');
    if (mapViewport && !mapViewport.querySelector('.ae-waiting-placeholder')) {
        var mapOverlay = document.createElement('div');
        mapOverlay.className = 'ae-waiting-placeholder';
        mapOverlay.style.cssText = 'position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;color:var(--ae-text-dim);font-size:12px;z-index:20;background:rgba(19,19,24,0.7);';
        mapOverlay.innerHTML = '🔌 Waiting for scene data…';
        mapViewport.style.position = 'relative';
        mapViewport.appendChild(mapOverlay);
    }

    // Other tabs: clear and show placeholder
    ['ae-tab-scene', 'ae-tab-hub'].forEach(function(tabId) {
        var tab = root.querySelector('#' + tabId); if (!tab) return;
        tab.innerHTML = '';
        var p = document.createElement('div'); p.className = 'ae-waiting-placeholder';
        p.style.cssText = 'padding:20px;text-align:center;color:var(--ae-text-dim);font-size:12px;';
        p.textContent = '🔌 Waiting for scene data…';
        var btn = $.btn('🔄 Request State', 'ghost sm', function() { if (engineScriptId) requestSceneState(); });
        btn.style.marginTop = '8px';
        p.appendChild(document.createElement('br')); p.appendChild(btn);
        tab.appendChild(p);
    });

    var titleEl = root.querySelector('#ae-scene-title');
    if (titleEl && titleEl.textContent === 'Loading…') titleEl.textContent = 'AE — Bridge Connected';
}

// [v021] ── Entity focus view (S1: character top pane) ────────────────────────
// Transient bridge-local focus layered over the scene; back-out returns to the
// location/hub banner. Characters get the full focus view; items/narratives stay
// popups. Snapshot text + image reuse the engine v027 pipeline.
var _focusedEntityId = null;
var _snapTextCache = {};

// Image cascade: snapshot slot -> avatar slot (-> legacy portrait fallback) -> (parent/location: later).
// CHARACTER-ONLY -- _em_Snapshot then _loadCharAvatarImage's own _em_Avatar/legacy
// _portrait chain. [v2.20.0 SCENE-BG-REHOME] _buildPhantomPlate's default resolver
// for entities that don't pass opts.resolveImage -- locations use a DIFFERENT single-
// slot key (locId + '_portrait', see _resolveLocationPlateImage below) and were
// silently resolving to nothing here before this pass, since this function never
// checked that key. Do not widen this one to branch on kind -- keep the two resolvers
// separate, same reasoning as _focusEntity/_focusLocation staying separate functions.
function resolveEntityImage(charId) {
    return _loadPortrait(charId + '_em_Snapshot').then(function(snap) {
        if (snap) return snap;
        return _loadCharAvatarImage(charId);
    }).catch(function() { return null; });
}

// [FEATURE v2.20.0 SCENE-BG-REHOME, per user] A location's own portrait first (single
// slot, locId + '_portrait' -- the Gallery tab's existing convention, grep
// "loc.id + '_portrait'"), then the module-level Scene Background default if it has
// none. That default used to be the dead #ae-top-pane banner's fallback (zero live
// consumers since PHANTOM-PRIMARY PASS 1 -- see the CE-INDEX); this is its rehome onto
// the live dossier's portrait plate, per user decision on the Forge-rebuild handoff.
// Same undefined-vs-'' semantics the original fallback earned the hard way (grep
// "v0.9.9.9" on _effBg): only fall back to the hardcoded AE_DEFAULT_BG_URL when the
// module field has never synced (undefined); an explicit clear (empty string) must
// stay cleared, not silently revert. lastSceneState.defaultBgUrl is intentionally NOT
// per-location -- it's one module-wide default, same as the field it was rehomed from.
function _resolveLocationPlateImage(locId) {
    return _loadPortrait(locId + '_portrait').then(function(url) {
        if (url) return url;
        var synced = lastSceneState && lastSceneState.defaultBgUrl !== undefined;
        var effBg = synced ? lastSceneState.defaultBgUrl : AE_DEFAULT_BG_URL;
        if (!effBg) return null;
        return _loadOrFetchDefaultBg(effBg);
    }).catch(function() { return null; });
}

var _priorPhantomMode = null; // [PHANTOM-PRIMARY PASS 5 BUGFIX] remembered so the sheet's back button returns to wherever you actually were (Map or Inspect roster), not always the roster
var _lastPhantomMode = 'Inspect'; // [v2.34.0 REOPEN-LAST-MODE, per user] the mode spawn() last opened, so re-toggling the HUD reopens THAT (e.g. Chat if Chat was up) instead of always Inspect
// [SPLIT-INSPECT-2 FOCUS-HISTORY] _priorPhantomMode alone can't tell "was on the roster"
// from "was on a focused location" -- both report data-mode="Inspect". This is a real
// one-level-deep undo stack of {id, kind} for whatever was focused BEFORE the current
// focus (e.g. the location a character was focused FROM), so Back can return to it
// instead of always collapsing to Map/roster. _focusHistorySuppress prevents the
// re-focus _clearFocus() does on Back from pushing itself back onto the stack.
var _focusHistory = [];
var _focusHistorySuppress = false;
var _focusedSheetActiveTab = 0; // [BUGFIX v2.0.3] survives _refreshPhantomInspectFocus() rebuilds (CHARACTER_DATA_SYNC on every field save); reset only when _focusEntity() below points at a (possibly different) character
var _focusedLocationMeta = null; // [FEATURE] description/atmosphere/locationVisuals/lorebookText for the currently _focusLocation()-ed location — from AE_FETCH_GALLERY_LOCATIONS, see _focusLocation below
// [FEATURE] Set synchronously by _focusEntity/_focusLocation at call time -- unlike
// _focusedIsCharacter's inference (cachedCharVisuals lookup, or detail.type once the
// async fetch lands), PhantomManager.spawn() needs to know character/location-ness on
// its VERY FIRST call, made before AE_ENTITY_DETAIL_RESPONSE has arrived. Without this
// flag, that first spawn() would fall through to the generic tab-stealing branch
// instead of the focused dossier, only self-correcting once _refreshPhantomInspectFocus()/
// _refreshPhantomLocationFocus() fires later -- a visible flash to the wrong view, OR
// (SPLIT-INSPECT bugfix, v2.19.1) worse: the tab-stealing branch physically detaches
// #ae-tab-scene from #ae-ui-root into the widget body, and _buildPhantomInspectFocused's
// unconditional body.innerHTML='' on the async correction then discards that detached
// node instead of returning it -- #ae-ui-root's Inspect tab is gone until reload. null =
// unknown/item/thread (still routed through the legacy steal branch, deliberately).
var _focusedEntityKind = null;

function _focusEntity(entityId) {
    // [SPLIT-INSPECT-2 FOCUS-HISTORY] Push whatever was focused before, so Back can
    // return to it. Guarded by _focusHistorySuppress (set while _clearFocus is
    // re-focusing a popped entry) and by entityId !== current (don't push re-focusing
    // the same entity, e.g. a data refresh).
    if (!_focusHistorySuppress && _focusedEntityId && _focusedEntityId !== entityId) {
        _focusHistory.push({ id: _focusedEntityId, kind: _focusedEntityKind });
    }
    _focusedEntityId = entityId;
    _focusedEntityDetail = null;
    // [BUGFIX v2.19.1 SPLIT-INSPECT] was null -- every existing caller of _focusEntity is
    // an avatar click in a character grid/roster, so 'character' is correct synchronously
    // here for the same reason _focusLocation sets 'location' synchronously below: spawn()'s
    // FIRST call can't wait on cachedCharVisuals/AE_ENTITY_DETAIL_RESPONSE. Previously this
    // only resolved via the async cachedCharVisuals fallback in spawn(), which is why the
    // dossier reliably rendered from the Map (its entities are already cached by the time
    // you click Inspect) but not reliably elsewhere (a freshly-focused, not-yet-cached
    // character). A future item/narrative-thread caller should pass null explicitly (or a
    // dedicated kind) to keep using the legacy steal branch -- see spawn()'s own comment.
    _focusedEntityKind = 'character';
    _focusedSheetActiveTab = 0; // [BUGFIX v2.0.3] fresh focus always opens on Status (tab 0)
    sendToEngine('AE_FETCH_ENTITY_DETAIL', { entityId: entityId });
    var tp = document.getElementById('ae-top-pane');
    if (tp) _renderFocusBanner(tp, entityId);
    // [PHANTOM-PRIMARY PASS 5 BUGFIX] Bring the widget into the focused
    // image+sheet view regardless of what it was showing before (Map or the
    // Inspect roster) — previously this only fired if the widget was already
    // in Inspect mode, so focusing a character from Map did nothing visible
    // and there was no way back to it afterward either.
    var widget = document.querySelector('.ae-phantom-widget');
    if (widget) { _priorPhantomMode = widget.getAttribute('data-mode'); PhantomManager.spawn('Inspect'); }
}

// [FEATURE] Location contact-card entry point — parallel to _focusEntity above,
// but for locations, which needed their own detail source: AE_FETCH_ENTITY_DETAIL
// alone (the character path) doesn't carry description/atmosphere/locationVisuals/
// lorebookText for a location entity. AE_FETCH_GALLERY_LOCATIONS already returns
// exactly those fields for every location in the world (it feeds the World-Build
// Studio's Gallery hierarchy) -- reused as-is here rather than adding a new
// engine message; the whole-world fetch is heavier than a single-location query
// would be, but it's an existing, already-relied-upon contract, and location
// counts are small relative to a real chat's token budget. window._aeGalleryLocationsCb
// is a one-shot global (see Section 6's AE_GALLERY_LOCATIONS_RESPONSE case) -- if the
// World-Build Studio's own Gallery is ALSO open when this fires, whichever response
// lands last wins, same pre-existing single-flight risk that callback already has.
function _focusLocation(locId) {
    // [SPLIT-INSPECT-2 FOCUS-HISTORY] Same guard as _focusEntity — currently locations
    // are only ever entered from the Map, so this is a no-op today, but keeps the two
    // entry points from drifting if a location-from-location path is ever added.
    if (!_focusHistorySuppress && _focusedEntityId && _focusedEntityId !== locId) {
        _focusHistory.push({ id: _focusedEntityId, kind: _focusedEntityKind });
    }
    _focusedEntityId = locId;
    _focusedEntityDetail = null;
    _focusedLocationMeta = null;
    _focusedEntityKind = 'location';
    _focusedSheetActiveTab = 0; // fresh focus always opens on the Present tab
    sendToEngine('AE_FETCH_ENTITY_DETAIL', { entityId: locId });
    window._aeGalleryLocationsCb = function(locs) {
        _focusedLocationMeta = (locs || []).find(function(l) { return l.id === locId; }) || null;
        _refreshPhantomLocationFocus();
    };
    sendToEngine('AE_FETCH_GALLERY_LOCATIONS', {});
    var widget = document.querySelector('.ae-phantom-widget');
    if (widget) { _priorPhantomMode = widget.getAttribute('data-mode'); PhantomManager.spawn('Inspect'); }
}

function _clearFocus() {
    // [SPLIT-INSPECT-2 FOCUS-HISTORY] Pop one level of real history FIRST. Back should
    // return to whatever you were actually looking at before (e.g. the location you
    // focused this character from), not collapse straight to Map/roster — that
    // collapse is now only the fallback for when there's nothing left to pop.
    if (_focusHistory.length) {
        var _fhPrev = _focusHistory.pop();
        _focusHistorySuppress = true;
        if (_fhPrev.kind === 'location') _focusLocation(_fhPrev.id);
        else _focusEntity(_fhPrev.id);
        _focusHistorySuppress = false;
        return;
    }
    // [v2.46.1 FOCUS-LOCATION-DEFAULT] When history is empty and the widget would
    // stay in Inspect mode, auto-focus the player's current location instead of
    // falling to the unfocused roster grid (the "bad view" — #ae-tab-scene stolen
    // into the widget body, showing scene characters with a squished banner). The
    // player is always *somewhere*, so the location dossier is the natural default.
    // If there's no known location (edge case: no story loaded), fall through to
    // Map, which is always safe.
    if (_priorPhantomMode !== 'Map' && lastSceneState && lastSceneState.locationId) {
        _focusHistorySuppress = true;
        _focusLocation(lastSceneState.locationId);
        _focusHistorySuppress = false;
        _priorPhantomMode = null;
        return;
    }
    _focusedEntityId = null;
    _focusedEntityDetail = null;
    _focusedLocationMeta = null;
    _focusedEntityKind = null;
    var tp = document.getElementById('ae-top-pane');
    if (tp) {
        ['#ae-focus-controls', '#ae-focus-back', '#ae-focus-snaptext'].forEach(function(sel) { var e = tp.querySelector(sel); if (e) e.remove(); });
        tp.classList.remove('portrait-mode');
    }
    if (lastSceneState) _doRenderSceneHUD(lastSceneState);
    // [PHANTOM-PRIMARY PASS 5 BUGFIX] Return to wherever you were before —
    // Map if that's where focusing happened from, otherwise Map (the unfocused
    // roster grid is no longer reachable — see FOCUS-LOCATION-DEFAULT above).
    if (document.querySelector('.ae-phantom-widget')) {
        PhantomManager.spawn('Map');
    }
    _priorPhantomMode = null;
}

function _getEntityNameFallback(entityId) {
    var vis = cachedCharVisuals.find(function(v) { return v.id === entityId; });
    if (vis) return vis.name;
    if (lastSceneState) {
        var pc = (lastSceneState.presentCharacters || []).find(function(c) { return c.id === entityId || c.entityId === entityId; });
        if (pc) return pc.name || pc.entityName;
        var pi = (lastSceneState.presentItems || []).find(function(i) { return i.id === entityId; });
        if (pi) return pi.name;
        var pn = (lastSceneState.activeNarratives || []).find(function(n) { return n.id === entityId; });
        if (pn) return pn.name;
        var pa = (lastSceneState.availableActions || []).find(function(a) { return a.entityId === entityId; });
        if (pa) return pa.entityName;
    }
    return 'Loading…';
}

function _writeInTitle(el, text) {
    // Set the title text and replay the write-in animation. CSS animations only
    // fire on mount, so we toggle the class with a forced reflow to restart it
    // every time a different entity/location/character is opened.
    if (!el) return;
    el.textContent = text;
    el.classList.remove('ae-writein');
    void el.offsetWidth; // force reflow
    el.classList.add('ae-writein');
}

function _renderFocusBanner(topPane, entityId) {
    var detail = _focusedEntityDetail;
    var name = detail ? detail.name : _getEntityNameFallback(entityId);
    var isChar = detail ? (detail.type === 'character') : true;

    topPane.classList.add('portrait-mode');
    var stale = topPane.querySelector('#ae-protag-edit-btn'); if (stale) stale.remove();

    var titleEl = topPane.querySelector('.ae-scene-title'); if (titleEl) _writeInTitle(titleEl, (name || '?').toUpperCase());
    
    var descEl = topPane.querySelector('.ae-scene-desc');
    if (descEl) {
        if (isChar) {
            var vis = cachedCharVisuals.find(function(v) { return v.id === entityId; }) || {};
            descEl.textContent = (detail && detail.compiledThought) 
                ? '💭 ' + detail.compiledThought 
                : (vis.compressedLine ? '💭 ' + vis.compressedLine : (vis.briefDescription || ''));
        } else {
            descEl.textContent = (detail && detail.narrative && detail.narrative.description) 
                ? detail.narrative.description 
                : '';
        }
    }
    var badge = topPane.querySelector('#ae-scene-badge'); if (badge) badge.style.display = 'none';

    topPane.style.background = _nameToColor(name);
    topPane.style.backgroundImage = '';
    
    if (isChar) {
        resolveEntityImage(entityId).then(function(url) { if (_focusedEntityId === entityId && url) topPane.style.backgroundImage = 'url(' + JSON.stringify(url) + ')'; });
    }

    var oldC = topPane.querySelector('#ae-focus-controls'); if (oldC) oldC.remove();
    var ctrls = document.createElement('div'); ctrls.id = 'ae-focus-controls';
    ctrls.style.cssText = 'position:absolute;top:12px;right:12px;display:flex;gap:6px;z-index:11;';    // Surgically modified to append SVG nodes instead of relying on textContent
    // Surgically modified to append SVG nodes instead of relying on textContent
    function _fbtn(iconName, title, cb) { 
        var b = document.createElement('button'); 
        b.className = 'ae-settings-btn'; 
        b.style.cssText = 'position:static;left:auto;top:auto;width:32px;height:32px;display:flex;align-items:center;justify-content:center;'; 
        b.title = title; 
        b.appendChild(createCyberIcon(iconName, 18));   // [v2.10.0 SHELL-1] currentColor — .ae-settings-btn sets it
        b.addEventListener('click', cb); 
        return b; 
    }
    
    // [v0.9.7.4] Wrench for edit. Snapshots moved to lower pane.
    if (isChar) {
        ctrls.appendChild(_fbtn('wrench', 'Edit Character', function() { sendToEngine('AE_OPEN_CHAR_EDIT', { charId: entityId }); }));
        ctrls.appendChild(_fbtn('journal', 'Character Journal', function() { openCharJournalModal(entityId, name); }));
    } else {
        ctrls.appendChild(_fbtn('wrench', 'Edit Entity', function() { sendToEngine('AE_OPEN_ENTITY_EDIT', { entityId: entityId }); }));
    }
    topPane.appendChild(ctrls);

    var back = topPane.querySelector('#ae-focus-back');
    if (!back) {
        back = document.createElement('button'); back.id = 'ae-focus-back'; back.className = 'ae-settings-btn';
        back.style.cssText = 'position:absolute;top:12px;left:52px;width:32px;height:32px;z-index:11;display:flex;align-items:center;justify-content:center;'; 
        back.title = 'Back to location'; 
        back.appendChild(createCyberIcon('arrowLeft', 18));   // [v2.10.0 SHELL-1] currentColor
        back.addEventListener('click', function() { _clearFocus(); });
        topPane.appendChild(back);
    }

    var oldS = topPane.querySelector('#ae-focus-snaptext'); if (oldS) oldS.remove();
    var txt = _snapTextCache[entityId];
    if (txt && isChar) {
        var snap = document.createElement('div'); snap.id = 'ae-focus-snaptext';
        var isCol = _snapTextCollapsed[entityId] || false;
        if (isCol) snap.classList.add('collapsed');
        snap.style.cssText = 'position:absolute;top:52px;left:12px;right:12px;max-height:42%;overflow-y:auto;z-index:4;background:var(--ae-overlay-bg);color:var(--ae-text-main);padding:8px 10px;border-radius:var(--ae-radius-sm);font-size:var(--ae-font-size-sm);line-height:1.45;backdrop-filter:blur(2px);box-shadow:0 1px 6px rgba(0,0,0,0.45);cursor:pointer;';
        snap.textContent = txt;
        
        snap.addEventListener('click', function() {
            var col = snap.classList.toggle('collapsed');
            _snapTextCollapsed[entityId] = col;
            if (col) {
                snap.style.maxHeight = '24px';
                snap.style.whiteSpace = 'nowrap';
                snap.style.textOverflow = 'ellipsis';
                snap.style.overflow = 'hidden';
            } else {
                snap.style.maxHeight = '42%';
                snap.style.whiteSpace = 'normal';
                snap.style.textOverflow = 'clip';
                snap.style.overflowY = 'auto';
            }
        });
        
        if (isCol) {
            snap.style.maxHeight = '24px';
            snap.style.whiteSpace = 'nowrap';
            snap.style.textOverflow = 'ellipsis';
            snap.style.overflow = 'hidden';
        }
        
        topPane.appendChild(snap);
    }
}

// =============================================================================
// [PHANTOM-PRIMARY PASS 3] CHARACTER-VIEW SLIDING TRAYS
// One spot to update visuals, profile info, drama/hooks/equipment, snapshots,
// and the image gallery for a focused character — reusing the exact same
// content that already existed (split across the old Gallery overlay and the
// inline focus-view sections below), not reinventing any of it. Conditions
// is the one genuinely new item user asked for; it has no engine concept yet
// (distinct from the old charResources system), so its tray is a labeled stub
// rather than invented UI — flag this to user, don't fake a feature.
// =============================================================================

// [PHANTOM-PRIMARY PASS 5] _getTrayHost / _closeAllCharTrays / _openCharTray /
// _resetCharTrays / _buildCharTrayLauncher (the edge-tab-handle + centered-
// card launcher from Pass 4) are removed — superseded by the persistent nav
// tray + bottom sheet in PhantomManager.spawn() below. The content builders
// underneath this comment (_buildAvatarVisualsSection etc.) are untouched —
// still the Gallery overlay's own code, not part of this rewrite.

// [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] _buildAvatarVisualsSection and
// _buildImageSlotsSection removed -- both were exclusively used by the now-removed
// _renderGalleryProfile (SECTION 21e). [v2.48.0] Their eventual successor, the flat
// dossier Gallery tab's _buildFlatVisualsGalleryTab, is ALSO now removed (see
// EMOSTUDIO-HEADER-MOVE below) -- field and image-slot rendering for a character's
// visuals now lives in _renderEmotionStudioModal only, reached from the plate
// header's Portraits action, not from any dossier tab.
// See CE-INDEX STUDIO-SHELL-TEARDOWN and EMOSTUDIO-HEADER-MOVE entries.

// Hooks, Carried Items (= per-character equipment), and Narrative Threads
// (= drama) originally existed as inline sections in the focus view — extracted
// verbatim into one combined "Drama" tab (now split, see below) so the Drama
// tray and the (now-removed) inline versions were one codepath. Character
// Resources is the OLD system; kept here read-only and labeled as such since
// Conditions is meant to replace it, not sit beside it forever.
// [PHANTOM-PRIMARY PASS 5] Flat rewrite — divider + row markup instead of
// $.section/card/chip components, per "we shouldn't copy stuff into this new
// layout... start from scratch UI-wise." Same data and engine messages as
// before (AE_RESOLVE_HOOK, AE_EQUIP_ITEM/UNEQUIP_ITEM, AE_ADJUST_CHAR_RESOURCE),
// only the DOM changed.
// [CHANGE] Was _buildFlatDramaTab (fed the old "Drama" tab). Renamed to Status —
// that tab is now first in the sheet, and no longer carries Hooks (moved to the
// new, separate Drama tab below) or Narrative Threads (removed per request; that
// data is still in detail.children if a future pass wants it back).
function _buildFlatStatusTab(bodyEl, detail, entityId) {
    var children = detail.children || [];
    var items = children.filter(function(c) { return c.type === 'item'; });
    var chRes = detail.charResources || [];

    var lblItems = document.createElement('div'); lblItems.className = 'ae-divider-lbl'; lblItems.textContent = 'Carried Items / Equipment (' + items.length + ')'; bodyEl.appendChild(lblItems);
    // [FEATURE v2.1.8] Character-scoped item add, moved here from the general
    // Inspect tab's "+ Add Item" (which always dropped the item at the current
    // room, disconnected from any character). detail.entityId is this character's
    // world-graph node id -- passing it as spawnItem's explicitParentId parents
    // the new item directly under THIS character instead of the room (see
    // buildEntityDetailPayload / spawnItem, engine Section 12/19).
    bodyEl.appendChild(_addEntityBtn('item', { entityId: detail.entityId, label: detail.name }));
    if (items.length === 0) {
        bodyEl.appendChild(_flatEmptyRow('No carried items.'));
    } else {
        items.forEach(function(item) {
            var row = document.createElement('div'); row.className = 'ae-drow';
            var t = document.createElement('div'); t.className = 'ae-drow-t'; t.textContent = item.name; row.appendChild(t);
            if (item.description) { var d = document.createElement('div'); d.className = 'ae-drow-d'; d.textContent = item.description; row.appendChild(d); }
            var eqBtn = document.createElement('button'); eqBtn.textContent = item.isEquipped ? 'Unequip' : 'Equip';
            eqBtn.addEventListener('click', function(e) { e.stopPropagation(); sendToEngine(item.isEquipped ? 'AE_UNEQUIP_ITEM' : 'AE_EQUIP_ITEM', { charId: detail.id, itemId: item.id }); });
            row.appendChild(eqBtn);
            bodyEl.appendChild(row);
        });
    }

    // [FEATURE v2.1.8 BRIDGE-CONDITIONS] Was a labeled stub ("new, not built yet")
    // since PHANTOM-PRIMARY PASS 3 -- the engine's Conditions system (ConditionDef/
    // activeConditions, CE-STRIP v2.6.0 PASS 10) shipped after this stub was
    // written and was never wired to the bridge (that pass's own note: "Bridge
    // needs no changes for this to take effect" was true for the lorebook feed,
    // but nothing exposed the data for the bridge to READ). buildEntityDetailPayload
    // now carries conditionDefs (cfg.conditions, the authored definitions) and
    // activeConditions (this character's state) for exactly this. Same semantics
    // as the native Character Edit modal's Conditions section: toggle adds/removes
    // entirely (no "clear to stage 0", unchecking drops it from activeConditions),
    // stage stepper only shown for defs that actually have stages.
    var condDefs = detail.conditionDefs || [];
    var activeConds = detail.activeConditions || [];
    var lblCond = document.createElement('div'); lblCond.className = 'ae-divider-lbl'; lblCond.textContent = 'Conditions (' + activeConds.length + ')'; bodyEl.appendChild(lblCond);
    if (condDefs.length === 0) {
        bodyEl.appendChild(_flatEmptyRow('No conditions defined yet \u2014 add some in World Settings.'));
    } else {
        condDefs.forEach(function(def) {
            var state = activeConds.filter(function(s) { return s.defId === def.id; })[0];
            var isActive = !!state;
            var hasStages = !!(def.stages && def.stages.length);
            var curStage = isActive ? (state.stageIndex || 0) : 0;

            var row = document.createElement('div'); row.className = 'ae-drow';
            var t = document.createElement('div'); t.className = 'ae-drow-t'; t.textContent = def.name; row.appendChild(t);
            if (isActive && hasStages) {
                var d = document.createElement('div'); d.className = 'ae-drow-d';
                d.textContent = 'Stage ' + (curStage + 1) + '/' + def.stages.length + ' \u2014 ' + (def.stages[curStage] || ''); row.appendChild(d);
            }
            var toggleBtn = document.createElement('button'); toggleBtn.textContent = isActive ? 'Remove' : 'Add';
            toggleBtn.addEventListener('click', function(e) { e.stopPropagation(); sendToEngine('AE_CHAR_CONDITION_ACTION', { charId: detail.id, defId: def.id, op: 'toggle' }); });
            row.appendChild(toggleBtn);
            if (isActive && hasStages) {
                var prevBtn = document.createElement('button'); prevBtn.textContent = '\u25c0 Stage'; prevBtn.style.marginRight = '10px'; prevBtn.disabled = curStage === 0;
                prevBtn.addEventListener('click', function(e) { e.stopPropagation(); sendToEngine('AE_CHAR_CONDITION_ACTION', { charId: detail.id, defId: def.id, op: 'setStage', stageIndex: curStage - 1 }); });
                row.appendChild(prevBtn);
                var nextBtn = document.createElement('button'); nextBtn.textContent = 'Stage \u25b6'; nextBtn.disabled = curStage >= def.stages.length - 1;
                nextBtn.addEventListener('click', function(e) { e.stopPropagation(); sendToEngine('AE_CHAR_CONDITION_ACTION', { charId: detail.id, defId: def.id, op: 'setStage', stageIndex: curStage + 1 }); });
                row.appendChild(nextBtn);
            }
            bodyEl.appendChild(row);
        });
    }

    if (chRes.length > 0) {
        var lblRes = document.createElement('div'); lblRes.className = 'ae-divider-lbl'; lblRes.textContent = 'Character Resources \u2014 legacy (' + chRes.length + ')'; bodyEl.appendChild(lblRes);
        chRes.forEach(function(res) {
            var row = document.createElement('div'); row.className = 'ae-drow';
            var t = document.createElement('div'); t.className = 'ae-drow-t'; t.textContent = res.name + ': ' + res.value + (res.max != null ? ' / ' + res.max : ''); row.appendChild(t);
            bodyEl.appendChild(row);
        });
    }
}

// [FEATURE] New Drama tab — hooks (moved here from Status) plus the dynamic
// narrative layer (ephemeral / mid-range / relationship) that previously had no
// bridge-side display at all. Read-only: no generation buttons here on purpose
// (per request) -- the engine's own update generators own that job; this tab is
// a window onto their output, same spirit as Status's read-only Conditions rows.
function _buildFlatDramaDynamicsTab(bodyEl, detail, entityId) {
    var hooks = detail.hooks || [];

    var lblHooks = document.createElement('div'); lblHooks.className = 'ae-divider-lbl'; lblHooks.textContent = 'Active Hooks (' + hooks.length + ')'; bodyEl.appendChild(lblHooks);
    if (hooks.length === 0) {
        bodyEl.appendChild(_flatEmptyRow('No active hooks.'));
    } else {
        hooks.forEach(function(h) {
            var row = document.createElement('div'); row.className = 'ae-drow';
            var targetNameDisp = h.targetName === '__player__' ? 'Player' : (h.targetName || 'Unknown');
            var k = document.createElement('div'); k.className = 'ae-drow-k'; k.textContent = npcPressureLabel(h.pressureLevel) + ' \u00b7 pressure ' + h.pressureLevel; row.appendChild(k);
            var t = document.createElement('div'); t.className = 'ae-drow-t'; t.textContent = detail.name + ' \u21c4 ' + targetNameDisp; row.appendChild(t);
            var d = document.createElement('div'); d.className = 'ae-drow-d'; d.textContent = h.description || ''; row.appendChild(d);
            var resBtn = document.createElement('button'); resBtn.textContent = 'Resolve';
            resBtn.addEventListener('click', function(e) { e.stopPropagation(); sendToEngine('AE_RESOLVE_HOOK', { charId: detail.id, hookId: h.id }); });
            row.appendChild(resBtn);
            bodyEl.appendChild(row);
        });
    }

    // [CROSS-ARTIFACT] ephemeral/midRange/primaryRelationship — new fields on
    // buildEntityDetailPayload (engine Section 12), same catch-up pattern as the
    // v2.15.0 Conditions exposure: these have lived on CharacterRecord for a long
    // time but were never serialized to the bridge until now.
    function _dramaRow(label, value) {
        if (!value) return;
        var row = document.createElement('div'); row.className = 'ae-drow';
        var t = document.createElement('div'); t.className = 'ae-drow-t'; t.textContent = label; row.appendChild(t);
        var d = document.createElement('div'); d.className = 'ae-drow-d'; d.textContent = value; row.appendChild(d);
        bodyEl.appendChild(row);
    }

    var eph = detail.ephemeral;
    var lblEph = document.createElement('div'); lblEph.className = 'ae-divider-lbl'; lblEph.textContent = 'Ephemeral (moment-to-moment)'; bodyEl.appendChild(lblEph);
    if (!eph) {
        bodyEl.appendChild(_flatEmptyRow('No ephemeral state generated yet.'));
    } else {
        _dramaRow('Event', eph.eventAnchor);
        _dramaRow('Emotional response', eph.emotionalResponse);
        _dramaRow('Immediate desire', eph.immediateDesire);
        _dramaRow('Summary', eph.compressedLine);
    }

    var mid = detail.midRange;
    var lblMid = document.createElement('div'); lblMid.className = 'ae-divider-lbl'; lblMid.textContent = 'Mid-range (slower-moving)'; bodyEl.appendChild(lblMid);
    if (!mid) {
        bodyEl.appendChild(_flatEmptyRow('No mid-range state generated yet.'));
    } else {
        _dramaRow('Current desire', mid.currentDesire);
        _dramaRow('Social mask', mid.socialMask);
        _dramaRow('Shifted view', mid.shiftedView);
        _dramaRow('Baseline view', mid.baselineView);
    }

    var rel = detail.primaryRelationship;
    var lblRel = document.createElement('div'); lblRel.className = 'ae-divider-lbl'; lblRel.textContent = 'Relationship'; bodyEl.appendChild(lblRel);
    if (!rel || rel.enabled === false || !rel.targetName) {
        bodyEl.appendChild(_flatEmptyRow('No primary relationship set.'));
    } else {
        _dramaRow(rel.targetName + ' \u2014 ' + (rel.archetype || 'Unspecified'), rel.summary);
        _dramaRow('Current status', rel.currentStatus);
        _dramaRow('Trajectory', rel.trajectory);
        _dramaRow('How it started', rel.howItStarted);
    }
}

function _flatEmptyRow(text) {
    var row = document.createElement('div'); row.className = 'ae-fg';
    var hint = document.createElement('div'); hint.className = 'ae-hint'; hint.textContent = text;
    row.appendChild(hint); return row;
}

function _buildFlatSnapshotsTab(bodyEl, entityId) {
    var snapCachedText = _snapTextCache[entityId] || null;
    var lbl = document.createElement('div'); lbl.className = 'ae-divider-lbl'; lbl.textContent = 'Snapshots'; bodyEl.appendChild(lbl);
    var actRow = document.createElement('div'); actRow.className = 'ae-drow';
    var txtBtn = document.createElement('button'); txtBtn.textContent = 'Text snapshot'; txtBtn.style.marginRight = '18px';
    txtBtn.addEventListener('click', function() { sendToEngine('AE_GEN_SNAPSHOT_TEXT', { charId: entityId }); _showToast('Generating text snapshot\u2026'); });
    var imgBtn = document.createElement('button'); imgBtn.textContent = 'Image snapshot';
    imgBtn.addEventListener('click', function() { sendToEngine('AE_GEN_SNAPSHOT_IMAGE', { charId: entityId }); _showToast('Generating image snapshot\u2026'); });
    actRow.appendChild(txtBtn); actRow.appendChild(imgBtn); bodyEl.appendChild(actRow);
    if (snapCachedText) {
        var textRow = document.createElement('div'); textRow.className = 'ae-fg';
        var p = document.createElement('div'); p.style.cssText = 'font-size:11.5px;color:var(--ae-text-muted);line-height:1.55;white-space:pre-wrap;'; p.textContent = snapCachedText;
        textRow.appendChild(p); bodyEl.appendChild(textRow);
    } else {
        bodyEl.appendChild(_flatEmptyRow('No text snapshot yet.'));
    }
}

// [PHANTOM-PRIMARY PASS 5] Sheet mechanism — content-fit height (not a fixed
// peek/full stop), freely draggable via the handle, scrolls past its cap.
// Adapted directly from the validated mockup.
// [BUGFIX v2.0.3] Rest/closed state is this, not literal 0 -- must match the
// .ae-sheet CSS rule's default height (grep it). A true 0px rest state
// clipped .ae-sheet-handle along with everything else (overflow:hidden lives
// on that same element), leaving a closed sheet with no visible way back open.
// [v2.18.0 SHELL-2 ROTATE] The sliding-sheet machinery is gone — the dossier is an
// in-flow grid now (see .ae-phantom-body.ae-dossier / _buildPhantomPlate). Removed:
// PHANTOM_SHEET_PEEK_PX, _phantomSheetMaxHeight, _openPhantomSheet,
// _openPhantomSheetInstant, _closePhantomSheet, _wirePhantomSheetDrag. Only the
// field-focus helper survives, neutered: with no sheet height to expand, focusing a
// field just scrolls it into view (its 5 call sites in the flat tabs keep working).
function _phantomFieldFocusExpand(fieldEl) {
    setTimeout(function() { try { fieldEl.scrollIntoView({ block: 'center', behavior: 'smooth' }); } catch (e) {} }, 80);
}

// [DEAD, v2.48.0 EMOSTUDIO-HEADER-MOVE] _buildFlatVisualsGalleryTab removed --
// zero remaining callers after the Gallery tab was deleted (see the actions[]
// comment on the plate header above). Per user: "no reason to keep the fields
// there instead of the popup." Its base fields (visuals/uc/avatarVisuals/size/
// seed) moved verbatim into _renderEmotionStudioModal below, which is now the
// single owner of both the base fields and the slot list -- previously split
// across this tab and the modal, which was the whole "too much info, no reason
// to keep it split" complaint. The old preview thumbnail + "Manage Emotion
// Portraits" + "Presets & Gallery" launch buttons are superseded by the plate
// header's Portraits/Gallery actions. See CE-INDEX EMOSTUDIO-HEADER-MOVE entry.

// =============================================================================
// [v2.47.0 EMOSTUDIO-24DEFAULT] EMOTION PORTRAIT STUDIO — dedicated modal
// Everything that used to render inline in the flat Visuals+Gallery tab's slot
// list now lives here instead: same per-slot behavior (thumbnail, tag textarea,
// Generate/Edit/Upload/Delete, +Add slot), unchanged, just relocated. Shell reuses
// .ae-jrnl-overlay/.ae-jrnl-modal/.ae-jrnl-head/.ae-jrnl-surface -- the existing
// per-theme overrides on those classes (cyberpunk/runestone/unicornbarf/witchhollow)
// apply here for free, zero new CSS needed for the shell.
// =============================================================================

// [v2.48.0 EMOSTUDIO-QUEUE] Per-character serial generation queue. Explicitly NOT a
// "Generate All" batch orchestrator -- per user, that wasn't wanted. This exists only
// to catch a second slot's Generate click landing before the first slot's call
// returns, so it queues rather than firing two concurrent NAI generation requests
// (which would race on save order and likely trip a rate limit). rows is rebuilt by
// every _renderEmotionStudioModal call, so a closed-and-reopened modal still finds
// live DOM for whatever is still active/queued from before it closed -- but note the
// generation in flight keeps using the `draft` object captured when IT started, not
// a draft from a modal reopened after it was queued; base-field edits made after a
// reopen only affect generations requested after that reopen. Not solved -- reopening
// mid-queue is a rare enough case that solving it wasn't worth the added state.
var _emoGenQ = {};   // charId -> { active: emoName|null, queue: string[], rows: {} }
function _emoGenState(charId) {
    if (!_emoGenQ[charId]) _emoGenQ[charId] = { active: null, queue: [], rows: {} };
    return _emoGenQ[charId];
}

// Paints one row's thumbnail + button + status label to match current queue state.
// No-ops safely if the row isn't in the currently-open modal (rows{} only holds the
// live modal's DOM; a slot generating with its modal closed just has nothing to paint
// until reopened, at which point renderSlot re-registers it and calls this itself).
function _emoGenPaintRow(charId, emoName) {
    var st = _emoGenState(charId);
    var r = st.rows[emoName];
    if (!r) return;
    var isActive = st.active === emoName;
    var isQueued = st.queue.indexOf(emoName) !== -1;
    r.thumb.classList.toggle('ae-slot-busy', isActive);
    r.thumb.classList.toggle('ae-slot-queued', isQueued);
    r.genBtn.disabled = isActive || isQueued;
    r.genBtn.textContent = isActive ? 'Generating\u2026' : (isQueued ? 'Queued' : 'Generate');
    r.statusEl.textContent = isActive ? 'generating\u2026' : (isQueued ? 'queued' : '');
}

function _emoGenRequest(charId, emoName, draft, pKey, entityId) {
    var st = _emoGenState(charId);
    if (st.active === emoName || st.queue.indexOf(emoName) !== -1) return;   // already pending
    if (st.active === null) {
        st.active = emoName;
        _emoGenPaintRow(charId, emoName);
        _emoGenRun(charId, emoName, draft, pKey, entityId);
    } else {
        st.queue.push(emoName);
        _emoGenPaintRow(charId, emoName);
    }
}

async function _emoGenRun(charId, emoName, draft, pKey, entityId) {
    var st = _emoGenState(charId);
    // Tags read live off the row's textarea at RUN time (not passed in at request
    // time), so an edit made while a slot sits queued is what actually generates.
    var r0 = st.rows[emoName];
    var tags = (r0 && r0.taRef) ? r0.taRef.value : (_getEmoTags(entityId)[emoName] || '');
    try {
        var gr = await _generateAvatarImage(draft, tags || '');
        await _savePortrait(pKey, gr.dataUrl, 'gen', { fp: gr.fp, fu: gr.fu, chars: gr.characters || [], settings: gr.settings });
        imgCache.set(pKey, { dataUrl: gr.dataUrl, fp: gr.fp, fu: gr.fu, prompt: gr.fp, characters: gr.characters || [], settings: gr.settings });
        var r1 = st.rows[emoName];   // re-fetch: the modal may have closed/reopened while this ran
        if (r1) {
            r1.img.src = gr.dataUrl; r1.img.style.display = 'block';
            var ph = r1.thumb.querySelector('.ae-slot-placeholder'); if (ph) ph.style.display = 'none';
        }
        _showToast(emoName + ' saved');
    } catch (e) {
        console.error('[AE] slot gen failed:', e);
        _showToast(emoName + ' generation failed');
    } finally {
        st.active = null;
        _emoGenPaintRow(charId, emoName);
        if (st.queue.length) {
            var next = st.queue.shift();
            st.active = next;
            _emoGenPaintRow(charId, next);
            _emoGenRun(charId, next, draft, charId + '_em_' + next, entityId);
        }
    }
}

function _closeEmotionStudioModal() {
    var ov = document.getElementById('ae-emostudio-overlay');
    if (ov) ov.remove();
}

function openEmotionStudioModal(vis, entityId) {
    if (document.getElementById('ae-emostudio-overlay')) return;   // already open

    var overlay = document.createElement('div');
    overlay.id = 'ae-emostudio-overlay';
    overlay.className = 'ae-jrnl-overlay';

    var modal = document.createElement('div');
    modal.id = 'ae-emostudio-modal';
    modal.className = 'ae-jrnl-modal ae-emostudio-modal';

    var head = document.createElement('div'); head.className = 'ae-jrnl-head';
    var title = document.createElement('div'); title.className = 'ae-jrnl-title';
    title.textContent = (vis.name || 'Character') + ' \u2014 Emotion Portraits';
    head.appendChild(title);
    var closeBtn = $.btn('\u2715', 'ghost sm icon', function() { _closeEmotionStudioModal(); });
    closeBtn.title = 'Close';
    head.appendChild(closeBtn);
    modal.appendChild(head);

    var surface = document.createElement('div'); surface.id = 'ae-emostudio-surface'; surface.className = 'ae-jrnl-surface';
    modal.appendChild(surface);

    overlay.appendChild(modal);
    overlay.addEventListener('click', function(e) { if (e.target === overlay) _closeEmotionStudioModal(); });
    document.body.appendChild(overlay);

    _renderEmotionStudioModal(surface, vis, entityId);
}

function _renderEmotionStudioModal(surface, vis, entityId) {
    surface.innerHTML = '';

    // [v2.48.0 EMOSTUDIO-HEADER-MOVE] draft is now the SINGLE writer for base
    // character-level fields -- the old split (flat tab owned the draft, this modal
    // only read vis.* for generation) is gone along with the flat tab itself. Every
    // slot's Generate call reads this same live object, so an edit made while a
    // generation is queued is picked up when that generation actually runs, not
    // frozen at click time.
    var draft = { visuals: vis.visuals || '', uc: vis.uc || '', avatarVisuals: vis.avatarVisuals || '', avatarWidth: vis.avatarWidth || 832, avatarHeight: vis.avatarHeight || 1216, avatarSeed: vis.avatarSeed || 0 };
    function saveDraft() { sendToEngine('AE_SAVE_CHAR_VISUALS', { charId: vis.id, visuals: draft.visuals, uc: draft.uc, avatarVisuals: draft.avatarVisuals, avatarWidth: draft.avatarWidth, avatarHeight: draft.avatarHeight, avatarSeed: draft.avatarSeed }); }

    // [v2.48.0] Quick-jump row, per user: "the modal start with a button to image gen
    // settings and gallery" -- lets someone tweak a global preset or browse everything
    // ever generated without backing out of the Studio first. Reuses the existing
    // Image Generation modal's two tabs (openImageGenModal({tab:'presets'|'gallery'})),
    // no new modal.
    var jumpRow = document.createElement('div'); jumpRow.style.cssText = 'display:flex;gap:8px;padding:12px 18px;border-bottom:1px solid var(--ae-bg-border);';
    var presetsBtn = $.btn('\u2699 Image Gen Settings', 'ghost sm', function() { openImageGenModal({ tab: 'presets', entityId: entityId }); });
    var galleryBtn = $.btn('\uD83D\uDDBC Gallery', 'ghost sm', function() { openImageGenModal({ tab: 'gallery', entityId: entityId }); });
    jumpRow.appendChild(presetsBtn); jumpRow.appendChild(galleryBtn);
    surface.appendChild(jumpRow);

    function draftField(label, key, ph, rows) {
        var fg = document.createElement('div'); fg.className = 'ae-fg';
        var l = document.createElement('label'); l.textContent = label; fg.appendChild(l);
        var ta = document.createElement('textarea'); ta.rows = rows || 2; ta.placeholder = ph || ''; ta.value = draft[key] || '';
        var grow = function() { ta.style.height = 'auto'; ta.style.height = ta.scrollHeight + 'px'; };
        ta.addEventListener('input', function() { draft[key] = ta.value; grow(); });
        ta.addEventListener('focus', function() { fg.classList.add('editing'); });
        ta.addEventListener('blur', function() { fg.classList.remove('editing'); saveDraft(); });
        fg.appendChild(ta); surface.appendChild(fg);
        setTimeout(grow, 0);
    }

    var lblBase = document.createElement('div'); lblBase.className = 'ae-divider-lbl'; lblBase.textContent = 'Base fields'; surface.appendChild(lblBase);
    draftField('Base visuals', 'visuals', 'Core visual description for all generation types\u2026', 2);
    draftField('Unwanted content', 'uc', 'UC applied to every generation\u2026', 1);
    draftField('Avatar-only tags', 'avatarVisuals', 'Face focus, close-up, solo\u2026', 1);

    var SIZES = [{ l: 'Portrait', w: 832, h: 1216 }, { l: 'Square', w: 1024, h: 1024 }, { l: 'Landscape', w: 1216, h: 832 }];
    var sizeRow = document.createElement('div'); sizeRow.className = 'ae-size-pick';
    SIZES.forEach(function(sz) {
        var b = document.createElement('button'); b.textContent = sz.l;
        if (draft.avatarWidth === sz.w && draft.avatarHeight === sz.h) b.classList.add('active');
        b.addEventListener('click', function() {
            draft.avatarWidth = sz.w; draft.avatarHeight = sz.h;
            sizeRow.querySelectorAll('button').forEach(function(x) { x.classList.remove('active'); }); b.classList.add('active');
            saveDraft();
        });
        sizeRow.appendChild(b);
    });
    surface.appendChild(sizeRow);
    // Every emotion portrait inherits this size/shape choice -- per user, slots do not
    // carry their own independent aspect. This is the one place it's set.

    var seedFg = document.createElement('div'); seedFg.className = 'ae-fg';
    var seedL = document.createElement('label'); seedL.textContent = 'Seed'; seedFg.appendChild(seedL);
    var seedIn = document.createElement('input'); seedIn.type = 'number'; seedIn.min = '0'; seedIn.placeholder = '0';
    seedIn.value = draft.avatarSeed ? String(draft.avatarSeed) : '';
    seedIn.addEventListener('input', function() {
        var n = parseInt(seedIn.value, 10);
        draft.avatarSeed = (isFinite(n) && n > 0) ? n : 0;
    });
    seedIn.addEventListener('blur', saveDraft);
    seedFg.appendChild(seedIn);
    var seedHint = document.createElement('div'); seedHint.className = 'ae-hint';
    seedHint.textContent = 'Locking a seed keeps this character\u2019s face consistent across every emotion portrait. Leave blank (0) for a fresh random look each generation.';
    seedFg.appendChild(seedHint);
    surface.appendChild(seedFg);

    var emoSlots = _getEmoSlots(vis.id);
    var emoTags = _getEmoTags(entityId);

    var lblSlots = document.createElement('div'); lblSlots.className = 'ae-divider-lbl';
    lblSlots.textContent = 'Image slots (' + emoSlots.length + ')';
    surface.appendChild(lblSlots);

    // [v2.48.0 EMOSTUDIO-QUEUE] Per-character generation state lives in the module-
    // level _emoGenQ map, not here -- rows{} is repopulated below on every render so
    // reopening the modal mid-generation still finds live DOM for whatever's active/
    // queued. See _emoGenState's doc comment for why this is a serial queue and
    // deliberately NOT a "Generate All" batch orchestrator.
    var qState = _emoGenState(vis.id);
    qState.rows = {};

    function renderSlot(emoName) {
        var pKey = vis.id + '_em_' + emoName;
        var isAvatar = (emoName === AVATAR_SLOT_NAME);
        var row = document.createElement('div'); row.className = 'ae-slot-flat';
        var thumb = document.createElement('div'); thumb.className = 'ae-slot-thumb';
        var placeholderIcon = $.icon('image', 22); placeholderIcon.classList.add('ae-slot-placeholder');
        thumb.appendChild(placeholderIcon);
        var img = document.createElement('img'); img.style.display = 'none'; thumb.appendChild(img);
        // [v2.48.0] Spinner overlay for the busy state -- reuses the existing regen
        // icon + cyber-pulse infrastructure rather than hand-drawing a new glyph.
        var spin = document.createElement('div'); spin.className = 'ae-slot-spin'; spin.appendChild(createCyberIcon('regen', 20));
        thumb.appendChild(spin);
        (isAvatar ? _loadCharAvatarImage(vis.id) : _loadPortrait(pKey)).then(function(url) { if (url) { img.src = url; img.style.display = 'block'; thumb.querySelector('.ae-slot-placeholder').style.display = 'none'; } });
        thumb.addEventListener('click', function() { if (img.src && img.style.display !== 'none') _galleryLightbox(img.src, vis.name + ' \u2014 ' + emoName); });
        row.appendChild(thumb);

        var body = document.createElement('div'); body.className = 'ae-slot-body';
        var row1 = document.createElement('div'); row1.className = 'ae-slot-row1';
        var nm = document.createElement('b'); nm.textContent = emoName; row1.appendChild(nm);
        var statusEl = document.createElement('span'); statusEl.className = 'ae-slot-status'; row1.appendChild(statusEl);
        body.appendChild(row1);
        var ta = document.createElement('textarea'); ta.rows = 1; ta.placeholder = 'Tags\u2026';
        ta.value = emoTags[emoName] !== undefined ? emoTags[emoName] : (_AE_EMOTION_TAGS[emoName] || '');
        var grow = function() { ta.style.height = 'auto'; ta.style.height = ta.scrollHeight + 'px'; };
        ta.addEventListener('input', function() { emoTags[emoName] = ta.value; _setEmoTags(entityId, emoTags); grow(); });
        body.appendChild(ta); setTimeout(grow, 0);

        var acts = document.createElement('div'); acts.className = 'ae-slot-acts';
        var genBtn = document.createElement('button'); genBtn.textContent = 'Generate';
        genBtn.addEventListener('click', function() { _emoGenRequest(vis.id, emoName, draft, pKey, entityId); });
        var editBtn = document.createElement('button'); editBtn.textContent = 'Edit';
        editBtn.addEventListener('click', async function() {
            var entry = imgCache.get(pKey);
            if (!entry) { var rec = await _loadPortraitRec(pKey); if (rec && rec.meta) { entry = { dataUrl: rec.dataUrl, fp: rec.meta.fp || '', fu: rec.meta.fu || '', prompt: rec.meta.fp || '', characters: rec.meta.chars || [], settings: rec.meta.settings }; imgCache.set(pKey, entry); } }
            if (!entry || !entry.settings) { _showToast('No editable prompt (uploaded or legacy image).'); return; }
            openPromptEditor(pKey);
        });
        var upBtn = document.createElement('button'); upBtn.textContent = 'Upload';
        upBtn.addEventListener('click', function() {
            var fi = document.createElement('input'); fi.type = 'file'; fi.accept = 'image/*';
            fi.onchange = async function() {
                if (!fi.files || !fi.files[0]) return;
                var fr = new FileReader();
                fr.onload = async function(ev) { try { var u = ev.target.result; await _savePortrait(pKey, u, 'upload', null); img.src = u; img.style.display = 'block'; thumb.querySelector('.ae-slot-placeholder').style.display = 'none'; _showToast('Uploaded'); } catch (e) { console.error(e); } };
                fr.readAsDataURL(fi.files[0]);
            };
            fi.click();
        });
        // [FEATURE v2.3.0 AVATAR-SLOT] Avatar is permanent -- no Delete button.
        var delBtn = isAvatar ? null : document.createElement('button');
        if (delBtn) {
            delBtn.textContent = 'Delete';
            delBtn.addEventListener('click', async function() {
                if (!confirm('Delete the "' + emoName + '" slot and its image?')) return;
                await _deletePortrait(pKey);
                var nl = _getEmoSlots(vis.id).filter(function(s) { return s !== emoName; }); _setEmoSlots(vis.id, nl);
                delete qState.rows[emoName];
                row.remove();
                lblSlots.textContent = 'Image slots (' + nl.length + ')';
            });
        }
        acts.appendChild(genBtn); acts.appendChild(editBtn); acts.appendChild(upBtn); if (delBtn) acts.appendChild(delBtn);
        body.appendChild(acts);
        row.appendChild(body);
        surface.appendChild(row);

        qState.rows[emoName] = { thumb: thumb, img: img, genBtn: genBtn, statusEl: statusEl, taRef: ta };
        // A reopened modal can land mid-generation for a slot queued/started before it
        // was last closed -- paint that state immediately instead of showing idle.
        _emoGenPaintRow(vis.id, emoName);
    }
    emoSlots.forEach(renderSlot);

    var addRow = document.createElement('div'); addRow.className = 'ae-fg';
    var addBtn = document.createElement('button'); addBtn.textContent = '+ Add slot';
    addBtn.style.cssText = 'background:none;border:none;color:var(--ae-accent);font-size:11px;cursor:pointer;';
    addBtn.addEventListener('click', function() {
        var nm = (prompt('New image slot name (e.g. Combat, Formal, Injured):') || '').trim();
        if (!nm) return;
        var cur = _getEmoSlots(vis.id);
        if (cur.indexOf(nm) !== -1) { _showToast('Slot already exists'); return; }
        cur.push(nm); _setEmoSlots(vis.id, cur); renderSlot(nm);
        lblSlots.textContent = 'Image slots (' + cur.length + ')';
    });
    addRow.appendChild(addBtn); surface.appendChild(addRow);
}

// [v2.53.0 SLOT-PICK] Ask the engine for N candidate values for one field. Writes
// nothing on its own -- the answer lands in the AE_SLOT_OPTIONS handler, and picking a
// candidate saves through AE_SAVE_CHAR_FIELD like any other edit, so this surface keeps
// exactly one write path.
function _requestSlotOptions(bareKey, displayKey, label, btnEl) {
    if (!_profileOpenCharId || _slotOptBusy[displayKey]) return;
    _slotOptBusy[displayKey] = true;
    _slotOptPending[bareKey] = { displayKey: displayKey, label: label };
    if (btnEl) { btnEl.disabled = true; btnEl.textContent = 'Generating\u2026'; }
    // [v2.54.0 SLOT-GUIDE] Whatever is already typed in the field steers the candidates.
    // Read LIVE at request time rather than captured, so an edit made between opening the
    // profile and pressing the button counts. Note the consequence: after picking a
    // candidate the field holds that text, so a following "More" is steered by the pick --
    // which reads as "more like this" and is the intended behaviour, not a leak.
    var guideEl = _profileFieldEls[displayKey];
    var guide = guideEl ? String(guideEl.value || '').trim() : '';
    sendToEngine('AE_GEN_SLOT_OPTIONS', {
        charId: _profileOpenCharId, fieldKey: bareKey, count: 3,
        hint: guide, includeStory: !!_slotOptUseStory
    });
}

// [v2.55.0 GEN-BUDGET] One line describing the current allowance, or null when there is
// nothing worth saying. Deliberately plain about the mechanism: output tokens replenish
// only while the user keeps interacting with the script, so "advance the story" is real
// advice rather than filler -- waiting alone may never replenish anything.
function _budgetLine(bud, failed) {
    if (!bud || typeof bud.out !== 'number' || bud.out < 0) return null;
    var el = document.createElement('div');
    el.className = 'ae-budline' + (failed ? ' warn' : '');
    if (failed) {
        var wait = (typeof bud.waitSec === 'number' && bud.waitSec > 0)
            ? (' Roughly ' + (bud.waitSec >= 60 ? Math.ceil(bud.waitSec / 60) + ' min' : bud.waitSec + 's') + ' at the earliest.')
            : '';
        el.textContent = 'Generation budget is short: ' + bud.out + ' output tokens left, this needs about '
            + (bud.need || 0) + '.' + wait + ' Budget refills as you use the story, so advance a turn and try again.';
    } else {
        el.textContent = 'Generation budget: ' + bud.out + ' output tokens left as of this reply.';
    }
    return el;
}

// [v2.53.0 SLOT-PICK] Draw candidates under their field. Re-rendering replaces any
// previous list for that field rather than stacking, so repeated "More" presses can
// never accumulate stale sets.
function _renderSlotOptions(displayKey, label, options) {
    var input = _profileFieldEls[displayKey];
    var fg = input && input.parentNode;
    if (!fg) return;

    var old = fg.querySelector('.ae-optlist');
    if (old) old.parentNode.removeChild(old);

    var list = document.createElement('div'); list.className = 'ae-optlist';
    options.forEach(function(txt) {
        var b = document.createElement('button');
        b.type = 'button'; b.className = 'ae-opt'; b.textContent = txt;
        b.addEventListener('click', function() {
            input.value = txt;
            if (input.tagName === 'TEXTAREA') { input.style.height = 'auto'; input.style.height = input.scrollHeight + 'px'; }
            sendToEngine('AE_SAVE_CHAR_FIELD', { charId: _profileOpenCharId, fieldKey: displayKey, value: txt });
            if (list.parentNode) list.parentNode.removeChild(list);
            _showToast('Applied to ' + label + '.');
        });
        list.appendChild(b);
    });

    var foot = document.createElement('div'); foot.className = 'ae-optfoot';
    var more = document.createElement('button'); more.type = 'button'; more.textContent = 'More';
    more.addEventListener('click', function() {
        more.disabled = true; more.textContent = 'Generating\u2026';
        var bare = displayKey.replace(/^custom\./, '');
        _requestSlotOptions(bare, displayKey, label, null);
    });
    var close = document.createElement('button'); close.type = 'button'; close.textContent = 'Close';
    close.addEventListener('click', function() { if (list.parentNode) list.parentNode.removeChild(list); });
    var story = document.createElement('button'); story.type = 'button';
    story.textContent = 'Story context: ' + (_slotOptUseStory ? 'on' : 'off');
    story.addEventListener('click', function() {
        _slotOptUseStory = !_slotOptUseStory;
        story.textContent = 'Story context: ' + (_slotOptUseStory ? 'on' : 'off');
    });
    foot.appendChild(more); foot.appendChild(close); foot.appendChild(story); list.appendChild(foot);
    var budEl = _budgetLine(_lastGenBudget, false);
    if (budEl) list.appendChild(budEl);
    fg.appendChild(list);
}

// [v2.55.0 GEN-BUDGET] Park an explanation under the field a refused request came from,
// so the reason survives the toast. Replaces any previous readout rather than stacking.
function _showSlotOptFailure(displayKey, bud) {
    var input = _profileFieldEls[displayKey];
    var fg = input && input.parentNode;
    if (!fg) return;
    var old = fg.querySelector('.ae-budline');
    if (old) old.parentNode.removeChild(old);
    var el = _budgetLine(bud, true);
    if (el) fg.appendChild(el);
}

// [v2.53.0 SLOT-PICK] Restore a field's option button after a request settles, whether
// it succeeded or not. Looked up by walking the field group rather than being cached:
// the profile tab re-renders on other events, so a cached button reference can outlive
// the element it pointed at.
function _clearSlotOptBusy(displayKey) {
    delete _slotOptBusy[displayKey];
    var input = _profileFieldEls[displayKey];
    var fg = input && input.parentNode;
    var btn = fg && fg.querySelector('.ae-optbtn');
    if (btn) { btn.disabled = false; btn.textContent = '3 options'; }
}

// [PHANTOM-PRIMARY PASS 5] Flat Profile tab. Reads the same _charProfileCache
// / AE_FETCH_CHAR_PROFILE / AE_SAVE_CHAR_FIELD as the full profile sheet
// (_renderCharSheetSections in Section 21e) — same data, new flat DOM.
// Scoped to Identity + Narrative + Custom fields for this pass; regen
// buttons, the Four Fs grid, Relationships, and Engine Behavior flags still
// only exist in the full sheet (reachable via the Gallery overlay) — not
// reproduced here yet, flagged rather than rushed.
function _buildFlatProfileTab(bodyEl, entityId) {
    var p = _charProfileCache[entityId];
    if (!p) { bodyEl.appendChild(_flatEmptyRow('Loading character sheet\u2026')); return; }

    function flatField(label, key, value, rows, optKey) {
        var fg = document.createElement('div'); fg.className = 'ae-fg';
        var l = document.createElement('label'); l.textContent = label;
        if (optKey) {
            // [v2.53.0 SLOT-PICK] Only fields carrying generation instructions get a
            // picker -- the four narrative statics and any slot/facet def. Identity
            // fields have no instructions behind them, so an option button there would
            // fire a request the engine correctly refuses.
            var head = document.createElement('div'); head.className = 'ae-fg-head';
            var ob = document.createElement('button'); ob.className = 'ae-optbtn';
            ob.type = 'button'; ob.textContent = '3 options';
            ob.addEventListener('click', function() { _requestSlotOptions(optKey, key, label, ob); });
            head.appendChild(l); head.appendChild(ob); fg.appendChild(head);
        } else {
            fg.appendChild(l);
        }
        var el = rows ? document.createElement('textarea') : document.createElement('input');
        if (rows) el.rows = rows; else el.type = 'text';
        el.value = value || '';
        var grow = rows ? function() { el.style.height = 'auto'; el.style.height = el.scrollHeight + 'px'; } : function() {};
        el.addEventListener('input', grow);
        el.addEventListener('focus', function() { fg.classList.add('editing'); _phantomFieldFocusExpand(fg); });
        el.addEventListener('blur', function() { fg.classList.remove('editing'); if (_profileOpenCharId) sendToEngine('AE_SAVE_CHAR_FIELD', { charId: _profileOpenCharId, fieldKey: key, value: el.value }); });
        _profileFieldEls[key] = el;
        fg.appendChild(el); bodyEl.appendChild(fg);
        if (rows) setTimeout(grow, 0);
    }

    var lblId = document.createElement('div'); lblId.className = 'ae-divider-lbl'; lblId.textContent = 'Identity'; bodyEl.appendChild(lblId);
    flatField('Name', 'name', p.name);
    flatField('Species', 'species', p.species);
    flatField('Age', 'age', p.age);
    flatField('Role', 'occupationRole', p.occupationRole);
    flatField('Brief (one-glance identity)', 'briefDescription', p.briefDescription, 2);

    var lblStatic = document.createElement('div'); lblStatic.className = 'ae-divider-lbl'; lblStatic.textContent = 'Static fields'; bodyEl.appendChild(lblStatic);
    flatField('Physical description', 'physicalDescription', p.physicalDescription, 3, 'physicalDescription');
    flatField('Personality core', 'personalityCore', p.personalityCore, 3, 'personalityCore');
    flatField('Voice & mannerisms', 'voiceAndMannerisms', p.voiceAndMannerisms, 2, 'voiceAndMannerisms');
    flatField('Background', 'background', p.background, 3, 'background');

    if (p.customFields && p.customFields.length) {
        var lblDyn = document.createElement('div'); lblDyn.className = 'ae-divider-lbl'; lblDyn.textContent = 'Dynamic fields'; bodyEl.appendChild(lblDyn);
        // cf.key is 'custom.<id>' for saving; cf.id is what the engine's
        // customStaticFields lookup expects. Both are needed -- see _slotOptPending.
        p.customFields.forEach(function(cf) { flatField(cf.label, cf.key, cf.value, 2, cf.id || String(cf.key || '').replace(/^custom\./, '')); });
    }
}

// [PHANTOM-PRIMARY PASS 5] Builds the whole Inspect-focused view into `body`:
// the natural-aspect background <img> (resolveEntityImage — same portrait/
// snapshot resolution the docked banner always used) plus the sheet with its
// three tabs. Does NOT trigger the entity-detail fetch itself — _focusEntity
// (called when a roster avatar is tapped) already does that; this only
// renders whatever's currently in _focusedEntityDetail / _charProfileCache,
// showing a loading state until the response arrives and calls
// _refreshPhantomInspectFocus() below.
// [v2.18.0 SHELL-2 ROTATE] AE_NO_PORTRAIT_SRC removed — its only consumer was
// _appendPhantomImage; the plate shows a text .ae-plate-none placeholder when a
// character has no portrait, so the silhouette data-URI is no longer referenced.

// [v2.18.0 SHELL-2 ROTATE] _appendPhantomImage + AE_PHANTOM_IMG_MIN_RATIO removed:
// the plate's .ae-plate-portrait (fixed 2:3, object-fit:cover) replaces the old
// natural-aspect image + measured buffer. Portrait building lives in _buildPhantomPlate.

// [v2.18.0 SHELL-2 ROTATE] Shared sticky portrait plate for the rotated dossier.
// Builds the left grid column: portrait (2:3, object-fit:cover, or a "no portrait
// yet" placeholder), a back-to-roster chevron, name + subtitle, and an optional
// row of entity actions. Returns the element plus live refs the caller updates as
// async detail lands (nameEl/subEl) and the <img> that spawn() watches to reveal.
function _buildPhantomPlate(entityId, name, opts) {
    opts = opts || {};
    var plate = document.createElement('div'); plate.className = 'ae-plate';

    var frame = document.createElement('div'); frame.className = 'ae-plate-portrait';
    var img = document.createElement('img'); img.className = 'ae-phantom-img'; img.alt = name || '';
    img.style.display = 'none';
    var none = document.createElement('div'); none.className = 'ae-plate-none';
    none.innerHTML = 'No portrait yet<br>\u2014 generate one \u2014';
    frame.appendChild(img); frame.appendChild(none);
    plate.appendChild(frame);
    // A real portrait reveals the <img> and hides the placeholder; no portrait
    // leaves the placeholder up. spawn() still gets its load/error reveal because
    // src is only assigned when there IS one (spawn's setTimeout covers the empty
    // case), and every resolver here returns base64/blob data, never a bare URL.
    // [v2.20.0 SCENE-BG-REHOME] opts.resolveImage lets a non-character caller (so far:
    // _buildPhantomLocationFocused) supply its own resolver instead of the character-
    // only default -- see resolveEntityImage's own doc comment for why they don't share one.
    var resolveImg = opts.resolveImage || resolveEntityImage;
    resolveImg(entityId).then(function(url) {
        if (_focusedEntityId !== entityId) return;
        if (url) { img.src = url; img.style.display = 'block'; none.style.display = 'none'; }
    }).catch(function(){});

    var head = document.createElement('div'); head.className = 'ae-plate-head';
    // [BUGFIX v2.32.2 FORGE-BUTTON-AUDIT, per user: "buttons in the dossier that are not
    // in the theme forge... theme special buttons should be used and appropriately sized"]
    // Was a bespoke <button class="ae-plate-back"> with background:none/border:none and
    // its own hardcoded 22x22 box -- none of that reads --ae-btn-*, so a Forge Buttons
    // edit did nothing to it. $.btn(..., 'ghost sm icon', ...) is the SAME class combo
    // already used elsewhere in this file (grep "danger sm icon" in the journal action
    // row) for a themeable icon-only button; .ae-btn.icon's 32px circle is this app's
    // standard icon-button footprint (every other icon button uses it), so this also
    // makes the back button's size consistent rather than a one-off. Note for Bruce: this
    // does change the visible footprint from 22px to the standard 32px -- flagging in
    // case that reads too large for this particular header and you want a dedicated
    // smaller variant instead.
    var back = $.btn('', 'ghost sm icon', function(e) { e.stopPropagation(); _clearFocus(); });
    back.title = opts.backTitle || 'Back'; back.appendChild(createCyberIcon('arrowLeft', 15, 'currentColor'));
    head.appendChild(back);
    var idBox = document.createElement('div'); idBox.className = 'ae-plate-id';
    var nameEl = document.createElement('div'); nameEl.className = 'ae-plate-name';
    nameEl.textContent = name || 'Loading\u2026'; idBox.appendChild(nameEl);
    var subEl = document.createElement('div'); subEl.className = 'ae-plate-sub';
    subEl.textContent = opts.sub || ''; if (!opts.sub) subEl.style.display = 'none';
    idBox.appendChild(subEl);
    // [v2.32.0] Entity-kind chip ('Character'/'Location') removed per user --
    // a redundant label under the title, unnecessary use of space. opts.kind is
    // still consumed for plate image resolution; the .ae-plate-chip CSS was swept v2.32.1.
    head.appendChild(idBox);
    // [v2.33.0 CHARCHAT-LAUNCHER, per user] Edit for the focused entity moved OFF the nav
    // tray and ONTO the title row here, right-justified (idBox is flex:1, so a trailing
    // child sits hard right). A subtle wrench, same 'ghost sm icon' themeable button the
    // back chevron already uses — opens the character or location edit modal via
    // opts.editAction, supplied by whichever focused builder called us. Absent for any
    // caller that doesn't pass one (nothing breaks if a future plate has no edit path).
    if (opts.editAction) {
        var editBtn = $.btn('', 'ghost sm icon', function(e) { e.stopPropagation(); opts.editAction(); });
        editBtn.title = opts.editTitle || 'Edit';
        editBtn.appendChild(createCyberIcon('wrench', 15, 'currentColor'));
        head.appendChild(editBtn);
    }
    plate.appendChild(head);

    if (opts.actions && opts.actions.length) {
        var acts = document.createElement('div'); acts.className = 'ae-plate-acts';
        opts.actions.forEach(function(a) {
            var b = document.createElement('button'); b.type = 'button'; b.title = a.title || a.label || '';
            if (a.icon) b.appendChild(createCyberIcon(a.icon, 13, 'currentColor'));
            if (a.label) b.appendChild(document.createTextNode(a.label));
            b.addEventListener('click', function(e) { e.stopPropagation(); a.onClick(); });
            acts.appendChild(b);
        });
        plate.appendChild(acts);
    }
    return { el: plate, nameEl: nameEl, subEl: subEl, img: img };
}

function _buildPhantomInspectFocused(body, entityId) {
    body.innerHTML = '';
    body.classList.add('ae-dossier');
    var name = _focusedEntityDetail ? _focusedEntityDetail.name : _getEntityNameFallback(entityId);

    if (!_charProfileCache[entityId]) {
        _profileOpenCharId = entityId;
        _profileFetchPending[entityId] = true;
        sendToEngine('AE_FETCH_CHAR_PROFILE', { charId: entityId });
    } else {
        _profileOpenCharId = entityId;
    }

    // Journal is the ONE action with no other home in the live UI (the nav tray's
    // Journal opens the PLAYER journal; Edit is on the nav tray). It moves onto the
    // plate so dropping the old idRow doesn't strip its only entry point.
    var plate = _buildPhantomPlate(entityId, name, {
        sub: 'In scene',
        kind: 'npc',
        backTitle: 'Back to roster',
        // [v2.33.0 CHARCHAT-LAUNCHER] Wrench on the title row opens the native character
        // edit modal (was the nav tray's idCard 'Edit' button, removed this pass).
        editTitle: 'Edit character',
        editAction: function() { sendToEngine('AE_OPEN_CHAR_EDIT', { charId: entityId }); },
        // [v2.48.0 EMOSTUDIO-HEADER-MOVE, per user] Portraits + Gallery moved here from the
        // now-deleted flat Visuals+Gallery tab -- "no reason to keep the fields there
        // instead of the popup" and the Gallery browse action needed a new home once that
        // tab's job was split between the Emotion Studio modal and the character gallery.
        // Both sit next to Journal, the one action row this header already has.
        actions: [{
            icon: 'journal', label: 'Journal', title: 'Character Journal',
            onClick: function() { openCharJournalModal(entityId, plate.nameEl.textContent); }
        }, {
            icon: 'idCard', label: 'Portraits', title: 'Emotion Portraits',
            onClick: function() {
                var v = cachedCharVisuals.find(function(x) { return x.id === entityId; });
                if (!v) { _showToast('Visual record not loaded yet'); return; }
                openEmotionStudioModal(v, entityId);
            }
        }, {
            icon: 'camera', label: 'Gallery', title: 'Character Gallery',
            onClick: function() { openImageGenModal({ tab: 'gallery', entityId: entityId }); }
        }]
    });
    body.appendChild(plate.el);

    var info = document.createElement('div'); info.className = 'ae-info';
    var tabsRow = document.createElement('div'); tabsRow.className = 'ae-info-tabs';
    // [v2.48.0 EMOSTUDIO-HEADER-MOVE] Gallery tab removed -- see the actions[] comment
    // above. Status/Profile/Drama keep their relative order, just shift down one index.
    var TAB_LABELS = ['Status', 'Profile', 'Drama'];
    // module-level _focusedSheetActiveTab preserves the open tab across the
    // CHARACTER_DATA_SYNC rebuild (was the "kicks back to Status on save" bug);
    // _focusEntity() resets it to 0 on a fresh focus.
    var activeTab = _focusedSheetActiveTab;
    var infoBody = document.createElement('div'); infoBody.className = 'ae-info-body';

    function renderTab() {
        var detail = _focusedEntityDetail;
        if (detail && detail.id === entityId && plate.nameEl.textContent !== detail.name) plate.nameEl.textContent = detail.name || 'Loading\u2026';
        infoBody.innerHTML = '';
        if (activeTab === 0) {
            if (detail && detail.id === entityId) _buildFlatStatusTab(infoBody, detail, entityId);
            else infoBody.appendChild(_flatEmptyRow('Loading\u2026'));
        } else if (activeTab === 1) {
            var host = document.createElement('div'); host.id = 'ae-flat-profile-host'; infoBody.appendChild(host);
            _buildFlatProfileTab(host, entityId);
        } else {
            if (detail && detail.id === entityId) _buildFlatDramaDynamicsTab(infoBody, detail, entityId);
            else infoBody.appendChild(_flatEmptyRow('Loading\u2026'));
        }
    }
    // [BUGFIX v2.32.2 FORGE-BUTTON-AUDIT, per user] Was a bare <button>, styled only by
    // the (now-removed) bespoke .ae-info-tabs button rule -- background:none/border:none,
    // not a single --ae-btn-* token in reach of the Forge. .ae-sub-tab-btn is this file's
    // EXISTING themeable tab-button class (already used the same way for the Hub's own
    // sub-tabs, grep the literal string ae-sub-tab-btn a few thousand lines down) --
    // reusing it here instead of inventing a second tab style. Note for Bruce: this trades
    // the old underline-active look for .ae-sub-tab-btn's filled-pill active state (border
    // + dim accent background) -- a real visual change, not just a token swap; flagging in
    // case the underline was intentional and you want it kept, just token-routed instead.
    TAB_LABELS.forEach(function(label, i) {
        var b = document.createElement('button'); b.type = 'button'; b.textContent = label;
        b.className = 'ae-sub-tab-btn' + (i === activeTab ? ' active' : '');
        b.addEventListener('click', function(e) {
            e.stopPropagation(); activeTab = i; _focusedSheetActiveTab = i;
            tabsRow.querySelectorAll('.ae-sub-tab-btn').forEach(function(x) { x.classList.remove('active'); });
            b.classList.add('active'); renderTab();
        });
        tabsRow.appendChild(b);
    });
    info.appendChild(tabsRow);
    info.appendChild(infoBody);
    renderTab();

    body.appendChild(info);
    return info;
}

// Called after AE_ENTITY_DETAIL_RESPONSE (or a profile refresh) so the dossier
// picks up newly-arrived data. In-flow now: there is no sheet height to preserve
// across the rebuild, the info column simply grows to fit.
function _refreshPhantomInspectFocus() {
    var widget = document.querySelector('.ae-phantom-widget[data-mode="Inspect"]');
    if (!widget || !_focusedEntityId) return;
    // [BUGFIX v2.19.1 SPLIT-INSPECT] same authoritative-flag-first check as spawn()'s
    // _focusedIsCharacter -- see that comment for why the flag has to come first.
    var isCharacter = _focusedEntityKind === 'character' ||
        cachedCharVisuals.some(function(v) { return v.id === _focusedEntityId; }) ||
        (_focusedEntityDetail && _focusedEntityDetail.id === _focusedEntityId && _focusedEntityDetail.type === 'character');
    if (!isCharacter) return; // item/narrative focus still goes through the old steal-and-render path, untouched
    var body = widget.querySelector('.ae-phantom-body');
    if (!body) return;
    _buildPhantomInspectFocused(body, _focusedEntityId);
}

// [FEATURE] Location sheet, tab 1 of 3 (default/active on fresh focus) -- present
// characters/items at THIS location, with the same "present here vs whole roster"
// toggle already used by the docked Inspect tab's roster grid (_renderSceneTab),
// reusing its 👁 Scene / 🌐 All wording. "Scene" here means present at THIS
// location (detail.children -- direct entity-graph children, the same
// computation buildEntityDetailPayload already does for a character's carried
// items, just rooted at the location's own body id instead) -- not the player's
// CURRENT scene, since a browsed map node is often not where the player actually
// is. "All" is the full roster, same list the docked Inspect tab's toggle shows.
function _buildFlatLocationPresentTab(bodyEl, detail, locId) {
    var children = detail.children || [];
    var presentChars = children.filter(function(c) { return c.type === 'character'; });
    var presentItems = children.filter(function(c) { return c.type === 'item'; });

    // [v2.42.0 SCENE-SWITCH, per user: the old text button "doesn't communicate that it has
    // another state to switch to"] $.switch replaces the plain-text toggle here — same
    // sceneFilterOn boolean and renderList() driver, just a slider affordance instead of
    // swapped label text. _renderSceneTab's own roster-grid toggle (docked Inspect tab, a
    // different surface) is untouched — out of scope for this pass.
    var hdrRow = document.createElement('div'); hdrRow.style.cssText = 'display:flex;align-items:center;justify-content:flex-end;margin-bottom:2px;';
    var sceneFilterOn = true;
    var filterBtn = $.switch('\ud83d\udc41 Scene', '\ud83c\udf10 All', sceneFilterOn, function(isOn) {
        sceneFilterOn = isOn;
        renderList();
    });
    hdrRow.appendChild(filterBtn);
    bodyEl.appendChild(hdrRow);

    var listHost = document.createElement('div'); bodyEl.appendChild(listHost);

    function renderList() {
        listHost.innerHTML = '';
        if (sceneFilterOn) {
            var lblC = document.createElement('div'); lblC.className = 'ae-divider-lbl'; lblC.textContent = 'Characters (' + presentChars.length + ')'; listHost.appendChild(lblC);
            listHost.appendChild(_addEntityBtn('npc', { entityId: locId, label: detail.name }));
            if (presentChars.length === 0) {
                listHost.appendChild(_flatEmptyRow('No characters here.'));
            } else {
                var grid = $.avatarGrid(); listHost.appendChild(grid);
                presentChars.forEach(function(c) {
                    // [BUGFIX] c.id is the character's ENTITY/body id (detail.children
                    // are world-graph nodes) — c.charId (engine v2.18.1) is the actual
                    // character storage id cachedCharVisuals/_focusEntity/AE_FETCH_CHAR_
                    // PROFILE/AE_OPEN_CHAR_EDIT all key on. Using c.id here silently
                    // pointed every one of those at a record that doesn't exist.
                    var charId = c.charId || c.id;
                    var vis = cachedCharVisuals.find(function(v) { return v.id === charId; }) || {};
                    grid.appendChild($.avatar(c.name, vis._avatarDataUrl, null, 'npc', function() { _focusEntity(charId); }));
                });
            }
            var lblI = document.createElement('div'); lblI.className = 'ae-divider-lbl'; lblI.textContent = 'Items (' + presentItems.length + ')'; listHost.appendChild(lblI);
            listHost.appendChild(_addEntityBtn('item', { entityId: locId, label: detail.name }));
            if (presentItems.length === 0) {
                listHost.appendChild(_flatEmptyRow('No items here.'));
            } else {
                presentItems.forEach(function(item) {
                    var row = document.createElement('div'); row.className = 'ae-drow';
                    var t = document.createElement('div'); t.className = 'ae-drow-t'; t.textContent = item.name; row.appendChild(t);
                    if (item.description) { var d = document.createElement('div'); d.className = 'ae-drow-d'; d.textContent = item.description; row.appendChild(d); }
                    listHost.appendChild(row);
                });
            }
        } else {
            var allChars = cachedCharVisuals.filter(function(v) { return v.name && v.name.trim(); });
            var lbl = document.createElement('div'); lbl.className = 'ae-divider-lbl'; lbl.textContent = 'All Characters (' + allChars.length + ')'; listHost.appendChild(lbl);
            if (allChars.length === 0) {
                listHost.appendChild(_flatEmptyRow('No character data \u2014 waiting for sync.'));
            } else {
                var grid2 = $.avatarGrid(); listHost.appendChild(grid2);
                allChars.forEach(function(vis) {
                    var isPresent = presentChars.some(function(c) { return (c.charId || c.id) === vis.id; });
                    var avatarBtn = $.avatar(vis.name, vis._avatarDataUrl, null, isPresent ? 'npc' : '', function() { _focusEntity(vis.id); });
                    if (isPresent) avatarBtn.style.borderColor = 'var(--ae-color-npc)'; else avatarBtn.style.opacity = '0.65';
                    grid2.appendChild(avatarBtn);
                });
            }
        }
    }
    renderList();
}

// Both location tabs below mutate _focusedLocationMeta directly (module-level,
// single source of truth) rather than keeping a separate local draft per tab --
// AE_SAVE_LOCATION_VISUALS takes description/visuals/lorebookText together, not
// as independent patches (see _renderLocationGalleryProfile, the original of
// this save call), so a tab-local draft would silently blank out whichever of
// the other two fields it didn't know about on save. Always reading/writing the
// shared cache and sending all three keeps Lorebook and Gallery edits safe
// regardless of which tab is open when the user blurs a field.
function _saveLocationMeta(locId) {
    var m = _focusedLocationMeta || {};
    sendToEngine('AE_SAVE_LOCATION_VISUALS', { locationId: locId, description: m.description || '', visuals: m.locationVisuals || '', lorebookText: m.lorebookText || '' });
}

// [FEATURE] Location sheet, tab 2 of 3 -- lorebook entry. meta comes from
// AE_FETCH_GALLERY_LOCATIONS (see _focusLocation) -- description is the short
// runtime summary, lorebookText is the extended lore body (same distinction
// _renderLocationGalleryProfile's help text already draws).
function _buildFlatLocationLorebookTab(bodyEl, meta, locId) {
    if (!meta) { bodyEl.appendChild(_flatEmptyRow('Loading\u2026')); return; }

    function flatField(label, key, ph, rows) {
        var fg = document.createElement('div'); fg.className = 'ae-fg';
        var l = document.createElement('label'); l.textContent = label; fg.appendChild(l);
        var ta = document.createElement('textarea'); ta.rows = rows || 3; ta.placeholder = ph || ''; ta.value = meta[key] || '';
        var grow = function() { ta.style.height = 'auto'; ta.style.height = ta.scrollHeight + 'px'; };
        ta.addEventListener('input', function() { meta[key] = ta.value; grow(); });
        ta.addEventListener('focus', function() { fg.classList.add('editing'); _phantomFieldFocusExpand(fg); });
        ta.addEventListener('blur', function() { fg.classList.remove('editing'); _saveLocationMeta(locId); });
        fg.appendChild(ta); bodyEl.appendChild(fg);
        setTimeout(grow, 0);
    }

    var lblD = document.createElement('div'); lblD.className = 'ae-divider-lbl'; lblD.textContent = 'Description (runtime summary)'; bodyEl.appendChild(lblD);
    flatField('Description', 'description', 'What matters here, right now\u2026', 3);

    var lblL = document.createElement('div'); lblL.className = 'ae-divider-lbl'; lblL.textContent = 'Lorebook Entry (extended lore)'; bodyEl.appendChild(lblL);
    flatField('Lorebook body', 'lorebookText', 'History, myths, hidden details, faction ties\u2026', 6);
}

// [FEATURE] Location sheet, tab 3 of 3 -- own gallery. Locations only ever have
// ONE portrait slot (loc.id + '_portrait'), unlike characters' multi-emotion
// slots -- same key convention the sheet's own header image (resolveEntityImage)
// and _renderLocationGalleryProfile both already use. Hero + Generate/Upload are
// copied from that function's Gallery-modal version (same engine calls, same
// portrait key) rather than re-invented.
function _buildFlatLocationGalleryTab(bodyEl, meta, locId) {
    if (!meta) { bodyEl.appendChild(_flatEmptyRow('Loading\u2026')); return; }
    var name = meta.name || _getEntityNameFallback(locId);
    var lbl = document.createElement('div'); lbl.className = 'ae-divider-lbl'; lbl.textContent = 'Scene Image'; bodyEl.appendChild(lbl);

    var hero = document.createElement('div'); hero.className = 'ae-loc-profile-hero'; bodyEl.appendChild(hero);
    var pWrap = document.createElement('div'); pWrap.className = 'ae-loc-portrait-wrap';
    var pPh = document.createElement('div'); pPh.className = 'ae-loc-portrait-ph'; pPh.style.background = _nameToColor(name); pPh.textContent = (meta.icon || name || '?').slice(0, 2); pWrap.appendChild(pPh);
    var pImg = document.createElement('img'); pImg.className = 'ae-loc-portrait-img'; pWrap.appendChild(pImg);
    _loadPortrait(locId + '_portrait').then(function(url) { if (url) { pImg.src = url; pImg.style.display = 'block'; } });
    pWrap.addEventListener('click', function() { if (pImg.src && pImg.style.display !== 'none') _galleryLightbox(pImg.src, name); });
    hero.appendChild(pWrap);

    var acts = document.createElement('div'); acts.className = 'ae-loc-profile-actions'; hero.appendChild(acts);
    var genBtn = $.btn('Generate Scene', 'primary sm', async function() {
        genBtn.disabled = true; genBtn.textContent = 'Generating\u2026';
        try {
            var compiled = _compileActiveImgFields();
            var fp = [compiled.quality || '', meta.locationVisuals || ''].filter(Boolean).join(', ');
            var reqBody = buildRequestBody(fp, compiled.negative || '', [], { width: _aeImgDefaults.width || 832, height: _aeImgDefaults.height || 1216, steps: Math.min(_aeImgDefaults.steps || 28, 28), scale: _aeImgDefaults.scale || 5.0 });
            var dataUrl = await callGenerateAPI(reqBody);
            await _savePortrait(locId + '_portrait', dataUrl, 'gen', null);
            pImg.src = dataUrl; pImg.style.display = 'block';
            _showToast('\u2713 Scene image saved');
            if (lastSceneState && lastSceneState.locationId === locId) { var root = document.getElementById('ae-ui-root'); if (root) _updateBanner(root, lastSceneState); }
        } catch (e) { _showToast('Generate failed: ' + (e.message || '')); }
        finally { genBtn.disabled = false; genBtn.textContent = 'Generate Scene'; }
    });
    var upBtn = $.btn('Upload Image', 'ghost sm', function() {
        var fi = document.createElement('input'); fi.type = 'file'; fi.accept = 'image/*';
        fi.onchange = function() {
            if (!fi.files || !fi.files[0]) return;
            var fr = new FileReader();
            fr.onload = async function(ev) {
                try {
                    var u = ev.target.result;
                    await _savePortrait(locId + '_portrait', u, 'upload', null);
                    pImg.src = u; pImg.style.display = 'block';
                    _showToast('\u2713 Uploaded');
                    if (lastSceneState && lastSceneState.locationId === locId) { var root = document.getElementById('ae-ui-root'); if (root) _updateBanner(root, lastSceneState); }
                } catch (e) { _showToast('Upload failed'); }
            };
            fr.readAsDataURL(fi.files[0]);
        };
        fi.click();
    });
    acts.appendChild(genBtn); acts.appendChild(upBtn);

    var lblV = document.createElement('div'); lblV.className = 'ae-divider-lbl'; lblV.textContent = 'Scene Visuals'; bodyEl.appendChild(lblV);
    var fg = document.createElement('div'); fg.className = 'ae-fg';
    var vTa = document.createElement('textarea'); vTa.rows = 3; vTa.placeholder = 'stone archway, torchlight, ivy-covered walls\u2026'; vTa.value = meta.locationVisuals || '';
    var vGrow = function() { vTa.style.height = 'auto'; vTa.style.height = vTa.scrollHeight + 'px'; };
    vTa.addEventListener('input', function() { meta.locationVisuals = vTa.value; vGrow(); });
    vTa.addEventListener('focus', function() { fg.classList.add('editing'); _phantomFieldFocusExpand(fg); });
    vTa.addEventListener('blur', function() { fg.classList.remove('editing'); _saveLocationMeta(locId); });
    fg.appendChild(vTa); bodyEl.appendChild(fg);
    setTimeout(vGrow, 0);

    // [v2.44.0 IMGGEN-MODAL] Launch button for the unified Image Generation modal.
    var imgGenBtn = $.btn('\u2699 Presets & Gallery', 'ghost sm', function() { openImageGenModal({ tab: 'gallery', entityId: locId }); });
    imgGenBtn.style.cssText = 'margin-top:10px;';
    bodyEl.appendChild(imgGenBtn);
}

// [FEATURE] Location sheet -- background image + tabbed sheet, mirroring
// _buildPhantomInspectFocused's structure for characters (image, .ae-sheet,
// idRow, tabsRow, sheetBody) so the two entity types share one visual language.
// Called from PhantomManager.spawn()'s new _focusedIsLocation branch.
function _buildPhantomLocationFocused(body, locId) {
    body.innerHTML = '';
    body.classList.add('ae-dossier');
    var detail = (_focusedEntityDetail && _focusedEntityDetail.id === locId) ? _focusedEntityDetail : null;
    var meta = _focusedLocationMeta;
    var name = (detail && detail.name) || (meta && meta.name) || _getEntityNameFallback(locId);

    // [v2.33.0 CHARCHAT-LAUNCHER] Location Edit moved onto the title-row wrench (was the
    // nav tray's idCard 'Edit', removed this pass). AE_OPEN_ENTITY_EDIT is the location
    // path (locations are entities, not characters) — same message the old nav button sent
    // for a focused location.
    var plate = _buildPhantomPlate(locId, name, {
        sub: 'Location', kind: 'loc', backTitle: 'Back to roster', resolveImage: _resolveLocationPlateImage,
        editTitle: 'Edit location',
        editAction: function() { sendToEngine('AE_OPEN_ENTITY_EDIT', { entityId: locId }); }
    });
    body.appendChild(plate.el);

    var info = document.createElement('div'); info.className = 'ae-info';
    var tabsRow = document.createElement('div'); tabsRow.className = 'ae-info-tabs';
    var TAB_LABELS = ['Present', 'Lorebook', 'Gallery'];
    var activeTab = _focusedSheetActiveTab;
    var infoBody = document.createElement('div'); infoBody.className = 'ae-info-body';

    function renderTab() {
        var d = (_focusedEntityDetail && _focusedEntityDetail.id === locId) ? _focusedEntityDetail : null;
        var m = _focusedLocationMeta;
        if (d && d.name && plate.nameEl.textContent !== d.name) plate.nameEl.textContent = d.name;
        else if (m && m.name && plate.nameEl.textContent !== m.name) plate.nameEl.textContent = m.name;
        infoBody.innerHTML = '';
        if (activeTab === 0) {
            if (d) _buildFlatLocationPresentTab(infoBody, d, locId);
            else infoBody.appendChild(_flatEmptyRow('Loading\u2026'));
        } else if (activeTab === 1) {
            _buildFlatLocationLorebookTab(infoBody, m, locId);
        } else {
            _buildFlatLocationGalleryTab(infoBody, m, locId);
        }
    }
    // [BUGFIX v2.32.2 FORGE-BUTTON-AUDIT, per user] Was a bare <button>, styled only by
    // the (now-removed) bespoke .ae-info-tabs button rule -- background:none/border:none,
    // not a single --ae-btn-* token in reach of the Forge. .ae-sub-tab-btn is this file's
    // EXISTING themeable tab-button class (already used the same way for the Hub's own
    // sub-tabs, grep the literal string ae-sub-tab-btn a few thousand lines down) --
    // reusing it here instead of inventing a second tab style. Note for Bruce: this trades
    // the old underline-active look for .ae-sub-tab-btn's filled-pill active state (border
    // + dim accent background) -- a real visual change, not just a token swap; flagging in
    // case the underline was intentional and you want it kept, just token-routed instead.
    TAB_LABELS.forEach(function(label, i) {
        var b = document.createElement('button'); b.type = 'button'; b.textContent = label;
        b.className = 'ae-sub-tab-btn' + (i === activeTab ? ' active' : '');
        b.addEventListener('click', function(e) {
            e.stopPropagation(); activeTab = i; _focusedSheetActiveTab = i;
            tabsRow.querySelectorAll('.ae-sub-tab-btn').forEach(function(x) { x.classList.remove('active'); });
            b.classList.add('active'); renderTab();
        });
        tabsRow.appendChild(b);
    });
    info.appendChild(tabsRow);
    info.appendChild(infoBody);
    renderTab();

    body.appendChild(info);
    return info;
}

// Called after AE_ENTITY_DETAIL_RESPONSE (the Present tab's data) or the
// AE_FETCH_GALLERY_LOCATIONS round trip (Lorebook/Gallery's data). In-flow now,
// so no sheet height to preserve across the rebuild.
function _refreshPhantomLocationFocus() {
    var widget = document.querySelector('.ae-phantom-widget[data-mode="Inspect"]');
    if (!widget || !_focusedEntityId) return;
    if (_focusedEntityKind !== 'location') return;
    var body = widget.querySelector('.ae-phantom-body');
    if (!body) return;
    _buildPhantomLocationFocused(body, _focusedEntityId);
}

function _openPhantomThemeMenu(anchorBtn) {
    var menu = document.getElementById('ae-theme-menu');
    if (!menu) return;
    if (menu.style.display === 'flex') { menu.style.display = 'none'; return; }
    var rect = anchorBtn.getBoundingClientRect();
    menu.style.display = 'flex';
    menu.style.top = 'auto';
    menu.style.bottom = (window.innerHeight - rect.top + 6) + 'px';
    menu.style.left = Math.max(8, Math.min(rect.left, window.innerWidth - 210)) + 'px';
}

// [PHANTOM-PRIMARY PASS 5] Persistent nav tray — the one thing that's always
// visible. Map/Inspect toggle content (re-spawning the widget in that mode);
// Journal/Settings open their existing panels; Edit acts on whatever's
// currently focused; Dismiss closes the widget.
function _buildPhantomNavTray(currentMode) {
    var tray = document.createElement('div'); tray.className = 'ae-nav-tray';
    function navBtn(iconName, title, active, action) {
        var b = document.createElement('button'); b.type = 'button'; b.title = title;
        b.appendChild(createCyberIcon(iconName, 16, 'currentColor'));
        if (active) b.classList.add('active');
        b.addEventListener('click', function(e) { e.stopPropagation(); action(b); });
        tray.appendChild(b);
        return b;
    }
    navBtn('mapPin', 'Map', currentMode === 'Map', function() { if (currentMode !== 'Map') PhantomManager.spawn('Map'); });
    navBtn('userScan', 'Inspect', currentMode === 'Inspect', function() { if (currentMode !== 'Inspect') PhantomManager.spawn('Inspect'); });
    navBtn('journal', 'Journal', false, function() { openJournalModal(); });
    // [v2.13.0 CHARCHAT-SHELL-BASELINE] The 'Messages' nav entry is REMOVED with the panel it
    // opened. Per user, chat mode should override the interface when the HUD is active rather
    // than being a button you press to enter a second mode — so a launcher is the wrong
    // shape for the surface being built, not merely a button with nothing behind it. The
    // engine's native Chat toolbar button starts/resumes/ends chats in the meantime, exactly
    // as it always has. The 'phone' icon stays in every theme's icon map: the overhaul's
    // in-chat header control is the next thing that wants it.
    // [v2.33.0 CHARCHAT-LAUNCHER, per user] Chat replaces the old idCard 'Edit' button in
    // the settings->[here]->close slot. Edit moved onto the focused entity's title-row
    // wrench (see _buildPhantomPlate); it was never the only way into either entity's edit
    // modal, and the wrench puts it where the thing being edited is. Chat opens the in-flow
    // Chat launcher (the phone-contacts view) as a real fourth spawn() mode. Uses the
    // 'speech' icon (the 'phone' glyph stays reserved for the eventual in-chat header
    // control). A later pass adds a Wizard-chats tab inside that view (room left, not built).
    var sep1 = document.createElement('div'); sep1.className = 'ae-nav-sep'; tray.appendChild(sep1);
    // [v2.10.0 SHELL-1] Image Studio rehomed here from the deleted outer tray, per user:
    // it "needs a home on the phantom widget". Sits next to the DO-things buttons, ahead
    // of Settings which is chrome.
    navBtn('camera', 'Image Studio', currentMode === 'Image', function() { if (currentMode !== 'Image') PhantomManager.spawn('Image'); });
    navBtn('speech', 'Chat', currentMode === 'Chat', function() { if (currentMode !== 'Chat') PhantomManager.spawn('Chat'); });
    navBtn('settings', 'Settings', false, function(btn) { _openPhantomThemeMenu(btn); });
    var sep2 = document.createElement('div'); sep2.className = 'ae-nav-sep'; tray.appendChild(sep2);
    navBtn('close', 'Dismiss', false, function() { PhantomManager.destroy(); });
    return tray;
}

function _renderFocusedEntityDetails(tab, entityId, state) {
    if (!_focusedEntityDetail) {
        var loading = document.createElement('div');
        loading.style.cssText = 'padding:20px;text-align:center;color:var(--ae-text-muted);font-style:italic;';
        loading.textContent = 'Loading details…';
        tab.appendChild(loading);
        return;
    }

    var detail = _focusedEntityDetail;

    if (detail.type === 'character') {
        // [PHANTOM-PRIMARY PASS 5] The real character-focus UI now lives entirely
        // in _buildPhantomInspectFocused (image + sheet), which does NOT call
        // this function at all. This branch still runs against whatever
        // #ae-tab-scene currently is — the dormant docked HUD in practice,
        // since the phantom widget skips stealing it when focused — so it must
        // not crash, but doesn't need real content either. Pass 3/4's tray-
        // launcher calls here were deleted along with those functions; this
        // used to throw (ReferenceError) every time a character was focused,
        // silently, since nothing in the render pipeline catches it — caught
        // while wiring the new path in, fixed here rather than left as a landmine.
        var dormantNote = document.createElement('div');
        dormantNote.style.cssText = 'padding:16px;font-size:11px;color:var(--ae-text-dim);';
        dormantNote.textContent = 'Character focus view has moved to the phantom widget.';
        tab.appendChild(dormantNote);

        // [PHANTOM-PRIMARY PASS 5] Follow/Stay + Kill Character banner removed
        // per user's request ("get rid of the banner at the bottom with the
        // follow me and kill character buttons"). Kill is still reachable via
        // the nav tray's Edit-character button (opens the native edit modal,
        // same AE_DELETE_CHAR path). Follow/Stay (AE_TOGGLE_FOLLOW) has no
        // home in the new design yet — flagged, not silently dropped.

    } else if (detail.type === 'item') {
        tab.appendChild($.section('Item Details', function(body) {
            var desc = document.createElement('div');
            desc.style.cssText = 'font-size:12px;color:var(--ae-text-main);line-height:1.45;';
            desc.textContent = detail.description || 'No description.';
            body.appendChild(desc);
            
            if (detail.atmosphere) {
                var atm = document.createElement('div');
                atm.style.cssText = 'font-size:11px;color:var(--ae-text-muted);font-style:italic;margin-top:6px;';
                atm.textContent = 'Atmosphere: ' + detail.atmosphere;
                body.appendChild(atm);
            }
        }, { open: true, stateKey: 'focus-item-desc-' + detail.id }));

        tab.appendChild($.section('Status & Equipment', function(body) {
            // [v0.9.84] Single equip toggle — no status label, no character picker.
            var eqToggle = $.btn(detail.isEquipped ? 'Equipped' : 'Equip',
                detail.isEquipped ? 'primary sm' : 'ghost sm',
                function() {
                    if (detail.isEquipped) {
                        sendToEngine('AE_UNEQUIP_ITEM', { charId: detail.equippedToCharId, itemId: detail.id });
                    } else {
                        sendToEngine('AE_EQUIP_ITEM', { charId: detail.ownerCharId, itemId: detail.id });
                    }
                });
            body.appendChild(eqToggle);
        }, { open: true, stateKey: 'focus-item-equip-' + detail.id }));

        var actionButtons = [];
        (detail.actionInstances || []).forEach(function(inst) {
            actionButtons.push($.btn('⚡ ' + inst.name, 'action sm', function() {
                execActionInstance(detail.id, inst.id, !!inst.silent);
            }));
        });
        (detail.actions || []).forEach(function(act) {
            actionButtons.push($.btn('⚡ ' + act.label, 'action sm', function() {
                execEntityAction(detail.id, act.id, null, null);
            }));
        });

        if (actionButtons.length > 0) {
            tab.appendChild($.section('Actions', function(body) {
                var grid = $.twoCol(actionButtons);
                body.appendChild(grid);
            }, { open: true, stateKey: 'focus-item-actions-' + detail.id }));
        }

    } else if (detail.type === 'narrative' && detail.narrative) {
        var narr = detail.narrative;
        // [v0.9.15] B9: Narrative description removed from bottom pane — it is
        // already displayed in the top-pane banner (ae-scene-desc). The state
        // badge is now inline inside the Quest Tracking section.

        tab.appendChild($.section('Quest Tracking', function(body) {
            // State badge at top of tracking section
            var stateEl = document.createElement('span');
            stateEl.className = 'ae-narr-state ' + (narr.storyState || 'locked');
            stateEl.style.cssText = 'display:inline-block;margin-bottom:8px;';
            var stateLabel = narr.storyState === 'active' ? '🔥 Active' : narr.storyState === 'completed' ? '✅ Done' : '🔒 Locked';
            stateEl.textContent = stateLabel;
            body.appendChild(stateEl);

            var isTracked = !!narr.isTracked;
            
            var row = document.createElement('div');
            row.style.cssText = 'display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;';
            var lbl = document.createElement('span');
            lbl.style.fontSize = '12px';
            lbl.textContent = isTracked ? '🎯 Currently Tracking' : '💤 Not Tracked';
            row.appendChild(lbl);
            
            var trackBtn = $.btn(isTracked ? '⏹ Stop Tracking' : '🎯 Track Quest', isTracked ? 'ghost sm' : 'primary sm', function() {
                sendToEngine('AE_TRACK_NARRATIVE', { narrativeId: detail.id });
            });
            row.appendChild(trackBtn);
            body.appendChild(row);

            if (isTracked && narr.questTargetName) {
                var pathBox = document.createElement('div');
                pathBox.style.cssText = 'font-size:11px;padding:8px;background:var(--ae-surface-narrative);border:1px solid rgba(203,166,247,0.15);border-radius:var(--ae-radius-sm);line-height:1.45;color:var(--ae-color-narrative);';
                if (narr.pathNames && narr.pathNames.length > 0) {
                    pathBox.textContent = '🗺 Path: ' + narr.pathNames.join(' → ');
                } else {
                    pathBox.textContent = '🎯 Target: ' + narr.questTargetName + ' — no travel path found.';
                }
                body.appendChild(pathBox);
            }
        }, { open: true, stateKey: 'focus-narr-track-' + detail.id }));

        var actionButtons = [];
        (detail.actionInstances || []).forEach(function(inst) {
            actionButtons.push($.btn('⚡ ' + inst.name, 'action sm', function() {
                execActionInstance(detail.id, inst.id, !!inst.silent);
            }));
        });
        (detail.actions || []).forEach(function(act) {
            actionButtons.push($.btn('⚡ ' + act.label, 'action sm', function() {
                execEntityAction(detail.id, act.id, null, null);
            }));
        });

        if (actionButtons.length > 0) {
            tab.appendChild($.section('Actions', function(body) {
                var grid = $.twoCol(actionButtons);
                body.appendChild(grid);
            }, { open: true, stateKey: 'focus-narr-actions-' + detail.id }));
        }
    }
}

function _updateBanner(root, state) {
    var topPane = root.querySelector('#ae-top-pane');
    if (_focusedEntityId) { _renderFocusBanner(topPane, _focusedEntityId); return; } // [v021] focus overrides tab banner
    var _fcStale = topPane.querySelector('#ae-focus-controls'); if (_fcStale) _fcStale.remove();
    var _fbStale = topPane.querySelector('#ae-focus-back'); if (_fbStale) _fbStale.remove();
    var _fsStale = topPane.querySelector('#ae-focus-snaptext'); if (_fsStale) _fsStale.remove();
    var activeTab = root.querySelector('.ae-tab-btn.active');
    var activeTabTarget = activeTab && activeTab.getAttribute('data-target');

    if (activeTabTarget === 'ae-tab-hub') {
        // Portrait mode: show protagonist
        var protag = (state.presentCharacters || []).find(function(c) { return c.isProtagonist; });
        var protagVis = protag && cachedCharVisuals.find(function(v) { return v.id === protag.id; });
        var bgUrl = protagVis && protagVis._avatarDataUrl;  // base avatar (default)
        topPane.style.backgroundImage = bgUrl ? 'url(' + JSON.stringify(bgUrl) + ')' : '';
        if (!bgUrl) topPane.style.background = _nameToColor(protag ? protag.name : '?');
        // [v0.9.100] Snapshot replaces the avatar in the top pane if one exists.
        if (protag) _loadPortrait(protag.id + '_em_Snapshot').then(function(snapUrl) {
            if (snapUrl && _focusedEntityId == null) { topPane.style.backgroundImage = 'url(' + JSON.stringify(snapUrl) + ')'; }
        }).catch(function() {});
        topPane.classList.add('portrait-mode');
        _writeInTitle(root.querySelector('.ae-scene-title'), (protag ? protag.name : 'Protagonist').toUpperCase());
        root.querySelector('.ae-scene-desc').textContent = protag ? (protag.compressedLine || protag.briefDescription || '') : '';
        var badge = root.querySelector('#ae-scene-badge');
        badge.textContent = protagVis ? [protagVis.species, protagVis.gender].filter(Boolean).join(' • ') : '';
        badge.style.display = badge.textContent ? 'inline-block' : 'none';
        // Portrait mode ✏️ edit button — top-right, mirrors ⚙️ on left
        var existingPEBtn = topPane.querySelector('#ae-protag-edit-btn');
        if (existingPEBtn) existingPEBtn.remove();
        var _staleLocEdit = topPane.querySelector('#ae-loc-edit-btn');
        if (_staleLocEdit) _staleLocEdit.remove();
        if (protag) {
            var peBtn = document.createElement('button');
            peBtn.id = 'ae-protag-edit-btn';
            peBtn.className = 'ae-settings-btn';
            peBtn.style.cssText = 'position:absolute;top:12px;right:12px;left:auto;'; // left:auto overrides .ae-settings-btn default left:12px
            peBtn.title = 'View / Edit Character Profile';
            peBtn.textContent = '🪪'; // [v0.9.15] B7: less confusing than ✏️
            var _captProtagId = protag.id;
            peBtn.addEventListener('click', function() { sendToEngine('AE_OPEN_CHAR_EDIT', { charId: _captProtagId }); });
            topPane.appendChild(peBtn);
        }
    } else {
        // Location banner mode — remove portrait edit button if still attached
        var _staleEBtn = topPane.querySelector('#ae-protag-edit-btn');
        if (_staleEBtn) _staleEBtn.remove();

        // [v0.9.18 GUIDE] Guide visibility managed in the portrait .then() below.
        // [v0.9.11] B3: ✏️ Edit button for current location — top-right, same as protagonist edit in hub mode.
        var _staleLocEdit2 = topPane.querySelector('#ae-loc-edit-btn');
        if (_staleLocEdit2) _staleLocEdit2.remove();
        if (state && state.locationId) {
            var _locEditBtn = document.createElement('button');
            _locEditBtn.id = 'ae-loc-edit-btn';
            _locEditBtn.className = 'ae-settings-btn';
            _locEditBtn.style.cssText = 'position:absolute;top:12px;right:12px;left:auto;';
            _locEditBtn.title = 'View / Edit Location';
            _locEditBtn.textContent = '🪪'; // [v0.9.15] B7
            var _captLocId = state.locationId;
            _locEditBtn.addEventListener('click', function() { sendToEngine('AE_OPEN_ENTITY_EDIT', { entityId: _captLocId }); });
            topPane.appendChild(_locEditBtn);
        }
        topPane.classList.remove('portrait-mode');
        topPane.style.backgroundImage = '';
        _loadPortrait(state.locationId + '_portrait').then(function(url) {
            if (url) {
                topPane.style.backgroundImage = 'url(' + JSON.stringify(url) + ')';
                return;
            }
            // [v0.9.28] No per-location image yet — use the module/default background
            // (fetched once, then served from IndexedDB). state.defaultBgUrl lets a
            // module theme its own default; AE_DEFAULT_BG_URL is the global default.
            // [v0.9.9.9] `|| AE_DEFAULT_BG_URL` used to fire on ANY falsy value, so an
            // explicit clear (defaultBgUrl set to '') was indistinguishable from
            // "never synced yet" — the banner reverted to the same hardcoded webp
            // every time, forever, no matter how many times Clear was pressed. Only
            // fall back to the hardcoded default when the field has never been synced
            // (undefined); an explicit empty string means the user cleared it on purpose.
            var _effBg = state.defaultBgUrl === undefined ? AE_DEFAULT_BG_URL : state.defaultBgUrl;
            _loadOrFetchDefaultBg(_effBg).then(function(bg) {
                if (_focusedEntityId) return; // a focus banner took over while awaiting
                topPane.style.backgroundImage = bg ? ('url(' + JSON.stringify(bg) + ')') : '';
            });
        });
        topPane.style.background = '';
        _writeInTitle(root.querySelector('.ae-scene-title'), (state.locationName || '—').toUpperCase());
        root.querySelector('.ae-scene-desc').textContent = [state.locationDescription, state.locationAtmosphere].filter(Boolean).join('  ') || '';
        var badge = root.querySelector('#ae-scene-badge');
        badge.style.display = 'none';

        // Overlay tint by locationState
        var overlay = root.querySelector('.ae-scene-overlay');
        var stateColors = {
            hostile:  'linear-gradient(to top,rgba(180,40,40,0.7) 5%,transparent 100%)',
            burning:  'linear-gradient(to top,rgba(200,80,0,0.7) 5%,transparent 100%)',
            default:  'linear-gradient(to top,var(--ae-bg-base) 5%,transparent 100%)'
        };
        overlay.style.background = stateColors[state.locationState] || stateColors['default'];
    }
}

// =============================================================================
// SECTION 11 — MAP TAB (🌎)
// Reads parent (up), children (down), explicit connections (side).
// Clicking a non-current node centers it + requests its graph from engine.
// =============================================================================

var MAP_ICONS = { 
    location: 'mapPin', 
    character: 'user', 
    item: 'toolbox', 
    narrative: 'quests', 
    default: 'circle' 
};

function _renderMapTab(root, state) {
    if (!state.locationId) return;
    _mapPlayerLocId = state.locationId;
    _mapInVehicleId       = state.inVehicleId || null;
    _mapVehicleWorldLocId = state.vehicleWorldLocationId || null;
    if (!state.inVehicleId && _mapOperateMode) {
        _mapOperateMode = false; _mapOperateVehicleId = null; _mapPreOperateGraph = null; _mapVehicleBaselineGraph = null;
    }

    // Operate button — shown when player is inside a vehicle
    var _opBtnVp = root.querySelector('#ae-map-viewport');
    var _opBtnEx = _opBtnVp && _opBtnVp.querySelector('#ae-map-operate-btn');
    if (_opBtnEx) _opBtnEx.remove();
    if (state.inVehicleId && _opBtnVp) {
        var _opBtn = document.createElement('button');
        _opBtn.id = 'ae-map-operate-btn';
        _opBtn.className = 'ae-btn sm';
        _opBtn.textContent = _mapOperateMode ? '🚢 Operating' : '🚢 Operate';
        _opBtn.style.cssText = ('position:absolute;top:8px;right:8px;z-index:20;'
            + ('background:' + (_mapOperateMode ? 'rgba(137,180,250,0.25);' : 'rgba(19,19,24,0.85);')
            + ('border:1px solid ' + (_mapOperateMode ? 'var(--ae-color-faction);' : 'var(--ae-bg-border);'))));
        _opBtn.title = _mapOperateMode ? 'Stop operating vehicle' : 'Operate vehicle — map shows vehicle routes';
        _opBtn.addEventListener('click', function() { _toggleOperateMode(); });
        _opBtnVp.appendChild(_opBtn);
    }

    // [v1.4.0 LOCGEN] "+ Location" author button — opens _showAddLocationPopup (Section
    // 12, beside _showAddEntityPopup). Rebuilt each render like the Operate button above,
    // since the viewport survives canvas repaints. Always anchored to the PLAYER's
    // location, never the map's currently-centered node.
    var _nlVp = root.querySelector('#ae-map-viewport');
    var _nlEx = _nlVp && _nlVp.querySelector('#ae-map-newloc-btn');
    if (_nlEx) _nlEx.remove();
    if (_nlVp && !_mapOperateMode) {
        var _nlBtn = document.createElement('button');
        _nlBtn.id = 'ae-map-newloc-btn';
        _nlBtn.className = 'ae-btn sm';
        _nlBtn.textContent = '+ Location';
        _nlBtn.style.cssText = 'position:absolute;top:8px;left:8px;z-index:20;background:rgba(19,19,24,0.85);border:1px solid var(--ae-bg-border);';
        // [v1.5.1 SAKURA] The hardcoded dark fill above reads as a black smear on
        // the light theme. Sakura gets its own lavender treatment via CSS (below),
        // which — being !important — wins over this inline background regardless.
        _nlBtn.title = 'Author a new location beside or inside the current one';
        _nlBtn.addEventListener('click', function() { _showAddLocationPopup(); });
        _nlVp.appendChild(_nlBtn);
    }

    var graph = state.locationGraph;
    if (graph) {
        _buildMapFromGraph(state.locationId, graph, root);
    } else {
        // Fallback: derive a minimal graph from availableActions
        var nodes = [{ id: state.locationId, name: state.locationName, type: 'location', direction: 'current' }];
        var edges = [];
        var seen = new Set([state.locationId]);
        (state.availableActions || []).forEach(function(a) {
            if (seen.has(a.entityId)) return;
            seen.add(a.entityId);
            nodes.push({ id: a.entityId, name: a.entityName, type: 'entity', direction: 'connection' });
            edges.push({ from: state.locationId, to: a.entityId, kind: 'connection' });
        });
        _layoutAndBuildMap(_getCanvasRoot(root), nodes, edges, state.locationId);
    }
}

// Toast notification — small pill at bottom of screen, auto-dismisses.
function _showToast(msg, dur) {
    var t = document.createElement('div');
    t.style.cssText = [
        'position:fixed;bottom:80px;left:50%;transform:translateX(-50%);',
        'background:var(--ae-bg-panel);border:1px solid var(--ae-bg-border);',
        'color:var(--ae-text-main);padding:8px 18px;border-radius:var(--ae-radius-pill);',
        'font-size:12px;z-index:var(--ae-z-toast);box-shadow:var(--ae-shadow-sm);',
        'pointer-events:none;font-family:var(--ae-font-sans);',
        'max-width:min(360px, calc(100vw - 40px));white-space:normal;overflow-wrap:break-word;text-align:center;line-height:1.45;'
    ].join('');
    t.textContent = msg;
    document.body.appendChild(t);
    setTimeout(function() { if (t.parentNode) t.remove(); }, dur || 3000);
}

// Checks whether targetId is adjacent to the player's current location.
// _mapCurrentGraph is always the PLAYER's location graph, not the inspected node's.
// Returns true (allow) when graph is unknown — engine will validate.
function _isAdjacentNode(targetId) {
    // In operate mode use the vehicle world-location graph for adjacency.
    var graph = _mapOperateMode ? _mapVehicleBaselineGraph : _mapCurrentGraph;
    if (!graph) return true;
    if (graph.parentId === targetId) return true;
    if ((graph.children  || []).some(function(c) { return c.id === targetId; })) return true;
    if ((graph.connections || []).some(function(c) { return c.id === targetId; })) return true;
    // [v0.9.7.6] Sibling travel: lateral moves between locations sharing a parent
    // (null parentId = shared world root). Engine validates via trIsSibling. Player
    // (non-operate) mode only - vehicle routing uses connections, not lateral siblings.
    if (!_mapOperateMode && (graph.siblings || []).some(function(c) { return c.id === targetId; })) return true;
    return false;
}

// Toggle vehicle operate mode. Switches the map to show the vehicle's world
// location and its connections as vehicle-navigable routes.
function _toggleOperateMode() {
    if (!_mapInVehicleId || !_mapVehicleWorldLocId) return;
    _mapOperateMode = !_mapOperateMode;
    
    var root = document.getElementById('ae-ui-root');
    var btn = root && root.querySelector('#ae-map-operate-btn');
    if (btn) {
        btn.textContent = _mapOperateMode ? '🚢 Operating' : '🚢 Operate';
        btn.style.background = _mapOperateMode ? 'rgba(137,180,250,0.25)' : 'rgba(19,19,24,0.85)';
        btn.style.borderColor = _mapOperateMode ? 'var(--ae-color-faction)' : 'var(--ae-bg-border)';
        btn.title = _mapOperateMode ? 'Stop operating vehicle' : 'Operate vehicle — map shows vehicle routes';
    }

    if (_mapOperateMode) {
        _mapOperateVehicleId = _mapInVehicleId;
        _mapPreOperateGraph  = _mapCurrentGraph;
        requestNodeGraph(_mapVehicleWorldLocId);
    } else {
        _mapOperateVehicleId = null;
        _mapVehicleBaselineGraph = null;
        if (_mapPreOperateGraph) {
            _mapCurrentGraph = _mapPreOperateGraph;
            _buildMapFromGraph(_mapPlayerLocId, _mapCurrentGraph);
        }
        _mapPreOperateGraph = null;
    }
}

function _buildMapFromGraph(focusId, graph, root) {
    if (!root) root = document.getElementById('ae-ui-root');
    var canvas = _getCanvasRoot(root);
    var playerLocId = _mapPlayerLocId || focusId;

    var nodes = [{
        id: focusId, name: graph.currentName || focusId,
        type: graph.currentType || 'location', direction: 'current',
        icon: graph.currentIcon || undefined,
        gated: !!graph.currentGated, isVehicle: !!graph.currentIsVehicle,
        requiresVehicle: false, 
        resourceTag: graph.currentResourceTag || null, 
        resourceCost: graph.currentResourceCost || null, 
        resourceIcon: graph.currentResourceIcon || null,
        isSilent: false
    }];
    var edges = [];

    if (graph.parentId) {
        nodes.push({ id: graph.parentId, name: graph.parentName || '↑ Up',
            type: graph.parentType || 'location', direction: 'up',
            icon: graph.parentIcon || undefined,
            gated: false, isVehicle: false, requiresVehicle: false, resourceTag: null, isSilent: false });
        edges.push({ from: focusId, to: graph.parentId, kind: 'parent', gated: false, requiresVehicle: false, resourceTag: null, isSilent: false });
    }
    (graph.children || []).forEach(function(c) {
        var isVeh = !!c.isVehicle;
        nodes.push({ id: c.id, name: c.name, type: c.type || 'location',
            direction: isVeh ? 'vehicle' : 'down',
            hasChildren: !!c.hasChildren, icon: c.icon || undefined,
            gated: !!c.gated, isVehicle: isVeh, requiresVehicle: false,
            resourceTag: c.resourceTag || null,
            resourceCost: c.resourceCost || null,
            resourceIcon: c.resourceIcon || null,
            isSilent: false });
        edges.push({ from: focusId, to: c.id, kind: isVeh ? 'vehicle-child' : 'child', gated: !!c.gated, requiresVehicle: false,
            resourceTag: c.resourceTag || null,
            resourceIcon: c.resourceIcon || null, // [v0.9.17 FIX2]
            isSilent: false });
    });
    (graph.connections || []).forEach(function(c) {
        if (nodes.find(function(n) { return n.id === c.id; })) return;
        nodes.push({ id: c.id, name: c.label || c.name, type: c.type || 'location',
            direction: 'connection', icon: c.icon || undefined,
            gated: !!c.gated, isVehicle: false,
            requiresVehicle: !!c.requiresVehicle,
            resourceTag: c.resourceTag || null,
            resourceCost: c.resourceCost || null,
            resourceIcon: c.resourceIcon || null,
            isSilent: !!c.isSilent });
        edges.push({ from: focusId, to: c.id, kind: 'explicit',
            oneWay: !!c.oneWay, gated: !!c.gated,
            requiresVehicle: !!c.requiresVehicle,
            resourceTag: c.resourceTag || null,
            resourceIcon: c.resourceIcon || null, // [v0.9.17 FIX2]
            isSilent: !!c.isSilent });
    });

    // [v0.9.89] Inject siblings into the node graph for Orbital HUD
    (graph.siblings || []).forEach(function(s) {
        if (nodes.find(function(n) { return n.id === s.id; })) return;
        nodes.push({ id: s.id, name: s.name, type: s.type || 'location',
            direction: 'sibling', icon: s.icon || undefined,
            gated: !!s.gated, isVehicle: false, requiresVehicle: false,
            resourceTag: s.resourceTag || null,
            resourceCost: s.resourceCost || null,
            resourceIcon: s.resourceIcon || null,
            isSilent: false });
        edges.push({ from: focusId, to: s.id, kind: 'sibling', gated: !!s.gated, requiresVehicle: false,
            resourceTag: s.resourceTag || null, resourceIcon: s.resourceIcon || null, isSilent: false });
    });

    _layoutAndBuildMap(canvas, nodes, edges, focusId, playerLocId);
}

function _layoutAndBuildMap(canvas, nodes, edges, currentId, playerLocId) {
    playerLocId = playerLocId || currentId;
    if (!canvas) return;
    canvas.innerHTML = '';

    var svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('class', 'ae-map-lines');
    var posMap = {};

    // Layout — Orbital HUD / Tactical Radar Pattern
    // Customizable radii to allow Theme Forge scaling
    // Responsive Scaling to prevent excessive width on mobile
    var vpContainer = canvas.closest('#ae-map-viewport');
    var viewportWidth = vpContainer ? vpContainer.clientWidth : window.innerWidth;
    var scale = viewportWidth < 768 ? Math.max(0.4, viewportWidth / 768) : 1.0;

    var R_VEHICLE = 58;
    var R_CHILD = 130;
    var R_SIBLING = 220;
    var R_EXPLICIT = 300;
    var R_PARENT = 340;

    var byDir = { up: [], down: [], connection: [], current: [], vehicle: [], sibling: [] };
    nodes.forEach(function(n) { (byDir[n.direction] || byDir.connection).push(n); });

    byDir.current.forEach(function(n) { posMap[n.id] = { x: 0, y: 0 }; });
    
    byDir.up.forEach(function(n) { 
        posMap[n.id] = { x: 0, y: -R_PARENT }; 
    });
    
    // [v0.9.9.9] Children ('down') used to all cram into one fixed 90 arc at one
    // fixed radius (R_CHILD), so past ~5-6 nodes they started overlapping — the
    // arc had a hard ceiling on how many nodes it could hold. Now: fill the
    // innermost ring first at a narrow 90 arc (visually identical to the old
    // behavior for small families); once a ring can't fit everyone at 90, widen
    // that ring's arc in steps (still centered straight down) up to ~288, which
    // leaves a gap near the top so children never crowd the parent connector or
    // the 'up' node. Only once a ring is at max arc AND still over capacity does
    // layout step out to the next radius and start a new ring — so nodes are
    // added starting from the lowest/innermost reaches and gradually work
    // outward and around, never touching the sibling track ring.
    (function layoutChildFan() {
        var list = byDir.down;
        var cnt = list.length;
        if (!cnt) return;

        var NODE_ARC_PX  = 62;              // approx angular footprint of one node + gutter
        var RING_STEP     = 46;             // radius added per extra ring
        var CENTER_ANGLE  = Math.PI / 2;    // straight down
        var MIN_ARC       = Math.PI * 0.5;  // 90, matches the old fixed fan
        var MAX_ARC       = Math.PI * 1.6;  // 288 - gap stays near the parent connector at top
        var MAX_R         = R_SIBLING - 40; // never crowd the sibling track ring

        var rings = [];
        var r = R_CHILD;
        var remaining = cnt;
        while (remaining > 0 && r <= MAX_R) {
            var circumference = 2 * Math.PI * r;
            var capacityFullCircle = Math.max(1, Math.floor(circumference / NODE_ARC_PX));
            var arc = MIN_ARC;
            var capacity = Math.max(1, Math.floor((arc / (Math.PI * 2)) * capacityFullCircle));
            while (capacity < Math.min(remaining, capacityFullCircle) && arc < MAX_ARC) {
                arc = Math.min(MAX_ARC, arc + Math.PI * 0.15);
                capacity = Math.max(1, Math.floor((arc / (Math.PI * 2)) * capacityFullCircle));
            }
            capacity = Math.min(capacity, remaining, capacityFullCircle);
            rings.push({ r: r, arc: arc, count: capacity });
            remaining -= capacity;
            r += RING_STEP;
        }
        // Pathological overflow (hit MAX_R with nodes still left): pile the rest
        // onto the outermost ring at full arc rather than dropping them.
        if (remaining > 0 && rings.length) {
            rings[rings.length - 1].count += remaining;
            rings[rings.length - 1].arc = MAX_ARC;
        }

        var idx = 0;
        rings.forEach(function(ring) {
            var n = ring.count;
            for (var i = 0; i < n; i++) {
                var t = n === 1 ? 0.5 : i / (n - 1);
                var angle = CENTER_ANGLE - ring.arc / 2 + ring.arc * t;
                var node = list[idx++];
                posMap[node.id] = { x: Math.round(Math.cos(angle) * ring.r), y: Math.round(Math.sin(angle) * ring.r) };
            }
        });

        // Faint extra ring track for each additional tier beyond the first, so
        // the layout reads as intentional "orbits" rather than random scatter.
        for (var ri = 1; ri < rings.length; ri++) {
            var extraTrack = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
            extraTrack.setAttribute('cx', '2000');
            extraTrack.setAttribute('cy', '2000');
            extraTrack.setAttribute('r', String(rings[ri].r));
            extraTrack.setAttribute('class', 'ae-map-orbital-ring child-tier');
            svg.appendChild(extraTrack);
        }
    })();

    byDir.sibling.forEach(function(n, i) {
        var cnt = byDir.sibling.length;
        // Distribute siblings evenly around the ring, offset to avoid exact top/bottom overlap
        var angle = (Math.PI * 2) * (i / cnt) + 0.5;
        posMap[n.id] = { x: Math.round(Math.cos(angle) * R_SIBLING), y: Math.round(Math.sin(angle) * R_SIBLING) };
    });

    byDir.connection.forEach(function(n, i) {
        var cnt = byDir.connection.length;
        // Explicit connections scattered on the outer rim (top-rightish quadrant)
        var angle = Math.PI * 1.75 - (i * 0.3);
        posMap[n.id] = { x: Math.round(Math.cos(angle) * R_EXPLICIT), y: Math.round(Math.sin(angle) * R_EXPLICIT) };
    });

    byDir.vehicle.forEach(function(n, i) {
        var cnt = byDir.vehicle.length;
        var angle = Math.PI * 0.55 + (i / Math.max(cnt, 1)) * Math.PI * 0.9;
        posMap[n.id] = { x: Math.round(Math.cos(angle) * R_VEHICLE), y: Math.round(Math.sin(angle) * R_VEHICLE) };
    });

    // --- DRAW ORBITAL RINGS ---
    // Sibling Track Ring
    if (byDir.sibling.length > 0) {
        var sibTrack = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
        sibTrack.setAttribute('cx', '2000');
        sibTrack.setAttribute('cy', '2000');
        sibTrack.setAttribute('r', String(R_SIBLING));
        sibTrack.setAttribute('class', 'ae-map-orbital-ring sibling-track');
        svg.appendChild(sibTrack);
    }

    // Parent/Outer Decorative Ring
    if (byDir.up.length > 0 || byDir.down.length > 0) {
        var outerTrack = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
        outerTrack.setAttribute('cx', '2000');
        outerTrack.setAttribute('cy', '2000');
        outerTrack.setAttribute('r', String(R_PARENT));
        outerTrack.setAttribute('class', 'ae-map-orbital-ring');
        svg.appendChild(outerTrack);
    }

    function midIcon(from, to, icon) {
        var ox = (from.x + to.x) / 2 + 2000, oy = (from.y + to.y) / 2 + 2000;
        var iconSvg;
        if (icon === '🔒')      iconSvg = $.svg('inspect', 14); // Or lock
        else if (icon === '🚢') iconSvg = $.svg('inspect', 14); // Or vehicle
        else if (icon.startsWith('<svg') || icon.startsWith('<path')) {
            // It's raw markup
            var temp = document.createElement('div'); temp.innerHTML = icon;
            iconSvg = temp.firstElementChild;
        } else {
            // Assume it's a known name or a fallback emoji
            var svgIcon = $.svg(icon, 14);
            if (svgIcon) {
                iconSvg = svgIcon;
            } else {
                iconSvg = document.createElementNS('http://www.w3.org/2000/svg', 'text');
                iconSvg.textContent = icon;
                iconSvg.setAttribute('font-size', '12');
                iconSvg.setAttribute('text-anchor', 'middle');
                iconSvg.setAttribute('dominant-baseline', 'central');
            }
        }
        
        if (iconSvg && typeof iconSvg.setAttribute === 'function') {
            if (iconSvg.tagName === 'text') {
                iconSvg.setAttribute('x', String(ox));
                iconSvg.setAttribute('y', String(oy));
            } else {
                iconSvg.setAttribute('x', String(ox - 7));
                iconSvg.setAttribute('y', String(oy - 7));
                iconSvg.setAttribute('width', '14');
                iconSvg.setAttribute('height', '14');
            }
            svg.appendChild(iconSvg);
        }
    }

    // Edges — class composition + condition midpoint icons
    edges.forEach(function(e) {
        if (e.kind === 'sibling') return; // Orbital HUD uses the Sibling Track ring instead of explicit lines

        var from = posMap[e.from]; var to = posMap[e.to];
        if (!from || !to) return;
        var line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
        line.setAttribute('x1', String(from.x + 2000)); line.setAttribute('y1', String(from.y + 2000));
        line.setAttribute('x2', String(to.x   + 2000)); line.setAttribute('y2', String(to.y   + 2000));
        var cls = 'ae-map-line ' + (e.kind || '');
        if (e.gated)           cls += ' locked';
        if (e.requiresVehicle) cls += ' vehicle';
        if (e.resourceTag)     cls += ' resource-cost';
        if (e.isSilent)        cls += ' silent';
        line.setAttribute('class', cls);
        svg.appendChild(line);
        if (e.oneWay) {
            var ox = (from.x + to.x) / 2 + 2000, oy = (from.y + to.y) / 2 + 2000;
            var dot = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
            dot.setAttribute('cx', String(ox)); dot.setAttribute('cy', String(oy)); dot.setAttribute('r', '4');
            dot.setAttribute('fill', 'var(--ae-accent)'); dot.setAttribute('opacity', '0.6');
            svg.appendChild(dot);
        }
        if (e.gated)                midIcon(from, to, '🔒');
        else if (e.requiresVehicle) midIcon(from, to, '🚢');
        else if (e.resourceTag)     midIcon(from, to, e.resourceIcon || '⛽️'); // [v0.9.15] B4: dynamic icon
    });
    canvas.appendChild(svg);

    nodes.forEach(function(node) {
        var pos = posMap[node.id];
        if (!pos) return;
        var isVehicleNode = !!node.isVehicle;
        var isAdj = _isAdjacentNode(node.id);

        var div = document.createElement('div');
        var cls = 'ae-node';
        if (node.id === currentId)      cls += ' current';
        if (node.id === playerLocId)    cls += ' player-loc';
        if (node.id === _mapSelectedId) cls += ' focused';
        if (node.gated)                 cls += ' ae-node-locked';
        if (isVehicleNode)              cls += ' ae-node-vehicle';
        if (!isAdj && node.id !== currentId && node.id !== playerLocId) cls += ' ae-node-browse';
        div.className = cls;
        div.style.left = pos.x + 'px'; div.style.top = pos.y + 'px';
        if (isVehicleNode) { div.style.width = '58px'; div.style.height = '58px'; }

        var icon = document.createElement('span');
        icon.className = 'ae-node-icon';
        icon.style.display = 'flex';
        icon.style.alignItems = 'center';
        icon.style.justifyContent = 'center';
            
        // [v0.9.9.11] Resolve the node icon against the designated library (CyberIcons,
        // AEFillIcons, and active-theme overrides, via _aeIconExists): a library name ->
        // SVG (stroke or fill family, whichever resolves it); an empty icon -> the type's
        // default library icon; any other value -> emoji/glyph rendered in full.
        var rawNodeIcon = node.icon ? String(node.icon).trim() : '';
        var typeIconName = MAP_ICONS[node.type] || MAP_ICONS.default;
        if (rawNodeIcon && _aeIconExists(rawNodeIcon)) {
            icon.appendChild(createCyberIcon(rawNodeIcon, isVehicleNode ? 16 : 24, 'currentColor'));
        } else if (!rawNodeIcon && _aeIconExists(typeIconName)) {
            icon.appendChild(createCyberIcon(typeIconName, isVehicleNode ? 16 : 24, 'currentColor'));
        } else {
            // Emoji / glyph icon (or an unresolved name): render the value in full.
            icon.style.fontSize = isVehicleNode ? '16px' : '22px';
            icon.textContent = rawNodeIcon || (typeIconName && typeIconName.charAt(0)) || '?';
        }
        div.appendChild(icon);

        div.appendChild(document.createTextNode(node.name));

        if (node.direction !== 'current') {
            var dirEl = document.createElement('div');
            dirEl.className = 'ae-node-dir';
            dirEl.textContent = node.direction === 'up'     ? '↑ parent'
                              : node.direction === 'vehicle' ? '🚗 vehicle'
                              : node.direction === 'down'    ? (node.hasChildren ? '↓ ▸' : '↓ child')
                              : '';
            if (dirEl.textContent) div.appendChild(dirEl);
        }

        if (node.gated) {
            var badge = document.createElement('div');
            badge.style.cssText = 'position:absolute;top:-5px;right:-5px;font-size:11px;line-height:1;pointer-events:none;';
            badge.textContent = '🔒';
            div.appendChild(badge);
        }

        div.addEventListener('click', (function(captNode, captPos, captPlayerLocId) { return function() {
            _mapSelectedId = captNode.id;
            canvas.querySelectorAll('.ae-node').forEach(function(n) { n.classList.remove('focused'); });
            div.classList.add('focused');
            canvas.classList.remove('dragging');
            canvas.classList.add('gliding');
            canvas.style.transform = 'translate(' + (-captPos.x) + 'px,' + (-captPos.y) + 'px)';
            _mapPanX = -captPos.x; _mapPanY = -captPos.y;

            if (captNode.id !== currentId) {
                clearTimeout(_mapGlideTimer);
                _mapGlideTimer = setTimeout(function() { requestNodeGraph(captNode.id); }, 750);
            }

            // [Phantom Widget Context Support] Look locally before falling back to UI root
            var rt = canvas.closest('.ae-phantom-widget') || document.getElementById('ae-ui-root');
            var ctrlPanel    = rt && rt.querySelector('#ae-node-controls');
            var ctrlName     = rt && rt.querySelector('#ae-ctrl-name');
            var inspectBtn   = rt && rt.querySelector('#ae-ctrl-inspect');
            var teleportCtrl = rt && rt.querySelector('#ae-ctrl-teleport');
            if (!ctrlPanel) return;
            ctrlPanel.style.display = 'flex';

            var isHere       = captNode.id === captPlayerLocId;
            var isAdjHere    = _isAdjacentNode(captNode.id);
            var nodeLocked   = !!captNode.gated;

            var nameLabel = captNode.name;
            if (isHere)         nameLabel += ' — [ HERE ]';
            else if (!isAdjHere) nameLabel += ' — [ BROWSE ]';
            else if (nodeLocked) nameLabel += ' — [ LOCKED ]';
            if (ctrlName) ctrlName.textContent = nameLabel;

            // [BATCH1 v2.1.4] Dead Travel/Ride button block removed. It sent
            // AE_TRAVEL_REQUEST / AE_VEHICLE_TRAVEL_REQUEST -- both removed engine-side
            // back in CE-STRIP pass 2 (see adventure-engine's own CE-INDEX) -- so tapping
            // it did nothing. Teleport (below) is the only actionable map control now.
            // _mapOperateMode / the vehicle-operate graph view / the separate "Operate"
            // toggle button elsewhere are UNTOUCHED -- out of scope for this fix, flagging
            // in case they're a future cleanup target of their own.

            if (teleportCtrl) {
                var showTp = !isHere && isAdjHere && !nodeLocked;
                teleportCtrl.style.display = showTp ? '' : 'none';
                if (showTp) teleportCtrl.onclick = function() {
                    // [v2.29.0 TELEPORT-KEEP-HUD, per user] Do NOT tear down the phantom
                    // widget on teleport. The engine's commitTravel() ends in
                    // queueSceneStateBroadcast() (character-engine commitTravel), so the
                    // SCENE_STATE_UPDATE receipt repaints the live map in place with the new
                    // [HERE] — destroying the widget here just kicked the user out of the map
                    // they were navigating. Hiding the node-control panel gives immediate
                    // feedback until that repaint lands; the destination becomes HERE and its
                    // Teleport button hides on the next render anyway.
                    sendToEngine('AE_SILENT_TELEPORT', { targetId: captNode.id });
                    if (ctrlPanel) ctrlPanel.style.display = 'none';
                };
            }
            // [FEATURE] Was _showLocationInspect (a small text-only popup layered
            // over the map) -- now opens the full location sheet (image + Present/
            // Lorebook/Gallery tabs), the same phantom-widget treatment characters
            // already get. _showLocationInspect had exactly one caller (this button) --
            // deleted below rather than left dead; see CE-INDEX for the AE_INSPECT_LOCATION/
            // AE_INSPECT_RESPONSE engine-side plumbing this orphans.
            if (inspectBtn) inspectBtn.onclick = function() { _focusLocation(captNode.id); };
        }; })(node, pos, playerLocId));

        canvas.appendChild(div);
    });

    // [FIX WP-3] Disable transition for initial re-center; CSS easing restored after reflow.
    _mapPanX = 0; _mapPanY = 0;
    canvas.classList.remove('gliding');
    canvas.style.transition = 'none';
    canvas.style.transform = 'translate(0,0)';
    void canvas.offsetWidth;
    canvas.style.transition = '';
}

function _getCanvasRoot(root) {
    root = root || document.getElementById('ae-ui-root');
    if (!root) return null;
    var canvas = root.querySelector('#ae-map-canvas');
    if (!canvas) {
        // Map DOM was destroyed (e.g. by a placeholder). Rebuild it.
        var tab = root.querySelector('#ae-tab-map');
        if (!tab) return null;
        tab.style.padding = '0';
        tab.innerHTML = [
            '<div id="ae-map-viewport">',
              '<div id="ae-map-canvas" style="position:absolute;top:50%;left:50%;width:0;height:0;transition:transform 0.4s cubic-bezier(0.2,0.8,0.2,1);"></div>',
              '<div id="ae-node-controls" style="position:absolute;bottom:10px;left:10px;right:10px;background:rgba(19,19,24,0.92);backdrop-filter:blur(4px);padding:10px;border-radius:6px;border:1px solid var(--ae-bg-border);display:none;flex-direction:column;gap:6px;z-index:10;">',
                '<div id="ae-ctrl-name" class="ae-node-ctrl-name">Select a location</div>',
                '<div class="ae-btn-row">',
                  '<button class="ae-btn sm primary" id="ae-ctrl-inspect">' + $.svg('inspect', 14).outerHTML + ' Inspect</button>',
                  '<button class="ae-btn sm ghost"   id="ae-ctrl-teleport" style="display:none;" title="Teleport silently — no story text generated">' + $.svg('teleport', 14).outerHTML + ' Teleport</button>',
                '</div>',
              '</div>',
            '</div>'
        ].join('');
        setupMapPan(root);
        canvas = root.querySelector('#ae-map-canvas');
    }
    return canvas;
}

// =============================================================================
// SECTION 12 — ENTITIES TAB (🔎)
// Full roster grid: all characters from cachedCharVisuals with presence indicator.
// Equipment section below. Narratives at bottom.
// Chat functions wired but overlay is a stub for now.
// =============================================================================

// [v1.2.0] Add-Entity popup (minor NPC or item) for the Inspect tab. Mirrors the
// native HUD's Add-Minor-NPC / Add-Item modals: pick a template, type name + text,
// optionally Generate-from-Scene (engine round-trip via AE_HUD_GEN_ENTITY /
// AE_HUD_GEN_RESULT), then Create (AE_HUD_SPAWN_ENTITY). The engine re-broadcasts
// scene state on spawn, so the tab refreshes itself.
//
// [v1.4.0 LOCGEN] >>> PAIRED with _showAddLocationPopup(), directly below: same overlay
// >>> chrome, same generate-then-create round-trip, different payload. If you restyle or
// >>> restructure one popup, do the other in the same patch — they are meant to look and
// >>> behave identically. Their engine handlers are likewise adjacent (Section 18).
var _addEntityPopup = null; // { kind, nameEl, descEl, genBtn }

function _showAddEntityPopup(kind, parentCtx) {
    // [CE-STRIP vNEXT] Archetype/template picker removed — npcArchetypes/itemArchetypes
    // no longer exist on SceneStatePayload (engine's Bestiary + Item Templates cut, and
    // the minor-NPC tier retired). Freeform name + description only now.
    //
    // [FEATURE v2.1.8] parentCtx = { entityId, label }. When provided (the character
    // Drama tray's "+ Add Item", or a location sheet's "+ Add Character/Item Here"),
    // the new entity is parented directly to that entityId instead of the current
    // room. [BUGFIX] The old comment here said "item-only", but locId resolution
    // below was never actually gated by kind — spawnSceneNpc accepts an explicit
    // parent the same way spawnItem does (engine Section 19/12626). Only the
    // sub-text three lines down was hardcoded to "at the current location" for
    // characters regardless of parentCtx — a display bug, not a functional one.
    var isItem = kind === 'item';
    var st = lastSceneState || {};
    var locId = (parentCtx && parentCtx.entityId) ? parentCtx.entityId : (st.locationId || null);

    var ovl = document.createElement('div');
    ovl.style.cssText = 'position:fixed;inset:0;z-index:var(--ae-z-popover);background:rgba(0,0,0,0.72);display:flex;align-items:center;justify-content:center;';
    var card = document.createElement('div');
    card.style.cssText = 'background:var(--ae-bg-panel);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius);padding:18px 20px;max-width:420px;width:92%;box-shadow:var(--ae-shadow);max-height:88vh;overflow-y:auto;';

    var ttl = document.createElement('div');
    ttl.style.cssText = 'font-size:14px;font-weight:600;margin-bottom:4px;color:var(--ae-accent);';
    ttl.textContent = isItem ? 'Add Item' : 'Add Character';
    card.appendChild(ttl);

    var sub = document.createElement('div');
    sub.style.cssText = 'font-size:11px;color:var(--ae-text-muted);margin-bottom:12px;line-height:1.5;';
    sub.textContent = isItem
        ? (parentCtx ? ('A new item, created directly into ' + (parentCtx.label || 'this character') + '\u2019s equipment.') : 'A quick drop-in item at the current location. Name plus what it is; it lands loose here, ready to pick up.')
        : (parentCtx ? ('A new character, created directly into ' + (parentCtx.label || 'this location') + '.') : 'A quick drop-in character at the current location. Name plus what they are doing here — an ordinary character like any other, just fast to create.');
    card.appendChild(sub);

    var nameEl = document.createElement('input'); nameEl.type = 'text';
    nameEl.placeholder = isItem ? 'Name' : 'Name';
    nameEl.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-base);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-sm);color:var(--ae-text-main);font-size:13px;font-family:inherit;padding:8px 10px;margin-bottom:8px;';
    card.appendChild(nameEl);

    var descEl = document.createElement('textarea'); descEl.rows = 2;
    descEl.placeholder = isItem ? 'What is it?' : 'What are they doing here?';
    descEl.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-base);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-sm);color:var(--ae-text-main);font-size:13px;font-family:inherit;padding:8px 10px;resize:vertical;margin-bottom:10px;';
    card.appendChild(descEl);

    var genBtn = $.btn('\u2728 Generate from Scene', 'ghost', function() {
        genBtn.disabled = true; genBtn.textContent = 'Generating\u2026';
        sendToEngine('AE_HUD_GEN_ENTITY', { kind: kind });
    });
    genBtn.style.cssText += ';width:100%;margin-bottom:10px;';
    card.appendChild(genBtn);

    var btnRow = document.createElement('div'); btnRow.style.cssText = 'display:flex;gap:8px;';
    var _done = false;
    function closePopup() { if (_done) return; _done = true; _addEntityPopup = null; ovl.remove(); }
    var cancelBtn = $.btn('Cancel', 'ghost', function() { closePopup(); }); cancelBtn.style.flex = '1';
    var createBtn = $.btn(isItem ? 'Create Item' : 'Create Character', 'primary', function() {
        var nm = (nameEl.value || '').trim();
        if (!nm) { _showToast('Name required.'); return; }
        sendToEngine('AE_HUD_SPAWN_ENTITY', { kind: kind, name: nm, brief: (descEl.value || '').trim(), locId: locId });
        closePopup();
    });
    createBtn.style.flex = '1';
    btnRow.appendChild(cancelBtn); btnRow.appendChild(createBtn);
    card.appendChild(btnRow);

    ovl.appendChild(card);
    ovl.addEventListener('click', function(e) { if (e.target === ovl) closePopup(); });
    document.body.appendChild(ovl);
    try { nameEl.focus(); } catch (_e) {}

    _addEntityPopup = { kind: kind, nameEl: nameEl, descEl: descEl, genBtn: genBtn };
}

function _addEntityBtn(kind, parentCtx) {
    var b = $.btn(kind === 'item' ? '+ Add Item' : '+ Add Character', 'ghost sm', function() { _showAddEntityPopup(kind, parentCtx); });
    b.style.cssText += ';width:100%;margin-bottom:6px;';
    return b;
}

// [v1.4.0 LOCGEN] Add-Location popup, launched from the Map tab's "+ Location" button.
// Deliberately the spatial twin of _showAddEntityPopup above — keep them side by side.
//
// The only structural choice the player makes is RELATION:
//   sibling  a place ALONGSIDE the current one, same tier (parentId = current's parent)
//   child    a place INSIDE the current one, one tier down (parentId = current's id)
// Everything else (gating, entry cost, vehicle flags) is left blank and edited in the
// engine's entity editor, exactly as the world-build wizard's batch path leaves it.
//
// Generation round-trip: AE_HUD_GEN_LOCATION -> AE_HUD_GEN_LOCATION_RESULT (Section 6).
// Create: AE_HUD_SPAWN_LOCATION. The engine re-broadcasts scene state on create, so the
// new node paints itself onto the map with no explicit refresh here.
var _addLocationPopup = null; // { nameEl, descEl, loreEl, genBtn }

function _showAddLocationPopup() {
    var st = lastSceneState || {};
    var refLocId   = st.locationId || null;
    var refLocName = st.locationName || 'here';
    var parentName = (st.locationGraph && st.locationGraph.parentName) ? st.locationGraph.parentName : '';
    if (!refLocId) { _showToast('No current location to build from.'); return; }

    var relation = 'sibling';

    var ovl = document.createElement('div');
    ovl.style.cssText = 'position:fixed;inset:0;z-index:var(--ae-z-popover);background:rgba(0,0,0,0.72);display:flex;align-items:center;justify-content:center;';
    var card = document.createElement('div');
    card.style.cssText = 'background:var(--ae-bg-panel);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius);padding:18px 20px;max-width:460px;width:92%;box-shadow:var(--ae-shadow);max-height:88vh;overflow-y:auto;';

    var ttl = document.createElement('div');
    ttl.style.cssText = 'font-size:14px;font-weight:600;margin-bottom:4px;color:var(--ae-accent);';
    ttl.textContent = 'New Location';
    card.appendChild(ttl);

    var sub = document.createElement('div');
    sub.style.cssText = 'font-size:11px;color:var(--ae-text-muted);margin-bottom:12px;line-height:1.5;';
    sub.textContent = 'Author a place relative to ' + refLocName + '. It gets a name, a scene description, and a lorebook entry.';
    card.appendChild(sub);

    // ── Relation toggle ──
    var relLbl = document.createElement('div');
    relLbl.style.cssText = 'font-size:11px;color:var(--ae-text-muted);margin-bottom:4px;';
    relLbl.textContent = 'Where does it sit?';
    card.appendChild(relLbl);

    var relRow = document.createElement('div');
    relRow.style.cssText = 'display:flex;gap:6px;margin-bottom:6px;';
    var sibBtn = document.createElement('button');
    var kidBtn = document.createElement('button');
    var relHint = document.createElement('div');
    relHint.style.cssText = 'font-size:10px;color:var(--ae-text-muted);opacity:0.75;margin-bottom:10px;line-height:1.5;min-height:26px;';

    function _relStyle(b, on) {
        b.className = 'ae-btn sm';
        b.style.cssText = 'flex:1 1 0;font-size:11px;padding:7px 8px;'
            + 'background:' + (on ? 'rgba(137,180,250,0.20);' : 'transparent;')
            + 'border:1px solid ' + (on ? 'var(--ae-accent);' : 'var(--ae-bg-border);')
            + 'color:' + (on ? 'var(--ae-accent);' : 'var(--ae-text-main);');
    }
    function _paintRelation() {
        _relStyle(sibBtn, relation === 'sibling');
        _relStyle(kidBtn, relation === 'child');
        relHint.textContent = (relation === 'sibling')
            ? ('Same tier as ' + refLocName + (parentName ? ', also inside ' + parentName : ', at the top level of the world') + '. Reachable from here without going up first.')
            : ('One tier down, contained within ' + refLocName + '. Entered from here.');
    }
    sibBtn.textContent = 'Beside — same tier';
    kidBtn.textContent = 'Inside — contained here';
    sibBtn.addEventListener('click', function() { relation = 'sibling'; _paintRelation(); });
    kidBtn.addEventListener('click', function() { relation = 'child'; _paintRelation(); });
    relRow.appendChild(sibBtn); relRow.appendChild(kidBtn);
    card.appendChild(relRow);
    card.appendChild(relHint);
    _paintRelation();

    // ── Direction for the generator ──
    var sugEl = document.createElement('input'); sugEl.type = 'text';
    sugEl.placeholder = 'Steer the generator (optional) — e.g. "a flooded undercroft"';
    sugEl.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-base);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-sm);color:var(--ae-text-main);font-size:13px;font-family:inherit;padding:8px 10px;margin-bottom:8px;';
    card.appendChild(sugEl);

    var genBtn = $.btn('\u2728 Generate from Story', 'ghost', function() {
        genBtn.disabled = true; genBtn.textContent = 'Generating\u2026';
        sendToEngine('AE_HUD_GEN_LOCATION', { relation: relation, refLocId: refLocId, suggestion: (sugEl.value || '').trim() });
    });
    genBtn.style.cssText += ';width:100%;margin-bottom:12px;';
    card.appendChild(genBtn);

    // ── Fields ──
    var nameEl = document.createElement('input'); nameEl.type = 'text';
    nameEl.placeholder = 'Name';
    nameEl.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-base);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-sm);color:var(--ae-text-main);font-size:13px;font-family:inherit;padding:8px 10px;margin-bottom:8px;';
    card.appendChild(nameEl);

    var descEl = document.createElement('textarea'); descEl.rows = 2;
    descEl.placeholder = 'Description — what a camera senses on arrival. No history.';
    descEl.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-base);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-sm);color:var(--ae-text-main);font-size:13px;font-family:inherit;padding:8px 10px;resize:vertical;margin-bottom:8px;';
    card.appendChild(descEl);

    var loreEl = document.createElement('textarea'); loreEl.rows = 5;
    loreEl.placeholder = 'Lorebook entry — history, significance, culture, tensions. Blank = no lorebook entry.';
    loreEl.style.cssText = 'width:100%;box-sizing:border-box;background:var(--ae-bg-base);border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-sm);color:var(--ae-text-main);font-size:13px;font-family:inherit;padding:8px 10px;resize:vertical;margin-bottom:10px;';
    card.appendChild(loreEl);

    var btnRow = document.createElement('div'); btnRow.style.cssText = 'display:flex;gap:8px;';
    var _done = false;
    function closePopup() { if (_done) return; _done = true; _addLocationPopup = null; ovl.remove(); }
    var cancelBtn = $.btn('Cancel', 'ghost', function() { closePopup(); }); cancelBtn.style.flex = '1';
    var createBtn = $.btn('Create Location', 'primary', function() {
        var nm = (nameEl.value || '').trim();
        if (!nm) { _showToast('Name required.'); return; }
        sendToEngine('AE_HUD_SPAWN_LOCATION', {
            relation: relation,
            refLocId: refLocId,
            name: nm,
            description: (descEl.value || '').trim(),
            lore: (loreEl.value || '').trim()
        });
        closePopup();
    });
    createBtn.style.flex = '1';
    btnRow.appendChild(cancelBtn); btnRow.appendChild(createBtn);
    card.appendChild(btnRow);

    ovl.appendChild(card);
    ovl.addEventListener('click', function(e) { if (e.target === ovl) closePopup(); });
    document.body.appendChild(ovl);
    try { nameEl.focus(); } catch (_e) {}

    // No `relation` cached here on purpose: it is read live at click time, and a
    // snapshot taken at render time is exactly the stale-closure bug class we keep hitting.
    _addLocationPopup = { nameEl: nameEl, descEl: descEl, loreEl: loreEl, genBtn: genBtn };
}

// [FEATURE v2.22.0 ROSTER-BANNER, per user report "there is still a separate view of the
// scene presence... it does not include the background image and location information"]
// Verified this was real and pre-existing, not introduced by v2.19.1/v2.20.0 (see the
// CE-INDEX "BUG FOUND, NOT FIXED, v2.21.0" entry this supersedes for the trace). Reuses
// _resolveLocationPlateImage's exact fallback chain (portrait -> module defaultBgUrl) --
// one image-resolution rule for "this location has no portrait", not two.
function _buildRosterLocationBanner(tab, state) {
    if (!state || !state.locationId) return;
    var banner = document.createElement('div'); banner.className = 'ae-roster-banner';
    var overlay = document.createElement('div'); overlay.className = 'ae-scene-overlay';
    var text = document.createElement('div'); text.className = 'ae-roster-banner-text';
    var title = document.createElement('div'); title.className = 'ae-roster-banner-title';
    title.textContent = (state.locationName || '\u2014').toUpperCase();
    var desc = document.createElement('div'); desc.className = 'ae-scene-desc';
    desc.textContent = [state.locationDescription, state.locationAtmosphere].filter(Boolean).join('  ');
    if (!desc.textContent) desc.style.display = 'none';
    text.appendChild(title); text.appendChild(desc);
    banner.appendChild(overlay); banner.appendChild(text);
    tab.appendChild(banner);
    var _bannerLocId = state.locationId;
    _resolveLocationPlateImage(_bannerLocId).then(function(url) {
        if (url && _bannerLocId === state.locationId) banner.style.backgroundImage = 'url(' + JSON.stringify(url) + ')';
    }).catch(function() {});
}

function _renderSceneTab(root, state) {
    var tab = root.querySelector('#ae-tab-scene');
    if (!tab) return;
    tab.innerHTML = '';

    if (_focusedEntityId) {
        _renderFocusedEntityDetails(tab, _focusedEntityId, state);
        return;
    }

    _buildRosterLocationBanner(tab, state);

    var presentIds = new Set((state.presentCharacters || []).map(function(c) { return c.id; }));

    // ── Full Roster Grid ────────────────────────────────────────────────────
    // Exclude protagonist from the roster grid — they appear in the Hub tab portrait.
    var _protagId = ((state.presentCharacters || []).find(function(c) { return c.isProtagonist; }) || {}).id;
    var allChars = cachedCharVisuals.filter(function(v) { return v.name && v.name.trim() && v.id !== _protagId; });
    tab.appendChild(_addEntityBtn('npc'));
    if (allChars.length > 0) {
        // Section header with filter toggle
        var hdrRow = document.createElement('div');
        hdrRow.style.cssText = 'display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;';
        hdrRow.appendChild($.label('Characters (' + allChars.length + ')'));
        var refreshBtn = document.createElement('button');
        refreshBtn.style.cssText = 'background:none;border:none;color:var(--ae-text-muted);font-size:11px;cursor:pointer;padding:2px 6px;';
        refreshBtn.textContent = '\u27f3 Detect';
        refreshBtn.title = 'Re-detect who is co-located with the player';
        refreshBtn.addEventListener('click', function() { sendToEngine('AE_REFRESH_PRESENCE', {}); _showToast('\u27f3 Refreshing scene presence\u2026'); });
        hdrRow.appendChild(refreshBtn);
        var filterBtn = document.createElement('button');
        filterBtn.style.cssText = 'background:none;border:none;color:var(--ae-text-muted);font-size:11px;cursor:pointer;padding:2px 6px;';
        var _sceneFilterOn = true;
        filterBtn.textContent = '👁 Scene';
        filterBtn.addEventListener('click', function() {
            _sceneFilterOn = !_sceneFilterOn;
            filterBtn.textContent = _sceneFilterOn ? '👁 Scene' : '🌐 All';
            renderGrid();
        });
        hdrRow.appendChild(filterBtn);
        tab.appendChild(hdrRow);

        var grid = $.avatarGrid();
        tab.appendChild(grid);

        function renderGrid() {
            grid.innerHTML = '';
            var toShow = _sceneFilterOn ? allChars.filter(function(v) { return presentIds.has(v.id); }) : allChars;
            if (toShow.length === 0) {
                var empty = document.createElement('div'); empty.style.cssText = 'color:var(--ae-text-dim);font-size:11px;grid-column:1/-1;padding:8px 0;'; empty.textContent = 'No characters in scene.'; grid.appendChild(empty); return;
            }
            toShow.forEach(function(vis) {
                var isPresent = presentIds.has(vis.id);
                var avatarBtn = $.avatar(vis.name, vis._avatarDataUrl, null,
                    isPresent ? 'npc' : '',
                    function() { _focusEntity(vis.id); }
                );
                if (isPresent) avatarBtn.style.borderColor = 'var(--ae-color-npc)';
                else avatarBtn.style.opacity = '0.65';
                // Cell wraps the avatar plus a scene-presence action button.
                var cell = document.createElement('div');
                cell.style.cssText = 'display:flex;flex-direction:column;align-items:stretch;gap:3px;';
                cell.appendChild(avatarBtn);
                var actBtn = document.createElement('button');
                if (isPresent) {
                    actBtn.textContent = 'Exclude';
                    actBtn.style.cssText = 'font-size:10px;padding:2px 4px;border-radius:4px;cursor:pointer;background:rgba(255,255,255,0.06);color:var(--ae-text-muted);border:1px solid rgba(255,255,255,0.15);';
                    actBtn.addEventListener('click', function(e) { e.stopPropagation(); sendToEngine('AE_SET_CHAR_PRESENT', { charId: vis.id, present: false }); });
                } else {
                    actBtn.textContent = '+ Add';
                    actBtn.style.cssText = 'font-size:10px;padding:2px 4px;border-radius:4px;cursor:pointer;background:rgba(126,200,160,0.15);color:#7ec8a0;border:1px solid rgba(126,200,160,0.3);';
                    actBtn.addEventListener('click', function(e) { e.stopPropagation(); sendToEngine('AE_MOVE_CHAR_TO_SCENE', { charId: vis.id }); });
                }
                cell.appendChild(actBtn);
                grid.appendChild(cell);
            });
        }
        renderGrid();
    } else {
        tab.appendChild($.label('No character data — waiting for sync.'));
    }

    tab.appendChild($.divider());

    // ── Equipment / Interactive entities ────────────────────────────────────
    var itemEnts = [];
    var seenItems = new Set();
    (state.availableActions || []).forEach(function(a) {
        if (!seenItems.has(a.entityId)) { seenItems.add(a.entityId); itemEnts.push(a); }
    });
    if (itemEnts.length > 0) {
        tab.appendChild($.label('Interactive'));
        itemEnts.forEach(function(ent) {
            tab.appendChild(_makeEntityBubble(ent, (ent.type === 'narrative' ? 'narrative' : 'item'), state));
        });
        tab.appendChild($.divider());
    }

    // [CE-STRIP vNEXT] "Present NPCs" section removed — presentMinorNpcs no longer
    // exists (minor-NPC tier retired). Those characters now appear in the Full Roster
    // Grid above like everyone else; the "+ Add Character" button moved up there too.

    // Items physically at the current location (not just those with action widgets)
    var sceneItems = (state.presentItems || []).filter(function(item) {
        // De-dup: skip items already shown in Interactive section via availableActions
        return !seenItems.has(item.id);
    });
    tab.appendChild($.label('Items (' + sceneItems.length + ')'));
    tab.appendChild(_addEntityBtn('item'));
    sceneItems.forEach(function(item) {
        tab.appendChild(_makeEntityBubble(item, 'item', state));
    });
    tab.appendChild($.divider());

    // ── Narratives ──────────────────────────────────────────────────────────
    var narratives = (state.activeNarratives || []).filter(function(n) { return n.parentId === state.locationId; });
    if (narratives.length > 0) {
        tab.appendChild($.label('Local Narratives'));
        narratives.forEach(function(n) {
            tab.appendChild(_makeEntityBubble(n, 'narrative', state));
        });
    }
}


function _renderEntityBubbleContent(body, detail, kind, state) {
    body.innerHTML = '';
    // [CE-STRIP vNEXT] isNpc / Promote-to-Major branch removed — its only source was
    // _makeEntityBubbleMinor (deleted, minor-NPC tier retired), and promoteMinorNpc()
    // no longer exists engine-side regardless.
    var isItem = (detail.type === 'item') || (kind === 'item' && detail.type !== 'narrative');
    var isNarr = (detail.type === 'narrative') || (kind === 'narrative');

    var descText = detail.description
        || (detail.narrative && detail.narrative.description)
        || 'No description.';
    var desc = document.createElement('div');
    desc.className = 'ae-eb-desc';
    desc.textContent = descText;
    body.appendChild(desc);

    if (detail.atmosphere) {
        var atm = document.createElement('div');
        atm.style.cssText = 'font-size:11px;color:var(--ae-text-muted);font-style:italic;';
        atm.textContent = 'Atmosphere: ' + detail.atmosphere;
        body.appendChild(atm);
    }

    if (isItem) {
        // [v0.9.84] Single equip toggle — no status label, no character picker.
        // ownerCharId is the character record ID whose entity is this item's parent.
        var eqRow = document.createElement('div'); eqRow.className = 'ae-eb-row';
        var eqToggle = $.btn(detail.isEquipped ? 'Equipped' : 'Equip',
            detail.isEquipped ? 'primary sm' : 'ghost sm',
            function() {
                _entityDetailCache[detail.id] = null;
                if (detail.isEquipped) {
                    sendToEngine('AE_UNEQUIP_ITEM', { charId: detail.equippedToCharId, itemId: detail.id });
                } else {
                    sendToEngine('AE_EQUIP_ITEM', { charId: detail.ownerCharId, itemId: detail.id });
                }
            });
        eqRow.appendChild(eqToggle);
        body.appendChild(eqRow);
    }

    if (isNarr) {
        var narr = detail.narrative || detail;
        var isTracked = !!narr.isTracked;
        var trackRow = document.createElement('div'); trackRow.className = 'ae-eb-row';
        var st = document.createElement('span');
        st.className = 'ae-narr-state ' + (narr.storyState || 'locked');
        st.textContent = narr.storyState === 'active' ? '\ud83d\udd25 Active'
                       : narr.storyState === 'completed' ? '\u2705 Done' : '\ud83d\udd12 Locked';
        trackRow.appendChild(st);
        trackRow.appendChild($.btn(isTracked ? '\u23f9 Stop Tracking' : '\ud83c\udfaf Track Quest',
            isTracked ? 'ghost sm' : 'primary sm', function() {
                _entityDetailCache[detail.id] = null;
                sendToEngine('AE_TRACK_NARRATIVE', { narrativeId: detail.id });
            }));
        body.appendChild(trackRow);
        if (isTracked && narr.questTargetName) {
            var pathBox = document.createElement('div'); pathBox.className = 'ae-eb-path';
            pathBox.textContent = (narr.pathNames && narr.pathNames.length)
                ? ('\ud83d\uddfa Path: ' + narr.pathNames.join(' \u2192 '))
                : ('\ud83c\udfaf Target: ' + narr.questTargetName + ' \u2014 no travel path found.');
            body.appendChild(pathBox);
        }
    }

    var actBtns = [];
    (detail.actionInstances || []).forEach(function(inst) {
        actBtns.push($.btn('\u26a1 ' + inst.name, 'action sm', function() {
            execActionInstance(detail.id, inst.id, !!inst.silent);
        }));
    });
    (detail.actions || []).forEach(function(act) {
        actBtns.push($.btn('\u26a1 ' + act.label, 'action sm', function() {
            execEntityAction(detail.id, act.id, null, null);
        }));
    });
    if (actBtns.length) {
        var grid = $.twoCol(actBtns);
        grid.style.marginTop = '4px';
        body.appendChild(grid);
    }

    var editRow = document.createElement('div'); editRow.style.cssText = 'margin-top:4px;';
    editRow.appendChild($.btn('\u270f\ufe0f Edit', 'ghost sm', function() {
        sendToEngine('AE_OPEN_ENTITY_EDIT', { entityId: detail.id });
    }));
    body.appendChild(editRow);
}

// [CE-STRIP vNEXT] _makeEntityBubbleMinor() removed — its only caller was the
// deleted "Present NPCs" section. Previously-minor characters render through the
// normal roster grid now, same as everyone else.

function _makeEntityBubble(ent, kind, state) {
    var id = ent.id || ent.entityId;
    var name = ent.name || ent.entityName || 'Unknown';
    var icon = ent.icon || (kind === 'narrative' ? '\ud83d\udcdc' : '\ud83c\udf92');

    var card = document.createElement('div');
    card.className = 'ae-entity-bubble ' + kind;
    card.setAttribute('data-entity-bubble', id);

    var hdr = document.createElement('button');
    hdr.type = 'button';
    hdr.className = 'ae-entity-bubble-hdr';

    var hIcon = document.createElement('span'); hIcon.className = 'ae-eb-icon'; hIcon.textContent = icon;
    var hName = document.createElement('span'); hName.className = 'ae-eb-name'; hName.textContent = name;
    hdr.appendChild(hIcon); hdr.appendChild(hName);

    if (kind === 'narrative') {
        var sb = document.createElement('span');
        sb.className = 'ae-narr-state ' + (ent.storyState || 'locked');
        sb.style.cssText = 'margin-left:auto;margin-right:8px;';
        sb.textContent = ent.isTracked ? '[ TRACKED ]'
            : (ent.storyState === 'active' ? '[ ACTIVE ]'
            : ent.storyState === 'completed' ? '[ DONE ]' : '[ LOCKED ]');
        hdr.appendChild(sb);
    }

    var hChev = document.createElement('span'); hChev.className = 'ae-eb-chev';
    hChev.textContent = '\u25b8';
    if (kind !== 'narrative') hChev.style.marginLeft = 'auto';
    hdr.appendChild(hChev);
    card.appendChild(hdr);

    var body = document.createElement('div');
    body.className = 'ae-entity-bubble-body';
    card.appendChild(body);

    function paint(detail) {
        if (detail) { _renderEntityBubbleContent(body, detail, kind, state); return; }
        body.innerHTML = '';
        if (ent.description) {
            var d = document.createElement('div'); d.className = 'ae-eb-desc';
            d.textContent = ent.description; body.appendChild(d);
        }
        var ld = document.createElement('div'); ld.className = 'ae-eb-loading';
        ld.textContent = 'Loading\u2026'; body.appendChild(ld);
    }

    function expand() {
        card.classList.add('expanded');
        hChev.textContent = '\u25be';
        _entityBubbleOpen[id] = true;
        var cached = _entityDetailCache[id];
        paint(cached || null);
        _openBubbleRenderers[id] = function(detail) {
            if (_entityBubbleOpen[id]) paint(detail);
        };
        sendToEngine('AE_FETCH_ENTITY_DETAIL', { entityId: id });
    }
    function collapse() {
        card.classList.remove('expanded');
        hChev.textContent = '\u25b8';
        _entityBubbleOpen[id] = false;
        delete _openBubbleRenderers[id];
        body.innerHTML = '';
    }

    hdr.addEventListener('click', function() {
        if (card.classList.contains('expanded')) collapse(); else expand();
    });

    if (_entityBubbleOpen[id]) expand();

    return card;
}



// =============================================================================
// SECTION 13 — PARTY TAB (🏠)
// [CE-STRIP vNEXT] Retitled from "Hub"/"Player" — no protagonist-only surface
// anymore. Journal launcher moved to its own main tab-bar button (see Section 3
// HTML template + the tab-click handler). Holdings popout removed outright (dead
// engine-side already). Sub-tabs: Stats (party-level resources + factions only,
// no personal/character resources or skills), Party (members + your equipment),
// Quests.
// =============================================================================

function _renderHubTab(root, state) {
    var tab = root.querySelector('#ae-tab-hub');
    if (!tab) return;
    tab.innerHTML = '';

    tab.appendChild($.subTabs([
        {
            label: $.svg('activity', 14).outerHTML + ' Stats',
            fill: function(panel) { _fillHubStats(panel, state); }
        },
        {
            label: $.svg('toolbox', 14).outerHTML + ' Inventory',
            fill: function(panel) { _fillHubParty(panel, state); }
        },
        {
            label: $.svg('quests', 14).outerHTML + ' Quests',
            fill: function(panel) { _fillHubQuests(panel, state); }
        }
    ], _hubActiveSubTab, function(idx) { _hubActiveSubTab = idx; }));
}

function _fillHubStats(panel, state) {
    // [CE-STRIP vNEXT] Personal/Character Resources and Skills sections removed —
    // no resources or skills for characters on the bridge anymore. Global (party)
    // Resources and Factions are party/world-level, not per-character, so they stay.
    // Edit toggle + Emotion slot row
    var editRow = document.createElement('div');
    editRow.style.cssText = 'display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;';

    // [v0.9.20 EMO1] Emotion button removed from the Player tab.
    var editToggle = $.btn((_hubEditMode ? '🔒 Lock' : '✎ Edit'), 'ghost sm', function() {
        _hubEditMode = !_hubEditMode;
        editToggle.textContent = _hubEditMode ? '🔒 Lock' : '✎ Edit';
        // Re-render to apply editable state (using _doRenderSceneHUD ensures it works in Phantom)
        if (lastSceneState) _doRenderSceneHUD(lastSceneState);
    });
    editRow.appendChild(editToggle);
    panel.appendChild(editRow);

    // Resources — collapsible; stateKey preserves open state across re-renders
    var resources = state.partyResources || [];
    if (resources.length > 0) {
        var resSection = $.section($.svg('hourglass', 14).outerHTML + ' Global Resources (' + resources.length + ')', function(body) {
            var grid = $.twoCol(resources.map(function(res) {
                return $.resource(res, _hubEditMode,
                    function(r, delta) { sendToEngine('AE_ADJUST_RESOURCE', { tag: r.tag, delta: delta }); },
                    function(r, value) { sendToEngine('AE_SET_RESOURCE',    { tag: r.tag, value: value }); }
                );
            }));
            body.appendChild(grid);
        }, { stateKey: 'hub-resources' });
        panel.appendChild(resSection);
    }

    // Factions — always show all cfg.factions (party-level; char-level factions are separate)
    var factions = state.factionRelationships || [];
    if (factions.length > 0) {
        var facSection = $.section($.svg('castle', 14).outerHTML + ' Factions (' + factions.length + ')', function(body) {
            factions.forEach(function(f) {
                body.appendChild($.faction(f, _hubEditMode, function(fac) { _editFaction(fac); }));
            });
        }, { stateKey: 'hub-factions' });
        panel.appendChild(facSection);
    }

    if (resources.length === 0 && factions.length === 0) {
        panel.appendChild($.label('No stats data yet — engine may need payload update.'));
    }
}

function _fillHubParty(panel, state) {
    var partyMembers = state.partyMembers || [];

    // Player equipment
    var playerEquipment = state.playerEquipment || [];
        if (playerEquipment.length > 0) {
            panel.appendChild($.label('Your Equipment'));
            // [v0.9.83 FIX] Use entity bubbles (same as scene inspect tab) instead of
            // equip rows that opened the full focus/inspection view on click.
            playerEquipment.forEach(function(item) {
                panel.appendChild(_makeEntityBubble(item, 'item', state));
            });
            panel.appendChild($.divider());
        }

    // Party members
    if (partyMembers.length > 0) {
        panel.appendChild($.label('Party'));
        partyMembers.forEach(function(member) {
            var vis = cachedCharVisuals.find(function(v) { return v.id === member.id; });
            var card = document.createElement('div');
            card.className = 'ae-char-card';
            var portrait = document.createElement('div');
            portrait.className = 'ae-char-portrait';
            portrait.style.height = '70px';
            var bgUrl = vis && vis._avatarDataUrl;
            if (bgUrl) portrait.style.backgroundImage = 'url(' + JSON.stringify(bgUrl) + ')';
            else portrait.style.background = _nameToColor(member.name);
            var pOverlay = document.createElement('div'); pOverlay.className = 'ae-char-portrait-overlay';
            var pName = document.createElement('div'); pName.className = 'ae-char-portrait-name'; pName.style.fontSize = '13px'; pName.textContent = member.name;
            portrait.appendChild(pOverlay); portrait.appendChild(pName);
            card.appendChild(portrait);
            var body = document.createElement('div'); body.className = 'ae-char-body';
            // [CE-STRIP vNEXT] Member resources display removed — no resources for characters.
            // Member equip items
            (member.equippedItemIds || []).forEach(function(itemId) {
                var vis2 = cachedCharVisuals.find(function(v) { return v.id === itemId; });
                body.appendChild($.equip({ id: itemId, name: vis2 ? vis2.name : itemId }, true, function(it, eq) {
                    if (eq) sendToEngine('AE_EQUIP_ITEM', { charId: member.id, itemId: it.id });
                    else sendToEngine('AE_UNEQUIP_ITEM', { charId: member.id, itemId: it.id });
                }));
            });
            card.appendChild(body);
            panel.appendChild(card);
        });
    } else if (playerEquipment.length === 0) {
        panel.appendChild($.label('No party data — engine update needed.'));
    }
}

function _fillHubQuests(panel, state) {
    var all = state.activeNarratives || [];
    // [v0.9.8] B6a: show only narratives under the player's hierarchy. The engine flags
    // these via inPlayerHierarchy; fall back to the full list if an older engine omits it.
    var scoped = all.filter(function(n) { return n.inPlayerHierarchy; });
    var flagged = all.some(function(n) { return n.inPlayerHierarchy !== undefined; });
    var narratives = (flagged ? scoped : all).slice();
    // [v0.9.22 NARR-SORT] Tracked pinned to top, then active, then locked, then completed.
    function _qRank(n) {
        if (n.isTracked) return 0;
        if (n.storyState === 'active') return 1;
        if (n.storyState === 'completed') return 3;
        return 2; // locked / anything else
    }
    narratives.sort(function(a, b) { return _qRank(a) - _qRank(b); });
    if (narratives.length === 0) {
        panel.appendChild($.label(flagged && all.length ? 'No quests in this area.' : 'No active narratives.'));
        return;
    }
    narratives.forEach(function(n) {
        // [v0.9.83 FIX] Use entity bubble (same as scene inspect tab) instead of
        // $.narrative card whose onInspect callback opened the full focus/inspection view.
        panel.appendChild(_makeEntityBubble(n, 'narrative', state));
    });
}


function _editFaction(fac) {
    var opts = (fac.states || []).map(function(s, i) { return { id: String(i), label: s, meta: s === fac.stateLabel ? 'current' : '' }; });
    $.picker({ title: fac.name + ' — Relationship', items: opts, searchable: false, selectedId: String(fac.stateIdx),
        onSelect: function(item) { sendToEngine('AE_SET_FACTION', { factionId: fac.id, stateIdx: parseInt(item.id, 10), isParty: fac.isParty }); }
    });
}

// [CE-STRIP vNEXT] _editSkill() removed — its only caller was the retired Skills
// section in _fillHubStats. AE_SET_SKILL is no longer sent from the bridge.

// =============================================================================
// =============================================================================
// SECTION 13b — PLAYER JOURNAL POPOUT  [v0.9.9.13 JOURNAL]
// The journal is a standalone overlay (roomy read/write; each theme owns the whole
// surface). Opened from the Player-tab launcher button. All state lives in the
// engine; this paints _journalState and dispatches AE_JOURNAL_* verbs. The footer
// compose box is built once on open (never on repaint) so typing never loses focus.
// =============================================================================

function _jrnlDiv(cls, text) {
    var d = document.createElement('div');
    d.className = cls;
    if (text != null) d.textContent = text;
    return d;
}

function _closeJournalModal() {
    var ov = document.getElementById('ae-jrnl-overlay');
    if (ov) ov.remove();
}

function openJournalModal() {
    if (document.getElementById('ae-jrnl-overlay')) return;   // already open

    var overlay = document.createElement('div');
    overlay.id = 'ae-jrnl-overlay';
    overlay.className = 'ae-jrnl-overlay';

    var modal = document.createElement('div');
    modal.id = 'ae-jrnl-modal';
    modal.className = 'ae-jrnl-modal';

    // ── Head ──
    var head = _jrnlDiv('ae-jrnl-head');
    head.appendChild(_jrnlDiv('ae-jrnl-title', 'Player Journal'));
    var refreshBtn = $.btn($.icon('refresh', 14).outerHTML, 'ghost sm icon', function() {
        requestJournal();
        _showToast('\u27f3 Refreshed from engine');
    });
    refreshBtn.title = 'Re-sync with the engine (entries already stay in sync automatically)';
    head.appendChild(refreshBtn);
    var closeBtn = $.btn('\u2715', 'ghost sm icon', function() { _closeJournalModal(); });
    closeBtn.title = 'Close';
    head.appendChild(closeBtn);
    modal.appendChild(head);

    // ── Scrolling surface (repainted by _renderJournalModal) ──
    var surface = _jrnlDiv('ae-jrnl-surface');
    surface.id = 'ae-jrnl-surface';
    modal.appendChild(surface);

    // ── Footer compose (built once; survives repaints) ──
    var foot = _jrnlDiv('ae-jrnl-foot');
    var composeRow = _jrnlDiv('ae-jrnl-compose');
    composeRow.appendChild(_jrnlDiv('ae-jrnl-prompt', '>'));   // visible only under the cyberpunk skin
    var ta = document.createElement('textarea');
    ta.className = 'ae-profile-textarea ae-jrnl-ta';
    ta.placeholder = 'Write what just happened\u2026';
    ta.value = _jrnlComposeDraft;
    ta.addEventListener('input', function() { _jrnlComposeDraft = ta.value; });
    composeRow.appendChild(ta);
    foot.appendChild(composeRow);

    var footRow = _jrnlDiv('ae-jrnl-foot-row');
    var lbl = document.createElement('label');
    lbl.className = 'ae-jrnl-stampchk';
    var chk = document.createElement('input');
    chk.type = 'checkbox';
    chk.checked = _jrnlStampNew;
    chk.addEventListener('change', function() { _jrnlStampNew = chk.checked; });
    lbl.appendChild(chk);
    lbl.appendChild(document.createTextNode('Stamp with story date/time'));
    footRow.appendChild(lbl);
    footRow.appendChild($.btn($.icon('plus', 13).outerHTML + ' Add entry', 'primary sm', function() {
        var t = (_jrnlComposeDraft || '').trim();
        if (!t) { _showToast('Nothing to add'); return; }
        journalAction('add', { text: t, stamped: _jrnlStampNew });
        _jrnlComposeDraft = ''; ta.value = ''; ta.focus();
    }));
    foot.appendChild(footRow);
    modal.appendChild(foot);

    overlay.appendChild(modal);
    // Backdrop click closes; clicks inside the modal stay open.
    overlay.addEventListener('click', function(e) { if (e.target === overlay) _closeJournalModal(); });
    document.body.appendChild(overlay);

    requestJournal();          // pull freshest state
    _renderJournalModal();     // paint immediately from cache
}

function _renderJournalModal() {
    var surface = document.getElementById('ae-jrnl-surface');
    if (!surface) return;
    surface.innerHTML = '';

    var bubbles = (_journalState && _journalState.bubbles) || [];
    var active = bubbles.filter(function(b) { return !b.archived; });
    var archived = bubbles.filter(function(b) { return b.archived; });

    surface.appendChild(_jrnlDiv('ae-jrnl-intro', 'This is your running record. Active entries stay Always-On in the lorebook as \u201CThe story so far\u201D. Archived entries are kept but never injected.'));

    var tb = _jrnlDiv('ae-jrnl-toolbar');
    if (active.length > 1) tb.appendChild($.btn('\u2935 Merge all', 'ghost sm', function() { journalAction('merge'); }));
    if (archived.length > 0) tb.appendChild($.btn((_jrnlShowArchived ? 'Hide' : 'Show') + ' archived (' + archived.length + ')', 'ghost sm', function() {
        _jrnlShowArchived = !_jrnlShowArchived; _renderJournalModal();
    }));
    if (tb.childNodes.length) surface.appendChild(tb);

    surface.appendChild(_jrnlDiv('ae-jrnl-sec-label', 'Entries (' + active.length + ')'));
    if (active.length === 0) surface.appendChild(_jrnlDiv('ae-jrnl-empty', 'No entries yet. Write one below.'));
    else active.forEach(function(b) { surface.appendChild(_journalEntry(b, false)); });

    if (_jrnlShowArchived && archived.length > 0) {
        surface.appendChild(_jrnlDiv('ae-jrnl-sec-label', 'Archived (' + archived.length + ')'));
        archived.forEach(function(b) { surface.appendChild(_journalEntry(b, true)); });
    }
}

function _journalEntry(b, isArchived) {
    var wrap = _jrnlDiv('ae-jrnl-entry' + (isArchived ? ' archived' : ''));
    var editing = _jrnlEditingId === b.id;

    // Stamp line: in-story label (engine-formatted) when stamped, else an Archived tag.
    if (b.stamped && b.stampLabel) wrap.appendChild(_jrnlDiv('ae-jrnl-stamp', b.stampLabel));
    else if (isArchived) wrap.appendChild(_jrnlDiv('ae-jrnl-stamp', 'Archived'));

    if (editing && _jrnlBusy) {
        wrap.appendChild(_jrnlDiv('ae-jrnl-working', 'Working\u2026'));
    } else if (editing) {
        var eta = document.createElement('textarea');
        eta.className = 'ae-profile-textarea ae-jrnl-editta';
        eta.value = _jrnlEditDraft;
        eta.addEventListener('input', function() { _jrnlEditDraft = eta.value; });
        wrap.appendChild(eta);
        setTimeout(function() { try { eta.focus(); } catch (e) {} }, 0);

        var erow = _jrnlDiv('ae-jrnl-actions');
        // [vNEXT] Was 'success sm' — Unicorn Barf never themes .ae-btn.success for the
        // Journal (only :not(.primary):not(.danger):not(.success) is covered), so it fell
        // through to the global cyan-on-10%-cyan success style: illegible against this
        // theme's near-white pastel page. 'primary' already carries its own opaque
        // gradient background + explicit white text, so it reads clearly here without
        // needing a separate color override.
        erow.appendChild($.btn($.icon('save', 13).outerHTML + ' Save', 'primary sm', function() {
            journalAction('update', { id: b.id, text: _jrnlEditDraft });
            _jrnlEditingId = null;
        }));
        erow.appendChild($.btn('Cancel', 'ghost sm', function() { _jrnlEditingId = null; _renderJournalModal(); }));
        erow.appendChild($.btn('\u270D Rewrite', 'sm', function() { journalGen('rewrite', b.id, _jrnlEditDraft); }));
        erow.appendChild($.btn('\u25BD Compress', 'sm', function() { journalGen('compress', b.id, _jrnlEditDraft); }));
        wrap.appendChild(erow);
    } else {
        wrap.appendChild(_jrnlDiv('ae-jrnl-body', (b.text && b.text.trim()) ? b.text : '(empty)'));

        var arow = _jrnlDiv('ae-jrnl-actions');
        arow.appendChild($.btn($.icon('edit', 13).outerHTML + ' Edit', 'ghost sm', function() {
            _jrnlEditingId = b.id; _jrnlEditDraft = b.text || ''; _renderJournalModal();
        }));
        arow.appendChild($.btn(b.stamped ? 'Unstamp' : 'Stamp', 'ghost sm', function() { journalAction('stamp', { id: b.id }); }));
        if (isArchived) arow.appendChild($.btn('Unarchive', 'ghost sm', function() { journalAction('unarchive', { id: b.id }); }));
        else arow.appendChild($.btn('Archive', 'ghost sm', function() { journalAction('archive', { id: b.id }); }));
        arow.appendChild($.btn('\u270D Rewrite', 'sm', function() { journalGen('rewrite', b.id, b.text); }));
        arow.appendChild($.btn('\u25BD Compress', 'sm', function() { journalGen('compress', b.id, b.text); }));
        arow.appendChild($.btn($.icon('trash', 13).outerHTML, 'danger sm icon', function() { journalAction('delete', { id: b.id }); }));
        wrap.appendChild(arow);
    }
    return wrap;
}

// [v2.1.5 CHARJOURNAL] Per-character journal popout. Same interaction model and
// CSS classes as the player journal above (ae-jrnl-overlay/modal/head/etc — no new
// CSS needed, just different element ids so both can coexist) -- scoped to one
// character, and deliberately does NOT carry forward the "stamp" feature (checkbox,
// stamped/stampLabel display, journalAction('stamp',...)) -- confirmed dead on the
// engine side (no handler for that op), not worth propagating into new code.
function _cjrnlDiv(cls, text) {
    var d = document.createElement('div');
    d.className = cls;
    if (text != null) d.textContent = text;
    return d;
}

function _closeCharJournalModal() {
    var ov = document.getElementById('ae-cjrnl-overlay');
    if (ov) ov.remove();
    _cjrnlCharId = null;
}

function openCharJournalModal(charId, charName) {
    if (document.getElementById('ae-cjrnl-overlay')) return;   // already open

    _cjrnlCharId = charId;
    _cjrnlCharName = charName || 'Character';
    _charJournalState = { bubbles: [] };
    _cjrnlEditingId = null; _cjrnlEditDraft = ''; _cjrnlBusy = false; _cjrnlShowArchived = false; _cjrnlComposeDraft = '';

    var overlay = document.createElement('div');
    overlay.id = 'ae-cjrnl-overlay';
    overlay.className = 'ae-jrnl-overlay';

    var modal = document.createElement('div');
    modal.id = 'ae-cjrnl-modal';
    modal.className = 'ae-jrnl-modal';

    // -- Head --
    var head = _cjrnlDiv('ae-jrnl-head');
    head.appendChild(_cjrnlDiv('ae-jrnl-title', _cjrnlCharName + ' \u2014 Journal'));
    var refreshBtn = $.btn($.icon('refresh', 14).outerHTML, 'ghost sm icon', function() {
        requestCharJournal(_cjrnlCharId);
        _showToast('\u27f3 Refreshed from engine');
    });
    refreshBtn.title = 'Re-sync with the engine (entries already stay in sync automatically)';
    head.appendChild(refreshBtn);
    var closeBtn = $.btn('\u2715', 'ghost sm icon', function() { _closeCharJournalModal(); });
    closeBtn.title = 'Close';
    head.appendChild(closeBtn);
    modal.appendChild(head);

    // -- Scrolling surface (repainted by _renderCharJournalModal) --
    var surface = _cjrnlDiv('ae-jrnl-surface');
    surface.id = 'ae-cjrnl-surface';
    modal.appendChild(surface);

    // -- Footer compose (built once; survives repaints) --
    var foot = _cjrnlDiv('ae-jrnl-foot');
    var composeRow = _cjrnlDiv('ae-jrnl-compose');
    composeRow.appendChild(_cjrnlDiv('ae-jrnl-prompt', '>'));
    var ta = document.createElement('textarea');
    ta.className = 'ae-profile-textarea ae-jrnl-ta';
    ta.placeholder = 'Write a note for ' + _cjrnlCharName + '\u2026';
    ta.value = _cjrnlComposeDraft;
    ta.addEventListener('input', function() { _cjrnlComposeDraft = ta.value; });
    composeRow.appendChild(ta);
    foot.appendChild(composeRow);

    var footRow = _cjrnlDiv('ae-jrnl-foot-row');
    footRow.appendChild($.btn($.icon('plus', 13).outerHTML + ' Add entry', 'primary sm', function() {
        var t = (_cjrnlComposeDraft || '').trim();
        if (!t) { _showToast('Nothing to add'); return; }
        charJournalAction(_cjrnlCharId, 'add', { text: t });
        _cjrnlComposeDraft = ''; ta.value = ''; ta.focus();
    }));
    foot.appendChild(footRow);
    modal.appendChild(foot);

    overlay.appendChild(modal);
    overlay.addEventListener('click', function(e) { if (e.target === overlay) _closeCharJournalModal(); });
    document.body.appendChild(overlay);

    requestCharJournal(charId);   // pull freshest state
    _renderCharJournalModal();    // paint immediately from cache
}

function _renderCharJournalModal() {
    var surface = document.getElementById('ae-cjrnl-surface');
    if (!surface) return;
    surface.innerHTML = '';

    var bubbles = (_charJournalState && _charJournalState.bubbles) || [];
    var active = bubbles.filter(function(b) { return !b.archived; });
    var archived = bubbles.filter(function(b) { return b.archived; });

    surface.appendChild(_cjrnlDiv('ae-jrnl-intro', 'Active entries fold into ' + _cjrnlCharName + '\u2019s own lorebook entry as running notes. Archived entries are kept but excluded. Nothing is auto-summarized \u2014 merge or archive as you see fit.'));

    var tb = _cjrnlDiv('ae-jrnl-toolbar');
    if (active.length > 1) tb.appendChild($.btn('\u2935 Merge all', 'ghost sm', function() { charJournalAction(_cjrnlCharId, 'merge'); }));
    if (archived.length > 0) tb.appendChild($.btn((_cjrnlShowArchived ? 'Hide' : 'Show') + ' archived (' + archived.length + ')', 'ghost sm', function() {
        _cjrnlShowArchived = !_cjrnlShowArchived; _renderCharJournalModal();
    }));
    if (tb.childNodes.length) surface.appendChild(tb);

    surface.appendChild(_cjrnlDiv('ae-jrnl-sec-label', 'Entries (' + active.length + ')'));
    if (active.length === 0) surface.appendChild(_cjrnlDiv('ae-jrnl-empty', 'No entries yet. Write one below.'));
    else active.forEach(function(b) { surface.appendChild(_charJournalEntry(b, false)); });

    if (_cjrnlShowArchived && archived.length > 0) {
        surface.appendChild(_cjrnlDiv('ae-jrnl-sec-label', 'Archived (' + archived.length + ')'));
        archived.forEach(function(b) { surface.appendChild(_charJournalEntry(b, true)); });
    }
}

function _charJournalEntry(b, isArchived) {
    var wrap = _cjrnlDiv('ae-jrnl-entry' + (isArchived ? ' archived' : ''));
    var editing = _cjrnlEditingId === b.id;

    if (isArchived) wrap.appendChild(_cjrnlDiv('ae-jrnl-stamp', 'Archived'));

    if (editing && _cjrnlBusy) {
        wrap.appendChild(_cjrnlDiv('ae-jrnl-working', 'Working\u2026'));
    } else if (editing) {
        var eta = document.createElement('textarea');
        eta.className = 'ae-profile-textarea ae-jrnl-editta';
        eta.value = _cjrnlEditDraft;
        eta.addEventListener('input', function() { _cjrnlEditDraft = eta.value; });
        wrap.appendChild(eta);
        setTimeout(function() { try { eta.focus(); } catch (e) {} }, 0);

        var erow = _cjrnlDiv('ae-jrnl-actions');
        erow.appendChild($.btn($.icon('save', 13).outerHTML + ' Save', 'primary sm', function() {
            charJournalAction(_cjrnlCharId, 'update', { id: b.id, text: _cjrnlEditDraft });
            _cjrnlEditingId = null;
        }));
        erow.appendChild($.btn('Cancel', 'ghost sm', function() { _cjrnlEditingId = null; _renderCharJournalModal(); }));
        erow.appendChild($.btn('\u270D Rewrite', 'sm', function() { charJournalGen(_cjrnlCharId, 'rewrite', b.id, _cjrnlEditDraft); }));
        erow.appendChild($.btn('\u25BD Compress', 'sm', function() { charJournalGen(_cjrnlCharId, 'compress', b.id, _cjrnlEditDraft); }));
        wrap.appendChild(erow);
    } else {
        wrap.appendChild(_cjrnlDiv('ae-jrnl-body', (b.text && b.text.trim()) ? b.text : '(empty)'));

        var arow = _cjrnlDiv('ae-jrnl-actions');
        arow.appendChild($.btn($.icon('edit', 13).outerHTML + ' Edit', 'ghost sm', function() {
            _cjrnlEditingId = b.id; _cjrnlEditDraft = b.text || ''; _renderCharJournalModal();
        }));
        if (isArchived) arow.appendChild($.btn('Unarchive', 'ghost sm', function() { charJournalAction(_cjrnlCharId, 'unarchive', { id: b.id }); }));
        else arow.appendChild($.btn('Archive', 'ghost sm', function() { charJournalAction(_cjrnlCharId, 'archive', { id: b.id }); }));
        arow.appendChild($.btn('\u270D Rewrite', 'sm', function() { charJournalGen(_cjrnlCharId, 'rewrite', b.id, b.text); }));
        arow.appendChild($.btn('\u25BD Compress', 'sm', function() { charJournalGen(_cjrnlCharId, 'compress', b.id, b.text); }));
        arow.appendChild($.btn($.icon('trash', 13).outerHTML, 'danger sm icon', function() { charJournalAction(_cjrnlCharId, 'delete', { id: b.id }); }));
        wrap.appendChild(arow);
    }
    return wrap;
}


// =============================================================================
// SECTION 13c — CHARACTER CHAT: NATIVE HOOKS  [v2.13.0 CHARCHAT-SHELL-BASELINE]
//
// THE PANEL IS GONE. ~1,100 lines of full-screen texting UI, its composer, its DOM
// injection, its anchoring poll and its five per-theme CSS blocks are deleted, per user:
// "get rid of it because it was never fully implemented and designed. We never got that
// implementation to work fully."
//
// WHY IT COULD NOT BE KEPT AND SKINNED: the panel was a SECOND chat mode. It held its own
// draft, wrote it into NAI's editor at pointerdown (execCommand insertText/insertParagraph),
// told the engine which section it had written (op 'povclaim'), painted its own bubbles from
// a broadcast copy of the transcript, and covered NAI's editor while doing it. The design
// this baseline exists for does the opposite: the user types in NAI's own editor and presses
// NAI's own Send, and we OVERLAY that surface rather than replace it. Every one of the
// panel's mechanisms is dead on arrival under that design, not merely restyled. So they go
// now, before the overhaul builds on top of them.
//
// WHAT SURVIVES, and why each earns it:
//   _ccVisible / _ccIsOurs / _ccSendCandidates / _ccFindNativeSend
//                        heuristic locator for NAI's Send control. The likeliest thing in
//                        this file to break on a NAI front-end change; unchanged from
//                        v2.5.0 and still the arm listener's only dependency.
//   charChatAction()     the one engine-bound message (AE_CHARCHAT_ACTION { op }). The op
//                        vocabulary IS the contract the new UI will call; only its callers
//                        changed.
//   _ccOnArmPointerDown / _ccOnArmPointerUp / _ccArmHookSend / _ccArmUnhook / _ccSyncArmHook
//                        "a Send is coming," fired at pointerdown on NAI's Send whenever a
//                        chat is ACTIVE (panel or no panel — there is no panel now).
//                        Engine v2.45.0 answers it by CANCELLING the in-flight post-reply
//                        thought (grep CHARCHAT-ARM-CANCEL engine-side). That is the whole
//                        job now; nothing here arms anything.
//   _charChatState       last AE_CHARCHAT_STATE payload. Declared in Section 16 as before.
//
// DELETED WITH THE PANEL (zero-caller verified, this pass): openCharChatModal,
// _closeCharChatModal, _renderCharChat, _ccBuildContacts, _ccBuildThread, _ccBuildRow,
// _ccStageWord, _ccStageLabel, _ccDiv, _ccNorm, _ccBuildImgIndex, _ccResolveImage,
// _ccAvatarFor, _ccFillAvatar, requestCharChatContacts, _ccEndChatIfActive, _ccInjectDraft,
// _ccFindEditor, _ccEditorCandidates, _ccEditorBlocks, _ccLastBlockEmpty, _ccCaretToEnd,
// _ccReadbackOk, _ccEnsureBreakForNudge, _ccCanonPov, _ccEscapeRx, _ccOnSendPointerDown,
// _ccOnSendClick, _ccShouldSuppressSend, _ccHookSend, _ccUnhookSend, _ccStartAnchor,
// _ccStopAnchor, _ccApplyAnchor, _ccMarkNativeSend, __ceCcAnchorDiag, __ceCcEditorDiag, and
// the vars _ccView/_ccPovId/_ccPovName/_ccContacts/_ccDraft/_ccEditIds/_ccEditDraft/_ccBusy/
// _ccStage/_ccEditorEl/_ccSendHooked/_ccThoughtOn/_ccActRow/_ccImgIndex/_ccImgIndexTs/
// _ccAnchorOk/_ccAnchorTmr.
//
// THE ONE THING WORTH REBUILDING FROM, NOT REDERIVING — the deleted image path knew two
// facts the overhaul needs, recorded here because the code holding them is gone:
//   * chat photo tags in the document carry only an 8-HEX PREFIX of the image uuid; the full
//     uuid is the IndexedDB key. Resolution was prefix-match against the gallery index.
//   * avatars live at IndexedDB key charId + '_em_Avatar', with charId + '_portrait' as a
//     legacy fallback.
// The anchoring mechanism the overhaul should use is NOT the deleted panel's: it is
// Auto-Illustrator's, which is proven in production — the ENGINE creates a node widget
// (api.v1.editor.decorations.createWidget { type:'node', sectionId, side:'after' }) whose
// content carries a 1px transparent sentinel string, and THIS file finds that sentinel with a
// TreeWalker and paints the real image into its container. NAI then keeps the anchor
// positioned across edits and disposes it with its section. See Auto-Illustrator_Bridge.txt
// (findPlaceholder/injectImage) and Auto-Illustrator-v3.txt (createWidgets + the storyStorage
// pending list it rebuilds from, since widgets do not survive a reload).
// =============================================================================

var _ccArmHooked  = false;       // [v2.12.0 CHARCHAT-ARM] is the ARM listener installed? Tracks CHAT state — see _ccSyncArmHook
var _ccNativeSend = null;        // [v2.5.0] cached NAI Send element (re-verified on use)

function _ccVisible(el) {
    if (!el || !el.isConnected) return false;
    var r = el.getBoundingClientRect();
    if (r.width < 4 || r.height < 4) return false;
    var cs = window.getComputedStyle(el);
    if (cs.visibility === 'hidden' || cs.display === 'none' || parseFloat(cs.opacity || '1') < 0.05) return false;
    return true;
}

function _ccIsOurs(el) {
    return !!(el.closest('.ae-hud') || el.closest('.ae-phantom')
           || el.closest('.ae-jrnl-overlay') || el.closest('.ae-icons-overlay'));
}

function _ccSendCandidates() {
    var out = [];
    var nodes;
    try { nodes = document.querySelectorAll('button, [role="button"], input[type="submit"]'); }
    catch (_e) { return out; }
    for (var i = 0; i < nodes.length; i++) {
        var b = nodes[i];
        if (!_ccVisible(b) || _ccIsOurs(b)) continue;
        var lbl = ((b.getAttribute('aria-label') || '') + ' '
                 + (b.getAttribute('title') || '') + ' '
                 + (b.value || '') + ' '
                 + (b.textContent || '')).toLowerCase();
        if (!/(^|[^a-z])send([^a-z]|$)/.test(lbl)) continue;
        out.push(b);
    }
    // Bottom-most first.
    out.sort(function(a, b) { return b.getBoundingClientRect().top - a.getBoundingClientRect().top; });
    return out;
}

function _ccFindNativeSend() {
    if (_ccNativeSend && _ccVisible(_ccNativeSend)) return _ccNativeSend;
    _ccNativeSend = null;
    var c = _ccSendCandidates();
    if (c.length) _ccNativeSend = c[0];
    return _ccNativeSend;
}

// The one engine-bound message. Ops: 'arm' | 'nudge' | 'regen' | 'remove' | 'edit' |
// 'images' — grep handleCharChatAction engine-side for the live list. The panel was only
// ever one caller of this; the contract outlives it.
function charChatAction(op, data) {
    var payload = { op: op };
    if (data) for (var k in data) if (Object.prototype.hasOwnProperty.call(data, k)) payload[k] = data[k];
    sendToEngine('AE_CHARCHAT_ACTION', payload);
}

// ── [v2.12.0 CHARCHAT-ARM] The native arm listener ────────────────────────
// Installed whenever a chat is ACTIVE. We never preventDefault, never re-dispatch, never
// write the editor: the user's genuine click must remain a genuine interaction, which is what
// licenses the reply's generation (bridge v2.9.0 died on exactly that — see the CE-INDEX).
// Pure observation plus one postMessage.
//
// [v2.13.0] Its meaning changed engine-side and the name no longer describes it: engine
// v2.45.0 answers 'arm' by CANCELLING the in-flight post-reply thought, because a Send that
// lands while api.v1.generate() is running is the one race that can cost the REPLY. Renaming
// it would break nothing but would cost a bridge/engine op-vocabulary flag day for a word;
// the engine's own CHARCHAT-ARM-CANCEL block is the authority on what it does.
function _ccOnArmPointerDown(e) {
    try {
        var st = _charChatState;
        if (!st || !st.active) return;
        var btn = _ccFindNativeSend();
        if (!btn || !btn.isConnected) return;
        var t = e.target;
        if (!t || (t !== btn && !btn.contains(t))) return;
        charChatAction('arm', {});
    } catch (err) {
        // Never throw into the click: a failed arm must still leave a working native Send.
        console.warn('[CE:ccarm] pointerdown error (send unaffected — we never touch the event):', err);
    }
}

// [v2.12.0 CHARCHAT-DISARM] A press that never became a send. Engine v2.45.0 accepts and
// ignores this (there is nothing to disarm, and cancelling a thought on a non-send would
// throw one away for free), but it is left wired: it costs one postMessage on a rare gesture
// and it is the signal a future pre-send feature would want.
function _ccOnArmPointerUp(e) {
    try {
        var st = _charChatState;
        if (!st || !st.active) return;
        var btn = _ccNativeSend;
        if (!btn || !btn.isConnected) return;
        var t = e.target;
        if (t && (t === btn || btn.contains(t))) return;   // released ON the button: a real send
        charChatAction('arm', { on: false });
    } catch (err) {
        console.warn('[CE:ccarm] pointerup error:', err);
    }
}

function _ccArmHookSend() {
    if (_ccArmHooked) return;
    document.addEventListener('pointerdown', _ccOnArmPointerDown, true);   // capture: earliest possible
    document.addEventListener('pointerup', _ccOnArmPointerUp, true);
    document.addEventListener('pointercancel', _ccOnArmPointerUp, true);
    _ccArmHooked = true;
    dbg('[CE:ccarm] armed listener INSTALLED — a chat is active.');
}

function _ccArmUnhook() {
    if (!_ccArmHooked) return;
    document.removeEventListener('pointerdown', _ccOnArmPointerDown, true);
    document.removeEventListener('pointerup', _ccOnArmPointerUp, true);
    document.removeEventListener('pointercancel', _ccOnArmPointerUp, true);
    _ccArmHooked = false;
    _ccNativeSend = null;
    dbg('[CE:ccarm] armed listener removed — no chat active.');
}

// Driven off the AE_CHARCHAT_STATE receipt, which is already this file's repaint pump for
// everything chat-related. No new poll, no new lifecycle.
function _ccSyncArmHook() {
    var st = _charChatState;
    if (st && st.active) _ccArmHookSend();
    else _ccArmUnhook();
}

// -- [v2.40.0 CHARCHAT-SENDSTATUS] Status badge over NAI's Send button ---------
// Gap 1 (the Fresh-Thoughts slot race) cannot be *won* cheaply: a Send that lands while
// the engine's post-reply api.v1.generate() holds NAI's slot is silently swallowed. So
// rather than race it, make the wait LEGIBLE -- a small pill anchored over NAI's own Send
// control that says what is happening, so the user waits the half-second instead of firing
// into a busy slot. Both drivers already arrive on this file's message pump, so there is
// NO new engine message and NO new storage key:
//   * _charChatState.busyStage -- 'thinking' | 'image' | '' (rides EVT_CHARCHAT_STATE)
//   * _ccEngineThinking        -- binary on/off (EVT_ENGINE_THINKING), the same signal the
//     ghost glyph rides; it is the ONLY one that marks the MAIN reply, which the engine
//     never stamps a busyStage for.
// Anchored to _ccFindNativeSend() -- the one NAI element this file already trusts. Fails
// closed: no button, no badge, nothing else affected. Gated on _charChatState.active, so
// it never shows during a wizard turn or a plain story generation (the wizard overlay has
// its own .ae-wiz-thinking spinner; this fills the gap only on CharChat's native-Send path).
var _ccEngineThinking = false;   // last EVT_ENGINE_THINKING edge
var _ccStatusEl = null;          // the pill (in document.body, position:fixed)
var _ccStatusRaf = 0;            // rAF handle for the reposition loop (0 = not looping)

// Label priority: an explicit stage beats the generic pulse. '' = hide.
function _ccStatusLabel() {
    var st = _charChatState;
    if (!st || !st.active) return '';
    var who = st.contactName ? st.contactName : 'They';
    var stage = st.busyStage || '';
    if (stage === 'image')    return 'sending photo\u2026';
    if (stage === 'thinking') return who + ' \u2014 thinking\u2026';
    if (_ccEngineThinking)    return who + ' \u2014 replying\u2026';
    return '';
}

function _ccStatusEnsureCss() {
    if (document.getElementById('ae-cc-sendstatus-css')) return;
    var s = document.createElement('style');
    s.id = 'ae-cc-sendstatus-css';
    // Text stays plain (rainbow in the aura, not the ink) -- only the dot animates. Every
    // colour resolves through --ae-* tokens with a hard fallback, so an unthemed load still
    // reads.
    s.textContent =
        '#ae-cc-sendstatus{position:fixed;z-index:2147483000;pointer-events:none;'
      + 'display:flex;align-items:center;gap:7px;padding:5px 11px;border-radius:999px;'
      + 'font-family:var(--ae-font-sans,system-ui,-apple-system,sans-serif);'
      + 'font-size:12px;line-height:1;font-weight:600;letter-spacing:.01em;white-space:nowrap;'
      + 'color:var(--ae-text-main,#e9e9ec);'
      + 'background:var(--ae-chat-them-bg,rgba(26,28,36,.97));'
      + 'border:1px solid var(--ae-chat-them-border,rgba(255,255,255,.16));'
      + 'box-shadow:0 6px 18px rgba(0,0,0,.34);'
      + 'transform:translate(-50%,0);opacity:0;transition:opacity .16s ease;}'
      + '#ae-cc-sendstatus.show{opacity:1;}'
      + '#ae-cc-sendstatus .ae-ccs-dot{width:7px;height:7px;border-radius:50%;flex:0 0 auto;'
      + 'background:var(--ae-chat-marker,var(--ae-accent-2,#e8a04a));'
      + 'animation:ae-ccs-pulse 1.15s ease-out infinite;}'
      + '@keyframes ae-ccs-pulse{'
      + '0%{box-shadow:0 0 0 0 color-mix(in srgb,var(--ae-chat-marker,#e8a04a) 55%,transparent);}'
      + '70%{box-shadow:0 0 0 7px transparent;}100%{box-shadow:0 0 0 0 transparent;}}';
    document.head.appendChild(s);
}

// Place the pill centred above NAI's Send button, clamped into the viewport. Flips below the
// button when there is no room above.
function _ccStatusPlace() {
    if (!_ccStatusEl) return;
    var btn = _ccFindNativeSend();
    if (!btn || !_ccVisible(btn)) { _ccStatusEl.classList.remove('show'); return; }
    var r = btn.getBoundingClientRect();
    var cx = r.left + r.width / 2;
    var top = r.top - _ccStatusEl.offsetHeight - 8;
    if (top < 4) top = r.bottom + 8;
    if (cx < 64) cx = 64;
    if (cx > window.innerWidth - 64) cx = window.innerWidth - 64;
    _ccStatusEl.style.left = cx + 'px';
    _ccStatusEl.style.top  = top + 'px';
    _ccStatusEl.classList.add('show');
}

// One self-rescheduling rAF loop while a label is showing. NAI's editor scrolls in its own
// container, which need not emit a window scroll event, so position is polled by frame --
// but only while visible; the loop stops itself the moment the label empties.
function _ccStatusLoop() {
    _ccStatusRaf = 0;
    if (!_ccStatusEl) return;
    _ccStatusPlace();
    if (_ccStatusLabel()) _ccStatusRaf = requestAnimationFrame(_ccStatusLoop);
}

function _ccStatusSync() {
    var label = _ccStatusLabel();
    if (!label) {
        if (_ccStatusEl) _ccStatusEl.classList.remove('show');
        if (_ccStatusRaf) { cancelAnimationFrame(_ccStatusRaf); _ccStatusRaf = 0; }
        return;
    }
    _ccStatusEnsureCss();
    if (!_ccStatusEl) {
        _ccStatusEl = document.createElement('div');
        _ccStatusEl.id = 'ae-cc-sendstatus';
        var dot = document.createElement('span'); dot.className = 'ae-ccs-dot';
        var txt = document.createElement('span'); txt.className = 'ae-ccs-txt';
        _ccStatusEl.appendChild(dot);
        _ccStatusEl.appendChild(txt);
        document.body.appendChild(_ccStatusEl);
    }
    var t = _ccStatusEl.querySelector('.ae-ccs-txt');
    if (t && t.textContent !== label) t.textContent = label;
    if (!_ccStatusRaf) _ccStatusRaf = requestAnimationFrame(_ccStatusLoop);
}

// Diagnostic. Console-only, spends nothing. Answers "is the hook even wired up?" without a send.
window.__ceCcArmDiag = function() {
    var st = _charChatState;
    var out = {
        chatActive: !!(st && st.active),
        freshThoughts: !!(st && st.freshThoughts),
        armListenerInstalled: _ccArmHooked,
        nativeSendFound: !!_ccFindNativeSend(),
        bridgeVersion: BRIDGE_VERSION
    };
    dbg('[CE:ccarm] diag', out);
    return out;
};

// -- [v2.42.0 CHARCHAT-MANAGER] Floating chat manager, chat-active only -------
// Per user: a Close button below the HUD toggle when chat mode is active, with
// Summarize / Delete alongside it ("buttons inside the manager can summarize or
// delete it"). Rides the SAME AE_CHARCHAT_STATE receipt every other chat-active
// affordance in this file does (send-status pill, arm hook, background retheme) --
// _ccManagerSync is a fourth rider on that one signal, no new poll or lifecycle.
// Anchored under #ae-toggle-btn (effectively always visible on a story page; the
// phantom-widget HUD only adds .active to it, never hides it), tracked by a self-
// rescheduling rAF while shown since the toggle is user-draggable. Three verbs, all
// engine-side already:
//   Close     -> AE_CHARCHAT_END { action:'save' }    (banks the thread, strips the doc)
//   Delete    -> AE_CHARCHAT_END { action:'discard' } (deletes saved thread, strips the doc)
//   Summarize -> AE_CHARCHAT_SUMMARIZE {}             (engine opens its own preview modal;
//                                                      chat STAYS open, so the manager stays up)
var _ccMgrEl = null;      // the cluster (document.body, position:fixed)
var _ccMgrRaf = 0;        // rAF handle for the reposition loop (0 = not looping)

function _ccMgrEnsureCss() {
    if (document.getElementById('ae-cc-manager-css')) return;
    var s = document.createElement('style');
    s.id = 'ae-cc-manager-css';
    // Every colour resolves through --ae-* tokens with a hard fallback, so an unthemed
    // load still reads; themes re-skin it for free, same principle as the send-status pill.
    s.textContent =
        '#ae-cc-manager{position:fixed;z-index:2147482000;display:none;flex-direction:column;'
      + 'align-items:center;gap:6px;transform:translateX(-50%);}'
      + '#ae-cc-manager.show{display:flex;}'
      + '#ae-cc-manager .ae-ccm-close{width:40px;height:40px;padding:0;border-radius:50%;cursor:pointer;'
      + 'display:flex;align-items:center;justify-content:center;'
      + 'background:var(--ae-bg-panel,rgba(26,28,36,.97));'
      + 'border:1px solid var(--ae-accent,#e8a04a);color:var(--ae-accent,#e8a04a);'
      + 'box-shadow:0 6px 18px rgba(0,0,0,.34);transition:background .15s,box-shadow .15s;}'
      + '#ae-cc-manager .ae-ccm-close:hover{background:var(--ae-accent-dim,rgba(232,160,74,.16));}'
      + '#ae-cc-manager .ae-ccm-close svg{width:24px;height:24px;}'
      + '#ae-cc-manager .ae-ccm-acts{display:flex;gap:5px;}'
      + '#ae-cc-manager .ae-ccm-btn{padding:4px 9px;border-radius:999px;cursor:pointer;'
      + 'font-family:var(--ae-font-sans,system-ui,-apple-system,sans-serif);font-size:11px;font-weight:600;'
      + 'letter-spacing:.01em;white-space:nowrap;'
      + 'background:var(--ae-bg-panel,rgba(26,28,36,.97));color:var(--ae-text-muted,#b7b9c2);'
      + 'border:1px solid var(--ae-btn-border,rgba(255,255,255,.16));'
      + 'box-shadow:0 4px 12px rgba(0,0,0,.28);transition:color .15s,border-color .15s,background .15s;}'
      + '#ae-cc-manager .ae-ccm-btn:hover{color:var(--ae-text-main,#e9e9ec);border-color:var(--ae-btn-border-hover,rgba(255,255,255,.32));}'
      + '#ae-cc-manager .ae-ccm-btn.danger{color:var(--ae-color-danger,#e5678b);border-color:color-mix(in srgb,var(--ae-color-danger,#e5678b) 45%,transparent);}'
      + '#ae-cc-manager .ae-ccm-btn.danger:hover{background:color-mix(in srgb,var(--ae-color-danger,#e5678b) 14%,transparent);}';
    document.head.appendChild(s);
}

// The user-supplied Chat_Close glyph (chat bubble + X), stroke re-routed to currentColor.
var _AE_CCM_CLOSE_SVG =
    '<svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">'
  + '<path d="M10 13L12 11M12 11L14 9M12 11L10 9M12 11L14 13M7.12357 18.7012L5.59961 19.9203C4.76744 '
  + '20.5861 4.35115 20.9191 4.00098 20.9195C3.69644 20.9198 3.40845 20.7813 3.21846 20.5433C3 20.2696 '
  + '3 19.7369 3 18.6712V7.2002C3 6.08009 3 5.51962 3.21799 5.0918C3.40973 4.71547 3.71547 4.40973 '
  + '4.0918 4.21799C4.51962 4 5.08009 4 6.2002 4H17.8002C18.9203 4 19.4796 4 19.9074 4.21799C20.2837 '
  + '4.40973 20.5905 4.71547 20.7822 5.0918C21 5.5192 21 6.07899 21 7.19691V14.8036C21 15.9215 21 '
  + '16.4805 20.7822 16.9079C20.5905 17.2842 20.2843 17.5905 19.908 17.7822C19.4806 18 18.921 18 17.8031 '
  + '18H9.12207C8.70603 18 8.49877 18 8.2998 18.0408C8.12328 18.0771 7.95216 18.1368 7.79168 18.2188C7.61281 '
  + '18.3101 7.45249 18.4384 7.13478 18.6926L7.12357 18.7012Z" stroke="currentColor" stroke-width="2" '
  + 'stroke-linecap="round" stroke-linejoin="round"></path></svg>';

function _ccMgrBuild() {
    _ccMgrEnsureCss();
    var wrap = document.createElement('div');
    wrap.id = 'ae-cc-manager';

    var close = document.createElement('button');
    close.className = 'ae-ccm-close';
    close.title = 'Close chat (save the thread and return to the story)';
    close.innerHTML = _AE_CCM_CLOSE_SVG;
    close.addEventListener('click', function() {
        sendToEngine('AE_CHARCHAT_END', { action: 'save' });
        // Optimistic: the engine's follow-up AE_CHARCHAT_STATE (active:false) takes the
        // manager down via _ccManagerSync. Hide now so it doesn't linger for that round-trip.
        wrap.classList.remove('show');
    });
    wrap.appendChild(close);

    var acts = document.createElement('div');
    acts.className = 'ae-ccm-acts';

    var summ = document.createElement('button');
    summ.className = 'ae-ccm-btn';
    summ.textContent = 'Summarize';
    summ.title = 'Preview a prose recap of this chat (keeps the chat open)';
    summ.addEventListener('click', function() { sendToEngine('AE_CHARCHAT_SUMMARIZE', {}); });
    acts.appendChild(summ);

    var del = document.createElement('button');
    del.className = 'ae-ccm-btn danger';
    del.textContent = 'Delete';
    del.title = 'Discard this chat and delete its saved thread';
    del.addEventListener('click', function() {
        var who = (_charChatState && _charChatState.contactName) ? (' with ' + _charChatState.contactName) : '';
        if (!window.confirm('Delete this chat' + who + '? The conversation is removed from your story and its saved thread is deleted. This cannot be undone.')) return;
        sendToEngine('AE_CHARCHAT_END', { action: 'discard' });
        wrap.classList.remove('show');
    });
    acts.appendChild(del);

    wrap.appendChild(acts);
    document.body.appendChild(wrap);
    return wrap;
}

// Centre the cluster just under #ae-toggle-btn, clamped into the viewport. If the toggle
// is somehow absent (never on a non-story page while a chat is active, but fail closed),
// pin to a sane top-centre default so the controls are never stranded off-screen.
function _ccMgrPlace() {
    if (!_ccMgrEl) return;
    var tb = document.getElementById('ae-toggle-btn');
    var cx, top;
    if (tb && tb.style.display !== 'none') {
        var r = tb.getBoundingClientRect();
        cx = r.left + r.width / 2;
        top = r.bottom + 8;
    } else {
        cx = window.innerWidth / 2;
        top = 60;
    }
    if (cx < 60) cx = 60;
    if (cx > window.innerWidth - 60) cx = window.innerWidth - 60;
    _ccMgrEl.style.left = cx + 'px';
    _ccMgrEl.style.top  = top + 'px';
}

function _ccMgrLoop() {
    _ccMgrRaf = 0;
    if (!_ccMgrEl) return;
    _ccMgrPlace();
    if (_charChatState && _charChatState.active) _ccMgrRaf = requestAnimationFrame(_ccMgrLoop);
}

function _ccManagerSync() {
    var active = !!(_charChatState && _charChatState.active);
    if (!active) {
        if (_ccMgrEl) _ccMgrEl.classList.remove('show');
        if (_ccMgrRaf) { cancelAnimationFrame(_ccMgrRaf); _ccMgrRaf = 0; }
        return;
    }
    if (!_ccMgrEl) _ccMgrEl = _ccMgrBuild();
    _ccMgrPlace();
    _ccMgrEl.classList.add('show');
    if (!_ccMgrRaf) _ccMgrRaf = requestAnimationFrame(_ccMgrLoop);
}


// =============================================================================
// [v2.14.0 CHARCHAT-HEADER; popup DELETED v2.34.0] Chat-active native background retheme.
// The docked header popup menu that used to live here (Fresh thoughts / Show last thought /
// Photo attachments / avatar size+shape) was removed in v2.34.0 CHARCHAT-LAUNCHER-SETTINGS:
// its rows moved to the Chat launcher's settings header (grep _ccLauncherRenderSettings),
// which also fixed the fragility that motivated the whole CHARCHAT-HEADER-RESYNC saga (NAI
// reflowing our button out of a cramped toolbar). What remains is ONLY the editor-background
// retheme while a chat is active -- always a separate concern from the menu, driven off the
// same AE_CHARCHAT_STATE receipt via _cchdrBgSync.
// =============================================================================

// [v2.34.0 CHARCHAT-LAUNCHER-SETTINGS] The docked popup MENU is gone -- its rows moved to the
// Chat launcher's settings header (see _ccLauncherRenderSettings). What remains below is ONLY
// the chat-active background retheme, which was always a separate concern from the menu.
var _cchdrBgEl = null;    // the element the background retheme is currently applied to
var _cchdrBgPrev = '';    // its own inline background, before we touched it (for restore)

// ── Native background retheme, chat-active only ─────────────────────────────
// UNVERIFIED, FLAGGED (see the section banner above): there is no established selector
// in this file for NAI's own editor viewport — every existing bridge override targets
// this file's OWN chrome, never NAI's. This walks up from the native Send button (the
// one concrete NAI anchor this file already trusts) until it finds an ancestor that is
// actually scrolling its content, on the theory that the nearest scrolling ancestor of
// NAI's own Send control is NAI's own editor viewport. A wrong guess fails closed: no
// class gets applied anywhere, nothing else breaks. Confirm with __ceCchdrBgDiag before
// trusting this in a themed screenshot.
function _cchdrFindBgTarget() {
    try {
        var btn = _ccFindNativeSend();
        if (!btn) return null;
        var el = btn.parentElement;
        var hops = 0;
        while (el && hops < 12) {
            if (el.scrollHeight > el.clientHeight + 4 && _ccVisible(el)) return el;
            el = el.parentElement;
            hops++;
        }
    } catch (_e) {}
    return null;
}

function _cchdrApplyBg(on) {
    var target = _cchdrFindBgTarget();
    if (on) {
        if (!target) { console.warn('[CE:cchdr] no background target found this pass — native background left untouched.'); return; }
        if (_cchdrBgEl !== target) _cchdrBgPrev = target.style.background || '';
        _cchdrBgEl = target;
        target.classList.add('ae-cchdr-bg-active');
    } else if (_cchdrBgEl) {
        _cchdrBgEl.style.background = _cchdrBgPrev;
        _cchdrBgEl.classList.remove('ae-cchdr-bg-active');
        _cchdrBgEl = null;
    }
}

// [v2.34.0] Was _cchdrSync -- the mount/unmount half is gone with the popup menu; this now
// ONLY drives the chat-active editor background retheme, off the same AE_CHARCHAT_STATE receipt.
function _cchdrBgSync() {
    var st = _charChatState;
    _cchdrApplyBg(!!(st && st.active));
}

// Diagnostics. Console-only, spend nothing, never fire on their own.
window.__ceCchdrBgDiag = function() {
    var t = _cchdrFindBgTarget();
    var out = { found: !!t, tag: t ? t.tagName : null, cls: t ? t.className : null };
    dbg('[CE:cchdr] background target diag', out);
    return out;
};

// =============================================================================
// [v2.15.0 CHARCHAT-IMGPAINT] Painting the engine's photo anchors.
//
// THE CONTRACT: engine v2.48.0's refreshCharChatImageWidgets() creates a node widget
// after every section carrying a resolved [Image#xxxxxxxx: desc] tag. Each widget holds
// one 1px transparent text node: 'ce-chatimg:' + SHORT_ID + '|||' + DESC. We find that
// string, walk up to the widget's own container, and paint the real photo into it from
// IndexedDB. The image bytes never cross into the Worker — they cannot, because
// script-types.txt forbids URLs in UIPartImage.src and base64 through a memoryLimit:128
// Worker is not viable. Same mechanism Auto-Illustrator v3 proved in production.
//
// SHORT ID vs FULL UUID — the one real subtlety: the document tag (and therefore the
// sentinel) carries only the first 8 hex of the uuid, but dbSave/imgCache/openPromptEditor
// all key on the FULL uuid. So we prefix-resolve against the gallery index, exactly as the
// deleted panel's _ccResolveImage did. The index is cached and rebuilt lazily (2s
// throttle) because a chat with photos re-scans on every repaint; invalidate it when a new
// charchat photo lands or the throttle will serve the miss (see the AE_IMAGE_RESULT hook).
// =============================================================================

var AE_CHARCHAT_IMG_SENTINEL = 'ce-chatimg:';   // MUST match the engine's constant of the same name — flag day if changed
var _ccimgIndex = null;      // Map(shortId -> full uuid)
var _ccimgIndexTs = 0;
var _ccimgScanTmr = null;
// [v2.25.2 IMGPAINT-DESTRUCTIVE-WIPE-FIX] host -> the ONE wrapper node we appended into it.
// Lets us remove exactly and only our own prior paint on a repaint/delete, never anything
// already in host that we did not create.
var _ccimgWrapMap = new WeakMap();

// short -> full uuid, from the gallery. Cheap and lazy: only built when a sentinel is
// actually on screen and the cache is cold.
function _ccimgBuildIndex() {
    var now = Date.now();
    if (_ccimgIndex && (now - _ccimgIndexTs) < 2000) return Promise.resolve(_ccimgIndex);
    return dbGetAll().then(function(recs) {
        var m = new Map();
        (recs || []).forEach(function(r) {
            if (!r || !r.uuid) return;
            var short = String(r.uuid).replace(/-/g, '').substring(0, 8).toLowerCase();
            if (!m.has(short)) m.set(short, r.uuid);
        });
        _ccimgIndex = m; _ccimgIndexTs = Date.now();
        return m;
    }).catch(function() { return _ccimgIndex || new Map(); });
}

function _ccimgInvalidate() { _ccimgIndex = null; _ccimgIndexTs = 0; }

// Find every unpainted sentinel. TreeWalker over text nodes is what Auto-Illustrator's
// bridge uses and it is the right tool: the sentinel is deliberately invisible (1px,
// transparent), so there is no class or id to query for — only its text content.
function _ccimgFindSentinels() {
    var out = [];
    var walker;
    try {
        walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, {
            acceptNode: function(n) {
                return (n.nodeValue && n.nodeValue.indexOf(AE_CHARCHAT_IMG_SENTINEL) === 0)
                    ? NodeFilter.FILTER_ACCEPT : NodeFilter.FILTER_REJECT;
            }
        });
    } catch (_e) { return out; }
    var n;
    while ((n = walker.nextNode())) out.push(n);
    return out;
}

// Walk up from the sentinel text node to a container we can safely own. Bounded hops —
// an unbounded walk on a miss would climb to <body> and we would wipe the page.
function _ccimgContainerFor(textNode) {
    // [v2.16.0] Engine v2.49.0 dropped the box wrapper (see its CHARCHAT-IMGWIDGET-FIX
    // note), so the sentinel text node now sits directly inside NAI's own widget container.
    // Climb while the ancestor's text is STILL only the sentinel — that is the test for
    // "this element exists solely to hold our sentinel", i.e. it is ours to wipe. Stop the
    // moment an ancestor contains anything else: that one belongs to NAI. Bounded hops so a
    // miss can never walk us up to <body> and blank the page.
    var el = textNode.parentElement;
    var best = el;
    var hops = 0;
    while (el && hops < 4) {
        if (el.hasAttribute && el.hasAttribute('data-ce-ccimg')) return el;
        var t = (el.textContent || '').trim();
        if (t.indexOf(AE_CHARCHAT_IMG_SENTINEL) !== 0 || t.length > 80) break;
        best = el;
        el = el.parentElement;
        hops++;
    }
    return best;
}

// [v2.16.0] Caption lookup. The sentinel no longer carries the desc — engine v2.49.0
// shrank it to the bare 8-hex id so the widget payload could drop noTemplate (model prose
// in a UIPartText.text is what made noTemplate necessary in the first place, and dropping
// unproven fields is what got createWidgets to validate at all). The desc was never worth
// a message of its own: EVT_CHARCHAT_STATE.turns[].images[] already carries { uuid (SHORT),
// desc, pending } and this file already parks it on _charChatState.
function _ccimgDescFor(shortId) {
    var st = _charChatState;
    if (!st || !st.turns) return '';
    for (var i = 0; i < st.turns.length; i++) {
        var imgs = st.turns[i] && st.turns[i].images;
        if (!imgs) continue;
        for (var j = 0; j < imgs.length; j++) {
            if (imgs[j] && String(imgs[j].uuid || '').toLowerCase() === shortId) return imgs[j].desc || '';
        }
    }
    return '';
}

function _ccimgPaintOne(sentinelNode) {
    var raw = sentinelNode.nodeValue || '';
    var shortId = raw.slice(AE_CHARCHAT_IMG_SENTINEL.length).trim().toLowerCase();
    if (!/^[0-9a-f]{8}$/.test(shortId)) return;
    var desc = _ccimgDescFor(shortId);

    var host = _ccimgContainerFor(sentinelNode);
    if (!host) return;
    if (host.getAttribute && host.getAttribute('data-ce-ccimg') === shortId) return;  // already painted

    _ccimgBuildIndex().then(function(idx) {
        var full = idx.get(shortId);
        if (!full) {
            // Not in the gallery (yet). Leave the anchor alone rather than painting a
            // permanent error: the photo may still be generating, and the next repaint
            // (or AE_IMAGE_RESULT's invalidate) will find it.
            return;
        }
        return _ccimgLoad(full).then(function(dataUrl) {
            if (!dataUrl) return;
            _ccimgRender(host, shortId, full, dataUrl, desc);
        });
    }).catch(function(e) { console.warn('[CE:ccimg] paint failed:', e); });
}

// dataUrl for a full uuid: memory cache first, then IndexedDB.
function _ccimgLoad(full) {
    var hit = imgCache.get(full);
    if (hit && hit.dataUrl) return Promise.resolve(hit.dataUrl);
    return dbGetAll().then(function(recs) {
        var rec = (recs || []).filter(function(r) { return r && r.uuid === full; })[0];
        return rec ? rec.dataUrl : null;
    }).catch(function() { return null; });
}

function _ccimgRender(host, shortId, full, dataUrl, desc) {
    // [v2.25.1 IMGPAINT-RACE-FIX] host was captured synchronously, then this function was
    // reached through 2 IndexedDB round-trips (_ccimgBuildIndex/_ccimgLoad). If the chat
    // closed in that window, NAI already tore this widget out of the document -- mutating
    // it now would race NAI's own teardown and can crash the whole page (confirmed:
    // NotFoundError: Node.removeChild inside NAI's React framework chunk). Bail silently.
    if (!host.isConnected) return;
    host.setAttribute('data-ce-ccimg', shortId);
    // [v2.25.2] Never innerHTML='' host -- that deletes content we did not create. Remove
    // only OUR OWN previously-appended wrapper, if any, and leave everything else (the
    // engine's sentinel text node included) exactly as it was.
    var _prevWrap = _ccimgWrapMap.get(host);
    if (_prevWrap && _prevWrap.parentNode === host) host.removeChild(_prevWrap);
    host.className = (host.className || '') + ' ae-ccimg';

    var frame = document.createElement('div');
    frame.className = 'ae-ccimg-frame';

    var img = document.createElement('img');
    img.className = 'ae-ccimg-img';
    img.src = dataUrl;
    img.alt = desc || 'chat photo';
    img.addEventListener('click', function() { _galleryLightbox(dataUrl, (desc || '').slice(0, 120)); });
    frame.appendChild(img);

    // The three standard actions, per user — deliberately the SAME three the gallery card
    // already offers (grep "Per-card actions" — download / edit-regenerate / delete), and
    // deliberately the same implementations, not copies of their intent:
    //   Edit -> openPromptEditor(FULL uuid). That is the Image Studio's prompt editor and
    //   it already reads fp/fu/characters/settings back out of the image's own cached
    //   metadata and offers Regenerate. It needs the FULL uuid, which is the entire reason
    //   the prefix resolve above exists.
    // [v2.29.0 CHATIMG-CORNER-ACTIONS, per user] These are now discreet SVG icon buttons
    // overlaid in the frame's corners (download top-left, edit top-right, delete bottom-
    // right) instead of the old text-button bar under the image. Each stopPropagations so a
    // corner tap never also fires the image's own lightbox click. Implementations unchanged.
    function _ccimgCorner(cls, iconName, titleText, onClick) {
        var b = document.createElement('button');
        b.type = 'button';
        b.className = 'ae-ccimg-corner ' + cls;
        b.title = titleText; b.setAttribute('aria-label', titleText);
        var _ic = $.icon(iconName, 14); if (_ic) b.appendChild(_ic);
        b.addEventListener('click', function(e) { e.stopPropagation(); onClick(); });
        return b;
    }

    var dl = _ccimgCorner('tl', 'download', 'Download PNG', function() {
        _downloadAsPng(dataUrl, 'ae-' + String(full).slice(0, 8) + '.png');
    });

    var ed = _ccimgCorner('tr', 'edit', 'Edit / Regenerate in Image Studio', function() {
        openPromptEditor(full);
    });

    var del = _ccimgCorner('br', 'trash', 'Delete image', function() {
        if (!confirm('Delete this image? This cannot be undone.')) return;
        dbDelete(full).then(function() {
            imgCache.delete(full);
            _ccimgInvalidate();
            // The document tag stays. Deleting the IMAGE does not rewrite the story text,
            // and should not: the tag is the character's line ("[Image#ab12: a photo of
            // the rain]"), which they still said. The anchor simply goes back to empty.
            host.removeAttribute('data-ce-ccimg');
            // [v2.25.2] same fix as the paint path -- remove only our own wrapper.
            var _delWrap = _ccimgWrapMap.get(host);
            if (_delWrap && _delWrap.parentNode === host) host.removeChild(_delWrap);
            _ccimgWrapMap.delete(host);
            _showToast('Image deleted — the message tag stays in the story.');
        });
    });

    frame.appendChild(dl); frame.appendChild(ed); frame.appendChild(del);
    host.appendChild(frame);
    _ccimgWrapMap.set(host, frame);   // [v2.25.2] so the NEXT repaint/delete removes only this node
    // [v2.17.0, per user] The desc caption is GONE ("the prompt text under the image is
    // unnecessary and breaks the bubble space between message and emotion"). desc is still
    // resolved and still set as the <img> alt/lightbox title above — it just no longer
    // renders a visible block that pushed the emotion tail away from its bubble.
}

// One scan pass. Cheap when there is nothing to do (TreeWalker rejects everything) and
// idempotent (data-ce-ccimg short-circuits an already-painted anchor).
function _ccimgScan() {
    if (!_charChatState || !_charChatState.active) return;
    var nodes = _ccimgFindSentinels();
    for (var i = 0; i < nodes.length; i++) _ccimgPaintOne(nodes[i]);
    // [v2.17.0 CHARCHAT-AVATAR] Avatars ride the same scan tick — same widget channel,
    // same async-mount race, so a separate timer would only double the cost for no benefit.
    _ccavScan();
    _ccctlScan();   // [v2.41.0 CHARCHAT-TURN-CONTROLS] rides the same idempotent tick
}

// Widgets appear asynchronously (NAI mounts them after the engine's createWidgets
// resolves), and they are re-mounted by NAI on document edits — so a single scan on
// AE_CHARCHAT_STATE would race the mount and miss the re-mounts. A short interval while a
// chat is ACTIVE is the honest cost here: bounded lifetime, ~nothing to do per tick.
// Stops dead when no chat is active, unlike the deleted panel's anchoring poll, which is
// the thing that made polls expensive last time.
function _ccimgSyncScanner() {
    var active = !!(_charChatState && _charChatState.active);
    if (active && !_ccimgScanTmr) {
        _ccavApplySettings();                 // [v2.17.0] push size/radius vars before first paint
        _ccimgScanTmr = setInterval(_ccimgScan, 700);
        _ccimgScan();
    } else if (!active && _ccimgScanTmr) {
        clearInterval(_ccimgScanTmr); _ccimgScanTmr = null;
    }
}

window.__ceCcImgDiag = function() {
    var s = _ccimgFindSentinels();
    var out = {
        chatActive: !!(_charChatState && _charChatState.active),
        sentinelsOnScreen: s.length,
        sentinelTexts: s.slice(0, 6).map(function(n) { return (n.nodeValue || '').slice(0, 60); }),
        scannerRunning: !!_ccimgScanTmr,
        indexSize: _ccimgIndex ? _ccimgIndex.size : 0
    };
    dbg('[CE:ccimg] diag', out);
    return out;
};

// =============================================================================
// [v2.17.0 CHARCHAT-AVATAR] Painting contact avatars into the gutter.
//
// SAME CHANNEL as chat photos: engine v2.50.0 anchors a node widget in the gap above each
// CONTACT turn carrying 'ce-chatava:' + contactId. We TreeWalk for it (the image scanner's
// exact mechanism), resolve the id to the character's hardwired avatar slot via the
// EXISTING _loadCharAvatarImage (charId+'_em_Avatar', legacy charId+'_portrait'), and
// absolute-position the image down out of the zero-height anchor so it lands beside the
// bubble's first line. POV turns get no widget from the engine, so this never paints on the
// user's own side — the "character (not pov)" rule is enforced upstream, not re-checked
// here.
//
// SIZE + ASPECT are user settings (header dropdown), stored in localStorage and pushed to
// :root as CSS variables so a change is instant and repaints nothing. Aspect is expressed
// as border-radius here (round vs rounded-square) rather than width≠height, because a
// chat avatar reads best square-cropped at any roundness; a true non-square aspect would
// fight object-fit:cover. If a rectangular avatar is ever wanted, this is where it changes.
//
// EMOTION REACTIONS [v2.47.0 EMOSTUDIO-24DEFAULT, bridge side shipped]: this file now
// parses an 'id|emotion' sentinel and does a per-emotion slot lookup with Avatar
// fallback (_loadCharEmotionImage, _ccavPaintOne). ENGINE SIDE STILL PENDING as of
// this patch — the engine still sends bare 'ce-chatava:' + contactId with no '|'
// suffix (refreshCharChatImageWidgets, SECTION 18 area), which this parser already
// degrades gracefully for (empty emotion -> plain Avatar-slot behavior, unchanged from
// before this patch). Once the engine appends the resolved Emotion: word
// ('ce-chatava:' + id + '|' + emotion), avatars start reacting with zero further
// bridge-side change — the seam was left clean on purpose and this patch is exactly
// the "nothing else here changes" the old comment promised.
// =============================================================================

var AE_CHARCHAT_AVA_SENTINEL = 'ce-chatava:';   // MUST match the engine constant — flag day if changed

function _ccavSettings() {
    var size = parseInt(localStorage.getItem('ae_ccav_size'), 10);
    if (!(size > 0)) size = 40;
    var radius = localStorage.getItem('ae_ccav_radius');
    if (radius !== 'round' && radius !== 'rounded' && radius !== 'portrait') radius = 'round';
    return { size: size, radius: radius };
}

function _ccavApplySettings() {
    var s = _ccavSettings();
    var root = document.documentElement;
    root.style.setProperty('--ae-cca-size', s.size + 'px');
    // [v2.27.0 CHAT-AVATAR-GUTTER] Portrait matches NAI's own 832x1216 (13:19) generation
    // frame -- a height multiplier only, so --ae-cca-size (the S/M/L knob) keeps meaning
    // "width" across all three shapes instead of needing a second sizing axis.
    if (s.radius === 'portrait') {
        root.style.setProperty('--ae-cca-radius', '12%');
        root.style.setProperty('--ae-cca-h-mult', String(1216 / 832));
    } else {
        root.style.setProperty('--ae-cca-radius', s.radius === 'round' ? '50%' : '8px');
        root.style.setProperty('--ae-cca-h-mult', '1');
    }
}

function _ccavFindSentinels() {
    var out = [];
    var walker;
    try {
        walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, {
            acceptNode: function(n) {
                return (n.nodeValue && n.nodeValue.indexOf(AE_CHARCHAT_AVA_SENTINEL) === 0)
                    ? NodeFilter.FILTER_ACCEPT : NodeFilter.FILTER_REJECT;
            }
        });
    } catch (_e) { return out; }
    var n;
    while ((n = walker.nextNode())) out.push(n);
    return out;
}

// Same bounded-climb reasoning as _ccimgContainerFor: find the element that exists solely
// to hold our sentinel, stop before any ancestor that holds real content.
function _ccavContainerFor(textNode) {
    var el = textNode.parentElement;
    var best = el;
    var hops = 0;
    while (el && hops < 4) {
        if (el.hasAttribute && el.hasAttribute('data-ce-ccav')) return el;
        var t = (el.textContent || '').trim();
        if (t.indexOf(AE_CHARCHAT_AVA_SENTINEL) !== 0 || t.length > 80) break;
        best = el;
        el = el.parentElement;
        hops++;
    }
    return best;
}

function _ccavPaintOne(sentinelNode) {
    var raw = sentinelNode.nodeValue || '';
    var body = raw.slice(AE_CHARCHAT_AVA_SENTINEL.length).trim();
    // [v2.47.0 EMOSTUDIO-24DEFAULT] The engine now appends 'id|emotion' once it sends the
    // trailing Emotion: line's resolved word; a sentinel with no '|' (older engine build,
    // or a turn with no Emotion: line) still parses fine and degrades to plain Avatar-slot
    // behavior via _loadCharEmotionImage's own empty-emotion guard.
    var bar = body.indexOf('|');
    var charId  = (bar >= 0 ? body.slice(0, bar) : body).trim();
    var emotion = (bar >= 0 ? body.slice(bar + 1) : '').trim();
    if (!charId) return;

    // Paint key includes emotion: a contact's emotion can change turn-to-turn even
    // though contactId doesn't, and the old charId-only guard would have skipped every
    // repaint after the first, freezing every avatar on whatever emotion painted first.
    var paintKey = charId + '|' + emotion;
    var host = _ccavContainerFor(sentinelNode);
    if (!host) return;
    if (host.getAttribute && host.getAttribute('data-ce-ccav') === paintKey) return;   // already painted this exact state

    _loadCharEmotionImage(charId, emotion).then(function(dataUrl) {
        if (!dataUrl) {
            // No avatar image for this character. Leave the anchor empty and unmarked so a
            // later upload + repaint fills it, rather than stamping a broken slot.
            return;
        }
        host.setAttribute('data-ce-ccav', paintKey);
        host.className = (host.className || '') + ' ae-ccav-anchor';
        // Idempotent: clear any prior img we painted (an avatar swap or emotion change
        // re-runs this).
        var old = host.querySelector('.ae-ccav');
        if (old) old.remove();
        var img = document.createElement('img');
        img.className = 'ae-ccav';
        img.src = dataUrl;
        img.alt = 'avatar';
        host.appendChild(img);
    }).catch(function(e) { console.warn('[CE:ccav] avatar paint failed:', e); });
}

function _ccavScan() {
    if (!_charChatState || !_charChatState.active) return;
    var nodes = _ccavFindSentinels();
    for (var i = 0; i < nodes.length; i++) _ccavPaintOne(nodes[i]);
}

// [v2.41.0 CHARCHAT-TURN-CONTROLS] Per-contact-turn edit / regen / delete controls.
// The engine already exposes every op this needs (handleCharChatAction: 'regen' drops+refires
// the LAST contact turn, 'edit' folds {ids,text} onto a turn, 'remove' drops {ids}); the sender
// charChatAction() already exists; and EVT_CHARCHAT_STATE.turns[] already carries per-turn
// { ids, isPov, body } on the wire (parked on _charChatState). So this is a pure bridge overlay:
// no new message, no new storage key, no engine change.
//
// MAPPING: the avatar sentinel is anchored one-per-contact-turn by the engine and carries only
// contactId, so we map by POSITION -- the Nth contact sentinel (TreeWalker DOM order) is the Nth
// contact turn (document order). Both derive from the same top-to-bottom document, so equal
// length guarantees identical ordering. We HARD-GATE on equal counts: if they disagree (a widget
// mid-mount, or a just-removed turn NAI has not re-mounted yet) we paint nothing and clear any
// stale cluster, rather than risk wiring a DELETE to the wrong turn. The 700ms scanner retries.
//
// SCOPE / LIVE-TUNE (flagged, not hidden): (a) controls attach to the CONTACT-turn avatar anchor
// only -- POV (user) turns have no engine sentinel to anchor to, so editing/removing one's own
// turns is a follow-up that needs a POV sentinel from the engine. (b) Placement is inherited from
// the avatar gutter, whose geometry the code itself calls unconfirmed -- one live positioning pass
// is expected. (c) edit/delete use window.prompt/confirm for v1: dependency-free and safe (no
// contenteditable surgery in NAI's editor); a themed modal can replace them once geometry is set.
function _ccctlContactTurns() {
    var st = _charChatState;
    if (!st || !st.turns) return [];
    var out = [];
    for (var i = 0; i < st.turns.length; i++) { var t = st.turns[i]; if (t && !t.isPov) out.push(t); }
    return out;
}

function _ccctlTurnText(turn) {
    return String((turn && (turn.body != null ? turn.body : turn.raw)) || '');
}

function _ccctlSig(ids, isLast) { return (ids || []).join(',') + '|' + (isLast ? 'L' : ''); }

function _ccctlClearHost(host) {
    if (!host) return;
    var old = host.querySelector('.ae-ccctl');
    if (old) old.remove();
    if (host.removeAttribute) host.removeAttribute('data-ce-ccctl');
}

function _ccctlEdit(turn) {
    var ids = (turn && turn.ids) || [];
    if (!ids.length) return;
    var cur = _ccctlTurnText(turn);
    var next = window.prompt('Edit message \u2014 it is re-formatted automatically:', cur);
    if (next === null) return;
    next = String(next).trim();
    if (!next || next === cur.trim()) return;
    charChatAction('edit', { ids: ids, text: next });
}

function _ccctlRemove(turn) {
    var ids = (turn && turn.ids) || [];
    if (!ids.length) return;
    var preview = _ccctlTurnText(turn).replace(/\s+/g, ' ').slice(0, 80);
    if (!window.confirm('Delete this message?\n\n\u201c' + preview + '\u201d')) return;
    charChatAction('remove', { ids: ids });
}

function _ccctlBuildCluster(turn, isLast) {
    var wrap = document.createElement('div');
    wrap.className = 'ae-ccctl';
    var mk = function(icon, cls, title, handler) {
        var b = document.createElement('button');
        b.type = 'button';
        b.className = 'ae-ccctl-btn' + (cls ? (' ' + cls) : '');
        b.title = title;
        b.innerHTML = getCyberIconHTML(icon, 13);
        b.addEventListener('click', function(ev) { ev.preventDefault(); ev.stopPropagation(); handler(); });
        wrap.appendChild(b);
    };
    mk('pencil', '', 'Edit this message', function() { _ccctlEdit(turn); });
    if (isLast) mk('regen', '', 'Regenerate this reply', function() { charChatAction('regen', {}); });
    mk('trash', 'ae-ccctl-danger', 'Delete this message', function() { _ccctlRemove(turn); });
    return wrap;
}

function _ccctlScan() {
    var st = _charChatState;
    if (!st || !st.active) return;
    var turns = _ccctlContactTurns();
    var sentinels = _ccavFindSentinels();   // one per contact turn, DOM order
    if (sentinels.length !== turns.length) {
        // Mismatched (mid-mount / mid-edit): clear any stale clusters and wait for a settled tick.
        for (var s = 0; s < sentinels.length; s++) _ccctlClearHost(_ccavContainerFor(sentinels[s]));
        return;
    }
    for (var i = 0; i < sentinels.length; i++) {
        var host = _ccavContainerFor(sentinels[i]);
        if (!host) continue;
        var turn = turns[i];
        var isLast = (i === turns.length - 1);
        var sig = _ccctlSig(turn.ids, isLast);
        if (host.getAttribute && host.getAttribute('data-ce-ccctl') === sig) continue;   // painted, unchanged
        _ccctlClearHost(host);
        if ((host.className || '').indexOf('ae-ccctl-anchor') < 0) host.className = (host.className || '') + ' ae-ccctl-anchor';
        host.appendChild(_ccctlBuildCluster(turn, isLast));
        if (host.setAttribute) host.setAttribute('data-ce-ccctl', sig);
    }
}

// [v2.28.0 CHAT-AVATAR-WIDGET-WIDTH] Was sentinelTexts-only; now reports the actual
// measured geometry of each avatar's host box and its parent, since the v2.27.0/v2.28.0
// positioning fixes are both hypotheses about what NAI renders here, not confirmed --
// run this live and read hostWidth off it before patching this again.
window.__ceCcAvDiag = function() {
    var s = _ccavFindSentinels();
    var geo = s.slice(0, 6).map(function(n) {
        var host = _ccavContainerFor(n);
        var hr = host ? host.getBoundingClientRect() : null;
        var pr = (host && host.parentElement) ? host.parentElement.getBoundingClientRect() : null;
        return {
            text: (n.nodeValue || '').slice(0, 40),
            hostTag: host ? host.tagName : null,
            hostClass: host ? host.className : null,
            hostWidth: hr ? hr.width : null,
            hostLeft: hr ? hr.left : null,
            parentWidth: pr ? pr.width : null,
            parentLeft: pr ? pr.left : null
        };
    });
    var out = {
        chatActive: !!(_charChatState && _charChatState.active),
        avatarSentinelsOnScreen: s.length,
        geometry: geo,
        settings: _ccavSettings()
    };
    dbg('[CE:ccav] diag', out);
    return out;
};




// =============================================================================
// [CE-STRIP vNEXT] SECTION 14 (ACTIONS TAB) and the old SECTION 13c (HOLDING POPOUT) removed wholesale. [v2.4.0 CHARCHAT-HUD] The 13c NUMBER IS REUSED above by the Character Chat popout — Holding itself is still gone. — Holding was already fully dead engine-side (AE_HOLDING_REQ/AE_HOLDING_ACTION have no handler), and the Actions tab's own primary paths (RUN_QUICK_INSTANCE, AE_SET_SILENT) were also already dead. execEntityAction()/execActionInstance() (Section 6) are left untouched — EXECUTE_ENTITY_ACTION is confirmed dead but RUN_ACTION_INSTANCE is engine-handled per this file's own prior note; not touching bridge senders without confirming every caller first.
// SECTION 15 — SMART READER
// Receives serialized UIPart arrays from engine and renders them as DOM.
// Phase 1: logs and inspects incoming parts (for development/debugging).
// Phase 2: full renderer — build as UIPart types become needed.
// =============================================================================

// Engine-side complement needed in adventure-engine (UIPart serialization +
// AE_SMART_CALLBACK / AE_OPEN_CHAR_EDIT message handling — check current section
// numbering there before patching, this file's numbering has drifted before):
//
//   const _cbReg = new Map();
//   let _cbN = 0;
//   function _serializeUIPart(part) {
//       var s = Object.assign({}, part);
//       if (typeof s.callback === 'function') { var id = 'cb_' + (_cbN++); _cbReg.set(id, s.callback); s.callback = id; }
//       if (typeof s.onChange  === 'function') { var id = 'cb_' + (_cbN++); _cbReg.set(id, s.onChange);  s.onChange  = id; }
//       if (Array.isArray(s.content)) s.content = s.content.map(_serializeUIPart);
//       return s;
//   }
//   async function openSmartModal(title, parts, modalId) {
//       await broadcastToTM('AE_SMART_MODAL', { modalId: modalId || generateId(), title: title, parts: parts.map(_serializeUIPart) });
//   }
//   // In handleBridgeMessage: case 'AE_SMART_CALLBACK': { const fn = _cbReg.get(payload.callbackId); if (fn) await fn(payload.value); break; }
//   // In handleBridgeMessage: case 'AE_OPEN_CHAR_EDIT': { const parts = await buildCharEditContent(payload.charId); await openSmartModal('Edit Character', parts, 'char_'+payload.charId); break; }

function handleSmartModal(payload) {
    console.log('[AE Bridge] Smart modal:', payload.title, '—', (payload.parts || []).length, 'parts');
    _renderSmartModal(payload);
}

function _renderSmartModal(payload) {
    // Remove existing modal with same ID
    var existing = document.getElementById('ae-smart-modal-' + (payload.modalId || 'default'));
    if (existing) existing.remove();

    // Hide HUD while modal is open (avoids z-index conflicts on some platforms)
    var _smRoot = document.getElementById('ae-ui-root');
    var _smWasVisible = _smRoot && _smRoot.style.display !== 'none';
    if (_smWasVisible) _smRoot.style.display = 'none';
    var _smRestore = function() { if (_smWasVisible && _smRoot) _smRoot.style.display = 'flex'; };

    var overlay = document.createElement('div');
    overlay.className = 'ae-picker-overlay';
    var sheet = document.createElement('div');
    sheet.id = 'ae-smart-modal-' + (payload.modalId || 'default');
    sheet.className = 'ae-picker-sheet';
    sheet.style.maxHeight = '80vh';

    var hdr = document.createElement('div'); hdr.className = 'ae-picker-header';
    var title = document.createElement('span'); title.className = 'ae-picker-title'; title.textContent = payload.title || 'Modal';
    hdr.appendChild(title);
    hdr.appendChild($.btn('✕', 'icon ghost', function() { overlay.remove(); _smRestore(); }));
    sheet.appendChild(hdr);

    var body = document.createElement('div');
    body.style.cssText = 'padding:var(--ae-space-md);overflow-y:auto;flex:1;display:flex;flex-direction:column;gap:var(--ae-space-sm);';
    _renderUIParts(payload.parts || [], body, payload.modalId);
    sheet.appendChild(body);
    overlay.appendChild(sheet);
    overlay.addEventListener('click', function(e) { if (e.target === overlay) { overlay.remove(); _smRestore(); } });
    document.body.appendChild(overlay);
}

function _renderUIParts(parts, container, modalId) {
    parts.forEach(function(part) { _renderUIPart(part, container, modalId); });
}

function _renderUIPart(part, container, modalId) {
    if (!part || !part.type) return;
    switch (part.type) {
        case 'text': {
            var el = document.createElement('div');
            el.textContent = part.text || '';
            Object.assign(el.style, part.style || {});
            container.appendChild(el); break;
        }
        case 'button': {
            var btn = $.btn(part.text || 'OK', '', function() {
                if (part.callback && typeof part.callback === 'string') {
                    sendToEngine('AE_SMART_CALLBACK', { callbackId: part.callback, value: null, modalId: modalId });
                }
            });
            Object.assign(btn.style, part.style || {});
            container.appendChild(btn); break;
        }
        case 'textInput':
        case 'numberInput': {
            var input = document.createElement('input');
            input.type = part.type === 'numberInput' ? 'number' : 'text';
            input.value = part.initialValue !== undefined ? part.initialValue : '';
            input.placeholder = part.placeholder || '';
            input.style.cssText = 'width:100%;background:var(--ae-bg-raised);border:1px solid var(--ae-bg-border);color:var(--ae-text-main);padding:8px 10px;border-radius:var(--ae-radius-sm);font-family:var(--ae-font-sans);font-size:13px;';
            Object.assign(input.style, part.style || {});
            if (part.label) { var lbl = document.createElement('label'); lbl.style.cssText = 'font-size:11px;color:var(--ae-text-muted);display:block;margin-bottom:3px;'; lbl.textContent = part.label; container.appendChild(lbl); }
            input.addEventListener('change', function() {
                if (part.onChange && typeof part.onChange === 'string') {
                    sendToEngine('AE_SMART_CALLBACK', { callbackId: part.onChange, value: input.value, modalId: modalId });
                }
            });
            container.appendChild(input); break;
        }
        case 'multilineTextInput': {
            var ta = document.createElement('textarea');
            ta.value = part.initialValue || '';
            ta.placeholder = part.placeholder || '';
            ta.rows = 4;
            ta.style.cssText = 'width:100%;background:var(--ae-bg-raised);border:1px solid var(--ae-bg-border);color:var(--ae-text-main);padding:8px 10px;border-radius:var(--ae-radius-sm);font-family:var(--ae-font-sans);font-size:13px;resize:vertical;';
            Object.assign(ta.style, part.style || {});
            if (part.label) { var lbl2 = document.createElement('label'); lbl2.style.cssText = 'font-size:11px;color:var(--ae-text-muted);display:block;margin-bottom:3px;'; lbl2.textContent = part.label; container.appendChild(lbl2); }
            ta.addEventListener('change', function() {
                if (part.onChange && typeof part.onChange === 'string') {
                    sendToEngine('AE_SMART_CALLBACK', { callbackId: part.onChange, value: ta.value, modalId: modalId });
                }
            });
            container.appendChild(ta); break;
        }
        case 'collapsibleSection': {
            var sec = $.section(part.title || 'Section', function(b) { _renderUIParts(part.content || [], b, modalId); }, { open: !part.initialCollapsed });
            container.appendChild(sec); break;
        }
        case 'row': {
            var row = document.createElement('div'); row.style.cssText = 'display:flex;gap:var(--ae-space-sm);align-items:center;';
            _renderUIParts(part.content || [], row, modalId); container.appendChild(row); break;
        }
        case 'column': {
            var col = document.createElement('div'); col.style.cssText = 'display:flex;flex-direction:column;gap:var(--ae-space-sm);';
            _renderUIParts(part.content || [], col, modalId); container.appendChild(col); break;
        }
        case 'box': {
            var box = document.createElement('div'); box.style.cssText = 'padding:8px;border-radius:var(--ae-radius-sm);background:var(--ae-bg-raised);';
            Object.assign(box.style, part.style || {});
            _renderUIParts(part.content || [], box, modalId); container.appendChild(box); break;
        }
        case 'sliderInput': {
            var sliderWrap = document.createElement('div'); sliderWrap.style.cssText = 'display:flex;align-items:center;gap:8px;';
            if (part.label) { var sl = document.createElement('span'); sl.style.cssText = 'font-size:12px;color:var(--ae-text-muted);min-width:60px;'; sl.textContent = part.label; sliderWrap.appendChild(sl); }
            var slider = document.createElement('input'); slider.type = 'range';
            slider.min  = String(part.min  || 0);
            slider.max  = String(part.max  || 100);
            slider.step = String(part.step || 1);
            slider.value = String(part.initialValue !== undefined ? part.initialValue : 50);
            slider.style.cssText = 'flex:1;accent-color:var(--ae-accent);';
            var slVal = document.createElement('span'); slVal.style.cssText = 'font-size:11px;color:var(--ae-text-main);min-width:28px;text-align:right;'; slVal.textContent = slider.value;
            slider.addEventListener('input', function() { slVal.textContent = slider.value; });
            slider.addEventListener('change', function() {
                if (part.onChange && typeof part.onChange === 'string') {
                    sendToEngine('AE_SMART_CALLBACK', { callbackId: part.onChange, value: Number(slider.value), modalId: modalId });
                }
            });
            sliderWrap.appendChild(slider); sliderWrap.appendChild(slVal); container.appendChild(sliderWrap); break;
        }
        case 'toggle': {
            var togWrap = document.createElement('label'); togWrap.style.cssText = 'display:flex;align-items:center;gap:8px;cursor:pointer;font-size:13px;';
            var togCb = document.createElement('input'); togCb.type = 'checkbox'; togCb.checked = !!part.initialValue;
            togCb.addEventListener('change', function() {
                if (part.onChange && typeof part.onChange === 'string') {
                    sendToEngine('AE_SMART_CALLBACK', { callbackId: part.onChange, value: togCb.checked, modalId: modalId });
                }
            });
            togWrap.appendChild(togCb); togWrap.appendChild(document.createTextNode(part.label || '')); container.appendChild(togWrap); break;
        }
        default: { console.log('[AE Bridge] SmartReader: unsupported UIPart type:', part.type); break; }
    }
}

