    sbHdr.style.cssText = 'font-size:10px; text-transform:uppercase; letter-spacing:1px; color:var(--ae-text-dim); font-weight:bold; margin-top:10px; padding-bottom:2px; border-bottom:1px solid var(--ae-bg-border);';
    sbHdr.textContent = 'Scene Background (module default)';
