    spider: '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M9 11.5L4.5 10L3 6M9 12.5L4 14L3.5 17M9 13L6 16.5L8 21M9 11L6 7L7.2 3M15 11.5L19.5 10L21 6M15 12.5L20 14L20.5 17M15 13L18 16.5L16 21M15 11L18 7L16.8 3M15 14C15 15.6569 13.6569 17 12 17C10.3431 17 9 15.6569 9 14C9 13.3333 9.21745 12.7175 9.58529 12.2195C9.80373 11.9237 9.91295 11.7758 9.95062 11.7017C9.99705 11.6104 10.0031 11.5944 10.0283 11.4951C10.0488 11.4145 10.0575 11.3103 10.0749 11.1018L10.3255 8.09689C10.3797 7.44678 10.4068 7.12173 10.5437 6.99076C10.6624 6.87726 10.8292 6.82925 10.99 6.86233C11.1756 6.90049 11.3713 7.16144 11.7627 7.68333L12.0002 8L12.2377 7.68333C12.6292 7.16144 12.8249 6.90049 13.0105 6.86233C13.1713 6.82925 13.3381 6.87726 13.4568 6.99076C13.5937 7.12173 13.6208 7.44678 13.675 8.09689L13.9252 11.1017C13.9425 11.3102 13.9512 11.4145 13.9717 11.4951C13.997 11.5944 14.003 11.6104 14.0494 11.7017C14.0871 11.7758 14.1963 11.9237 14.4148 12.2196C14.7826 12.7176 15 13.3334 15 14Z" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>',
    snake:  '<svg viewBox="0 0 512 512" width="19" height="19" xmlns="http://www.w3.org/2000/svg"><path fill="currentColor" d="M395.25,443.374c-2.552-2.5-4.37-5.249-5.636-8.24c-1.886-4.469-2.424-9.521-1.552-14.315c0.886-4.795,3.029-9.21,6.748-13.035l47.694-48.899c8.953-9.164,15.724-19.852,20.148-31.19c6.65-17.011,8.12-35.424,4.484-53.041c-3.613-17.595-12.482-34.523-26.267-47.944c-9.164-8.953-19.86-15.724-31.19-20.147c-17.011-6.65-35.424-8.12-53.034-4.491c-17.602,3.62-34.53,12.489-47.959,26.274l-77.816,79.77c-2.499,2.552-5.256,4.378-8.248,5.636c-4.46,1.886-9.52,2.424-14.307,1.56c-4.802-0.894-9.21-3.037-13.034-6.755c-2.552-2.492-4.37-5.242-5.635-8.241c-1.886-4.469-2.424-9.513-1.553-14.3c0.886-4.802,3.029-9.218,6.74-13.042l20.087-20.586c8.952-9.165,15.723-19.86,20.146-31.19c6.651-17.012,8.12-35.424,4.484-53.034c-3.469-16.906-11.831-33.137-24.677-46.293l-10.679-35.462c-6.044-20.117-22.17-35.614-42.506-40.87l-40.34-10.437c-7.513-1.939-15.496,0.288-20.919,5.832L85.613,56.125c-5.423,5.552-7.446,13.588-5.316,21.048l11.429,40.074c5.764,20.208,21.654,35.932,41.923,41.491l33.174,9.089c0,0,3.136,6.514,4.393,9.506c1.886,4.477,2.424,9.52,1.56,14.307c-0.894,4.803-3.037,9.218-6.756,13.043L145.94,225.27c-8.945,9.172-15.716,19.859-20.146,31.19c-6.643,17.011-8.112,35.424-4.477,53.041c3.606,17.595,12.482,34.531,26.26,47.952c9.164,8.953,19.859,15.724,31.19,20.148c17.012,6.65,35.424,8.112,53.042,4.484c17.602-3.62,34.523-12.482,47.951-26.267l77.824-79.778c2.5-2.545,5.249-4.37,8.24-5.628c4.469-1.886,9.521-2.432,14.3-1.56c4.802,0.894,9.225,3.037,13.042,6.748c2.56,2.5,4.378,5.249,5.635,8.24c1.893,4.469,2.431,9.521,1.56,14.308c-0.886,4.802-3.037,9.21-6.748,13.042l-47.702,48.891c-8.953,9.164-15.716,19.867-20.147,31.198c-6.643,17.004-8.112,35.416-4.476,53.034c3.606,17.602,12.482,34.522,26.26,47.952c41.18,40.165,117.088,11.262,123.087-18.05C449.041,475.753,415.238,466.641,395.25,443.374z"/><path fill="currentColor" d="M92.786,42.461c0,0-32.19-30.403-31.713-42.461c-7.165,7.166,0.576,20.284,0.576,20.284s-13.118-7.741-20.284-0.576c12.066-0.478,42.468,31.706,42.468,31.706L92.786,42.461z"/></svg>'
