// bat weighted heavier than the crawlers -- reads as the signature familiar.
var AE_WITCH_CRITTER_BAG = ['bat', 'bat', 'spider', 'snake'];

function _witchCrittersOn() {
    return (document.documentElement.className || '').indexOf('theme-witchhollow') !== -1;
}

function _setupWitchCritters() {
    document.addEventListener('pointerdown', function(e) {
        if (!_witchCrittersOn()) return;
        try { if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return; } catch (_) {}
        var t = e.target && e.target.closest ? e.target.closest('.ae-btn, .ae-sub-tab-btn') : null;
        if (!t) return;
        var n = 3 + Math.floor(Math.random() * 3);   // 3..5 familiars
        for (var i = 0; i < n; i++) {
            var key = AE_WITCH_CRITTER_BAG[Math.floor(Math.random() * AE_WITCH_CRITTER_BAG.length)];
            var c = document.createElement('div');
            c.className = 'ae-critter ' + key;
            c.innerHTML = AE_WITCH_CRITTERS[key];
            c.style.left = e.clientX + 'px';
            c.style.top  = e.clientY + 'px';
            var ang  = Math.random() * Math.PI * 2;
            var dist = 34 + Math.random() * 42;       // 34..76px escape radius
            c.style.setProperty('--cdx',  (Math.cos(ang) * dist).toFixed(1) + 'px');
            c.style.setProperty('--cdy',  (Math.sin(ang) * dist).toFixed(1) + 'px');
            c.style.setProperty('--crot', ((ang * 180 / Math.PI) + 90).toFixed(0) + 'deg');
            document.body.appendChild(c);
            (function(el) { setTimeout(function() { el.remove(); }, 1120); })(c);  /* [v2.36.0 WITCH-CRITTERS-ART] matches the slowed 1.1s animation */
        }
    }, true);
}

function _nameToColor(name) {
    var hash = 0;
    for (var i = 0; i < name.length; i++) hash = ((hash << 5) - hash) + name.charCodeAt(i);
    return 'hsl(' + (Math.abs(hash) % 360) + ',30%,25%)';
}

function _showLightbox(dataUrl, caption) {
    var lb = document.createElement('div'); lb.className = 'ae-lightbox';
    lb.addEventListener('click', function() { lb.remove(); });
    var img = document.createElement('img'); img.src = dataUrl; img.style.borderRadius = '8px';
    img.addEventListener('click', function(e) { e.stopPropagation(); });
    var cap = document.createElement('p'); cap.textContent = caption; cap.style.cssText = 'color:rgba(255,255,255,0.5);font-size:11px;max-width:90vw;text-align:center;margin:0;';
    lb.appendChild(img); lb.appendChild(cap); document.body.appendChild(lb);
}

// =============================================================================
// SECTION 17b — SAKURA GLASS FX  [v1.5.0 SAKURA]
// Rain on the glass, koi under it. Bridge-local decoration: no engine message,
// no storage key, nothing to sync. It reads exactly one thing — whether
// documentElement carries `theme-sakura` — and builds or tears down accordingly.
//
// WHY A TICK AND NOT PURE EVENTS: the HUD re-renders the map tab wholesale, so a
// layer parented into #ae-map-viewport can vanish between frames. _aeSakuraFXTick
// is idempotent — it re-attaches anything missing and does nothing otherwise —
// which is far more robust than trying to hook every render path. The class
// MutationObserver just makes theme switches feel instant instead of up to 1.4s
// late; the tick alone would still get there.
//
// COST CONTROL, in order of how much they save:
//   - nothing is built at all unless theme-sakura is active
//   - spawners stop on document.hidden and while the HUD is minimized/hidden
//   - AE_SAKURA_FX.cap bounds live drops; drops self-remove on animationend
//   - prefers-reduced-motion: no drops, no koi, ever
// Each drop carries a backdrop-filter, which is the expensive part. The cap is
// the dial to turn if this ever costs frames.
// =============================================================================
var AE_SAKURA_FX = {
    on: false,
    tick: null,
    spawners: [],   // interval ids
    cap: { rain: 16, glass: 10 },
    koiCount: 2   // [v1.5.1] two fixed corner koi, not three cross-pond swimmers
};

function _aeSakuraOn() {
    return (document.documentElement.className || '').indexOf('theme-sakura') !== -1;
}

function _aeSakuraReduceMotion() {
    try { return window.matchMedia('(prefers-reduced-motion: reduce)').matches; }
    catch (_) { return false; }
}

function _aeRand(a, b) { return a + Math.random() * (b - a); }

// Is this layer worth animating right now? An offscreen or zero-height layer
// still runs its animations, so check before spawning into it.
function _aeSakuraLayerLive(el) {
    if (!el || !el.isConnected) return false;
    if (document.hidden) return false;
    var r = el.getBoundingClientRect();
    return r.width > 8 && r.height > 8;
}

// Spawn one drop into `layer`. ~55% of drops let go and run; the rest cling and
// evaporate. Run distance is measured from the drop to the bottom of the layer,
// so a drop born near the floor takes a short, quick fall — which is correct.
function _aeSakuraSpawnDrop(layer, cap) {
    if (!_aeSakuraLayerLive(layer)) return;
    if (layer.childElementCount >= cap) return;

    var h = layer.clientHeight || 400;
    var run = Math.random() < 0.55;
    var w = run ? _aeRand(4.5, 13) : _aeRand(2.5, 6.5);
    var yPct = run ? _aeRand(4, 55) : _aeRand(3, 92);
    var fall = h * (1 - yPct / 100) + 24;

    var d = document.createElement('div');
    d.className = 'ae-sakura-drop ' + (run ? 'run' : 'still');
    d.style.setProperty('--ae-drop-x', _aeRand(2, 98).toFixed(2) + '%');
    d.style.setProperty('--ae-drop-y', yPct.toFixed(2) + '%');
    d.style.setProperty('--ae-drop-w', w.toFixed(1) + 'px');
    d.style.setProperty('--ae-drop-o', (run ? _aeRand(0.62, 0.92) : _aeRand(0.35, 0.70)).toFixed(2));
    d.style.setProperty('--ae-drop-delay', _aeRand(0, 1.6).toFixed(2) + 's');
    if (run) {
        d.style.setProperty('--ae-drop-dy', fall.toFixed(0) + 'px');
        d.style.setProperty('--ae-drop-trail', (w * _aeRand(1.6, 3.4)).toFixed(0) + 'px');
        // Bigger drops are heavier: they fall faster over the same distance.
        d.style.setProperty('--ae-drop-dur', _aeRand(2.4, 5.2 - w * 0.12).toFixed(2) + 's');
    } else {
        d.style.setProperty('--ae-drop-dur', _aeRand(4.5, 9).toFixed(2) + 's');
    }

    d.addEventListener('animationend', function () { try { d.remove(); } catch (_) {} });
    layer.appendChild(d);
}

// One spawner per layer. Returns the interval id so teardown can clear it.
function _aeSakuraStartRain(layer, cap, everyMs) {
    return setInterval(function () {
        if (!AE_SAKURA_FX.on) return;
        if (Math.random() < 0.72) _aeSakuraSpawnDrop(layer, cap);
    }, everyMs);
}

// Build the koi. Three fish, three depths. `flip` mirrors half of them so the
// same artwork does not read as a repeated sprite.
function _aeSakuraBuildKoi(pond) {
    // [v1.5.1 SAKURA] Two fixed medallions instead of three cross-pond swimmers:
    // one large and near, bottom-left; one smaller, blurrier and further, top-right.
    // Counterclockwise (see ae-koi-spin) at two different speeds so they never sync.
    var koi = [
        { size: 132, op: 0.60, blur: '0.4px', dur: 52, x: '14%', y: '86%' },  // bottom-left, near
        { size: 72,  op: 0.34, blur: '2.1px', dur: 74, x: '87%', y: '15%' }   // top-right, far
    ];
    for (var i = 0; i < AE_SAKURA_FX.koiCount && i < koi.length; i++) {
        var k = koi[i];
        var el = document.createElement('div');
        el.className = 'ae-sakura-koi';
        el.innerHTML = AE_SAKURA_ART.koi;
        el.style.setProperty('--ae-koi-size', k.size + 'px');
        el.style.setProperty('--ae-koi-op', String(k.op));
        el.style.setProperty('--ae-koi-blur', k.blur);
        el.style.setProperty('--ae-koi-dur', k.dur + 's');
        el.style.setProperty('--ae-koi-delay', (-i * 17) + 's');   // negative: not both starting from the same angle
        el.style.setProperty('--ae-koi-x', k.x);
        el.style.setProperty('--ae-koi-y', k.y);
        pond.appendChild(el);
    }
}

// Idempotent. Attaches whatever is missing, for whichever hosts currently exist.
function _aeSakuraFXEnsure() {
    var reduce = _aeSakuraReduceMotion();

    // 1. Shell rain pane — always first child of #ae-ui-root.
    var root = document.getElementById('ae-ui-root');
    if (root && !document.getElementById('ae-sakura-rain')) {
        var rain = document.createElement('div');
        rain.id = 'ae-sakura-rain';
        root.insertBefore(rain, root.firstChild);
        if (!reduce) AE_SAKURA_FX.spawners.push(_aeSakuraStartRain(rain, AE_SAKURA_FX.cap.rain, 300));
    }

    // 2. Pond + glass — only once the Map tab has actually built its viewport.
    var vp = document.getElementById('ae-map-viewport');
    if (vp && !document.getElementById('ae-sakura-pond')) {
        var pond = document.createElement('div');
        pond.id = 'ae-sakura-pond';
        var glass = document.createElement('div');
        glass.id = 'ae-sakura-glass';
        vp.insertBefore(glass, vp.firstChild);
        vp.insertBefore(pond, glass);
        if (!reduce) {
            _aeSakuraBuildKoi(pond);
            AE_SAKURA_FX.spawners.push(_aeSakuraStartRain(glass, AE_SAKURA_FX.cap.glass, 420));
        }
    }
}

function _aeSakuraFXTeardown() {
    for (var i = 0; i < AE_SAKURA_FX.spawners.length; i++) clearInterval(AE_SAKURA_FX.spawners[i]);
    AE_SAKURA_FX.spawners = [];
    var ids = ['ae-sakura-rain', 'ae-sakura-pond', 'ae-sakura-glass'];
    for (var j = 0; j < ids.length; j++) {
        var el = document.getElementById(ids[j]);
        if (el) { try { el.remove(); } catch (_) {} }
    }
}

function _aeSakuraFXSync() {
    var want = _aeSakuraOn();
    if (want && !AE_SAKURA_FX.on) {
        AE_SAKURA_FX.on = true;
        _aeSakuraFXEnsure();
    } else if (!want && AE_SAKURA_FX.on) {
        AE_SAKURA_FX.on = false;
        _aeSakuraFXTeardown();
    } else if (want) {
        _aeSakuraFXEnsure();   // map tab may have appeared since last tick
    }
}

function _aeSakuraFXInit() {
    try {
        _aeSakuraFXSync();
        AE_SAKURA_FX.tick = setInterval(_aeSakuraFXSync, 1400);
        // Theme switches rewrite documentElement.className wholesale.
        new MutationObserver(_aeSakuraFXSync).observe(document.documentElement, {
            attributes: true, attributeFilter: ['class']
        });
        document.addEventListener('visibilitychange', function () {
            if (!document.hidden) _aeSakuraFXSync();
        });
    } catch (e) {
        try { console.warn('[AE] sakura FX init failed:', e); } catch (_) {}
    }
}

// =============================================================================
// SECTION 18 — INIT
// =============================================================================

// [PHANTOM-PRIMARY PASS 1] _renderCyoaWidget removed — CYOA retired entirely
// (fed by RUN_QUICK_INSTANCE / AE_CYOA_GENERATE, neither had an engine handler).
// spawnContent (the generic titled-floating-widget helper this used) is
// untouched — see Section 7 image comment flow and spawnImageStudio.

// =============================================================================
    // PHANTOM WIDGET ENGINE
    // =============================================================================

    // [PHANTOM-PRIMARY PASS 5] Party is gone (folded into Inspect's own
    // scene/all roster toggle, confirmed already "perfect" — nothing built
    // here). Shared defs for the launcher tray below (World renamed Map).
    // [v2.10.0 SHELL-1] PHANTOM_SCENE_TABS removed with the outer tray — it existed only to
    // populate that tray, and it carried both of the shipping placehold.co placeholder URLs
    // ('?text=Map+Widget' / '?text=Inspect+Widget'). PhantomManager.spawn(name) takes the
    // image argument as optional and falls back on its own, so nothing else wanted this.

    // [PHANTOM-PRIMARY PASS 5] _buildPhantomSceneSwitcher removed — superseded
    // by the persistent nav tray (_buildPhantomNavTray, built inside every
    // spawned widget itself) which already has Map/Inspect toggle buttons.
    PhantomManager = (function() {   // [v0.9.95 PHANTOM] assign the one canonical instance
        var activeWidget = null;
        var paddingEl = null;
        var stolenTabId = null;
        var originalParent = null;
        var originalSibling = null;
        var originalTopParent = null;
        var originalTopSibling = null;
        
        function getSafeAnchor() {
            var pm = document.querySelector('.ProseMirror');
            return pm ? pm.parentElement : null;
        }

        return {
            spawn: function(tabName, payload) {
                var pm = document.querySelector('.ProseMirror');
                if (!pm) { console.warn("[AE] PhantomManager: ProseMirror not found."); return; }
                _lastPhantomMode = tabName; // [v2.34.0 REOPEN-LAST-MODE] remember for the toggle-open path

                this.destroy(); // Clear existing

                var pList = pm.querySelectorAll('p');
                var lastP = pList[pList.length - 1];

                activeWidget = document.createElement('div');
                activeWidget.className = 'ae-phantom-widget';
                activeWidget.setAttribute('data-mode', tabName);
                // [PHANTOM-PRIMARY PASS 5] Width tightened toward "fit the mobile
                // browser width closer" — was 90%/700px cap.
                activeWidget.style.cssText = 'position: relative; width: 95%; max-width: 640px; margin: 20px auto; background: var(--ae-bg-panel); border: 1px solid var(--ae-bg-border-hi); border-radius: var(--ae-radius-lg); display: flex; flex-direction: column; box-shadow: var(--ae-shadow); z-index: var(--ae-z-hood); overflow: visible; font-family: var(--ae-font-sans); color: var(--ae-text-main); transition: opacity 0.2s ease-in;';

                // [PHANTOM-PRIMARY PASS 5] No more banner-stealing (#ae-top-pane) —
                // the Inspect-focused path below builds its own <img> from
                // resolveEntityImage() directly. #ae-top-pane now has zero live
                // consumers in the phantom widget; the docked HUD's copy is
                // dormant and untouched.
                var body = document.createElement('div');
                body.className = 'ae-phantom-body';

                // [PHANTOM-PRIMARY PASS 5] _focusEntity() is also used for
                // narrative threads and items (Inspect on a quest/item), not just
                // characters — the new image+sheet view only makes sense for an
                // actual character, so guard on that instead of assuming.
                // [BUGFIX v2.19.1 SPLIT-INSPECT] _focusedEntityKind === 'character' is now
                // checked FIRST and is authoritative when present -- it's set synchronously by
                // _focusEntity(), so it's available on THIS very call, unlike the cache/detail
                // fallbacks below (which is exactly the race that used to route a freshly-
                // focused, not-yet-cached character into the legacy steal branch). The cache/
                // detail checks stay as a fallback for any caller that doesn't set the flag.
                var _focusedIsCharacter = _focusedEntityId && (
                    _focusedEntityKind === 'character' ||
                    cachedCharVisuals.some(function(v) { return v.id === _focusedEntityId; }) ||
                    (_focusedEntityDetail && _focusedEntityDetail.id === _focusedEntityId && _focusedEntityDetail.type === 'character')
                );
                // [FEATURE] Same image+sheet treatment for a focused location
                // (_focusLocation, called from the Map tab's Inspect button).
                // Uses the synchronous _focusedEntityKind flag, not detail.type --
                // spawn()'s first call happens before AE_ENTITY_DETAIL_RESPONSE
                // lands, same reasoning as _focusedEntityKind's own doc comment.
                var _focusedIsLocation = _focusedEntityId && _focusedEntityKind === 'location';
                var _focusedImgEl = null; // tracked so revealWidget() below can scroll the widget into view once this (async, IndexedDB-backed) portrait actually loads
                if (tabName === 'Inspect' && _focusedIsCharacter) {
                    // Focused character: the in-flow dossier (plate + info grid),
                    // built entirely fresh — does NOT steal #ae-tab-scene at all.
                    _buildPhantomInspectFocused(body, _focusedEntityId);
                    _focusedImgEl = body.querySelector('.ae-phantom-img'); // spawn watches this to reveal the widget once the async portrait lands
                    activeWidget.appendChild(body);
                } else if (tabName === 'Inspect' && _focusedIsLocation) {
                    _buildPhantomLocationFocused(body, _focusedEntityId);
                    _focusedImgEl = body.querySelector('.ae-phantom-img');
                    activeWidget.appendChild(body);
                } else if (tabName === 'Image') {
                    // [v2.19.0 SHELL-3 IMAGE-INFLOW, per user] True in-flow mode, not the
                    // old PhantomManager.spawnContent() floating overlay -- Image Studio is
                    // now a real sibling of Map/Inspect on the SAME persistent widget/nav
                    // tray, so it inherits in-flow layout, theming, and the nav tray's
                    // Map/Inspect/Image toggle for free instead of fighting position:absolute
                    // for a footing of its own. No .ae-dossier grid: there's no portrait/
                    // plate here, just the composer form, so body stays the plain
                    // flex-column base rule. 'payload' (renamed from the never-read
                    // defaultImageUrl param) carries an optional prefill object for the
                    // edit/regenerate flow; spawnImageStudio(prefill) is now a thin wrapper
                    // over this branch.
                    body.appendChild(_buildImageStudioBody(payload || null));
                    activeWidget.appendChild(body);
                } else if (tabName === 'Chat') {
                    // [v2.33.0 CHARCHAT-LAUNCHER, per user] In-flow Chat launcher — a phone
                    // contacts view. Pick a POV, then a contact; tapping a contact starts (or
                    // resumes) the in-story chat and dismisses the widget, handing off to the
                    // existing CHARCHAT-SHELL-BASELINE overlay. No .ae-dossier grid: there's no
                    // portrait/plate, just the launcher form, so body stays the plain flex-column.
                    body.appendChild(_buildCharChatLauncher());
                    activeWidget.appendChild(body);
                } else if (tabName === 'Inspect' && !_focusedEntityId && lastSceneState && lastSceneState.locationId) {
                    // [v2.46.1 FOCUS-LOCATION-DEFAULT] Inspect pressed with nothing focused:
                    // auto-focus the player's current location so the user sees the proper
                    // location dossier instead of the unfocused roster grid. destroy() was
                    // already called at the top of spawn(), so we re-enter cleanly through
                    // _focusLocation which will call spawn('Inspect') again — this time with
                    // _focusedEntityKind === 'location', hitting the location dossier branch.
                    _focusLocation(lastSceneState.locationId);
                    return;
                } else {
                    // Map — same steal-the-real-tab mechanism as before.
                    var tabMap = { 'Map': 'map', 'Inspect': 'scene' };
                    stolenTabId = 'ae-tab-' + tabMap[tabName];
                    var realTab = document.getElementById(stolenTabId);
                    if (realTab) {
                        originalParent = realTab.parentNode;
                        originalSibling = realTab.nextSibling;
                        body.appendChild(realTab);
                        realTab.style.display = 'flex';
                        realTab.style.flexDirection = 'column';
                        realTab.style.flex = '1';
                        realTab.style.padding = (tabName === 'Map') ? '0' : '16px';
                        if (tabName === 'Map') {
                            body.style.height = '62vh'; body.style.minHeight = '440px';
                            setTimeout(function() { window.dispatchEvent(new Event('resize')); }, 100);
                        } else {
                            realTab.style.maxHeight = '60vh';
                            realTab.style.overflowY = 'auto';
                        }
                        activeWidget.appendChild(body);
                        setTimeout(function() { if (engineScriptId) requestSceneState(); }, 50);
                    } else {
                        body.innerHTML = '<div style="padding:16px;text-align:center;color:var(--ae-color-danger);">Critical Error: Could not locate HUD tab.</div>';
                        activeWidget.appendChild(body);
                    }
                }

                // [PHANTOM-PRIMARY PASS 5] Persistent nav tray replaces the old
                // scene-switcher + Dismiss row — Map/Inspect/Journal/Settings/
                // Edit/Dismiss, always visible, same on every mode.
                activeWidget.appendChild(_buildPhantomNavTray(tabName));

                var anchor = getSafeAnchor();
                anchor.style.position = 'relative';
                anchor.appendChild(activeWidget);

                // [BUGFIX v2.0.3] Captured so the deferred re-measure below can
                // tell a later spawn()/destroy() apart from this one -- portrait
                // resolution is async (IndexedDB), so its 'load' can fire after
                // the widget that requested it is already gone.
                var thisWidget = activeWidget;

                // Calculate positioning & dedicated spacer padding.
                // [BUGFIX v2.0.3] Was a single blind setTimeout(..., 50). If the
                // focused character's portrait (resolveEntityImage, IndexedDB-
                // backed) took longer than 50ms to resolve -- routine, not an
                // edge case -- `h` was measured against an image-less, near-0-
                // height body. The sheet's _phantomSheetMaxHeight() cap and the
                // story-text paddingEl spacer both got locked to that too-small
                // number and never revisited, so once the portrait did arrive
                // and the body grew to its real height, the sheet -- still
                // capped tiny, anchored bottom:0 to a now-taller body -- ended
                // up squashed down against the nav tray: the reported “rests
                // below the bottom button row so it disappears.” Pulled into a
                // named, idempotent function so it can run again once the image
                // actually loads, on top of the original 50ms fallback below.
                // [v2.18.0 SHELL-2 ROTATE] In-flow now: the widget is a normal
                // block in the story column (position:relative, margin:auto), so
                // there is no absolute top to compute and no paddingEl spacer to
                // reserve — the column reflows around it and the sticky plate
                // sticks against the editor's own scroll. All that remains is to
                // bring the freshly-spawned widget into view, re-running once the
                // async portrait lands in case it changed the height. If NAI's
                // editor layout ever fights an in-flow sibling, the fallback is the
                // engine-widget anchor (per user), not the old absolute+spacer hack.
                function revealWidget() {
                    if (activeWidget !== thisWidget) return; // stale — a later spawn()/destroy() ran
                    try { activeWidget.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); } catch (e) {}
                }
                setTimeout(revealWidget, 60);
                if (_focusedImgEl) {
                    _focusedImgEl.addEventListener('load', revealWidget, { once: true });
                    _focusedImgEl.addEventListener('error', revealWidget, { once: true });
                }
            },
            spawnContent: function(title, contentNode) {
                // [v0.9.7.0 CYOA] Like spawn(), but hosts a caller-built content node
                // (no tab-stealing) inside a titled, dismissable floating shell.
                var pm = document.querySelector('.ProseMirror');
                if (!pm) { console.warn('[AE] PhantomManager: ProseMirror not found.'); return; }
                this.destroy();
                var pList = pm.querySelectorAll('p');
                var lastP = pList[pList.length - 1];
                activeWidget = document.createElement('div');
                activeWidget.className = 'ae-phantom-widget';
                activeWidget.style.cssText = 'position: absolute; width: 90%; max-width: 700px; left: 50%; transform: translateX(-50%); background: var(--ae-bg-panel); border: 1px solid var(--ae-bg-border-hi); border-radius: var(--ae-radius-lg); display: flex; flex-direction: column; box-shadow: var(--ae-shadow); z-index: var(--ae-z-hood); overflow: hidden; font-family: var(--ae-font-sans); color: var(--ae-text-main);';
                var hdr = document.createElement('div');
                hdr.style.cssText = 'display:flex;align-items:center;padding:10px 14px;background:var(--ae-bg-base);border-bottom:1px solid var(--ae-bg-border);';
                var ht = document.createElement('span'); ht.textContent = title || 'Adventure Engine'; ht.style.cssText = 'flex:1;font-size:13px;font-weight:bold;color:var(--ae-accent);'; hdr.appendChild(ht);
                activeWidget.appendChild(hdr);
                var cbody = document.createElement('div');
                cbody.style.cssText = 'display:flex;flex-direction:column;width:100%;max-height:60vh;overflow-y:auto;';
                cbody.appendChild(contentNode);
                activeWidget.appendChild(cbody);
                var selfPm = this;
                var btnRow = document.createElement('div');
                btnRow.style.cssText = 'display:flex;gap:8px;padding:8px 14px;background:var(--ae-bg-base);border-top:1px solid var(--ae-bg-border);';
                var closeBtn = document.createElement('button');
                closeBtn.textContent = 'Dismiss';
                closeBtn.style.cssText = 'flex:1;padding:6px;background:transparent;color:var(--ae-text-muted);border:1px solid var(--ae-bg-border-hi);border-radius:var(--ae-radius-sm);cursor:pointer;font-size:12px;';
                closeBtn.onclick = function() { selfPm.destroy(); };
                btnRow.appendChild(closeBtn); activeWidget.appendChild(btnRow);
                var anchor = getSafeAnchor(); if (!anchor) { console.warn('[AE] PhantomManager: no anchor.'); activeWidget = null; return; }
                anchor.style.position = 'relative';
                anchor.appendChild(activeWidget);
                setTimeout(function() {
                    if (!activeWidget) return;
                    var h = activeWidget.offsetHeight;
                    paddingEl = document.createElement('div');
                    paddingEl.style.height = (h + 40) + 'px'; paddingEl.style.width = '100%'; paddingEl.style.pointerEvents = 'none';
                    anchor.appendChild(paddingEl);
                    if (lastP) {
                        var anchorRect = anchor.getBoundingClientRect();
                        var pRect = lastP.getBoundingClientRect();
                        activeWidget.style.top = ((pRect.bottom - anchorRect.top) + anchor.scrollTop + 16) + 'px';
                    } else { activeWidget.style.bottom = '24px'; }
                    setTimeout(function() { if (paddingEl) paddingEl.scrollIntoView({ behavior: 'smooth', block: 'end' }); }, 50);
                }, 50);
            },
            destroy: function() {
                // Return stolen DOM to main HUD
                if (stolenTabId && originalParent) {
                    var realTab = document.getElementById(stolenTabId);
                    if (realTab) {
                        realTab.style.display = ''; 
                        realTab.style.flexDirection = '';
                        realTab.style.flex = '';
                        realTab.style.padding = '';
                        realTab.style.height = '';
                        realTab.style.maxHeight = '';
                        realTab.style.overflowY = '';
                        realTab.style.position = ''; // [PHANTOM-PRIMARY PASS 1]
                        realTab.style.zIndex = '';    // [PHANTOM-PRIMARY PASS 1]
                        if (originalSibling) originalParent.insertBefore(realTab, originalSibling);
                        else originalParent.appendChild(realTab);
                    }
                }
                
                if (originalTopParent) {
                    var realTop = document.getElementById('ae-top-pane');
                    if (realTop) {
                        if (originalTopSibling) originalTopParent.insertBefore(realTop, originalTopSibling);
                        else originalTopParent.appendChild(realTop);
                    }
                }

                stolenTabId = null; originalParent = null; originalSibling = null;
                originalTopParent = null; originalTopSibling = null;

                if (activeWidget) { activeWidget.remove(); activeWidget = null; }
                if (paddingEl) { paddingEl.remove(); paddingEl = null; }
            }
        };
    })();

    function initUI() {
        // Remove stale instance on live-reload
    var ex = document.getElementById('ae-ui-root'); if (ex) ex.remove();
    var et = document.getElementById('ae-toggle-btn'); if (et) et.remove();

    // Inject CSS
    var style = document.createElement('style'); style.textContent = AE_CSS; document.head.appendChild(style);

    // Restore persisted button style preset + wire click ripple
    _applyBtnStyle();
    _setupBtnRipple();
    _setupWitchCritters();  // [v2.35.0 WITCH-CRITTERS] theme-gated familiars on button press

    // Toggle button — round logo button, single click target (see below: no
    // chevron, no text — pointerup's non-drag branch already opens/closes the tray).
    var toggleBtn = document.createElement('button'); toggleBtn.id = 'ae-toggle-btn';
    toggleBtn.title = 'Character Engine';
    toggleBtn.innerHTML = getCyberIconHTML('ceLogo', 26);
    toggleBtn.style.display = 'none'; // hidden until engine confirms a story is open
    document.body.appendChild(toggleBtn);

    // [v2.30.0 GHOST-SIGNATURE] Theme switches rewrite documentElement.className
    // wholesale, so the ceLogo override (Ghostlight bulb / Runestone foxfire) will
    // not reach the already-rendered button. Re-render its glyph on class change --
    // same MutationObserver pattern as the Sakura FX sync.
    try {
        new MutationObserver(function() {
            toggleBtn.innerHTML = getCyberIconHTML('ceLogo', 26);
        }).observe(document.documentElement, { attributes: true, attributeFilter: ['class'] });
    } catch (e) { try { console.warn('[AE] toggle icon observer failed:', e); } catch (_) {} }

    // Root UI
    var rootUI = document.createElement('div'); rootUI.id = 'ae-ui-root'; rootUI.innerHTML = AE_HTML;
    rootUI.style.display = 'none'; document.body.appendChild(rootUI);

    // [v1.5.0 SAKURA] Glass FX. No-op unless theme-sakura is active; self-syncs
    // on theme switch and re-attaches to the map viewport when that tab builds.
    _aeSakuraFXInit();

    // Toggle button: opens/closes the phantom tray — also draggable, position
    // saved in localStorage. [BUGFIX] No chevron anymore — single round icon
    // button, click-anywhere-to-toggle (see pointerup's non-drag branch below).
    // [v2.10.0 SHELL-1] THE OUTER TRAY IS GONE, per user: "redundant with the phantom
    // widget's own tray of options". It was, exactly: _buildPhantomNavTray already carries
    // Map, Inspect, Journal, Messages, Settings, Edit and Dismiss, on the widget itself.
    // Settings needed no rehoming — the PASS 2 comment worried about it being clipped at
    // the screen edge because it was "the one entry you can't reach any other way", but
    // that stopped being true when it landed on the widget nav. Image Studio was the one
    // genuine orphan, so it moved onto the widget nav (see _buildPhantomNavTray), per user:
    // it "needs a home on the phantom widget". The toggle button now spawns and dismisses
    // the widget directly, instead of opening a pill of buttons to reach a second pill of
    // buttons — one fewer click to everything, and one fewer surface to theme, layer,
    // position, clip against the viewport edge, and keep in sync.

    // Tray Toggle Logic

    // [BUGFIX] The chevron (and its own pointerdown/click listeners) is gone —
    // the whole round button is now the single click target. toggleBtn's own
    // pointerup handler below (non-drag branch) calls _toggleWidget() directly.
    // [v2.10.0 SHELL-1] Was _toggleTray: open a pill of buttons, one of which spawned the
    // widget, whose own nav then offered the same destinations over again. The tray is gone,
    // so the button does the thing directly. 'Inspect' is the default because it is the
    // character view, and this is a Character Engine.
    function _toggleWidget() {
        if (typeof PhantomManager === 'undefined') return;
        var live = document.querySelector('.ae-phantom-widget');
        if (live) { PhantomManager.destroy(); toggleBtn.classList.remove('active'); return; }
        // [v2.34.0 REOPEN-LAST-MODE, per user: HUD "always opens to the last inspected entity
        // instead of the chat menu if the chat menu was last open"] Reopen whatever mode was
        // last up (tracked in spawn()), defaulting to Inspect. Chat reopens to the launcher,
        // Map to the map, etc.
        PhantomManager.spawn(_lastPhantomMode || 'Inspect');
        toggleBtn.classList.add('active');
    }

    // Restore saved drag position or default to centered.
    (function() {
        var saved = null;
        try { saved = JSON.parse(localStorage.getItem('ae_toggle_pos')); } catch(_) {}
        if (saved && typeof saved.left === 'number') {
            toggleBtn.style.left      = Math.max(0, Math.min(window.innerWidth  - 44, saved.left)) + 'px';
            toggleBtn.style.top       = Math.max(0, Math.min(window.innerHeight - 44, saved.top  || 8)) + 'px';
            toggleBtn.style.transform = '';
        } else {
            toggleBtn.style.left      = '50%';
            toggleBtn.style.top       = '8px';
            toggleBtn.style.transform = 'translateX(-50%)';
        }
    })();

    // Drag + click — distinguish by 5px movement threshold.
    var _tDragging = false, _tSX = 0, _tSY = 0, _tIL = 0, _tIT = 0;
    toggleBtn.addEventListener('pointerdown', function(e) {
        if (e.button !== 0) return;
        
        var r = toggleBtn.getBoundingClientRect();
        _tIL = r.left; _tIT = r.top; _tSX = e.clientX; _tSY = e.clientY; _tDragging = false;
        toggleBtn.setPointerCapture(e.pointerId);
        e.preventDefault();
    });
    toggleBtn.addEventListener('pointermove', function(e) {
        if (!toggleBtn.hasPointerCapture(e.pointerId)) return;
        var dx = e.clientX - _tSX, dy = e.clientY - _tSY;
        if (!_tDragging && (Math.abs(dx) > 5 || Math.abs(dy) > 5)) _tDragging = true;
        if (!_tDragging) return;
        var nL = Math.max(0, Math.min(window.innerWidth  - toggleBtn.offsetWidth,  _tIL + dx));
        var nT = Math.max(0, Math.min(window.innerHeight - toggleBtn.offsetHeight, _tIT + dy));
        toggleBtn.style.left = nL + 'px'; toggleBtn.style.top = nT + 'px'; toggleBtn.style.transform = '';
    });
    toggleBtn.addEventListener('pointerup', function(e) {
        if (!toggleBtn.hasPointerCapture(e.pointerId)) return;
        if (_tDragging) {
            try { localStorage.setItem('ae_toggle_pos', JSON.stringify({ left: parseInt(toggleBtn.style.left, 10), top: parseInt(toggleBtn.style.top, 10) })); } catch(_) {}
        } else {
            // [v2.10.0 SHELL-1] Plain click spawns/dismisses the widget directly.
            _toggleWidget();
        }
        _tDragging = false;
    });

    // Close button: hide HUD (subtle × notch at top-center)
    var closeBtn = rootUI.querySelector('#ae-close-btn');
    if (closeBtn) {
        closeBtn.addEventListener('click', function() {
            rootUI.style.display = 'none';
            // Only restore toggle if still on a story page
            if (window.location.pathname.startsWith('/stories')) toggleBtn.style.display = 'flex';
        });
    }

    // [v2.1.2 WIZLIVE] Wizard button: opens the engine's native World-Build Wizard
    // modal (Live Chat tab). The bridge has no api.v1 access, so this only sends the
    // request — the engine dispatcher (case 'AE_OPEN_WIZARD') calls openWizardModal().
    var wizardBtn = rootUI.querySelector('#ae-wizard-btn');
    if (wizardBtn) {
        wizardBtn.addEventListener('click', function() { sendToEngine('AE_OPEN_WIZARD', {}); });
    }

    // ── Settings / theme dropdown — built dynamically, appended to body directly.
    // Avoids rootUI transform+overflow clipping. No HTML template dependency.
    var themeBtn = rootUI.querySelector('[title="Themes"]');
    var themeMenu = (function() {
        var ex2 = document.getElementById('ae-theme-menu'); if (ex2) ex2.remove();
        var m = document.createElement('div'); m.id = 'ae-theme-menu';
        function addItem(text, action, theme, id2, extraCSS) {
            var b2 = document.createElement('button'); b2.className = 'ae-theme-option'; b2.textContent = text;
            if (id2) b2.id = id2; if (extraCSS) b2.style.cssText = extraCSS;
            if (action) { b2.addEventListener('click', function() { m.style.display='none'; if(action==='imggen') openImageGenModal(); else if(action==='autosnap') triggerAutoSnap(); else if(action==='manualpic') showManualPicPopup(); else if(action==='floaters') showFloatingImagePicker(); }); }
            else if (theme !== undefined && !id2) { b2.addEventListener('click', function() { m.style.display='none'; document.documentElement.className=theme; document.documentElement.style=''; _applyBtnStyle(); }); }
            m.appendChild(b2);
        }
        function addDiv2() { var hr2 = document.createElement('hr'); hr2.className = 'ae-menu-divider'; m.appendChild(hr2); }
        addItem('Image Generation', 'imggen');
        // [v2.46.0 STUDIO-SHELL-TEARDOWN] The v2.45.0 "World-Build Studio" tray entry
        // (temporary mitigation for an access gap) is removed along with the rest of
        // the shell it pointed to -- see CE-INDEX STUDIO-SHELL-TEARDOWN entry.
        // [v0.9.8.0] Auto-Snap + Manual Image consolidated into the Image Studio (camera, left tray).
        addItem('📌 Floating Images', 'floaters');
        addDiv2();
        addItem('Dark (Default)', null, '');
        addItem('Cyberpunk', null, 'theme-cyberpunk');
        addItem('Runestone',        null, 'theme-runestone');
        addItem('🦄 Unicorn Barf',  null, 'theme-unicornbarf');
        addItem("🌙 Witch's Hollow", null, 'theme-witchhollow');
        addItem('🌸 Cherry Blossom', null, 'theme-sakura');
        addItem('💡 Ghost Light',    null, 'theme-ghostlight');
        addItem('➕ Custom Theme…', null, null, 'ae-open-creator', 'border-top:1px solid var(--ae-bg-border);margin-top:4px;color:var(--ae-accent);');
        document.body.appendChild(m); return m;
    })();
    if (themeBtn) {
        themeBtn.addEventListener('click', function(e) {
            e.stopPropagation();
            var isOpen = themeMenu.style.display === 'flex';
            if (isOpen) { themeMenu.style.display = 'none'; } else {
                var rect2 = themeBtn.getBoundingClientRect();
                themeMenu.style.top  = (rect2.bottom + 6) + 'px';
                themeMenu.style.left = rect2.left + 'px';
                themeMenu.style.display = 'flex';
            }
        });
        document.addEventListener('click', function(e) {
            if (themeMenu.style.display === 'flex' && !themeMenu.contains(e.target) && e.target !== themeBtn)
                themeMenu.style.display = 'none';
        });
    }

    // Tab switching
    var tabBtns     = rootUI.querySelectorAll('.ae-tab-btn');
    var tabContents = rootUI.querySelectorAll('.ae-tab-content');
    tabBtns.forEach(function(btn) {
        btn.addEventListener('click', function() {
            // [CE-STRIP vNEXT] Journal is a popout launcher, not a tab pane — it has no
            // data-target and sits outside the tab-switch state machine entirely (no
            // active-class toggling, no focus clearing, same as tapping any other
            // popout-opening button elsewhere in the HUD).
            if (btn.getAttribute('data-popout') === 'journal') { openJournalModal(); return; }

            // [v0.9.15] B2: Track focus state before the switch. Switching tabs always
            // clears focus now — the old Actions-tab exception (which preserved focus so
            // the user could run actions "at" the entity they were inspecting) no longer
            // applies since Actions is gone.
            var _targetTabId = btn.getAttribute('data-target');
            var _hadFocus = !!_focusedEntityId;
            if (_hadFocus) {
                _focusedEntityId = null;
                _focusedEntityDetail = null;
                var _tpClr = document.getElementById('ae-top-pane');
                if (_tpClr) {
                    ['#ae-focus-controls', '#ae-focus-back', '#ae-focus-snaptext'].forEach(function(sel) { var e = _tpClr.querySelector(sel); if (e) e.remove(); });
                    _tpClr.classList.remove('portrait-mode');
                }
            }
            tabBtns.forEach(function(b) { b.classList.remove('active'); });
            tabContents.forEach(function(c) { c.classList.remove('active'); });
            btn.classList.add('active');
            var target = document.getElementById(_targetTabId);
            if (target) target.classList.add('active');
            if (_targetTabId === 'ae-tab-story') {
                rootUI.classList.add('minimized');
            } else {
                rootUI.classList.remove('minimized');
                if (lastSceneState) _updateBanner(rootUI, lastSceneState);
                // [v0.9.15] B3: Always re-render the newly active tab from cached state
                // so switching tabs never shows stale content from a previous render pass.
                if (lastSceneState) {
                    if      (_targetTabId === 'ae-tab-scene')   _renderSceneTab(rootUI, lastSceneState);
                    else if (_targetTabId === 'ae-tab-hub')     _renderHubTab(rootUI, lastSceneState);
                }
                // [v0.9.9] If we cleared focus, reset Scene tab to normal view.
                if (_hadFocus && lastSceneState && _targetTabId === 'ae-tab-scene') _renderSceneTab(rootUI, lastSceneState);
            }
        });
    });

    // Panel resizer
    setupResizer(rootUI);

    // Map pan/drag
    setupMapPan(rootUI);

    // Theme Forge
    setupThemeCreator(rootUI);

    // NAI native modal z-index observer
    setupNAIModalObserver();

    // Story-page monitor: hide toggle + HUD if user navigates away from /stories/*
    setInterval(function() {
        if (window.location.pathname.startsWith('/stories')) return;
        var _mon_t = document.getElementById('ae-toggle-btn');
        var _mon_r = document.getElementById('ae-ui-root');
        if (_mon_t && _mon_t.style.display !== 'none') _mon_t.style.display = 'none';
        if (_mon_r && _mon_r.style.display !== 'none') _mon_r.style.display = 'none';
    }, 1500);

    // Engine bridge listener — re-check window.NAITMBridge at init time since
    // it's installed by Part 0 above, not at module-scope capture time.
    loadCachedImgFields();
    (function registerBridgeListener(attempt) {
        var bridge = window.NAITMBridge;
        if (bridge) {
            if (_bridgeUnsubscribe) { _bridgeUnsubscribe(); _bridgeUnsubscribe = null; }
            _bridgeUnsubscribe = bridge.on(function(payload, meta) { handleEngineMessage(payload, meta); });
            console.log('[AE Bridge] NAITMBridge listener registered (attempt ' + attempt + '). Waiting for engine handshake…');
        } else {
            console.warn('[AE Bridge] NAITMBridge not ready on attempt ' + attempt + '. Retrying in 1s…');
            if (attempt < 5) setTimeout(function() { registerBridgeListener(attempt + 1); }, 1000);
            else console.error('[AE Bridge] NAITMBridge never became available. Bridge disabled.');
        }
    })(1);
}

function setupResizer(rootUI) {
    var resizer = rootUI.querySelector('#ae-resizer');
    if (!resizer) return;
    var isResizing = false;
    resizer.addEventListener('pointerdown', function(e) {
        isResizing = true; resizer.classList.add('active'); resizer.setPointerCapture(e.pointerId); document.body.style.userSelect = 'none'; e.preventDefault();
    });
    window.addEventListener('pointerup', function() { isResizing = false; resizer.classList.remove('active'); document.body.style.userSelect = ''; });
    window.addEventListener('pointermove', function(e) {
        if (!isResizing) return;
        var rootRect = rootUI.getBoundingClientRect();
        var maxH = window.innerHeight - rootRect.top - 50;
        var newH = Math.max(80, Math.min(maxH, e.clientY - rootRect.top - 30));
        document.documentElement.style.setProperty('--ae-hud-height', newH + 'px');
    });
}

function setupMapPan(rootUI) {
    // [v0.9.15] B6: viewport pointerdown is always re-bound (the canvas element
    // is rebuilt by _buildMapFromGraph). Window-level pointerup/pointermove are
    // registered exactly ONCE via _mapPanSetup to prevent listener accumulation
    // that caused pan to slow exponentially after each node focus.
    var viewport = rootUI.querySelector('#ae-map-viewport');
    var canvas   = rootUI.querySelector('#ae-map-canvas');
    if (!viewport || !canvas) return;
    var isDragging = false, startX = 0, startY = 0;
    viewport.addEventListener('pointerdown', function(e) {
        if (e.target.closest('.ae-node') || e.target.closest('#ae-node-controls') || e.target.closest('button')) return;
        isDragging = true; startX = e.clientX; startY = e.clientY;
        canvas.classList.remove('gliding'); // [v0.9.17 FIX3] kill transition before drag
        canvas.classList.add('dragging'); viewport.setPointerCapture(e.pointerId);
        var ctrl = rootUI.querySelector('#ae-node-controls'); if (ctrl) ctrl.style.display = 'none';
    });
    if (!_mapPanSetup) {
        _mapPanSetup = true;
        window.addEventListener('pointerup', function() { isDragging = false; var _cv = document.querySelector('#ae-map-canvas'); if (_cv) _cv.classList.remove('dragging'); });
        window.addEventListener('pointermove', function(e) {
            if (!isDragging) return;
            var _cv = document.querySelector('#ae-map-canvas');
            _mapPanX += (e.clientX - startX); _mapPanY += (e.clientY - startY);
            if (_cv) _cv.style.transform = 'translate(' + _mapPanX + 'px,' + _mapPanY + 'px)';
            startX = e.clientX; startY = e.clientY;
        });
    }
}

