// SECTION 19 — NAI MODAL Z-INDEX OBSERVER
// Detects when NAI opens a native modal and ducks the HUD's z-index.
// NAI modal backdrop uses data-partid="modal-overlay" on the overlay div.
// Fallback: also checks for [class*="overlay"] in case NAI changes the partid.
// =============================================================================

// [v2.10.0 SHELL-1] setupNAIModalObserver DELETED. It read #ae-ui-root and toggled
// .ae-behind-modal on it — a class whose only rule is `display:none !important` — so that
// the HUD would duck out of the way when NovelAI opened a native modal. PHANTOM-PRIMARY
// PASS 1 made #ae-ui-root permanently display:none, at which point this became a
// MutationObserver running on every DOM mutation of the whole page, subtree:true, for the
// entire session, in order to hide an element that was already hidden. That is not free.
// It has also been the reason the live surfaces have no ducking behaviour at all: the
// mechanism that was supposed to provide it was pointed at a corpse, so nobody noticed it
// stopped working. If the live surfaces SHOULD duck for NAI modals — and they probably
// should — that is a real feature, built on purpose against the layer tokens above, not a
// fossil to resurrect. Flagged, not silently reimplemented.
function setupNAIModalObserver() { /* removed — see note above */ }

// =============================================================================
// SECTION 20 — UNIFIED PICKER ITEMS LIBRARY
// Builds typed, icon-rich item arrays for $.picker(). All picker call sites
// should use these helpers so icons, grouping, and special tokens stay consistent.
// =============================================================================

// Entity-type icon resolution (shared with MAP_ICONS for consistency)
// These now directly reference CyberIcons names, if available.
var _AE_TYPE_ICONS = {
    character:  'user',
    item:       'toolbox',
    location:   'mapPin',
    narrative:  'quests',
    resource:   'gem', // Using gem for general resource, adjust as needed
    skill:      'bolt', // Using bolt for skill, adjust as needed
    faction:    'castle',
    default:    'circle'
};
// [v0.9.9.11] Shared entity-icon resolver (HTML-string form). The entity `icon` field is
// free text shared with the engine. Resolution order:
//   (1) a name in our SVG library (CyberIcons, AEFillIcons, or an active-theme override,
//       via _aeIconExists) renders as an inline SVG — so typing "crown" or "littleMushrooms"
//       yields the SVG, whichever family resolves it;
//   (2) any other non-empty value is treated as an emoji/glyph and rendered as text (this is
//       new: the old CyberIcons-only check silently dropped emoji to the type icon);
//   (3) empty falls back to the entity type's default library icon.
function _resolveEntityIconHTML(iconField, type, size) {
    size = size || 16;
    var raw = (iconField == null) ? '' : String(iconField).trim();
    if (raw && _aeIconExists(raw)) return getCyberIconHTML(raw, size);
    if (raw) {
        var esc = raw.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        return '<span style="display:inline-block;font-size:' + Math.round(size * 0.9) + 'px;line-height:1;vertical-align:middle;">' + esc + '</span>';
    }
    var tName = (_AE_TYPE_ICONS[type] || _AE_TYPE_ICONS.default);
    return getCyberIconHTML(tName, size);
}

function _entityIcon(vis) {
    if (!vis) return getCyberIconHTML(_AE_TYPE_ICONS.default);
    return _resolveEntityIconHTML(vis.icon, vis.type, 16);
}

// Special "magic" tokens for action targeting
var _AE_SPECIAL_TOKENS = {
    __player__: { id: '__player__', label: 'Player', icon: '👑', meta: 'special', group: 'Special', special: true },
    __self__:   { id: '__self__',   label: 'Self (caster)', icon: '🎭', meta: 'special', group: 'Special', special: true },
    __all__:    { id: '__all__',    label: 'Everyone', icon: '★', meta: 'special', group: 'Special', special: true },
    __none__:   { id: '__none__',   label: 'No target', icon: '✕', meta: 'special', group: 'Special', special: true }
};

$.pickerItems = {
    // Characters from cachedCharVisuals.
    // opts: { presentIds (Set), sceneOnly (bool), includeProtagonist (bool), specials (array of token keys) }
    characters: function(opts) {
        opts = opts || {};
        var presentIds = opts.presentIds || new Set();
        var items = [];

        // Prepend specials if requested
        if (opts.specials) {
            opts.specials.forEach(function(key) {
                if (_AE_SPECIAL_TOKENS[key]) items.push(_AE_SPECIAL_TOKENS[key]);
            });
        }

        var chars = cachedCharVisuals.filter(function(v) {
            if (!v.name || !v.name.trim()) return false;
            if (!opts.includeProtagonist && v.isProtagonist) return false;
            if (opts.sceneOnly && !presentIds.has(v.id)) return false;
            return true;
        });

        // Sort: present first
        var present  = chars.filter(function(v) { return presentIds.has(v.id); });
        var absent   = chars.filter(function(v) { return !presentIds.has(v.id); });

        present.forEach(function(v) {
            items.push({ id: v.id, label: v.name, icon: _entityIcon(v), meta: v.species || '', group: 'In Scene', present: true, _vis: v });
        });
        if (!opts.sceneOnly) {
            absent.forEach(function(v) {
                items.push({ id: v.id, label: v.name, icon: _entityIcon(v), meta: v.species || '', group: 'Elsewhere', _vis: v });
            });
        }
        return items;
    },

    // Location nodes from a graph payload (or just current + adjacents)
    locations: function(graph) {
        if (!graph) return [];
        var items = [];
        function addLoc(id, name, type, icon, dir) {
            items.push({ id: id, label: name || id, icon: icon || _AE_TYPE_ICONS.location, meta: dir, group: 'Locations', type: 'location' });
        }
        if (graph.currentId) addLoc(graph.currentId, graph.currentName, graph.currentType, graph.currentIcon, 'current');
        if (graph.parentId)  addLoc(graph.parentId,  graph.parentName,  graph.parentType,  graph.parentIcon, '↑ parent');
        (graph.children    || []).forEach(function(c) { addLoc(c.id, c.name, c.type, c.icon, '↓ child'); });
        (graph.connections || []).forEach(function(c) { addLoc(c.id, c.label || c.name, c.type, c.icon, '→ exit'); });
        (graph.siblings    || []).forEach(function(c) { addLoc(c.id, c.name, c.type, c.icon, '↔ nearby'); });
        return items;
    },

    // Resources from state
    resources: function(state) {
        var items = [];
        (state && state.resources || []).forEach(function(r) {
            items.push({ id: r.tag, label: r.name || r.tag, icon: r.icon || _AE_TYPE_ICONS.resource, meta: r.type, group: 'Resources', type: 'resource' });
        });
        return items;
    },

    // Skills from state
    skills: function(state) {
        var items = [];
        (state && state.skills || []).forEach(function(sk) {
            items.push({ id: sk.id || sk.name, label: sk.name, icon: sk.icon || _AE_TYPE_ICONS.skill, meta: sk.rank || '', group: 'Skills', type: 'skill' });
        });
        return items;
    },

    // Factions from state
    factions: function(state) {
        var items = [];
        (state && state.factions || []).forEach(function(f) {
            items.push({ id: f.id || f.name, label: f.name, icon: f.icon || _AE_TYPE_ICONS.faction, meta: f.relationshipLabel || '', group: 'Factions', type: 'faction' });
        });
        return items;
    },

    // A flat list of all scene entities (chars + items + narratives)
    allScene: function(state) {
        var presentIds = new Set(((state && state.presentCharacters) || []).map(function(c) { return c.id; }));
        return $.pickerItems.characters({ presentIds: presentIds, sceneOnly: true });
    },

    // Combine multiple item arrays, deduplicating by id
    combine: function() {
        var seen = new Set(); var out = [];
        for (var i = 0; i < arguments.length; i++) {
            (arguments[i] || []).forEach(function(it) {
                if (!seen.has(it.id)) { seen.add(it.id); out.push(it); }
            });
        }
        return out;
    }
};

