// =============================================================================

// [v0.9.93 PROFILE] Combined character profile (sheet + visuals) state -- now
// exclusively feeds the flat dossier Profile tab (_buildFlatProfileTab).
var _charProfileCache   = {};    // charId -> last AE_CHAR_PROFILE_RESPONSE payload
var _profileOpenCharId  = null;  // charId whose profile is currently open
var _profileFieldEls    = {};    // fieldKey -> input element, for in-place regen patching
var _profileFetchPending = {};   // charId -> true while an open-fetch response is awaited
// [v2.53.0 SLOT-PICK] Option-picker state. _slotOptPending maps the BARE field id the
// engine answers with back to the display key this surface saves under -- those two
// differ for custom/slot fields (payload key is 'custom.<id>', the engine's
