var _slotOptPending = {};        // bare fieldKey -> { displayKey, label }
var _slotOptBusy    = {};        // displayKey -> true while a request is in flight
// [v2.54.0 SLOT-GUIDE] Whether option generation may read recent story text. Default OFF:
