var _slotOptUseStory = false;
// [v2.55.0 GEN-BUDGET] Last allowance figures the engine reported, kept so the readout
// can be drawn before a fresh reply arrives. Never authoritative -- output tokens
// replenish on a timer the bridge cannot observe, so this is always "as of last reply".
var _lastGenBudget = null;       // { out, inp, waitSec, need } or null
// [v0.9.98 WIZHUD] World-Build Wizard HUD state.

// -----------------------------------------------------------------------------
// SECTION 21a — WIZARD CHAT
// Chat surface, transcript, source-chat management, and project setup fields.
// -----------------------------------------------------------------------------

// [DEAD, v2.44.0 IMGGEN-MODAL] showWorldWizard() removed -- its only caller was the
// tray's old 'wizard' action key, replaced by 'imggen'->openImageGenModal() in
// v2.44.0. Caught on the E2 sweep (confirmed via grep, zero remaining callers).

// Full layout build (rail + main). Transcript and chat-list are repainted separately
// so incoming state never clobbers the input or scroll position.
function _renderWizard(body) {
    body.innerHTML = '';
    // Rail (slide-out drawer on narrow screens)
    var scrim = document.createElement('div'); scrim.className = 'ae-wiz-scrim'; scrim.id = 'ae-wiz-scrim';
    scrim.addEventListener('click', function() { _wizCloseRail(); });
    body.appendChild(scrim);
    var rail = document.createElement('div'); rail.className = 'ae-wiz-rail'; rail.id = 'ae-wiz-rail';
    var railHead = document.createElement('div'); railHead.className = 'ae-wiz-rail-head';
    var railClose = document.createElement('button'); railClose.className = 'ae-wiz-railbtn'; railClose.textContent = 'Close \u00d7'; railClose.style.cssText = 'align-self:flex-end;';
    railClose.addEventListener('click', function() { _wizCloseRail(); });
    railHead.appendChild(railClose);
    var topicSel = document.createElement('select'); topicSel.className = 'ae-wiz-topic-sel'; topicSel.id = 'ae-wiz-topic-sel';
    var newBtn = $.btn('+ New Chat', 'primary sm', function() {
        var tid = topicSel.value || '';
        sendToEngine('AE_WIZ_NEW_CHAT', { topicId: tid, title: 'New Chat' });
    });
    railHead.appendChild(topicSel); railHead.appendChild(newBtn); rail.appendChild(railHead);
    var chatList = document.createElement('div'); chatList.className = 'ae-wiz-chats'; chatList.id = 'ae-wiz-chats'; rail.appendChild(chatList);
    body.appendChild(rail);

    // Main
    var main = document.createElement('div'); main.className = 'ae-wiz-main'; main.style.position = 'relative'; main.id = 'ae-wiz-main';
    var chathead = document.createElement('div'); chathead.className = 'ae-wiz-chathead'; chathead.id = 'ae-wiz-chathead'; main.appendChild(chathead);
    var transcript = document.createElement('div'); transcript.className = 'ae-wiz-transcript'; transcript.id = 'ae-wiz-transcript'; main.appendChild(transcript);
    var inbar = document.createElement('div'); inbar.className = 'ae-wiz-inbar'; inbar.id = 'ae-wiz-inbar';
    var input = document.createElement('textarea'); input.className = 'ae-wiz-input'; input.id = 'ae-wiz-input'; input.rows = 1; input.placeholder = 'Message the wizard\u2026'; input.value = _wizInputDraft || '';
    input.addEventListener('input', function() { _wizInputDraft = input.value; input.style.height = 'auto'; input.style.height = Math.min(input.scrollHeight, 120) + 'px'; });
    input.addEventListener('keydown', function(e) { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); _wizSend(); } });
    var sendBtn = $.btn('Send', 'primary sm', function() { _wizSend(); });
    inbar.appendChild(input); inbar.appendChild(sendBtn); main.appendChild(inbar);
    body.appendChild(main);

    _wizRepaint();
}

// Repaint rail + chathead + transcript from _wizState (input untouched).
function _wizRepaint() {
    if (!_wizState) return;
    var topicSel = document.getElementById('ae-wiz-topic-sel');
    if (topicSel && topicSel.options.length !== (_wizState.topics || []).length) {
        topicSel.innerHTML = '';
        (_wizState.topics || []).forEach(function(t) { var o = document.createElement('option'); o.value = t.id; o.textContent = t.label; topicSel.appendChild(o); });
    }
    _wizPaintChatList();
    _wizPaintHead();
    _wizPaintTranscript();
}

function _wizPaintChatList() {
    var host = document.getElementById('ae-wiz-chats'); if (!host) return;
    host.innerHTML = '';
    var chats = (_wizState && _wizState.chats) || [];
    var topicMap = {}; ((_wizState && _wizState.topics) || []).forEach(function(t) { topicMap[t.id] = t.label; });
    if (!chats.length) { var e = document.createElement('div'); e.style.cssText = 'padding:14px;color:var(--ae-text-dim);font-size:11px;text-align:center;'; e.textContent = 'No chats yet. Pick a topic and start one.'; host.appendChild(e); return; }
    chats.forEach(function(c) {
        var item = document.createElement('div'); item.className = 'ae-wiz-chat-item' + (c.id === _wizState.activeChatId ? ' active' : '');
        var col = document.createElement('div'); col.style.cssText = 'flex:1;min-width:0;';
        var ti = document.createElement('div'); ti.className = 'ae-wiz-chat-title'; ti.textContent = c.title; col.appendChild(ti);
        var tp = document.createElement('div'); tp.className = 'ae-wiz-chat-topic'; tp.textContent = (topicMap[c.topicId] || '') + ' \u00b7 ' + c.msgCount; col.appendChild(tp);
        item.appendChild(col);
        var del = document.createElement('button'); del.className = 'ae-wiz-chat-del'; del.textContent = '\u00d7'; del.title = 'Delete chat';
        del.addEventListener('click', function(ev) { ev.stopPropagation(); sendToEngine('AE_WIZ_DELETE_CHAT', { chatId: c.id }); });
        item.appendChild(del);
        item.addEventListener('click', function() { _wizCloseRail(); if (c.id !== _wizState.activeChatId) sendToEngine('AE_WIZ_SELECT_CHAT', { chatId: c.id }); });
        host.appendChild(item);
    });
}

function _wizPaintHead() {
    var head = document.getElementById('ae-wiz-chathead'); if (!head) return;
    head.innerHTML = '';
    var railBtn = document.createElement('button'); railBtn.className = 'ae-wiz-railbtn'; railBtn.textContent = 'Chats'; railBtn.title = 'Show chats';
    railBtn.addEventListener('click', function() { _wizOpenRail(); });
    head.appendChild(railBtn);
    var ac = _wizState && _wizState.activeChat;
    // [v0.9.7.5] Bubble title ref removed — wizard is now a full studio tab.
    if (!ac) { var hint = document.createElement('span'); hint.style.cssText = 'flex:1;color:var(--ae-text-dim);font-size:12px;'; hint.textContent = 'No chat selected — open Chats to start one'; head.appendChild(hint); return; }
    var title = document.createElement('input'); title.className = 'ae-wiz-chathead-title'; title.value = ac.title;
    title.addEventListener('blur', function() { if (title.value.trim() && title.value !== ac.title) sendToEngine('AE_WIZ_RENAME_CHAT', { chatId: ac.id, title: title.value.trim() }); });
    head.appendChild(title);
    var srcBtn = $.btn('Sources', 'ghost sm', function() { _wizOpenSources(ac.id); });
    head.appendChild(srcBtn);
}

function _wizPaintTranscript() {
    var host = document.getElementById('ae-wiz-transcript'); if (!host) return;
    host.innerHTML = '';
    var ac = _wizState && _wizState.activeChat;
    if (!ac) {
        var empty = document.createElement('div'); empty.className = 'ae-wiz-empty';
        empty.textContent = 'Select a chat on the left, or pick a topic and start a new one. Talk through what you want, then generate world elements from the conversation.';
        host.appendChild(empty); return;
    }
    var allMsgs = ac.messages || [];
    var WIZ_MSG_WINDOW = (_wizMsgWindow && _wizMsgWindow[ac.id]) || 40;
    var startIdx = Math.max(0, allMsgs.length - WIZ_MSG_WINDOW);
    if (startIdx > 0) {
        var more = document.createElement('button'); more.className = 'ae-wiz-msg-act'; more.style.cssText = 'align-self:center;padding:6px;color:var(--ae-text-muted);';
        more.textContent = 'Show ' + Math.min(startIdx, 40) + ' earlier message(s) (' + startIdx + ' hidden)';
        more.addEventListener('click', function() { if (!_wizMsgWindow) _wizMsgWindow = {}; _wizMsgWindow[ac.id] = WIZ_MSG_WINDOW + 40; _wizPaintTranscript(); });
        host.appendChild(more);
    }
    allMsgs.slice(startIdx).forEach(function(m, _i) {
        var idx = startIdx + _i;
        var wrap = document.createElement('div'); wrap.className = 'ae-wiz-msg-wrap ' + (m.role === 'user' ? 'user' : 'assistant');
        var b = document.createElement('div'); b.className = 'ae-wiz-msg ' + (m.role === 'user' ? 'user' : 'assistant'); b.textContent = m.content; wrap.appendChild(b);
        var acts = document.createElement('div'); acts.className = 'ae-wiz-msg-acts';
        var editBtn = document.createElement('button'); editBtn.className = 'ae-wiz-msg-act'; editBtn.textContent = 'edit';
        editBtn.addEventListener('click', function() { _wizEditMessage(wrap, b, ac.id, idx, m.content); });
        var delBtn = document.createElement('button'); delBtn.className = 'ae-wiz-msg-act del'; delBtn.textContent = 'delete';
        delBtn.addEventListener('click', function() { sendToEngine('AE_WIZ_DELETE_MSG', { chatId: ac.id, index: idx }); });
        acts.appendChild(editBtn); acts.appendChild(delBtn); wrap.appendChild(acts);
        host.appendChild(wrap);
    });
    void 0;
    if (_wizThinking) { var th = document.createElement('div'); th.className = 'ae-wiz-thinking'; th.textContent = 'Wizard is thinking\u2026'; host.appendChild(th); }
    host.scrollTop = host.scrollHeight;
}

function _wizEditMessage(wrap, bubble, chatId, idx, current) {
    var ta = document.createElement('textarea'); ta.className = 'ae-wiz-msg-edit'; ta.value = current;
    // [v1.4.1 WIZ-EDIT-SIZE] Open the edit box sized to the message's actual content
    // instead of the CSS min-height:60px default — editing a long message no longer
    // visually collapses the bubble down to a few lines. Mirrors the auto-grow pattern
    // already used on the main wizard input (ae-wiz-input, see its 'input' listener).
    ta.addEventListener('input', function() { ta.style.height = 'auto'; ta.style.height = ta.scrollHeight + 'px'; });
    var bar = document.createElement('div'); bar.style.cssText = 'display:flex;gap:6px;margin-top:4px;';
    var save = $.btn('Save', 'primary sm', function() { sendToEngine('AE_WIZ_EDIT_MSG', { chatId: chatId, index: idx, content: ta.value }); });
    var cancel = $.btn('Cancel', 'ghost sm', function() { _wizPaintTranscript(); });
    bar.appendChild(save); bar.appendChild(cancel);
    bubble.style.display = 'none';
    wrap.appendChild(ta); wrap.appendChild(bar);
    // scrollHeight is only meaningful once ta is attached to the DOM, so size it here,
    // after appendChild, not before.
    ta.style.height = ta.scrollHeight + 'px';
    ta.focus();
}

function _wizSend() {
    var input = document.getElementById('ae-wiz-input'); if (!input) return;
    var text = input.value.trim();
    var ac = _wizState && _wizState.activeChat;
    if (!ac) { _showToast('Start or select a chat first'); return; }
    if (!text) return;
    input.value = ''; _wizInputDraft = ''; input.style.height = 'auto';
    _wizThinking = true;
    // Optimistic: show the user message + thinking immediately
    var host = document.getElementById('ae-wiz-transcript');
    if (host) {
        var ub = document.createElement('div'); ub.className = 'ae-wiz-msg user'; ub.textContent = text; host.appendChild(ub);
        var th = document.createElement('div'); th.className = 'ae-wiz-thinking'; th.textContent = 'Wizard is thinking\u2026'; host.appendChild(th);
        host.scrollTop = host.scrollHeight;
    }
    sendToEngine('AE_WIZ_SEND', { chatId: ac.id, text: text });
}

// --- Context sources picker ---
function _wizOpenSources(chatId) {
    var main = document.getElementById('ae-wiz-main'); if (!main) return;
    var existing = document.getElementById('ae-wiz-src-panel'); if (existing) existing.remove();
    var panel = document.createElement('div'); panel.className = 'ae-wiz-src-panel'; panel.id = 'ae-wiz-src-panel';
    var head = document.createElement('div'); head.className = 'ae-wiz-chathead';
    var bk = $.btn('\u2190 Back', 'ghost sm', function() { panel.remove(); });
    var ti = document.createElement('span'); ti.style.cssText = 'flex:1;font-weight:bold;font-size:13px;'; ti.textContent = 'Context Sources';
    head.appendChild(bk); head.appendChild(ti); panel.appendChild(head);
    var list = document.createElement('div'); list.className = 'ae-wiz-src-list'; list.id = 'ae-wiz-src-list';
    var loading = document.createElement('div'); loading.style.cssText = 'padding:20px;text-align:center;color:var(--ae-text-dim);font-size:12px;'; loading.textContent = 'Loading sources\u2026'; list.appendChild(loading);
    panel.appendChild(list); main.appendChild(panel);
    _wizSources = null;
    sendToEngine('AE_WIZ_LIST_CONTEXT_SOURCES', { chatId: chatId });
}

function _wizRenderSources() {
    var list = document.getElementById('ae-wiz-src-list'); if (!list || !_wizSources) return;
    list.innerHTML = '';
    var sel = _wizSources.selected || { contextChatIds: [], lorebookEntryIds: [], includeStory: false };
    var chosenChats = {}; (sel.contextChatIds || []).forEach(function(id) { chosenChats[id] = true; });
    var chosenLore = {}; (sel.lorebookEntryIds || []).forEach(function(id) { chosenLore[id] = true; });
    var chosenChars = {}; (sel.characterIds || []).forEach(function(id) { chosenChars[id] = true; });

    function commit() {
        var ctxChats = []; for (var k in chosenChats) if (chosenChats[k]) ctxChats.push(k);
        var loreIds = []; for (var l in chosenLore) if (chosenLore[l]) loreIds.push(l);
        var charIds = []; for (var c in chosenChars) if (chosenChars[c]) charIds.push(c);
        sendToEngine('AE_WIZ_SET_CHAT_CONTEXT', { chatId: _wizSources.chatId, contextChatIds: ctxChats, lorebookEntryIds: loreIds, characterIds: charIds, includeStory: storyCb.checked });
    }

    // Include story
    var grpS = document.createElement('div'); grpS.className = 'ae-wiz-src-group-h'; grpS.textContent = 'Story'; list.appendChild(grpS);
    var storyRow = document.createElement('label'); storyRow.className = 'ae-wiz-src-row';
    var storyCb = document.createElement('input'); storyCb.type = 'checkbox'; storyCb.checked = !!sel.includeStory;
    storyCb.addEventListener('change', commit);
    var storyTxt = document.createElement('span'); storyTxt.textContent = 'Include recent story text'; storyRow.appendChild(storyCb); storyRow.appendChild(storyTxt); list.appendChild(storyRow);

    // Other chats
    if ((_wizSources.chats || []).length) {
        var grpC = document.createElement('div'); grpC.className = 'ae-wiz-src-group-h'; grpC.textContent = 'Other Wizard Chats'; list.appendChild(grpC);
        _wizSources.chats.forEach(function(c) {
            var row = document.createElement('label'); row.className = 'ae-wiz-src-row';
            var cb = document.createElement('input'); cb.type = 'checkbox'; cb.checked = !!chosenChats[c.id];
            cb.addEventListener('change', function() { chosenChats[c.id] = cb.checked; commit(); });
            var t = document.createElement('span'); t.style.flex = '1'; t.textContent = c.title;
            row.appendChild(cb); row.appendChild(t); list.appendChild(row);
        });
    }

    // Characters
    if ((_wizSources.characters || []).length) {
        var grpCh = document.createElement('div'); grpCh.className = 'ae-wiz-src-group-h'; grpCh.textContent = 'Characters'; list.appendChild(grpCh);
        _wizSources.characters.forEach(function(ch) {
            var row = document.createElement('label'); row.className = 'ae-wiz-src-row';
            var cb = document.createElement('input'); cb.type = 'checkbox'; cb.checked = !!chosenChars[ch.id];
            cb.addEventListener('change', function() { chosenChars[ch.id] = cb.checked; commit(); });
            var t = document.createElement('span'); t.style.flex = '1'; t.textContent = ch.name;
            row.appendChild(cb); row.appendChild(t);
            // characters now feed straight from their record into this chat's context
            list.appendChild(row);
        });
    }

    // Lorebook entries
    if ((_wizSources.lorebookEntries || []).length) {
        var grpL = document.createElement('div'); grpL.className = 'ae-wiz-src-group-h'; grpL.textContent = 'Lorebook Entries'; list.appendChild(grpL);
        _wizSources.lorebookEntries.forEach(function(e) {
            var row = document.createElement('label'); row.className = 'ae-wiz-src-row';
            var cb = document.createElement('input'); cb.type = 'checkbox'; cb.checked = !!chosenLore[e.id];
            cb.addEventListener('change', function() { chosenLore[e.id] = cb.checked; commit(); });
            var t = document.createElement('span'); t.style.cssText = 'flex-shrink:0;max-width:40%;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;'; t.textContent = e.label;
            var pv = document.createElement('span'); pv.className = 'ae-wiz-src-prev'; pv.textContent = e.preview;
            row.appendChild(cb); row.appendChild(t); row.appendChild(pv); list.appendChild(row);
        });
    }
}

function _wizOpenRail() { var r = document.getElementById('ae-wiz-rail'); var sc = document.getElementById('ae-wiz-scrim'); if (r) r.classList.add('open'); if (sc) sc.classList.add('open'); }
function _wizCloseRail() { var r = document.getElementById('ae-wiz-rail'); var sc = document.getElementById('ae-wiz-scrim'); if (r) r.classList.remove('open'); if (sc) sc.classList.remove('open'); }

// [DEAD, v2.45.0 ENTITY-CRUD-TEARDOWN] _GEN_KINDS and _ENT_DEF (the
// species/factions/memory/intro/drama data tables) removed with _renderGeneratePanel
// and _renderEntityTab below -- see CE-INDEX ENTITY-CRUD-TEARDOWN entry.
// [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] _wizGatherSrc removed too -- its only caller
// (the Locations tab's batch-gen bar) was removed with SECTION 21e this pass.

// [REMOVED v2.1.7 SETUP] _setupSyncFields (project name/genre/concept sync) --
// the Setup tab no longer carries those fields; see _buildSetupBody below.

// [v2.1.7 SETUP] Setup tab is now dedicated entirely to Image Fields -- project
// name/genre/concept (and AE_SET_PROJECT) removed per user's call; nothing else
// in the pipeline read them as load-bearing wizard seed context anymore.
//
// [BUGFIX v2.1.8] This used to hand _buildImageFieldsBody the FULL gallery-overlay
// rerender (function() { _renderGalleryGrid(ov); }), which the Add Field button
// then called on a 200ms guess-timer after its mutation. _renderGalleryGrid wipes
// and rebuilds the entire overlay -- rail, topbar, and this tab's own scroll
// position along with it -- on every single call. Toggle/update/delete had no
// rerender wired at all, so they just went stale until the tab was reopened. Both
// halves of "any change to them refreshes the menu, kicking the view back to top"
// (Add Field resetting scroll; everything else not updating at all) trace to this
// same design gap. Fixed by giving this container its own id and a scoped repaint
// function, matching the pattern the standalone Image Fields panel
// (#ae-imgfields-surface) and the Image Studio composer's chip bar
// (#ae-imgstudio-fieldsbar) already use: AE_IMG_FIELDS_SYNC is the sole repaint
// trigger for all three surfaces now, each rebuilding only its own container with
// its own scroll position preserved. The manual rerender+setTimeout call on Add
// Field is gone -- sync handles it the same as every other mutation now.
function _buildSetupBody(main) {
    var head = document.createElement('div'); head.className = 'ae-studio-content'; head.id = 'ae-setup-imgfields-body';
    main.appendChild(head);
    _renderSetupImageFields();
    sendToEngine('AE_WIZ_FETCH_STATE', {});
}

function _renderSetupImageFields() {
    var head = document.getElementById('ae-setup-imgfields-body');
    if (!head) return;
    var prevScroll = head.scrollTop;
    head.innerHTML = '';
    var pe = document.createElement('div'); pe.style.cssText = 'font-size:12px;color:var(--ae-text-dim);line-height:1.5;margin-bottom:10px;';
    pe.textContent = 'Image Fields let you build a library of reusable prompt/UC fragments (with weights) and toggle any combination active for every portrait and scene image, plus set default resolution/scale/steps.';
    head.appendChild(pe);
    _buildImageFieldsBody(head);
    head.scrollTop = prevScroll;
}

// -----------------------------------------------------------------------------
// [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] SECTIONS 21b (HELP & RULES TAB) and 21c
// (STUDIO RAIL & TOPBAR) removed in full: _galleryRepaintCharsIfOpen,
// _studioNotice, _renderHelpTab + _AE_FOUR_FS/_AE_HELP_BANDS (Four Fs explainer
// + dice-odds test roller -- a static reference/calculator with no engine
// message traffic; if this is wanted back, it has no engine-native equivalent
// and would need re-adding, unlike the rest of this teardown), _buildStudioRail,
// _buildStudioTopbar, _studioSvg, _STUDIO_SVGS. Confirmed dead: all senders of
// AE_WIZ_GENERATE and AE_SYNC_LOREBOOK were inside this code (see the
// neutralized AE_WIZ_GEN_RESULT / AE_SYNC_LOREBOOK_RESULT dispatch cases).
// See CE-INDEX STUDIO-SHELL-TEARDOWN entry.

// [RESTORED, v2.46.0 STUDIO-SHELL-TEARDOWN] _galHdr and _buildStudioInfoBox were
// caught in the SECTION 21e sweep below, but both have live callers OUTSIDE the
// removed shell: _galHdr is still used by showFloatingImagePicker() (the
// \ud83d\udccc Floating Images tray item, unrelated to the Studio), and
// _buildStudioInfoBox is still used by _renderLiveWizTab() (SECTION 21d2, Live
// Wizard Chat Control Panel, kept). Restored here rather than left deleted --
// caught via grep sweep after the fact, not before; see CE-INDEX
// STUDIO-SHELL-TEARDOWN entry for the full note on this correction.
function _galHdr(ov, titleText, backFn, rightFn) {
    var h = document.createElement('div'); h.style.cssText = 'display:flex;align-items:center;padding:12px 16px;background:var(--ae-bg-panel);border-bottom:1px solid var(--ae-bg-border);gap:8px;flex-shrink:0;';
    if (backFn) h.appendChild($.btn('\u2190 Back', 'ghost sm', backFn));
    var t = document.createElement('span'); t.style.cssText = 'flex:1;font-size:15px;font-weight:bold;color:var(--ae-accent);'; t.textContent = titleText; h.appendChild(t);
    if (rightFn) rightFn(h);
    h.appendChild($.btn('\u2715', 'ghost sm', function() { ov.style.display = 'none'; }));
    ov.appendChild(h);
}

// Helper: builds the collapsible info+sources box used atop content areas.
// `lead` = section description text; `srcChats` = array of chat objects or null to hide.
function _buildStudioInfoBox(lead, srcChats) {
    var box = document.createElement('div'); box.className = 'ae-section-info';
    var hdr = document.createElement('div'); hdr.className = 'ae-section-info-hdr';
    var leadEl = document.createElement('span'); leadEl.className = 'ae-section-info-lead'; leadEl.textContent = lead || ''; hdr.appendChild(leadEl);
    var caret = document.createElement('span'); caret.className = 'ae-section-info-caret'; caret.innerHTML = '&#9658;'; hdr.appendChild(caret);
    var body = document.createElement('div'); body.className = 'ae-section-info-body';
    var descEl = document.createElement('div'); descEl.className = 'ae-section-info-desc'; descEl.textContent = lead || ''; body.appendChild(descEl);
    if (srcChats !== null) {
        var srcLbl = document.createElement('div'); srcLbl.className = 'ae-section-info-srclabel'; srcLbl.textContent = 'Source chats for generation'; body.appendChild(srcLbl);
        var chips = document.createElement('div'); chips.className = 'ae-section-info-chips';
        if (!srcChats.length) {
            var noSrc = document.createElement('span'); noSrc.style.cssText = 'font-size:11px;color:var(--ae-text-dim);font-style:italic;'; noSrc.textContent = 'No wizard chats yet \u2014 start one in Wizard Chat'; chips.appendChild(noSrc);
        } else {
            srcChats.forEach(function(c) {
                var on = !!_wizEntitySrc[c.id];
                var chip = document.createElement('button'); chip.className = 'ae-src-chip' + (on ? ' on' : ''); chip.type = 'button'; chip.textContent = c.title;
                chip.addEventListener('click', function() { _wizEntitySrc[c.id] = !_wizEntitySrc[c.id]; chip.classList.toggle('on', !!_wizEntitySrc[c.id]); });
                chips.appendChild(chip);
            });
        }
        body.appendChild(chips);
    }
    box.appendChild(hdr); box.appendChild(body);
    hdr.addEventListener('click', function() {
        var isOpen = body.classList.contains('open');
        body.classList.toggle('open', !isOpen); caret.classList.toggle('open', !isOpen);
    });
    return box;
}

// [v0.9.7.5 STUDIO-RAIL] Wizard is now a rail tab — FAB/bubble removed.

// [v0.9.8.1] Image Gallery tab renderer.
// Reads the nai_illustrator images store and displays records scoped to the
// active story (activeStoryId). Falls back to ALL records when the story has no
// stamped images (i.e. pre-v0.9.8.0 images or the storyId is blank). A toggle
// lets the user flip between scoped and all-stories views.
// Per-card actions: click = lightbox, ↓ PNG = download, ✏️ = Edit/Regenerate, 🗑 = delete.

// -----------------------------------------------------------------------------
// SECTION 21d — IMAGE GALLERY TAB
// -----------------------------------------------------------------------------

var _imgGalleryShowAll = false;

function _renderGalleryImageTab(host) {
    host.innerHTML = '';

    // -- header row: scope toggle + count --
    var hrow = document.createElement('div');
    hrow.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:12px;flex-shrink:0;';
    var scopeLbl = document.createElement('span');
    scopeLbl.style.cssText = 'font-size:12px;color:var(--ae-text-muted);flex:1;';
    hrow.appendChild(scopeLbl);
    var toggleBtn = $.btn('Show all stories', 'ghost sm', function() {
        _imgGalleryShowAll = !_imgGalleryShowAll;
        toggleBtn.textContent = _imgGalleryShowAll ? 'This story only' : 'Show all stories';
        _imgGalleryRepaint();
    });
    toggleBtn.textContent = _imgGalleryShowAll ? 'This story only' : 'Show all stories';
    hrow.appendChild(toggleBtn);
    host.appendChild(hrow);

    // -- image grid --
    var grid = document.createElement('div');
    // [v0.9.9.9] Plain-height grid: the host .ae-studio-content already scrolls,
    // so the grid must NOT be its own flex:1 scroll region. The old
    // flex:1;min-height:0;overflow-y:auto nested a second scroller inside the
    // scrolling host, which collapsed each grid row to a sliver (images rendered
    // as thin horizontal bands that wouldn't scroll). Matches the sibling
    // location/visualization grids, which lay out correctly.
    grid.style.cssText = 'display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:8px;align-content:start;grid-auto-rows:max-content;';
    host.appendChild(grid);

    var loadingEl = document.createElement('div');
    loadingEl.style.cssText = 'grid-column:1/-1;text-align:center;padding:40px;color:var(--ae-text-dim);font-size:13px;';
    loadingEl.textContent = 'Loading images…';
    grid.appendChild(loadingEl);

    var _allRecs = [];

    // [v0.9.9.9] Effective story id. activeStoryId is only populated by an
    // inbound STORY_ID_SYNC message; if that hasn't arrived when the gallery
    // opens, it's blank and the old `!storyId` short-circuit forced ALL images
    // regardless of the toggle (so "This story only" did nothing). Fall back to
    // the newest stamped record's storyId — records are saved with the story id
    // that was known at generation time and sorted newest-first — so scoping
    // still works. Only truly falls back to "all" when no record carries a
    // storyId (pre-stamp images).
    function _effectiveStoryId() {
        if (activeStoryId) return activeStoryId;
        for (var i = 0; i < _allRecs.length; i++) {
            if (_allRecs[i] && _allRecs[i].storyId) return _allRecs[i].storyId;
        }
        return '';
    }

    function _imgGalleryRepaint() {
        grid.innerHTML = '';
        var storyId = _effectiveStoryId();
        var recs = _imgGalleryShowAll || !storyId
            ? _allRecs
            : _allRecs.filter(function(r) { return (r.storyId || '') === storyId; });

        // Count for scope label
        var scopedCount = storyId ? _allRecs.filter(function(r) { return (r.storyId || '') === storyId; }).length : _allRecs.length;
        scopeLbl.textContent = storyId
            ? (scopedCount + ' image' + (scopedCount !== 1 ? 's' : '') + ' in this story')
            : (_allRecs.length + ' image' + (_allRecs.length !== 1 ? 's' : '') + ' total');

        if (!recs.length) {
            var empty = document.createElement('div');
            empty.style.cssText = 'grid-column:1/-1;text-align:center;padding:48px 20px;color:var(--ae-text-dim);font-size:13px;line-height:1.5;';
            empty.textContent = _imgGalleryShowAll
                ? 'No images saved yet. Generate one from the Image Studio (camera button on the left tray).'
                : 'No images for this story yet. Use the Image Studio to generate some, or tap “Show all stories” to browse older images.';
            grid.appendChild(empty); return;
        }

        recs.forEach(function(rec) {
            if (!rec.dataUrl) return;
            var card = document.createElement('div');
            card.style.cssText = 'position:relative;border:1px solid var(--ae-bg-border);border-radius:var(--ae-radius-md);overflow:hidden;background:var(--ae-bg-raised);display:flex;flex-direction:column;transition:border-color 0.15s;';
            card.addEventListener('mouseenter', function() { card.style.borderColor = 'var(--ae-accent)'; });
            card.addEventListener('mouseleave', function() { card.style.borderColor = 'var(--ae-bg-border)'; });

            // -- Thumbnail (click = lightbox) --
            var thumb = document.createElement('img');
            thumb.src = rec.dataUrl;
            thumb.style.cssText = 'width:100%;aspect-ratio:1/1;object-fit:cover;display:block;cursor:pointer;';
            thumb.setAttribute('data-nai-uuid', rec.uuid);
            thumb.addEventListener('click', function() { _galleryLightbox(rec.dataUrl, (rec.prompt || '').slice(0, 120)); });
            card.appendChild(thumb);

            // -- Prompt snippet --
            if (rec.prompt) {
                var snip = document.createElement('div');
                snip.style.cssText = 'font-size:9px;color:var(--ae-text-dim);padding:4px 5px;line-height:1.3;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;';
                snip.textContent = rec.prompt;
                card.appendChild(snip);
            }

            // -- Action row: download, edit/regen, delete --
            var acts = document.createElement('div');
            acts.style.cssText = 'display:flex;gap:2px;padding:3px 4px;background:var(--ae-bg-panel);border-top:1px solid var(--ae-bg-border);';

            var dlBtn = $.btn('Dn', 'ghost sm', function() {
                _downloadAsPng(rec.dataUrl, 'ae-' + String(rec.uuid).slice(0, 8) + '.png');
            });
            dlBtn.title = 'Download PNG'; dlBtn.style.flex = '1 1 0';

            var editBtn = $.btn($.icon('edit', 14).outerHTML, 'ghost sm', function() { openPromptEditor(rec.uuid); });
            editBtn.title = 'Edit / Regenerate'; editBtn.style.flex = '1 1 0';

            var delBtn = $.btn($.icon('trash', 14).outerHTML, 'ghost sm', function() {
                if (!confirm('Delete this image? This cannot be undone.')) return;
                dbDelete(rec.uuid).then(function() {
                    _allRecs = _allRecs.filter(function(r) { return r.uuid !== rec.uuid; });
                    imgCache.delete(rec.uuid);
                    _imgGalleryRepaint();
                });
            });
            delBtn.title = 'Delete image'; delBtn.style.flex = '1 1 0';

            acts.appendChild(dlBtn); acts.appendChild(editBtn); acts.appendChild(delBtn);
            card.appendChild(acts);
            grid.appendChild(card);
        });
    }

    // Load records then paint
    dbGetAll().then(function(recs) {
        // Sort newest-first
        _allRecs = (recs || []).slice().sort(function(a, b) { return (b.ts || 0) - (a.ts || 0); });
        _imgGalleryRepaint();
    });
}

// -----------------------------------------------------------------------------
// SECTION 21d2 — LIVE WIZARD CHAT CONTROL PANEL  [v2.1.0 WIZLIVE]
// The chat itself happens IN the NAI editor: the engine appends a purple marker
// + an editable protocol paragraph, and the user talks in native { } instruct
// blocks, pressing NAI's own Send. Nothing is hidden or swallowed. This panel
// only opens/closes a session and reflects its state. Message contract:
//   bridge→engine: AE_WIZLIVE_START { topicId? } / AE_WIZLIVE_END { action:
//                  'save'|'commit'|'summarize'|'discard' } / AE_WIZLIVE_FETCH {}
//   engine→bridge: AE_WIZLIVE_STATE { active, topicId, startedAt }
// -----------------------------------------------------------------------------
// [v2.4.0 CHARCHAT] engine-ready, bridge-pending: engine v2.23.0 broadcasts
//   AE_CHARCHAT_STATE { active, contactId, contactName, povId, povName, startedAt }.
//   Stored in _charChatState (grep it) so it stops hitting the console-noise default
//   case; no HUD panel consumes it yet — that is P6.
// -----------------------------------------------------------------------------

var _liveWizState = null;   // last AE_WIZLIVE_STATE payload (null until first echo)
var _charChatState = null;  // [v2.4.0 CHARCHAT] last AE_CHARCHAT_STATE payload (null until first echo) — no consumer yet, ready for the P6 HUD panel

// [v2.33.0 CHARCHAT-LAUNCHER] In-flow Chat launcher state + builder — the phone-contacts
// view. POV-first (parity with the engine's native picker), then a contact list whose
// message-count badges come from the engine's saved-thread roster (AE_CHARCHAT_THREADS_*).
// Tapping a contact sends AE_CHARCHAT_START { contactId, povId } (the engine resolves
// resume-vs-start itself — see engine CHARCHAT-RESUME) and dismisses the widget, handing
// off to the CHARCHAT-SHELL-BASELINE overlay. Roster comes from cachedCharVisuals (already
// the active-character cache, refreshed on CHARACTER_DATA_SYNC) — no new roster message.
var _ccLauncherThreads = [];          // last AE_CHARCHAT_THREADS_RESP threads[], one per (contactId, povId)
var _ccLauncherThreadsLoaded = false; // has the once-per-open fetch returned yet?
var _ccLauncherPovId = '';            // currently selected POV ('' = No POV / just me)

// Message count for a specific (contactId, povId) pair from the cached roster. A contact
// with a thread under a DIFFERENT pov reads as fresh here, exactly the engine's
// "one chat per character pair" behavior.
function _ccLauncherCount(contactId, povId) {
    for (var i = 0; i < _ccLauncherThreads.length; i++) {
        var t = _ccLauncherThreads[i];
        if (t && t.contactId === contactId && (t.povId || '') === (povId || '')) return t.turnCount || 0;
    }
    return 0;
}

// Repaint just the contact list (called on POV change and when the thread roster lands).
function _ccLauncherRenderContacts() {
    var host = document.getElementById('ae-ccl-contacts');
    if (!host) return;
    host.innerHTML = '';
    var povId = _ccLauncherPovId;
    // Every active character except whoever is the POV (you can't text as and to the same
    // person). cachedCharVisuals is already the active roster.
    var contacts = cachedCharVisuals.filter(function(v) { return v && v.id && v.id !== povId; });
    if (!contacts.length) {
        var empty = document.createElement('div');
        empty.className = 'ae-ccl-empty';
        empty.textContent = 'No characters to text yet.';
        host.appendChild(empty);
        return;
    }
    contacts.forEach(function(vis) {
        var row = document.createElement('button'); row.type = 'button'; row.className = 'ae-ccl-contact';
        var av = document.createElement('div'); av.className = 'ae-ccl-ava';
        if (vis._avatarDataUrl) { av.style.backgroundImage = 'url(' + JSON.stringify(vis._avatarDataUrl) + ')'; }
        else { av.style.background = _nameToColor(vis.name || '?'); av.textContent = (vis.name || '?').charAt(0).toUpperCase(); }
        row.appendChild(av);
        var mid = document.createElement('div'); mid.className = 'ae-ccl-mid';
        var nm = document.createElement('div'); nm.className = 'ae-ccl-name'; nm.textContent = vis.name || 'Unknown';
        mid.appendChild(nm);
        var count = _ccLauncherThreadsLoaded ? _ccLauncherCount(vis.id, povId) : -1;
        var sub = document.createElement('div'); sub.className = 'ae-ccl-sub';
        if (count > 0) sub.textContent = count + (count === 1 ? ' message' : ' messages');
        else if (count === 0) sub.textContent = 'Start a chat';
        else sub.textContent = '…';   // roster not loaded yet
        mid.appendChild(sub);
        row.appendChild(mid);
        var badge = document.createElement('div'); badge.className = 'ae-ccl-badge';
        if (count > 0) { badge.textContent = String(count); badge.classList.add('has'); }
        row.appendChild(badge);
        row.addEventListener('click', function() {
            // Hand off: start/resume in the story, then dismiss the widget. The engine
            // resolves resume-vs-start from the deterministic (contactId, povId) id.
            sendToEngine('AE_CHARCHAT_START', { contactId: vis.id, povId: povId });
            if (typeof PhantomManager !== 'undefined') PhantomManager.destroy();
        });
        host.appendChild(row);
    });
}

// [v2.34.0 CHARCHAT-LAUNCHER-SETTINGS] Chat settings header, moved here from the deleted
// _cchdr toolbar popup. Same actions, same labels; the difference is these now live on the
// launcher and (for thinking/images) work pre-chat via engine v2.51.6.
function _ccLauncherRenderSettings(hostEl) {
    // [BUGFIX v2.39.0 CHARCHAT-SETTINGS-DETACHED-DOM, per user] hostEl lets the
    // caller pass a direct element reference instead of relying on
    // document.getElementById -- which returns null for a node that's been
    // created but not yet attached to the document (exactly the state this was
    // always called in from _buildCharChatLauncher, below). Resync callers (the
    // AE_CHARCHAT_STATE handler, the avatar size/shape click handlers) still pass
    // nothing and fall back to the lookup, which is fine by then -- the host is
    // genuinely in the document at that point.
    var host = hostEl || document.getElementById('ae-ccl-settings');
    if (!host) return;
    host.innerHTML = '';
    var st = _charChatState;
    var chatActive = !!(st && st.active);
    var av = _ccavSettings();

    // Fresh thoughts on/off -- config op, works pre-chat now (engine v2.51.6).
    var thoughtsOn = !!(st && st.freshThoughts);
    host.appendChild($.btn(getCyberIconHTML('speech', 14) + ' Thoughts: ' + (thoughtsOn ? 'ON' : 'off'), 'sm ' + (thoughtsOn ? 'primary' : 'ghost'), function() {
        charChatAction('thinking', { on: !thoughtsOn });
    }));

    // Photo attachments on/off -- config op, works pre-chat now.
    var imagesOn = !!(st && st.images);
    host.appendChild($.btn(getCyberIconHTML('camera', 14) + ' Photos: ' + (imagesOn ? 'ON' : 'off'), 'sm ' + (imagesOn ? 'primary' : 'ghost'), function() {
        charChatAction('images', { on: !imagesOn });
    }));

    // Avatar size (S/M/L) -- bridge-local, instant.
    var sizeLbl = av.size <= 28 ? 'S' : (av.size >= 52 ? 'L' : 'M');
    host.appendChild($.btn('Size: ' + sizeLbl, 'sm ghost', function() {
        var cur = _ccavSettings().size;
        var next = cur < 40 ? 40 : (cur < 52 ? 52 : 28);
        localStorage.setItem('ae_ccav_size', String(next));
        _ccavApplySettings(); _ccLauncherRenderSettings();
    }));

    // Avatar shape (Round/Rounded/Portrait) -- bridge-local, instant.
    var shapeLbl = av.radius === 'round' ? 'Round' : (av.radius === 'rounded' ? 'Rounded' : 'Portrait');
    host.appendChild($.btn('Shape: ' + shapeLbl, 'sm ghost', function() {
        var cur = _ccavSettings().radius;
        var next = cur === 'round' ? 'rounded' : (cur === 'rounded' ? 'portrait' : 'round');
        localStorage.setItem('ae_ccav_radius', next);
        _ccavApplySettings(); _ccLauncherRenderSettings();
    }));

    // [v2.53.1 THOUGHT-INLINE-DISPLAY, per user] Was a tap-to-toast button (v2.38.0
    // CHARCHAT-SETTINGS-REBUILD, see its comment above for why the old submenu was
    // removed) -- per user, the popup itself should go too, replaced with a persistent
    // in-menu display. `width:100%` drops it onto its own line under the pill-button
    // row in this flex-wrap host rather than fighting them for space. No new state or
    // message -- reads the same st.lastThought this function already had, and repaints
    // on the same schedule (every _ccLauncherRenderSettings call) as the rest of the panel.
    var thoughtWrap = document.createElement('div');
    thoughtWrap.style.cssText = 'width:100%;display:flex;align-items:flex-start;gap:6px;margin-top:2px;padding:6px 8px;border-radius:6px;background:var(--ae-bg-panel);border:1px solid var(--ae-bg-border);';
    var thoughtIcon = document.createElement('span');
    thoughtIcon.style.cssText = 'flex-shrink:0;opacity:0.7;line-height:1;';
    thoughtIcon.innerHTML = getCyberIconHTML('inspect', 14);
    thoughtWrap.appendChild(thoughtIcon);
    var thoughtCol = document.createElement('div'); thoughtCol.style.cssText = 'flex:1 1 0;min-width:0;';
    var thoughtLbl = document.createElement('div');
    thoughtLbl.style.cssText = 'font-size:9.5px;letter-spacing:0.08em;text-transform:uppercase;color:var(--ae-text-dim);margin-bottom:2px;';
    thoughtLbl.textContent = 'Last thought';
    thoughtCol.appendChild(thoughtLbl);
    var thoughtHasText = chatActive && !!(st && st.lastThought);
    var thoughtTxt = document.createElement('div');
    thoughtTxt.style.cssText = 'font-size:12px;line-height:1.4;color:' + (thoughtHasText ? 'var(--ae-text-main)' : 'var(--ae-text-muted)') + ';font-style:' + (thoughtHasText ? 'normal' : 'italic') + ';';
    thoughtTxt.textContent = !chatActive ? 'No chat open.' : (thoughtHasText ? st.lastThought : 'No thought yet.');
    thoughtCol.appendChild(thoughtTxt);
    thoughtWrap.appendChild(thoughtCol);
    host.appendChild(thoughtWrap);
}

// Repaint the POV strip (avatar chips + a pinned "No POV" chip). Selecting a POV just
// re-renders the contact list from the cached roster — no round-trip.
function _ccLauncherRenderPov() {
    var host = document.getElementById('ae-ccl-pov');
    if (!host) return;
    host.innerHTML = '';
    function povChip(id, label, avUrl) {
        var chip = document.createElement('button'); chip.type = 'button';
        chip.className = 'ae-ccl-pov-chip' + ((_ccLauncherPovId === id) ? ' active' : '');
        var dot = document.createElement('div'); dot.className = 'ae-ccl-pov-ava';
        if (avUrl) { dot.style.backgroundImage = 'url(' + JSON.stringify(avUrl) + ')'; }
        else if (id) { dot.style.background = _nameToColor(label || '?'); dot.textContent = (label || '?').charAt(0).toUpperCase(); }
        else { dot.classList.add('nopov'); dot.appendChild(createCyberIcon('userScan', 13, 'currentColor')); }
        chip.appendChild(dot);
        var cl = document.createElement('span'); cl.className = 'ae-ccl-pov-lbl'; cl.textContent = label; chip.appendChild(cl);
        chip.addEventListener('click', function() {
            if (_ccLauncherPovId === id) return;
            _ccLauncherPovId = id;
            _ccLauncherRenderPov();
            _ccLauncherRenderContacts();
        });
        return chip;
    }
    host.appendChild(povChip('', 'No POV', null));
    cachedCharVisuals.forEach(function(vis) {
        if (vis && vis.id) host.appendChild(povChip(vis.id, vis.name || 'Unknown', vis._avatarDataUrl));
    });
}

function _buildCharChatLauncher() {
    // Reset per-open selection to No POV, and fetch the saved-thread roster ONCE.
    _ccLauncherPovId = '';
    _ccLauncherThreadsLoaded = false;
    _ccLauncherThreads = [];
    requestCharChatThreads();
    // The roster itself may be stale if the widget was opened cold; a cheap nudge keeps
    // the POV/contact lists honest (same request the roster grid relies on).
    if (engineScriptId) sendToEngine('REQUEST_CHAR_DATA', {});

    var wrap = document.createElement('div'); wrap.className = 'ae-ccl-wrap';

    // Header. Room is deliberately left here for a segmented [Characters | Wizard] tab in a
    // later pass (per user) — not built now, just not boxed out.
    var head = document.createElement('div'); head.className = 'ae-ccl-head';
    var title = document.createElement('div'); title.className = 'ae-ccl-title'; title.textContent = 'New message';
    head.appendChild(title);
    wrap.appendChild(head);

    // [v2.34.0 CHARCHAT-LAUNCHER-SETTINGS, per user] The chat settings that used to live in
    // the toolbar-docked popup (_cchdr, DELETED this pass) now sit here at the top of the
    // launcher -- the one chat control center. Fresh thoughts + Photo attachments write
    // GlobalConfig via charChatAction('thinking'/'images'); engine v2.51.6 honors both
    // PRE-chat now (they run above its active-chat guard), so toggling them here before you
    // pick a contact sticks. 'Show last thought' reads the ACTIVE chat's lastThought, so it
    // is greyed until a chat is open. Avatar size/shape are bridge-local (localStorage via
    // _ccavSettings), instant, no engine round-trip. _ccLauncherRenderSettings repaints the
    // labels off _charChatState the same way _cchdrRefreshLabels did.
    var settings = document.createElement('div'); settings.id = 'ae-ccl-settings'; settings.className = 'ae-ccl-settings';
    wrap.appendChild(settings);
    _ccLauncherRenderSettings(settings);  // [BUGFIX v2.39.0 CHARCHAT-SETTINGS-DETACHED-DOM] settings is not yet
    // in the document here (wrap hasn't been returned to the caller's appendChild yet) -- pass the
    // element directly so this doesn't depend on a getElementById lookup that would silently fail.

    var povLbl = document.createElement('div'); povLbl.className = 'ae-ccl-section-lbl'; povLbl.textContent = 'Text as';
    wrap.appendChild(povLbl);
    var povStrip = document.createElement('div'); povStrip.id = 'ae-ccl-pov'; povStrip.className = 'ae-ccl-pov-strip';
    wrap.appendChild(povStrip);

    var toLbl = document.createElement('div'); toLbl.className = 'ae-ccl-section-lbl'; toLbl.textContent = 'To';
    wrap.appendChild(toLbl);
    var contacts = document.createElement('div'); contacts.id = 'ae-ccl-contacts'; contacts.className = 'ae-ccl-contact-list';
    wrap.appendChild(contacts);

    _ccLauncherRenderPov();
    _ccLauncherRenderContacts();
    return wrap;
}

function _renderLiveWizTab(container) {
    container.id = 'ae-wizlive-body';
    container.innerHTML = '';
    var st = _liveWizState;
    var active = !!(st && st.active);

    container.appendChild(_buildStudioInfoBox('Chat with the world-build wizard directly inside the story document. Instructions and replies are plain, editable story text \u2014 nothing is hidden \u2014 and your system prompt and memory stay untouched while the chat is open.', null));

    var card = document.createElement('div');
    card.style.cssText = 'margin-top:12px;padding:16px;border:1px solid var(--ae-bg-border);border-radius:10px;background:var(--ae-bg-panel);display:flex;flex-direction:column;gap:12px;max-width:560px;';
    container.appendChild(card);

    var status = document.createElement('div');
    status.style.cssText = 'font-size:13px;font-weight:bold;color:' + (active ? 'var(--ae-accent)' : 'var(--ae-text-muted)') + ';';
    status.textContent = active
        ? ('\u25CF Chat open in the story' + (st.startedAt ? ' \u2014 since ' + new Date(st.startedAt).toLocaleTimeString() : ''))
        : '\u25CB No chat open';
    card.appendChild(status);

    if (!active) {
        var lead = document.createElement('div'); lead.style.cssText = 'font-size:12px;color:var(--ae-text-muted);line-height:1.5;';
        lead.textContent = 'Starting a chat appends a marker and an editable protocol paragraph to the end of your story. Talk to the wizard in { } instruct blocks (start a new paragraph with a curly brace), then press Send as normal. Edit any instruction \u2014 including the protocol itself \u2014 right in the document.';
        card.appendChild(lead);

        var selRow = document.createElement('div'); selRow.style.cssText = 'display:flex;gap:8px;align-items:center;flex-wrap:wrap;';
        var selLbl = document.createElement('span'); selLbl.style.cssText = 'font-size:12px;color:var(--ae-text-muted);flex-shrink:0;'; selLbl.textContent = 'Persona:'; selRow.appendChild(selLbl);
        var sel = document.createElement('select'); sel.id = 'ae-wizlive-topic';
        sel.style.cssText = 'flex:1;min-width:180px;background:var(--ae-bg-base);color:var(--ae-text-main);border:1px solid var(--ae-bg-border);border-radius:6px;padding:6px 8px;font-size:12px;';
        var og = document.createElement('option'); og.value = ''; og.textContent = 'General worldbuilding'; sel.appendChild(og);
        var lwTopics = (_wizState && _wizState.topics) ? _wizState.topics : [];
        lwTopics.forEach(function(t) { var o = document.createElement('option'); o.value = t.id; o.textContent = t.label; sel.appendChild(o); });
        selRow.appendChild(sel);
        card.appendChild(selRow);

        card.appendChild($.btn('\u25B6 Start Chat in Story', 'primary', function() {
            sendToEngine('AE_WIZLIVE_START', { topicId: sel.value || '' });
            // [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] _galleryOverlay no longer exists.
        }));
    } else {
        var lead2 = document.createElement('div'); lead2.style.cssText = 'font-size:12px;color:var(--ae-text-muted);line-height:1.5;';
        lead2.textContent = 'The chat is live below the purple marker in your story. When you are done, choose how to close it \u2014 every option except Discard also archives the transcript to Wizard Chats first, and all of them remove the chat paragraphs back to the marker.';
        card.appendChild(lead2);

        var mkEnd = function(label, action, variant, confirmMsg) {
            return $.btn(label, variant, function() {
                if (confirmMsg && !window.confirm(confirmMsg)) return;
                sendToEngine('AE_WIZLIVE_END', { action: action });
                // [DEAD, v2.46.0 STUDIO-SHELL-TEARDOWN] _galleryOverlay no longer exists.
            });
        };
        card.appendChild(mkEnd('\uD83D\uDCBE Save & Clear', 'save', 'primary', null));
        card.appendChild(mkEnd('\uD83D\uDCCC Commit Chat to Memory & Clear', 'commit', 'ghost', null));
        card.appendChild(mkEnd('\u2728 Summarize \u2192 Memory & Clear', 'summarize', 'ghost', null));
        card.appendChild(mkEnd('\uD83D\uDDD1 Discard Chat', 'discard', 'danger', 'Discard the chat without saving anything?'));
    }
}

